  ------------------------------------------------------------------------------
  -- Procedimento para Obter o Parâmetro da Filial STRING
  ------------------------------------------------------------------------------
  PROCEDURE POBTEM_PARAMFILIAL_STRING(pi_vCodFilial   IN VARCHAR2,
                                      pi_vNomeCampo   IN VARCHAR2,
                                      pi_vValorPadrao IN VARCHAR2,
                                      po_vValor     OUT VARCHAR2) IS
  BEGIN

    -- Inicializa Retorno
    po_vValor := NULL;

    -- Pesquisa Parametro
    BEGIN
      SELECT PCPARAMFILIAL.VALOR
        INTO po_vValor
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = pi_vNomeCampo);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_vValor := NULL;
    END;
    
    -- Valor Padrão se NULO
    po_vValor := NVL(po_vValor,pi_vValorPadrao);

  END POBTEM_PARAMFILIAL_STRING;
  
  ----------------------------------------------------
  -- Funções auxiliares de texto - DDVENDAS-33943
  ----------------------------------------------------  

  FUNCTION GET_CHR_OP RETURN VARCHAR2 IS
  BEGIN 
    RETURN CHR(63);
  END GET_CHR_OP;

  FUNCTION LPAD_BRANCOS(pi_vTexto   IN VARCHAR2, 
                        pi_nTamanho IN NUMBER) RETURN VARCHAR2 IS
    vvTexto VARCHAR2(4000);                        
  BEGIN 
    vvTexto := REPLACE(pi_vTexto,GET_CHR_OP,'');
    RETURN SUBSTR(LPAD(NVL(vvTexto,' '), pi_nTamanho, ' '),1,pi_nTamanho);
  END LPAD_BRANCOS;

  FUNCTION RPAD_BRANCOS(pi_vTexto   IN VARCHAR2, 
                        pi_nTamanho IN NUMBER) RETURN VARCHAR2 IS
    vvTexto VARCHAR2(4000);                        
  BEGIN 
    vvTexto := REPLACE(pi_vTexto,GET_CHR_OP,'');
    RETURN SUBSTR(RPAD(NVL(vvTexto,' '), pi_nTamanho, ' '),1,pi_nTamanho);
  END RPAD_BRANCOS;

  FUNCTION LPAD_ZEROS(pi_vTexto   IN VARCHAR2, 
                      pi_nTamanho IN NUMBER) RETURN VARCHAR2 IS
    vvTexto VARCHAR2(4000);                        
  BEGIN 
    vvTexto := REPLACE(pi_vTexto,GET_CHR_OP,'');
    RETURN SUBSTR(LPAD(NVL(vvTexto,'0'), pi_nTamanho, '0'),1,pi_nTamanho);
  END LPAD_ZEROS;

  FUNCTION LPAD_ZEROS_DEC(pi_nValor    IN NUMBER, 
                          pi_nTamanho  IN NUMBER,
                          pi_iCasasDec IN INTEGER) RETURN VARCHAR2 IS
    vvTexto  VARCHAR2(4000);     
    vvFator  VARCHAR2(255);                   
    vnFator  NUMBER;       
    vnNumero NUMBER;            
  BEGIN     
    IF (NVL(pi_iCasasDec,0) > 0) THEN
      vvFator := '1';
      FOR viLaco IN 1..pi_iCasasDec LOOP
        vvFator := vvFator || '0';
      END LOOP;
      vnFator := TO_NUMBER(vvFator);
    ELSE
      vnFator := 1;
    END IF;
    vnNumero := ROUND(pi_nValor * vnFator,0);
    vvTexto  := TO_CHAR(vnNumero);
    --123456789
    --Se TAM 7
    --3456789
    IF (LENGTH(vvTexto) > pi_nTamanho) THEN
      vvTexto := SUBSTR(vvTexto, (LENGTH(vvTexto)-pi_nTamanho) + 1, LENGTH(vvTexto));
    END IF;
    RETURN SUBSTR(LPAD(NVL(vvTexto,'0'), pi_nTamanho, '0'),1,pi_nTamanho);
  END LPAD_ZEROS_DEC;

  ------------------------------------------------------------------
  -- Função para retornar o Código do Cliente do ST - DDVENDAS-33943
  ------------------------------------------------------------------  
  FUNCTION F_CODCLI_ST(pi_vCodFilial IN VARCHAR2,
                       pi_vUf        IN VARCHAR2) RETURN NUMBER IS
    vnRetCodCliSt PCCLIENT.CODCLI%TYPE;
  BEGIN
    
    vnRetCodCliSt := NULL;
    
    -- Pesquisa uma pessoa Jurica com Compras que calcula ST Fonte
    FOR vc_Cliente IN (SELECT PCCLIENT.CODCLI
                         FROM PCCLIENT
                        WHERE (PCCLIENT.TIPOFJ = 'J')
                          AND (NVL(PCCLIENT.ORGAOPUB,'N') = 'N')
                          AND (NVL(PCCLIENT.ORGAOPUBMUNICIPAL,'N') = 'N')
                          AND (NVL(PCCLIENT.ORGAOPUBFEDERAL,'N') = 'N')
                          AND (PCCLIENT.SULFRAMA IS NULL)
                          AND (NVL((SELECT CF.CLIENTEFONTEST 
                                      FROM PCCLIENTFILIALMED CF
                                     WHERE CF.CODFILIAL = pi_vCodFilial
                                       AND CF.CODCLI = PCCLIENT.CODCLI),PCCLIENT.CLIENTEFONTEST) = 'S')
                          AND (PCCLIENT.ESTENT = pi_vUf)  
                          AND (PCCLIENT.DTULTCOMP IS NOT NULL)
                          AND (NVL(PCCLIENT.SIMPLESNACIONAL,'N') = 'N')
                         ORDER BY PCCLIENT.DTULTCOMP DESC) LOOP
      vnRetCodCliSt := vc_Cliente.CODCLI;     
      EXIT;                    
    END LOOP;   
    
    -- Procura qualquer cliente pessoa Jurifica que calcula ST Fonte
    IF (NVL(vnRetCodCliSt,0) = 0) THEN
      FOR vc_Cliente IN (SELECT PCCLIENT.CODCLI
                           FROM PCCLIENT
                          WHERE (PCCLIENT.TIPOFJ = 'J')
                            AND (NVL((SELECT CF.CLIENTEFONTEST 
                                        FROM PCCLIENTFILIALMED CF
                                       WHERE CF.CODFILIAL = pi_vCodFilial
                                         AND CF.CODCLI = PCCLIENT.CODCLI),PCCLIENT.CLIENTEFONTEST) = 'S')
                            AND (PCCLIENT.ESTENT = pi_vUf)  
                           ORDER BY PCCLIENT.DTULTCOMP DESC) LOOP
        vnRetCodCliSt := vc_Cliente.CODCLI;                         
        EXIT;                    
      END LOOP;       
    END IF;

    -- Procura o Cliente da Filial
    IF (NVL(vnRetCodCliSt,0) = 0) THEN    
      FOR vc_Cliente IN (SELECT PCFILIAL.CODCLI
                           FROM PCFILIAL
                          WHERE (PCFILIAL.CODIGO = pi_vCodFilial)) LOOP
        vnRetCodCliSt := vc_Cliente.CODCLI;                         
      END LOOP;       
    END IF;
    
    -- Retorna o Cliente
    RETURN vnRetCodCliSt;
                          
  END F_CODCLI_ST;

  -----------------------------------------------------------
  -- Função para retornar a Operação - DDVENDAS-33943
  -----------------------------------------------------------  
  PROCEDURE P_OPERACAO_HYPER(pi_vCodSistema             IN VARCHAR2,
                             pi_vCodFilial              IN VARCHAR2,
                             pi_vArquivo                IN VARCHAR2,
                             pi_vTipoRegistro           IN VARCHAR2,
                             pi_vConteudo               IN VARCHAR2,
                             pi_vTipoCodigoPrincipal    IN VARCHAR2,
                             pi_vCodigoPrincipal        IN VARCHAR2,
                             pi_vTipoCodigoSecundario   IN VARCHAR2,
                             pi_vCodigoSecundario       IN VARCHAR2,
                             pi_vTipoCodigoComplementar IN VARCHAR2,
                             pi_vCodigoComplementar     IN VARCHAR2,
                             po_vExisteRegistro         OUT VARCHAR2,
                             po_vOperacao               OUT VARCHAR2)
  IS
    vvConteudoAnterior PCCONFIGSISTCONDOPERLOG.CONTEUDO%TYPE;
  BEGIN    
    -- Retorno retorna como padrão N - Nenhuma
    po_vOperacao := 'N';
    -- Pesquisa alterações do último conteúdo com relação ao conteúdo atual
    BEGIN
      SELECT 'S'
           , PCCONFIGSISTCONDOPERLOG.CONTEUDO           
        INTO po_vExisteRegistro
           , vvConteudoAnterior
        FROM PCCONFIGSISTCONDOPERLOG
       WHERE (PCCONFIGSISTCONDOPERLOG.CODSISTEMA             = pi_vCodSistema)
         AND (PCCONFIGSISTCONDOPERLOG.CODFILIAL              = pi_vCodFilial)
         AND (PCCONFIGSISTCONDOPERLOG.ARQUIVO                = pi_vArquivo)
         AND (PCCONFIGSISTCONDOPERLOG.TIPOREGISTRO           = pi_vTipoRegistro)
         AND (PCCONFIGSISTCONDOPERLOG.TIPOCODIGOPRINCIPAL    = NVL(pi_vTipoCodigoPrincipal,'NA'))
         AND (PCCONFIGSISTCONDOPERLOG.CODIGOPRINCIPAL        = NVL(pi_vCodigoPrincipal,'NA'))
         AND (PCCONFIGSISTCONDOPERLOG.TIPOCODIGOSECUNDARIO   = NVL(pi_vTipoCodigoSecundario,'NA'))
         AND (PCCONFIGSISTCONDOPERLOG.CODIGOSECUNDARIO       = NVL(pi_vCodigoSecundario,'NA'))
         AND (PCCONFIGSISTCONDOPERLOG.TIPOCODIGOCOMPLEMENTAR = NVL(pi_vTipoCodigoComplementar,'NA'))
         AND (PCCONFIGSISTCONDOPERLOG.CODIGOCOMPLEMENTAR     = NVL(pi_vCodigoComplementar,'NA'));
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_vExisteRegistro := 'N';
        vvConteudoAnterior := NULL;        
    END;
    IF (vvConteudoAnterior IS NULL) THEN
      po_vOperacao := 'I';    
    ELSE
      IF (NVL(pi_vConteudo,' ') <> NVL(vvConteudoAnterior,' ')) THEN
        po_vOperacao := 'A';    
      END IF;
    END IF;
  END P_OPERACAO_HYPER;
  
  --------------------------------------------------------------
  -- Procedimento para Inicializar os Registros - DDVENDAS-33943
  --------------------------------------------------------------  
  PROCEDURE P_INICIALIZA_REGISTRO_HYPER(pi_vCodSistema IN VARCHAR2,
                                        pi_vCodFilial  IN VARCHAR2) 
  IS
    vvOperacao PCCONFIGSISTCONDOPERLOG.OPERACAO%TYPE; 
  BEGIN
    -- Inicializa Novo Conteúdo e Operação
    UPDATE PCCONFIGSISTCONDOPERLOG
       SET NOVOCONTEUDO = NULL
         , NOVAOPERACAO = NULL
     WHERE (CODSISTEMA = pi_vCodSistema)
       AND (CODFILIAL  = pi_vCodFilial);
  END P_INICIALIZA_REGISTRO_HYPER;  
  
   ----------------------------------------------------------------------
  -- Função para verificar se vai ter Inclusão/Alteração - DDVENDAS-37737
  -----------------------------------------------------------------------
  FUNCTION F_VALIDA_REGISTRO_HYPER(pi_vCodSistema             IN VARCHAR2,
                                   pi_vCodFilial              IN VARCHAR2,
                                   pi_vArquivo                IN VARCHAR2,
                                   pi_vTipoRegistro           IN VARCHAR2,
                                   pi_vConteudo               IN VARCHAR2,
                                   pi_vAlterouDetalhes        IN VARCHAR2,
                                   pi_vObservacao             IN VARCHAR2,
                                   pi_vTipoCodigoPrincipal    IN VARCHAR2,
                                   pi_vCodigoPrincipal        IN VARCHAR2,
                                   pi_vTipoCodigoSecundario   IN VARCHAR2 DEFAULT 'NA',
                                   pi_vCodigoSecundario       IN VARCHAR2 DEFAULT 'NA',
                                   pi_vTipoCodigoComplementar IN VARCHAR2 DEFAULT 'NA',
                                   pi_vCodigoComplementar     IN VARCHAR2 DEFAULT 'NA') 
  RETURN VARCHAR2 IS
    vvExisteRegistro VARCHAR2(1);
    vvOperacao       PCCONFIGSISTCONDOPERLOG.OPERACAO%TYPE; 
  BEGIN
  
    -- Verifica a Operação
    P_OPERACAO_HYPER(pi_vCodSistema,
                     pi_vCodFilial,
                     pi_vArquivo,
                     pi_vTipoRegistro,
                     pi_vConteudo,
                     pi_vTipoCodigoPrincipal,
                     pi_vCodigoPrincipal,
                     pi_vTipoCodigoSecundario,
                     pi_vCodigoSecundario,
                     pi_vTipoCodigoComplementar,
                     pi_vCodigoComplementar,
                     vvExisteRegistro,
                     vvOperacao);
                                   
    -- Se alterou os detalhes e não foi Inclusão
    -- (A ideia é: Se o cabeçalho não mudou, porém seus detalhes foram alterados, é considerado também alteração do cabeçalho)
    IF (pi_vAlterouDetalhes = 'S') THEN
      IF (vvOperacao <> 'I') THEN
        vvOperacao := 'A';
      END IF;
    END IF;
                                       
    RETURN vvOperacao;
    
  END F_VALIDA_REGISTRO_HYPER;
 
  -----------------------------------------------------------
  -- Função para Inserir os Registros - DDVENDAS-33943
  -----------------------------------------------------------  
  FUNCTION F_GRAVA_REGISTRO_HYPER(pi_vCodSistema             IN VARCHAR2,
                                  pi_vCodFilial              IN VARCHAR2,
                                  pi_vArquivo                IN VARCHAR2,
                                  pi_vTipoRegistro           IN VARCHAR2,
                                  pi_vConteudo               IN VARCHAR2,
                                  pi_vAlterouDetalhes        IN VARCHAR2,
                                  pi_vObservacao             IN VARCHAR2,
                                  pi_vTipoCodigoPrincipal    IN VARCHAR2,
                                  pi_vCodigoPrincipal        IN VARCHAR2,
                                  pi_vTipoCodigoSecundario   IN VARCHAR2 DEFAULT 'NA',
                                  pi_vCodigoSecundario       IN VARCHAR2 DEFAULT 'NA',
                                  pi_vTipoCodigoComplementar IN VARCHAR2 DEFAULT 'NA',
                                  pi_vCodigoComplementar     IN VARCHAR2 DEFAULT 'NA') 
  RETURN VARCHAR2 IS
    vvExisteRegistro VARCHAR2(1);
    vvOperacao       PCCONFIGSISTCONDOPERLOG.OPERACAO%TYPE; 
  BEGIN
  
    -- Verifica a Operação
    P_OPERACAO_HYPER(pi_vCodSistema,
                     pi_vCodFilial,
                     pi_vArquivo,
                     pi_vTipoRegistro,
                     pi_vConteudo,
                     pi_vTipoCodigoPrincipal,
                     pi_vCodigoPrincipal,
                     pi_vTipoCodigoSecundario,
                     pi_vCodigoSecundario,
                     pi_vTipoCodigoComplementar,
                     pi_vCodigoComplementar,
                     vvExisteRegistro,
                     vvOperacao);
                                   
    -- Se alterou os detalhes e não foi Inclusão
    -- (A ideia é: Se o cabeçalho não mudou, porém seus detalhes foram alterados, é considerado também alteração do cabeçalho)
    IF (pi_vAlterouDetalhes = 'S') THEN
      IF (vvOperacao <> 'I') THEN
        vvOperacao := 'A';
      END IF;
    END IF;
                                   
    -- Filiais - nunca mandar alteração - DDVENDAS-38410
    IF (pi_vTipoCodigoPrincipal  = 'PM') AND
       (pi_vTipoCodigoSecundario = 'FI') AND
       (vvOperacao               = 'A')  THEN
      vvOperacao := 'I'; 
    END IF;
                                   
    -- Se não existir o Registro
    IF    (vvExisteRegistro = 'N') THEN
    
      INSERT INTO PCCONFIGSISTCONDOPERLOG
                ( CODSISTEMA
                , CODFILIAL
                , ARQUIVO
                , TIPOREGISTRO
                , TIPOCODIGOPRINCIPAL
                , CODIGOPRINCIPAL
                , TIPOCODIGOSECUNDARIO
                , CODIGOSECUNDARIO
                , TIPOCODIGOCOMPLEMENTAR
                , CODIGOCOMPLEMENTAR
                , NOVOCONTEUDO
                , NOVAOPERACAO
                , OBSEXPORTACAO )
         VALUES ( pi_vCodSistema
                , pi_vCodFilial
                , pi_vArquivo
                , pi_vTipoRegistro
                , NVL(pi_vTipoCodigoPrincipal,'NA')
                , NVL(pi_vCodigoPrincipal,'NA')
                , NVL(pi_vTipoCodigoSecundario,'NA')
                , NVL(pi_vCodigoSecundario,'NA')
                , NVL(pi_vTipoCodigoComplementar,'NA')
                , NVL(pi_vCodigoComplementar,'NA')
                , pi_vConteudo
                , vvOperacao
                , pi_vObservacao );
                
    -- Se não for Inclusão
    ELSE
    
      UPDATE PCCONFIGSISTCONDOPERLOG
         SET NOVOCONTEUDO  = pi_vConteudo
           , NOVAOPERACAO  = vvOperacao
           , OBSEXPORTACAO = pi_vObservacao
       WHERE (CODSISTEMA             = pi_vCodSistema)
         AND (CODFILIAL              = pi_vCodFilial)
         AND (ARQUIVO                = pi_vArquivo)
         AND (TIPOREGISTRO           = pi_vTipoRegistro)
         AND (TIPOCODIGOPRINCIPAL    = NVL(pi_vTipoCodigoPrincipal,'NA'))
         AND (CODIGOPRINCIPAL        = NVL(pi_vCodigoPrincipal,'NA'))
         AND (TIPOCODIGOSECUNDARIO   = NVL(pi_vTipoCodigoSecundario,'NA'))
         AND (CODIGOSECUNDARIO       = NVL(pi_vCodigoSecundario,'NA'))
         AND (TIPOCODIGOCOMPLEMENTAR = NVL(pi_vTipoCodigoComplementar,'NA'))
         AND (CODIGOCOMPLEMENTAR     = NVL(pi_vCodigoComplementar,'NA'));
         
    END IF;
    
    RETURN vvOperacao;
    
  END F_GRAVA_REGISTRO_HYPER;

  ------------------------------------------------------------------
  -- Procedimento para obter o Preço e a Tributação - DDVENDAS-33943
  ------------------------------------------------------------------
  PROCEDURE P_OBTER_PRECO_TRIBUTACAO(pi_vCodFilial                IN VARCHAR2,
                                     pi_vUsaTributacaoPorUf       IN VARCHAR2,
                                     pi_nNumCasasDecVenda         IN NUMBER,
                                     pi_vUsaRegraRecalDescPTabMed IN VARCHAR2,
                                     pi_vOrigemPreco              IN VARCHAR2,
                                     pi_vAplicarDescPtabelaTribut IN VARCHAR2,
                                     pi_vGerarAcordoPreco         IN VARCHAR2,
                                     pi_vAplicarIndiceAcordoPreco IN VARCHAR2,
                                     pi_nNumRegiao                IN NUMBER,
                                     pi_vUfRegiao                 IN VARCHAR2,
                                     pi_nCodProd                  IN NUMBER,
                                     pi_vTipoMerc                 IN VARCHAR2,
                                     pi_vUtilizaPrecoFabrica      IN VARCHAR2,
                                     po_nPreco                    OUT NUMBER,
                                     po_nCodSt                    OUT NUMBER) 
  IS
  
    vnPerDesTab      PCTRIBUT.PERDESTAB%TYPE;
    vnPrecoMaxConsum PCPRODUT.PRECOMAXCONSUM%TYPE;
    vnPrecoFabrica   PCPRODUT.CUSTOREP%TYPE;
    vvMensagemPmc    VARCHAR2(2000);
    vnIndicePreco    PCTABPR.INDICEPRECO%TYPE;
  
  BEGIN                         
    
    po_nPreco := 0;
    po_nCodSt := NULL;
      
    -- Se usa Tributação por UF
    IF (NVL(pi_vUsaTributacaoPorUf,'N') = 'S') THEN
      -- Pesquisa Tributação por UF
      BEGIN
        SELECT CODST
          INTO po_nCodSt
          FROM PCTABTRIB
         WHERE (CODPROD     = pi_nCodProd)
           AND (UFDESTINO   = pi_vUfRegiao)
           AND (CODFILIALNF = pi_vCodFilial);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_nCodSt := NULL;
      END;
    -- Se NÃO usa Tributação por UF
    ELSE
      -- Pesquisa Tributação por Região
      BEGIN
        SELECT CODST
          INTO po_nCodSt
          FROM PCTABPR
         WHERE (CODPROD   = pi_nCodProd)
           AND (NUMREGIAO = pi_nNumRegiao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_nCodSt := NULL;
      END;
    END IF; -- Fim Condição v_usatributacaoporuf
  
    -- Dados Complementares do Produto - Tributação
    BEGIN
      SELECT PCTRIBUT.PERDESTAB
        INTO vnPerDesTab
        FROM PCTRIBUT
       WHERE (PCTRIBUT.CODST = po_nCodSt);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnPerDesTab := 0;
    END;
    
    -- Zera Desconto Repasse se na Integradora não estiver marcada para Aplicar o Desconto PTabela da Tributação
    IF (pi_vAplicarDescPtabelaTribut <> 'S') THEN
      vnPerDesTab := 0;
    END IF;
  
    -- Obtém PMC e Preço Fábrica
    PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(pi_vCodFilial,
                                         pi_nCodProd,
                                         pi_vUfRegiao,
                                         pi_nNumRegiao,
                                         vnPrecoMaxConsum,
                                         vnPrecoFabrica,
                                         vvMensagemPmc);
  
    -- Preço Inicial será da Tabela de Preços
    BEGIN
      SELECT PVENDA1
           , INDICEPRECO
        INTO po_nPreco
           , vnIndicePreco
        FROM PCTABPR
       WHERE (CODPROD   = pi_nCodProd)
         AND (NUMREGIAO = pi_nNumRegiao);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        po_nPreco     := 0;
        vnIndicePreco := 0;
    END;

    -- Aplica Indice sobre o Preço Tabela
    IF (NVL(pi_vGerarAcordoPreco,'N') = 'S')         AND
       (NVL(pi_vAplicarIndiceAcordoPreco,'N') = 'S') AND
       (NVL(vnIndicePreco,0) <> 0)                   THEN
      po_nPreco := (NVL(po_nPreco,0) * NVL(vnIndicePreco,0));
    END IF;
  
    -- Se Medicamento
    IF (NVL(pi_vTipoMerc,' ') IN ('M','MA')) OR
       (NVL(pi_vUtilizaPrecoFabrica,'N') = 'S') THEN
      -- Se Origem Preço é Fábrica
      IF (NVL(pi_vOrigemPreco,'F') = 'F') THEN
        -- O Preço será o Fábrica
        po_nPreco := NVL(vnPrecoFabrica,0);
        -- Desconto de Repasse
        IF (pi_vAplicarDescPtabelaTribut = 'S') THEN
          po_nPreco := round(po_nPreco * (1 - (nvl(vnPerDesTab,0) / 100)), pi_nNumCasasDecVenda);
        END IF;
      -- Se não for Fábrica, trato as exceções
      ELSE
        -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela e mandar o Preço Fábrica,
        -- onde a Integradora tem Origem Preço = Preço Tabela
        IF (pi_vUsaRegraRecalDescPTabMed = 'S') THEN
          ------------------
          -- Redefine para o Preço Fábrica
          po_nPreco := NVL(vnPrecoFabrica,0);
          -- Desconto de Repasse
          IF (pi_vAplicarDescPtabelaTribut = 'S') THEN
            po_nPreco := round(po_nPreco * (1 - (nvl(vnPerDesTab,0) / 100)), pi_nNumCasasDecVenda);
          END IF;
          ------------------
        END IF;
      END IF;
    END IF;
              
  END P_OBTER_PRECO_TRIBUTACAO;

