                                        pi_nPrecoMaxConsum,
                                        pi_nValorUltEnt,
                                        pi_nCustoNfSemSt,
                                        pi_nPTabela,
                                        pi_vSomenteIVATribut,
                                        pi_vPesquisarCustos,
                                        pi_vItemBonific,
                                        pi_nVlFreteOutrasDesp,
                                        po_nBaseStFonte,        -->> RETORNA A BASE DO ST
                                        po_nValorStFonte,       -->> RETORNA O VALOR DO ST
                                        po_vMensagem,           -->> Retorna a Mensagem de Erro
