                                        vnVLICMSSTRETANTERIOR,
                                        vnSTCLIENTEGNRE,
                                        vnPMPF,
                                        vvClienteFonteSt);

    po_nValorStFonte := NVL(po_nValorStFonte,0) + NVL(vrDadosFuncep.nVLFECP,0) + NVL(vnVLICMSSTRETANTERIOR,0);

  END P_OBTEM_STFONTE_4PMPF;

  --+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
  -- Nome         : P_INSERE_RESTRICAO_PRODUTO
  -- Descricão    : Inserir Restrição de Produtos da Condição - DDMEDICA-5511
  --+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++/
  PROCEDURE P_INSERE_RESTRICAO_PRODUTO(pi_vCodSistema            IN VARCHAR2,
                                       pi_nCodCondicaoVenda      IN NUMBER,
                                       pi_nCodProd               IN NUMBER,
                                       pi_nQtInicial             IN NUMBER,
                                       pi_nQtFinal               IN NUMBER,
                                       pi_nCodPromocaoFaixa      IN NUMBER,
                                       pi_nCodPromocaoNormal     IN NUMBER,
                                       pi_vRejeitarItemForaFaixa IN VARCHAR2) IS
    vvInseriuRestricao VARCHAR2(1);
  BEGIN
    -- Se parametrizado para Rejeitar Itens Fora da Faixa de Quantidade
    IF (pi_vRejeitarItemForaFaixa = 'S') THEN
      -- Se não tem Promoção Normal (Promoção sem Faixa de Quantidade)
      IF (NVL(pi_nCodPromocaoNormal,0) = 0) THEN
        
        -- Verifica se já inseriu a Restrição
        BEGIN
          SELECT 'S'
            INTO vvInseriuRestricao
            FROM PCMED_VIEWOLCONDVENDA_RESTPR_T
           WHERE (CODSISTEMA       = pi_vCodSistema)
             AND (CODCONDICAOVENDA = pi_nCodCondicaoVenda)
             AND (CODPROD          = pi_nCodProd)
             AND (QTINICIAL        = pi_nQtInicial)
             AND (QTFINAL          = pi_nQtFinal);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvInseriuRestricao := 'N';
        END;
      
        -- Se ainda não inseriu a Restrição insere
        IF (vvInseriuRestricao = 'N') THEN
          INSERT INTO PCMED_VIEWOLCONDVENDA_RESTPR_T
                    ( CODSISTEMA
                    , CODCONDICAOVENDA
                    , CODPROD
                    , QTINICIAL
                    , QTFINAL
                    , CODPROMOCAOMED )
             VALUES ( pi_vCodSistema
                    , pi_nCodCondicaoVenda
                    , pi_nCodProd
                    , pi_nQtInicial
                    , pi_nQtFinal
                    , pi_nCodPromocaoFaixa );
        END IF;
      
      END IF;         
    END IF;
  END P_INSERE_RESTRICAO_PRODUTO;
  --+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++

  -----------------------------------------------------------------------------
  -- Procedimento para Inserir os Grupos de Plano de Pagamento - DDVENDAS-35908
  ----------------------------------------------------------------------------
  PROCEDURE P_INSERE_GRUPO_PLANO(pi_vCodSistema IN VARCHAR2) IS
    -- Informações de Extração
    TYPE TT_NUMBER         IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    vtCODCLI               TT_NUMBER;
    vtCODLINHAPRAZO        TT_NUMBER;
    vtCODPLPAG             TT_NUMBER;
    -- Lista de Planos
    TYPE TRecPlanoCliente  IS RECORD (
         vnCodLinhaPrazo   PCLINHAPRAZO.CODLINHAPRAZO%TYPE,
         vnCodPlPag        PCPLPAG.CODPLPAG%TYPE);
    TYPE TTvPlanosCliente  IS TABLE OF TRecPlanoCliente INDEX BY BINARY_INTEGER;
    vtPlanosCliente        TTvPlanosCliente;
    viIdxPlanos            INTEGER;
    -- Valores
    vnCodCli               PCCLIENT.CODCLI%TYPE;
    vnCodLinhaPrazo        PCLINHAPRAZO.CODLINHAPRAZO%TYPE;
    vnCodPlPag             PCPLPAG.CODPLPAG%TYPE;
    vvValoresEtico         VARCHAR2(4000);
    vvValoresGenerico      VARCHAR2(4000);
    vnCodGrupo             NUMBER;
    -- Quebra
    vnQuebraCliente        NUMBER;   
    -- Função para retornar quebra
    FUNCTION F_RETORNA_QUEBRA_GRUPO(pi_vValoresEtico    IN VARCHAR2,
                                    pi_vValoresGenerico IN VARCHAR2,
                                    pi_tPlanosCliente   IN TTvPlanosCliente) RETURN NUMBER IS 
      vnRetCodGrupo NUMBER;
    BEGIN

      BEGIN
        SELECT CODGRUPO
          INTO vnRetCodGrupo
          FROM PCCONFIGSISTGRUPLANO
         WHERE (PCCONFIGSISTGRUPLANO.CODSISTEMA               = pi_vCodSistema)
           AND (PCCONFIGSISTGRUPLANO.VALORAGRUPAMENTOETICO    = NVL(pi_vValoresEtico,'0'))
           AND (PCCONFIGSISTGRUPLANO.VALORAGRUPAMENTOGENERICO = NVL(pi_vValoresGenerico,'0'));
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnRetCodGrupo := 0;
      END;
      
      IF (NVL(vnRetCodGrupo,0) = 0) THEN
      
        SELECT MAX(CODGRUPO)
          INTO vnRetCodGrupo
          FROM PCCONFIGSISTGRUPLANO
         WHERE (PCCONFIGSISTGRUPLANO.CODSISTEMA = pi_vCodSistema);
        vnRetCodGrupo := NVL(vnRetCodGrupo,0) + 1;
        
        -- Grupos
        INSERT INTO PCCONFIGSISTGRUPLANO
                  ( CODSISTEMA
                  , CODGRUPO
                  , DESCRICAO
                  , VALORAGRUPAMENTOETICO
                  , VALORAGRUPAMENTOGENERICO )
           VALUES ( pi_vCodSistema
                  , vnRetCodGrupo
                  , 'Grupo ' || vnRetCodGrupo
                  , NVL(pi_vValoresEtico,'0')
                  , NVL(pi_vValoresGenerico,'0') );
                  
        IF (pi_tPlanosCliente.COUNT > 0) THEN
          FOR viIdx IN pi_tPlanosCliente.FIRST..pi_tPlanosCliente.LAST LOOP
            -- Relacionamento Grupo x Linha de Prazo
            INSERT INTO PCCONFIGSISTGRUPLANOLIN
                      ( CODSISTEMA
                      , CODGRUPO
                      , CODLINHAPRAZO
                      , CODPLPAG )
               VALUES ( pi_vCodSistema
                      , vnRetCodGrupo
                      , pi_tPlanosCliente(viIdx).vnCodLinhaPrazo
                      , pi_tPlanosCliente(viIdx).vnCodPlPag );
          END LOOP;
        END IF; 
                  
      END IF;
      
      RETURN vnRetCodGrupo;
    
    END F_RETORNA_QUEBRA_GRUPO;
    --
  BEGIN
  
    -------------------------------------------
    -- Carrega o Relacionamento Plano x Cliente
    -------------------------------------------

    BEGIN
      EXECUTE IMMEDIATE ' SELECT VIEW_OL_CLIENTEPLPAG.CODCLI
                               , VIEW_OL_CLIENTEPLPAG.CODLINHAPRAZO
                               , VIEW_OL_CLIENTEPLPAG.CODPLPAG
                            FROM VIEW_OL_CLIENTEPLPAG
                           WHERE (VIEW_OL_CLIENTEPLPAG.CODSISTEMA = ' || '''' || pi_vCodSistema || '''' || ')
                           ORDER BY VIEW_OL_CLIENTEPLPAG.CODCLI
                                  , VIEW_OL_CLIENTEPLPAG.CODLINHAPRAZO 
                                  , VIEW_OL_CLIENTEPLPAG.CODPLPAG '
        BULK COLLECT INTO vtCODCLI
                        , vtCODLINHAPRAZO
                        , vtCODPLPAG;
    EXCEPTION
      WHEN OTHERS THEN
        NULL;
    END;                        
  
    IF (vtCODCLI.COUNT > 0) THEN
    
      DELETE FROM PCCONFIGSISTGRUPLANO    WHERE CODSISTEMA = pi_vCodSistema; 
      DELETE FROM PCCONFIGSISTGRUPLANOCLI WHERE CODSISTEMA = pi_vCodSistema; 
      DELETE FROM PCCONFIGSISTGRUPLANOLIN WHERE CODSISTEMA = pi_vCodSistema; 
    
      vnQuebraCliente := -1;
  
      FOR viIdxCli IN vtCODCLI.FIRST..vtCODCLI.LAST LOOP
      
        -- Pega valores da Extração
        vnCodCli        := vtCODCLI(viIdxCli);
        vnCodLinhaPrazo := vtCODLINHAPRAZO(viIdxCli);
        vnCodPlPag      := vtCODPLPAG(viIdxCli);
        
        -- Se Quebra de Cliente
        IF (vnQuebraCliente <> vnCodCli) THEN
        
          -- Se não for primeira quebra
          IF (vnQuebraCliente <> -1) THEN
          
            vnCodGrupo := F_RETORNA_QUEBRA_GRUPO(vvValoresEtico,
                                                 vvValoresGenerico,
                                                 vtPlanosCliente);            
            
            -- Relacionamento Grupo x Cliente
            INSERT INTO PCCONFIGSISTGRUPLANOCLI
                      ( CODSISTEMA
                      , CODGRUPO
                      , CODCLI )
               VALUES ( pi_vCodSistema
                      , vnCodGrupo
                      , vnQuebraCliente );
            
          END IF;      

          vtPlanosCliente.DELETE;           
          vvValoresEtico    := NULL;
          vvValoresGenerico := NULL;
          vnQuebraCliente   := vnCodCli;   
          
        END IF;            
        
        IF    (vnCodLinhaPrazo = 1) THEN
          vvValoresEtico    := vvValoresEtico    || '|' || vnCodPlPag;
        ELSIF (vnCodLinhaPrazo = 2) THEN
          vvValoresGenerico := vvValoresGenerico || '|' || vnCodPlPag;
        END IF;
        viIdxPlanos := NVL(vtPlanosCliente.COUNT,0) + 1;
        vtPlanosCliente(viIdxPlanos).vnCodLinhaPrazo := vnCodLinhaPrazo;
        vtPlanosCliente(viIdxPlanos).vnCodPlPag      := vnCodPlPag;
      
      END LOOP;
      
      -- Última Quebra
      vnCodGrupo := F_RETORNA_QUEBRA_GRUPO(vvValoresEtico,
                                           vvValoresGenerico,
                                           vtPlanosCliente);            
      
      -- Relacionamento Grupo x Cliente
      INSERT INTO PCCONFIGSISTGRUPLANOCLI
                ( CODSISTEMA
                , CODGRUPO
                , CODCLI )
         VALUES ( pi_vCodSistema
                , vnCodGrupo
                , vnQuebraCliente );      
      
    END IF;
    
  END P_INSERE_GRUPO_PLANO;

  --============================================================================
  -- Função para Verificar se Usa Regra Específica de Medicamentos --
  --=================================================================
  FUNCTION FUSA_REGRA_MEDICAMENTOS(pi_vCodFilial IN VARCHAR2,
                                   pi_vNome      IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetUsaRegraMedicamentos VARCHAR2(240);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ' || '''' || pi_vNome || '''' || ' AND CODFILIAL = ' || '''' || pi_vCodFilial || ''''
                   INTO vvRetUsaRegraMedicamentos;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetUsaRegraMedicamentos := 'N';
      WHEN OTHERS THEN
        vvRetUsaRegraMedicamentos := 'N';
    END;
    -- Retorno
    RETURN vvRetUsaRegraMedicamentos;
  END FUSA_REGRA_MEDICAMENTOS;
  --============================================================================

  --============================================================================
  -- Função para Obter Regra Específica de Medicamentos --
  --=================================================================
  FUNCTION FOBTEM_REGRA_MEDICAMENTOS(pi_vCodFilial IN VARCHAR2,
                                     pi_vNome      IN VARCHAR2,
                                     pi_vDefault   IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetRegraMedicamentos VARCHAR2(240);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ' || '''' || pi_vNome || '''' || ' AND CODFILIAL = ' || '''' || pi_vCodFilial || ''''
                   INTO vvRetRegraMedicamentos;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetRegraMedicamentos := pi_vDefault;
      WHEN OTHERS THEN
        vvRetRegraMedicamentos := pi_vDefault;
    END;
    -- Retorno
    RETURN NVL(vvRetRegraMedicamentos,pi_vDefault);
  END FOBTEM_REGRA_MEDICAMENTOS;
  --============================================================================

