    -- Promoção de Preço
    CURSOR c_PromocaoPreco(pi_vCodSistema       IN VARCHAR2,
                           pi_nCodCondicaoVenda IN NUMBER,
                           pi_nCodProd          IN NUMBER,
                           pi_nCodFornec        IN NUMBER,
                           pi_nCodMarca         IN NUMBER,
                           pi_vCodLinhaProd     IN NUMBER,
                           pi_nNumRegiao        IN NUMBER,
                           pi_nCodepto          IN NUMBER,
                           pi_nCodCategoria     IN NUMBER,
                           pi_nCodSec           IN NUMBER,
                           pi_vCodFilial        IN VARCHAR2) IS -- 20170802
      SELECT CASE WHEN (PCMED_VIEWOLAUX02.codprod      IS NOT NULL) THEN 1
                  WHEN (PCMED_VIEWOLAUX02.codfornec    IS NOT NULL) THEN 2
                  WHEN (PCMED_VIEWOLAUX02.codmarca     IS NOT NULL) THEN 3
                  WHEN (PCMED_VIEWOLAUX02.codcategoria IS NOT NULL) THEN 4
                  WHEN (PCMED_VIEWOLAUX02.codsec       IS NOT NULL) THEN 5
                  WHEN (PCMED_VIEWOLAUX02.codlinhaprod IS NOT NULL) THEN 6
                  WHEN (PCMED_VIEWOLAUX02.codepto      IS NOT NULL) THEN 7
                  ELSE 8 END PRIORIDADE
           , 'P' TIPOPROMOCAO
           , PCMED_VIEWOLAUX02.PRECOPROMOCIONAL
           , PCMED_VIEWOLAUX02.PERCDESCFIN
           , PCMED_VIEWOLAUX02.QTDEMINIMA
           , PCMED_VIEWOLAUX02.CODPROMOCAOMED
  
        FROM PCMED_VIEWOLAUX02
       WHERE ((PCMED_VIEWOLAUX02.CODSISTEMA       = pi_vCodSistema))
         AND ((PCMED_VIEWOLAUX02.CODCONDICAOVENDA = pi_nCodCondicaoVenda))
         AND ((PCMED_VIEWOLAUX02.NUMREGIAO        = pi_nNumRegiao)    OR (PCMED_VIEWOLAUX02.NUMREGIAO IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODPROD          = pi_nCodProd)      OR (PCMED_VIEWOLAUX02.CODPROD IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODFORNEC        = pi_nCodFornec)    OR (PCMED_VIEWOLAUX02.CODFORNEC IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODMARCA         = pi_nCodMarca)     OR (PCMED_VIEWOLAUX02.CODMARCA IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODLINHAPROD     = pi_vCodLinhaProd) OR (PCMED_VIEWOLAUX02.CODLINHAPROD IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODEPTO          = pi_nCodepto)      OR (PCMED_VIEWOLAUX02.CODEPTO IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODCATEGORIA     = pi_nCodCategoria) OR (PCMED_VIEWOLAUX02.CODCATEGORIA IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODSEC           = pi_nCodSec)       OR (PCMED_VIEWOLAUX02.CODSEC IS NULL))
         AND ((PCMED_VIEWOLAUX02.CODFILIAL        = pi_vCodFilial)    OR (PCMED_VIEWOLAUX02.CODFILIAL IS NULL)) -- 20170802
       ORDER BY 1 ASC -->> Da maior prioridade para a menor prioridade
              , PCMED_VIEWOLAUX02.PRECOPROMOCIONAL ASC; -->> Do menor Preço para o Maior Preço
  
