         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         --
         AND (PCPROMOCAOMED.TIPOPOLITICA              IN ('Q'))          -->> Promoção de Desconto por Faixa de Quantidade
         AND (PCPROMOCAOMED.TIPOPROMOCAO              IN ('C'))          -->> Promoção de Cliente para não ir Combos, Bonificações e Outros
         AND ( ((NVL(vvUsaMultiplasCondVenda,'N') = 'S') AND (PCCONDICAOVENDA.ENVIAPEDIDOELET = 'S')) OR (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') )
         AND (NVL(PCDESCONTO.TIPOFV,'FV')             = vvTipoFv)        -->> TIPO FV da Integradora
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL) -->> Somente Promoções Vigentes
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')         = 'N')             -->> Bloqueadas não entram
         AND (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema); -->> Somente Sistema passado no Parâmetro
  
      -- Carrega Tabelas com Informações de Condições x Promoções de Preço Fixo por Faixa de Quantidade
      INSERT INTO PCMED_VIEWOLAUX04
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , PRECOPROMOCIONAL
                , PERCDESCFIN
                , CODPROD
                , QTINICIAL
                , QTFINAL
                , CODFORNEC
                , CODMARCA
                , CODCATEGORIA
                , CODSEC
                , CODLINHAPROD
                , CODEPTO
                , PRIORIDADE
                , CODPROMOCAOMED
                , NUMREGIAO 
                , CODFILIAL ) -- 20170802
      SELECT PCCONFIGSISTOPERLOG.CODSISTEMA
           , PCCONDICAOVENDA.CODCONDICAOVENDA
           , PCDESCONTO.PRECOFIXOPROMOCAOMED
           , PCDESCONTO.PERCDESCFIN
           , PCDESCONTO.CODPROD
           , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
           , PCDESCONTO.FIMINTERVALOPROMOCAOMED
           , PCDESCONTO.CODFORNEC
           , PCDESCONTO.CODMARCA
           , PCDESCONTO.CODCATEGORIA
           , PCDESCONTO.CODSEC
           , PCDESCONTO.CODLINHAPROD
           , PCDESCONTO.CODEPTO
           , CASE WHEN PCDESCONTO.CODPROD      IS NOT NULL THEN 1
                  WHEN PCDESCONTO.CODFORNEC    IS NOT NULL THEN 2
                  WHEN PCDESCONTO.CODMARCA     IS NOT NULL THEN 3
                  WHEN PCDESCONTO.CODCATEGORIA IS NOT NULL THEN 4
                  WHEN PCDESCONTO.CODSEC       IS NOT NULL THEN 5
                  WHEN PCDESCONTO.CODLINHAPROD IS NOT NULL THEN 6
                  WHEN PCDESCONTO.CODEPTO      IS NOT NULL THEN 7
                  ELSE 8 END PRIORIDADE
           , PCDESCONTO.CODPROMOCAOMED
           , NVL(PCPROMOCAOREGIAOMED.NUMREGIAO,PCDESCONTO.NUMREGIAO) NUMREGIAO -- 20170802
           , NVL(PCPROMOCAOFILMED.CODFILIAL,PCDESCONTO.CODFILIAL) CODFILIAL -- 20170802
        FROM PCCONDICAOVENDA
           , PCCONDVENDAINTEGRADORA
           , PCCONFIGSISTOPERLOG
           , PCDESCONTO
           , PCPROMOCAOMED
           , PCPROMOCAOCONDVENDAMED
           , PCPROMOCAOREGIAOMED -- 20170802
           , PCPROMOCAOFILMED -- 20170802
       WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
         AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
         --
         AND (PCPROMOCAOCONDVENDAMED.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA) -->> VÍNCULO DA PROMOÇÃO COM A CONDIÇÃO DE VENDA
         AND (PCDESCONTO.CODPROMOCAOMED               = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         --
         AND (PCPROMOCAOMED.TIPOPOLITICA              IN ('F')) -->> Promoção de Preço Fixo por Faixa de Quantidade
         AND (PCPROMOCAOMED.TIPOPROMOCAO              IN ('C')) -->> Promoção de Cliente
         AND ( ((NVL(vvUsaMultiplasCondVenda,'N') = 'S') AND (PCCONDICAOVENDA.ENVIAPEDIDOELET = 'S')) OR (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') )
         AND (NVL(PCDESCONTO.TIPOFV,'FV')             = vvTipoFv)        -->> TIPO FV da Integradora
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL) -->> Somente Promoções Vigentes
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')         = 'N')             -->> Bloqueadas não entram
         AND (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema); -->> Somente Sistema passado no Parâmetro
  
      -- Carrega Tabelas com Informações de Condições x Promoções de Descontos de COMBOS
      INSERT INTO PCMED_VIEWOLAUX06
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , PERCDESC
                , PERCDESCFIN
                , CODPROD
                , QTCOMBO
                , OBRIGATORIO
                , PERMITIRAUMENTARQTDEKIT
                , CODFORNEC
                , CODMARCA
                , CODCATEGORIA
                , CODSEC
                , CODLINHAPROD
                , CODEPTO
                , PRIORIDADE
                , CODPROMOCAOMED
                , NUMREGIAO 
                , CODFILIAL ) -- 20170802
      SELECT DISTINCT -->> Precisa pq não tem regra de prioridade no Combo
             PCCONFIGSISTOPERLOG.CODSISTEMA
           , PCCONDICAOVENDA.CODCONDICAOVENDA
           , NVL(PCDESCONTO.PERCDESC,0)
           , NVL(PCDESCONTO.PERCDESCFIN,0)
           , PCDESCONTO.CODPROD
           , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
           , NVL(PCDESCONTO.PROMOCAOMEDOBRIGATORIO,'S')
           , NVL(PCDESCONTO.PERMITIRAUMENTARQTDEKITMED,'N')
           , PCDESCONTO.CODFORNEC
           , PCDESCONTO.CODMARCA
           , PCDESCONTO.CODCATEGORIA
           , PCDESCONTO.CODSEC
           , PCDESCONTO.CODLINHAPROD
           , PCDESCONTO.CODEPTO
           , CASE WHEN PCDESCONTO.CODPROD      IS NOT NULL THEN 1
                  WHEN PCDESCONTO.CODFORNEC    IS NOT NULL THEN 2
                  WHEN PCDESCONTO.CODMARCA     IS NOT NULL THEN 3
                  WHEN PCDESCONTO.CODCATEGORIA IS NOT NULL THEN 4
                  WHEN PCDESCONTO.CODSEC       IS NOT NULL THEN 5
                  WHEN PCDESCONTO.CODLINHAPROD IS NOT NULL THEN 6
                  WHEN PCDESCONTO.CODEPTO      IS NOT NULL THEN 7
                  ELSE 8 END PRIORIDADE
           , PCDESCONTO.CODPROMOCAOMED
           , NVL(PCPROMOCAOREGIAOMED.NUMREGIAO,PCDESCONTO.NUMREGIAO) NUMREGIAO -- 20170802
           , NVL(PCPROMOCAOFILMED.CODFILIAL,PCDESCONTO.CODFILIAL) CODFILIAL -- 20170802
        FROM PCCONDICAOVENDA
           , PCCONDVENDAINTEGRADORA
           , PCCONFIGSISTOPERLOG
           , PCDESCONTO
           , PCPROMOCAOMED
           , PCPROMOCAOCONDVENDAMED
           , PCPROMOCAOREGIAOMED -- 20170802
           , PCPROMOCAOFILMED -- 20170802
       WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
         AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
         --
         AND (PCPROMOCAOCONDVENDAMED.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA) -->> VÍNCULO DA PROMOÇÃO COM A CONDIÇÃO DE VENDA
         AND (PCDESCONTO.CODPROMOCAOMED               = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         --
         AND (PCPROMOCAOMED.TIPOPOLITICA              IN ('D'))          -->> Promoção de Desconto
         AND (PCPROMOCAOMED.TIPOPROMOCAO              IN ('K'))          -->> Promoção Combo
         AND ( ((NVL(vvUsaMultiplasCondVenda,'N') = 'S') AND (PCCONDICAOVENDA.ENVIAPEDIDOELET = 'S')) OR (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') )
         AND (NVL(PCDESCONTO.TIPOFV,'FV')             = vvTipoFv)        -->> TIPO FV da Integradora
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL) -->> Somente Promoções Vigentes
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')         = 'N')             -->> Bloqueadas não entram
         AND (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema); -->> Somente Sistema passado no Parâmetro
  
      -- Carrega Tabelas com Informações de Condições x Promoções de Preço Fixo
      INSERT INTO PCMED_VIEWOLAUX07
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , PRECOPROMOCIONAL
                , PERCDESCFIN
                , CODPROD
                , QTCOMBO
                , OBRIGATORIO
                , PERMITIRAUMENTARQTDEKIT
                , CODFORNEC
                , CODMARCA
                , CODCATEGORIA
                , CODSEC
                , CODLINHAPROD
                , CODEPTO
                , PRIORIDADE
                , CODPROMOCAOMED
                , NUMREGIAO 
                , CODFILIAL ) -- 20170802
      SELECT DISTINCT -->> Precisa pq não tem regra de prioridade no Combo
             PCCONFIGSISTOPERLOG.CODSISTEMA
           , PCCONDICAOVENDA.CODCONDICAOVENDA
           , PCDESCONTO.PRECOFIXOPROMOCAOMED
           , PCDESCONTO.PERCDESCFIN
           , PCDESCONTO.CODPROD
           , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
           , NVL(PCDESCONTO.PROMOCAOMEDOBRIGATORIO,'S')
           , NVL(PCDESCONTO.PERMITIRAUMENTARQTDEKITMED,'N')
           , PCDESCONTO.CODFORNEC
           , PCDESCONTO.CODMARCA
           , PCDESCONTO.CODCATEGORIA
           , PCDESCONTO.CODSEC
           , PCDESCONTO.CODLINHAPROD
           , PCDESCONTO.CODEPTO
           , CASE WHEN PCDESCONTO.CODPROD      IS NOT NULL THEN 1
                  WHEN PCDESCONTO.CODFORNEC    IS NOT NULL THEN 2
                  WHEN PCDESCONTO.CODMARCA     IS NOT NULL THEN 3
                  WHEN PCDESCONTO.CODCATEGORIA IS NOT NULL THEN 4
                  WHEN PCDESCONTO.CODSEC       IS NOT NULL THEN 5
                  WHEN PCDESCONTO.CODLINHAPROD IS NOT NULL THEN 6
                  WHEN PCDESCONTO.CODEPTO      IS NOT NULL THEN 7
                  ELSE 8 END PRIORIDADE
           , PCDESCONTO.CODPROMOCAOMED
           , NVL(PCPROMOCAOREGIAOMED.NUMREGIAO,PCDESCONTO.NUMREGIAO) NUMREGIAO
           , NVL(PCPROMOCAOFILMED.CODFILIAL,PCDESCONTO.CODFILIAL) CODFILIAL -- 20170802
        FROM PCCONDICAOVENDA
           , PCCONDVENDAINTEGRADORA
           , PCCONFIGSISTOPERLOG
           , PCDESCONTO
           , PCPROMOCAOMED
           , PCPROMOCAOCONDVENDAMED
           , PCPROMOCAOREGIAOMED -- 20170802
           , PCPROMOCAOFILMED -- 20170802
       WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
         AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
         --
         AND (PCPROMOCAOCONDVENDAMED.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA) -->> VÍNCULO DA PROMOÇÃO COM A CONDIÇÃO DE VENDA
         AND (PCDESCONTO.CODPROMOCAOMED               = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         --
         AND (PCPROMOCAOMED.TIPOPOLITICA              IN ('P'))          -->> Promoção de Preço Fixo
         AND (PCPROMOCAOMED.TIPOPROMOCAO              IN ('K'))          -->> Promoção Combo
         AND ( ((NVL(vvUsaMultiplasCondVenda,'N') = 'S') AND (PCCONDICAOVENDA.ENVIAPEDIDOELET = 'S')) OR (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') )
         AND (NVL(PCDESCONTO.TIPOFV,'FV')             = vvTipoFv)        -->> TIPO FV da Integradora
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL) -->> Somente Promoções Vigentes
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')         = 'N')             -->> Bloqueadas não entram
         AND (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema); -->> Somente Sistema passado no Parâmetro
  
    END IF; -- FIM CONDIÇÃO PROMOÇÕES PARA FORÇA DE VENDAS OU OL/PE
  
    vdDataHoraFinGerDescontos := SYSDATE;
  
  
  
  
  
  
   /*************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    G E R A C A O   D O S   I T E N S   D A S   C O N D I C O E S   -   PCMED_VIEWOLCONDVENDAPROD_TMP
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************/
  
  
  
  
  
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------
    -- LAÇO DE REGIÕES E FILIAIS
    ----------------------------
    ----------------------------	
    vbAchouCondicoes := FALSE;
    FOR vc_RegiaoFilial IN (SELECT DISTINCT -- Precisa do Distinct por causa das Condições de Venda
                                   PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST
                                 , MAX(PCMED_VIEWOLSISTCONDVENDA_TMP.CODCLIST) CODCLIST
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.INTEGRADORA
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.UFREGIAO
                              FROM PCMED_VIEWOLSISTCONDVENDA_TMP
                             WHERE (PCMED_VIEWOLSISTCONDVENDA_TMP.CODSISTEMA = pi_vCodSistema)
                             GROUP BY PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.INTEGRADORA
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.UFREGIAO                           
                             ORDER BY PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST) LOOP
  
      -- Achou Condições
      vbAchouCondicoes := TRUE;
  
      -- Verifica se a Região é Zona Franca
      BEGIN
        SELECT PCREGIAO.REGIAOZFM
          INTO vvRegiaoZfm
          FROM PCREGIAO
         WHERE (PCREGIAO.NUMREGIAO = vc_RegiaoFilial.NUMREGIAO);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvRegiaoZfm := 'N';
      END;
  
      -- Dados Complementares - Cliente ST
      BEGIN
        SELECT PARTICIPAFARMACIAPOPULAR
             , ESTENT
          INTO vvParticipaFarmaciaPopular
             , vvUfCliente
          FROM PCCLIENT
         WHERE (CODCLI = vc_RegiaoFilial.CODCLIST);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
         vvParticipaFarmaciaPopular := 'N';
         vvUfCliente                := NULL;
      END;
  
      -- Pesquisa o Tipo de Preço da Integradora
      BEGIN
        SELECT NVL(PCINTEGRADORA.ORIGEMPRECO,'F')
             , LAYOUT
             , NVL(APLICARDESCPTABELATRIBUT,'N')
          INTO vvOrigemPreco
             , vnLayout
             , vvAplicarDescPtabelaTribut
          FROM PCINTEGRADORA
         WHERE (PCINTEGRADORA.INTEGRADORA = vc_RegiaoFilial.INTEGRADORA);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvOrigemPreco              := 'F';
          vnLayout                   := NULL;
          vvAplicarDescPtabelaTribut := 'N';
      END;
  
      ---------------------------------------
      -- Informação de Estoque, carrega Array
      ---------------------------------------
      -- Verifica se Usará a Filial Retira - DDMEDICA-5782
      BEGIN
        SELECT CODFILIALRETIRA
          INTO vvCodFilialRetira
          FROM PCFILIALRETIRA
         WHERE (CODFILIALVENDA = vc_RegiaoFilial.CODFILIALST)
           AND ((SELECT VALOR 
                   FROM PCREGRASEXCECAOMED
                  WHERE PCREGRASEXCECAOMED.NOME = 'USAFILIALRETIRADICDADOS' 
                    AND PCREGRASEXCECAOMED.CODFILIAL = '99') = 'S')
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvCodFilialRetira := vc_RegiaoFilial.CODFILIALST; -- Padrão
      END;
      vtEstoque_CodProd.DELETE;
      vtEstoque_Saldo.DELETE;
      vtEstoque_CodProd_Saldo.DELETE;
	  
      vvBLOQUEIAVENDAESTPENDENTE := 'N';
      IF vnNumDicionario = 18 THEN
        POBTEM_PARAMFILIAL_STRING(vc_RegiaoFilial.CODFILIALST,
                                  'BLOQUEIAVENDAESTPENDENTE',
                                  'N',
                                  vvBLOQUEIAVENDAESTPENDENTE);	  
      END IF;	  
      
      IF NVL(vvBLOQUEIAVENDAESTPENDENTE, 'N') = 'S' THEN	  
        SELECT CODPROD
             , GREATEST((NVL(QTESTGER,0) - NVL(QTRESERV,0) - NVL(QTBLOQUEADA,0) - NVL(QTPENDENTE,0)), 0)
        BULK COLLECT INTO vtEstoque_CodProd
                        , vtEstoque_Saldo
         FROM PCEST
        WHERE (CODFILIAL = vvCodFilialRetira); -- DDMEDICA-5782	  	  
      ELSE
        SELECT CODPROD
             , GREATEST((NVL(QTESTGER,0) - NVL(QTRESERV,0) - NVL(QTBLOQUEADA,0)), 0)
        BULK COLLECT INTO vtEstoque_CodProd
                        , vtEstoque_Saldo
         FROM PCEST
        WHERE (CODFILIAL = vvCodFilialRetira); -- DDMEDICA-5782	  
      END IF;
	  
      -- Carrega Array Indexado pelo Produto
      IF (vtEstoque_CodProd.COUNT > 0) THEN
        FOR viIdxEstoque IN vtEstoque_CodProd.FIRST..vtEstoque_CodProd.LAST LOOP
          -- INDICE
          IF (vtEstoque_Saldo(viIdxEstoque) < 0) THEN
            vtEstoque_CodProd_Saldo(vtEstoque_CodProd(viIdxEstoque)) := 0;
          ELSE
            vtEstoque_CodProd_Saldo(vtEstoque_CodProd(viIdxEstoque)) := vtEstoque_Saldo(viIdxEstoque);
          END IF;
        END LOOP;
      END IF;
      
      ----------------------------------------------------------
      -- Informação de ShelfLife, carrega Array - HIS.02727.2016
      ----------------------------------------------------------
      IF (vbValidaShelfLife) THEN
  
        -- Pesquisa ShelfLife do Cliente    
        BEGIN
          SELECT TRUNC(SYSDATE) + NVL(PRAZOMAXVALIDADE,0)
            INTO vdShelfLifeCliente
            FROM PCCLIENT
           WHERE (CODCLI = vc_RegiaoFilial.CODCLIST);                 
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vdShelfLifeCliente := TRUNC(SYSDATE); 
        END;
      
        vtProShelfLife_CodProd.DELETE;
        vtProShelfLife.DELETE;
        SELECT CODPROD
          BULK COLLECT INTO vtProShelfLife_CodProd
          FROM PCLOTE
         WHERE (CODFILIAL   = vc_RegiaoFilial.CODFILIALST)
           AND (DTVALIDADE >= vdShelfLifeCliente)
         GROUP BY CODPROD
        HAVING (SUM(GREATEST(NVL(QT,0) - NVL(QTRESERV,0),0)) > 0);
        -- Carrega Array Indexado pelo Produto
        IF (vtProShelfLife_CodProd.COUNT > 0) THEN
          FOR viIdxEstoque IN vtProShelfLife_CodProd.FIRST..vtProShelfLife_CodProd.LAST LOOP
            -- INDICE
            vtProShelfLife(vtProShelfLife_CodProd(viIdxEstoque)) := 0;
          END LOOP;
        END IF;
        
      END IF; -- FIM: (vbValidaShelfLife)    
  
     /*
      -- Itens KIT
      vtItensKit.DELETE;
      IF (vtSistCondVenda(viIdx).vvKit = 'S') THEN
        FOR vc_ItensKit IN (SELECT DISTINCT CODPROD
                              FROM PCDESCONTO
                             WHERE (CODPROMOCAOMED = vnCodCondicaoVenda)) LOOP
          vtItensKit(vc_ItensKit.CODPROD) := vc_ItensKit.CODPROD;
        END LOOP;
      END IF;
      */
  
      -- HIS.01061.2016 - Envia FV
      -- DDMEDICA-5540 - Envia Dicionário de Dados
      IF (vbValidaEnviaFv) OR
         (vbValidaEnviarDicD) THEN
        SELECT CODPROD
             , NVL(ENVIARFORCAVENDAS,'N')
             , NVL(ENVIARDICIONARIODADOSMED,'N')
        BULK COLLECT INTO vtProdFilial_CodProd
                        , vtProdFilial_EnviaFv
                        , vtProdFilial_EnviarDicD
         FROM PCPRODFILIAL
        WHERE (CODFILIAL = vc_RegiaoFilial.CODFILIALST);
        -- Carrega Array Indexado pelo Produto
        IF (vtProdFilial_CodProd.COUNT > 0) THEN
          FOR viIdxProdFil IN vtProdFilial_CodProd.FIRST..vtProdFilial_CodProd.LAST LOOP
            -- INDICE ENVIA FV
            IF (vbValidaEnviaFv) THEN
              vtEstoque_CodProd_EnviaFv(vtProdFilial_CodProd(viIdxProdFil)) := vtProdFilial_EnviaFv(viIdxProdFil);
            END IF;
            -- INDICE ENVIA DICIONARIO DE DADOS
            IF (vbValidaEnviarDicD) THEN
              vtEstoque_CodProd_EnviarDicD(vtProdFilial_CodProd(viIdxProdFil)) := vtProdFilial_EnviarDicD(viIdxProdFil);
            END IF;
          END LOOP;
        END IF;
      END IF;
  
      ----------------------------------------------------
      -- Carrega Lista de Condições para a Região e Filial
      ----------------------------------------------------
      vtListaCondicoes.DELETE;
      FOR vc_Condicao IN (SELECT DISTINCT
                                 PCMED_VIEWOLSISTCONDVENDA_TMP.CODCONDICAOVENDA
                               , PCMED_VIEWOLSISTCONDVENDA_TMP.CODPLPAG
                               , PCMED_VIEWOLSISTCONDVENDA_TMP.PRAZOMEDIO
                               , PCMED_VIEWOLSISTCONDVENDA_TMP.KIT
                            FROM PCMED_VIEWOLSISTCONDVENDA_TMP
                           WHERE (PCMED_VIEWOLSISTCONDVENDA_TMP.CODSISTEMA  = pi_vCodSistema)
                             AND (PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO   = vc_RegiaoFilial.NUMREGIAO)
                             AND (PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST = vc_RegiaoFilial.CODFILIALST)) LOOP
        viIdxCondicao := NVL(vtListaCondicoes.COUNT,0) + 1;
        vtListaCondicoes(viIdxCondicao).vnCodCondicaoVenda := vc_Condicao.CODCONDICAOVENDA;
        vtListaCondicoes(viIdxCondicao).vnCodPlPag         := vc_Condicao.CODPLPAG;
        vtListaCondicoes(viIdxCondicao).vnPrazoMedio       := vc_Condicao.PRAZOMEDIO;
        vtListaCondicoes(viIdxCondicao).vvKit              := vc_Condicao.KIT;
      END LOOP;
  
      ---------------------------------------------------------------------------------------------
      --                    Laço de Processamento dos Produtos POR REGIÃO                        --
      ---------------------------------------------------------------------------------------------
      vbAchouTabelaPreco := FALSE;
      FOR vc_Produto IN (SELECT PCPRODUT.CODPROD
                              , PCPRODUT.CODFORNEC
                              , PCPRODUT.CODMARCA
                              , PCPRODUT.CODCATEGORIA
                              , PCPRODUT.CODSEC
                              , PCPRODUT.CODLINHAPROD
                              , PCPRODUT.CODEPTO
                              , PCTABPR.PVENDA
                              , PCTABPR.PVENDA1
                              , PCTABPR.PVENDA2
                              , PCTABPR.PVENDA3
                              , PCTABPR.PVENDA4
                              , PCTABPR.PVENDA5
                              , PCTABPR.PVENDA6
                              , PCTABPR.PVENDA7
                              , PCPRODUT.CUSTOREP
                              , PCPRODUT.CUSTOREPZFM
                              , PCPRODUT.TIPOMERC
                              , PCPRODUT.UTILIZAPRECOFABRICA -- MED-2433
                              , 'A' ATIVOINATIVO
                              , PCPRODUT.FARMACIAPOPULAR
                              , PCPRODUT.NATUREZAPRODUTO
                              , PCPRODUT.PERPIS
                              , PCPRODUT.PERCOFINS
                              , PCPRODUT.PERCBONIFICVENDA PERCBONIFICVENDA_PROD
                              , PCTABPR.PERCBONIFICVENDA PERCBONIFICVENDA_REG
                              , PCPRODUT.OBS2
                              , PCTABPR.INDICEPRECO
                              , PCPRODUT.ESTOQUEPORLOTE -- 2956.004535.2018
                              , PCPRODUT.OBS
                              , PCPRODUT.CODLINHAPRAZO -- DDMEDICA-545
                              , PCDEPTO.TIPOMERC TIPOMERCDEP
                              , PCTABPR.VLST -- STP
                           FROM PCPRODUT
                              , PCTABPR
                              , PCDEPTO
                         WHERE (PCTABPR.CODPROD = PCPRODUT.CODPROD)
                           AND (PCPRODUT.CODEPTO = PCDEPTO.CODEPTO(+))
                           AND (PCTABPR.NUMREGIAO = vc_RegiaoFilial.NUMREGIAO) --> REGIÃO DO LAÇO PARA PESQUISAR O PREÇO
                           --Passou para Crítica:
                           --AND ((PCPRODUT.OBS <> 'PV') OR (PCPRODUT.OBS IS NULL))
                           --AND ((NVL(PCPRODUT.OBS, '  ') <> 'EQ') OR
                           --     ((NVL (PCPRODUT.OBS, '  ') = 'EQ') AND ((SELECT NVL (PCDEPTO.TIPOMERC, '  ') TIPOMERC
                           --                                                FROM PCDEPTO
                           --                                               WHERE PCDEPTO.CODEPTO = PCPRODUT.CODEPTO) <> 'IM')))
                           AND (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                           AND (PCPRODUT.DTEXCLUSAO IS NULL)
                           --AND (NVL(PCDEPTO.TIPOMERC,' ') NOT IN ('IM','CI','RD')) -->> Não pode gerar Dicionário para Imobilizado e Consumo Interno e Eletrodoméstico
                           --HIS.03857.2015--AND ((NVL(vvGeraDicionarioForcaVendas,'N') = 'S') OR ((NVL(vvGeraDicionarioForcaVendas,'N') = 'N') AND (NVL(PCPRODUT.OBS2,' ') <> 'FL'))) -->> Não pode gerar Dicionário para Produtos Fora de Linha
                           ) LOOP
  
        -- Achou Tabela de Preços
        vbAchouTabelaPreco := TRUE;
        
        -- Iniciar TRUE DDMEDICA-2494
        vbGravarProduto    := TRUE;
        
        -------------------------------------
        -- Validação dos Atributos do Produto
        -------------------------------------
        IF (NVL(vc_Produto.TIPOMERC,'X') IN ('IM','CI','RD')) THEN
          vbGravarProduto := FALSE;
          -- CONTROLE DE RELATÓRIO ---------              
          P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                           vc_RegiaoFilial.CODFILIALST,
                           vnCodCondicaoVenda,
                           vc_Produto.CODPROD,
                           'P', -- Critica Por Produto
                           'Tipo Mercadoria de Produto "IM" ou "CI" ou "RD" não permitidos');
        ----------------------------------
        ELSIF (NVL(vc_Produto.TIPOMERCDEP,'X') IN ('IM','CI','RD')) THEN
          vbGravarProduto := FALSE;
          -- CONTROLE DE RELATÓRIO ---------              
          P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                           vc_RegiaoFilial.CODFILIALST,
                           vnCodCondicaoVenda,
                           vc_Produto.CODPROD,
                           'P', -- Critica Por Produto
                           'Tipo Mercadoria de Depto "IM" ou "CI" ou "RD" não permitidos');
          ----------------------------------
        ELSE
          IF (NVL(vc_Produto.OBS,'X') = 'PV') THEN
            vbGravarProduto := FALSE;
            -- CONTROLE DE RELATÓRIO ---------              
            P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                             vc_RegiaoFilial.CODFILIALST,
                             vnCodCondicaoVenda,
                             vc_Produto.CODPROD,
                             'P', -- Critica Por Produto
                             'Produto Proibido para Venda');
            ----------------------------------
          ELSE
            IF (NVL(vc_Produto.OBS,'X') = 'EQ') THEN
            vbGravarProduto := FALSE;
              -- CONTROLE DE RELATÓRIO ---------              
              P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                               vc_RegiaoFilial.CODFILIALST,
                               vnCodCondicaoVenda,
                               vc_Produto.CODPROD,
                               'P', -- Critica Por Produto
                               'Produto cadastrado com Observação EQ-Equipamento');
            END IF;
          END IF;
        END IF;
  
        ---------------------------------------------------------------------------------------------
        ---------------------------------------------------------------------------------------------
        -- LAÇO DE CONDIÇÕES PARA A REGIÃO E FILIAL
        -------------------------------------------
        -------------------------------------------
        vbAchouCondicaoProduto := FALSE;
        IF (vtListaCondicoes.COUNT > 0) THEN            
          FOR viIdxCondicao IN vtListaCondicoes.FIRST..vtListaCondicoes.LAST LOOP
  
            -- Achou Condição de Venda para o Produto
            vbAchouCondicaoProduto := TRUE;
                               
            -- Pega o Código da Condição
            vnCodCondicaoVenda := vtListaCondicoes(viIdxCondicao).vnCodCondicaoVenda;
  
            -- Pesquisa Coluna da Tabela de Preços do Plano de Pagamento da Condição de Venda
            BEGIN
              SELECT PCPLPAG.NUMPR
                INTO vnNumPr
               FROM PCPLPAG
               WHERE (PCPLPAG.CODPLPAG = vtListaCondicoes(viIdxCondicao).vnCodPlPag);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnNumPr := 1;
            END;
            IF (NVL(vnNumPr,0) = 0) THEN -- Garante ao menos a Coluna 1 se não tiver preenchido
              vnNumPr := 1;
            END IF;
  
            IF (vbGravarProduto) THEN -- Se passou pela validação anterior
            -- Restrição de Marcas
            IF    (vvTipoPesquisaMarcas = 'G') THEN
              -->> Pesquisa Geral de Marcas, considera TODOS os Produtos
              vbGravarProduto := TRUE;
            ELSIF (vvTipoPesquisaMarcas = 'E') THEN
              -->> Pesquisa Específica de Marcas, somente considera as Marcas Cadastradas na Rotina 2325
              IF (vtRestricaoMarca.EXISTS(vc_Produto.CODMARCA)) THEN
                vbGravarProduto := TRUE;
              ELSE
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------              
                P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                 vc_RegiaoFilial.CODFILIALST,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Restrição de Marca da Rotina 2325');
                ----------------------------------              
              END IF;
            END IF;
            END IF;
  
           /*
            -- Restrição de KIT
            IF (vbGravarProduto) THEN -- Se passou pela validação anterior
              IF (vtSistCondVenda(viIdx).vvKit = 'S') THEN
                -- Se existe o Produto no Array de Itens de Kit
                IF (vtItensKit.EXISTS(vc_Produto.CODPROD)) THEN
                  vbGravarProduto := TRUE;
                ELSE
                  vbGravarProduto := FALSE;
                END IF;
              END IF;
            END IF;
            */
  
            -- HIS.01061.2016 - Envia FV
            IF (vbValidaEnviaFv) THEN -->> Somente SE VALIDAR O CAMPO ENVIA FV
              IF (vbGravarProduto) THEN -- Se passou pela validação anterior
                IF (vtEstoque_CodProd_EnviaFv.EXISTS(vc_Produto.CODPROD)) THEN
                  IF (vtEstoque_CodProd_EnviaFv(vc_Produto.CODPROD) = 'S') THEN
                    vbGravarProduto := TRUE;
                  ELSE
                    vbGravarProduto := FALSE;
                    -- CONTROLE DE RELATÓRIO ---------
                    P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                     vc_RegiaoFilial.CODFILIALST,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Campo "Enviar para Força de Vendas" = Não (Cadastro do Produto por Filial)');
                    ----------------------------------              
                  END IF;
                ELSE
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                   vc_RegiaoFilial.CODFILIALST,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Campo "Enviar para Força de Vendas" = Não (Cadastro do Produto por Filial)');
                  ----------------------------------              
                END IF;
              END IF;
            END IF;
  
            -- DDMEDICA-5540 - Envia Dicionário de Dados
            IF (vbValidaEnviarDicD) THEN -->> Somente SE VALIDAR O CAMPO Envia Dicionário de Dados
              IF (vbGravarProduto) THEN -- Se passou pela validação anterior
                IF (vtEstoque_CodProd_EnviarDicD.EXISTS(vc_Produto.CODPROD)) THEN
                  IF (vtEstoque_CodProd_EnviarDicD(vc_Produto.CODPROD) = 'S') THEN
                    vbGravarProduto := TRUE;
                  ELSE
                    vbGravarProduto := FALSE;
                    -- CONTROLE DE RELATÓRIO ---------
                    P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                     vc_RegiaoFilial.CODFILIALST,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Campo "Enviar para no Dicionário de Dados Farma" = Não (Cadastro do Produto por Filial)');
                    ----------------------------------              
                  END IF;
                ELSE
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                   vc_RegiaoFilial.CODFILIALST,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Campo "Enviar para no Dicionário de Dados Farma" = Não (Cadastro do Produto por Filial)');
                  ----------------------------------              
                END IF;
              END IF;
            END IF;
            ----------------
            -- Saldo Estoque
            ----------------
            IF (vtEstoque_CodProd_Saldo.EXISTS(vc_Produto.CODPROD)) THEN
              vnSaldoEstoque := NVL(vtEstoque_CodProd_Saldo(vc_Produto.CODPROD),0);
            ELSE
              vnSaldoEstoque := NULL;
            END IF;                 
            
            -- Validação Estoque
            IF (vbValidaEstoque) THEN
              IF (NVL(vnSaldoEstoque,0) <= 0) THEN
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                 vc_RegiaoFilial.CODFILIALST,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Produto sem Estoque Disponível para Venda');
                ----------------------------------              
              END IF;
            END IF; 
            
            ---------------------------------------
            -- Validação ShelfLife - HIS.02727.2016
            ---------------------------------------
            IF (vbValidaShelfLife) AND
               (NVL(vc_Produto.ESTOQUEPORLOTE,'N') = 'S') THEN -- Somente Produtos com Estoque por Lote - 2956.004535.2018
                      
              -- Pesquisa ShelfLife
              IF (NOT vtProShelfLife.EXISTS(vc_Produto.CODPROD)) THEN
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                 vc_RegiaoFilial.CODFILIALST,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Produto sem Estoque por Lote conforme Shelf Life do Cliente (Prazo de Validade minímo do lote)');
                ----------------------------------              
              END IF;
              
            END IF; -- FIM: (vbValidaShelfLife)
  
           /************************
            SE PODE GRAVAR O PRODUTO
            ************************/
            IF (vbGravarProduto) THEN
  
              ------------------------------------------------------------------------
              -- Restringe envio de Produtos conforme o Fora de Linha - HIS.03857.2015
              ------------------------------------------------------------------------
              IF (NVL(vvGeraDicionarioForcaVendas,'N') = 'S') OR                                                                           -->> Se Força de Vendas envia todos os produtos independentemente de ser Fora de Linha
                 ((NVL(vvGeraDicionarioForcaVendas,'N') = 'N') AND (NVL(vc_Produto.OBS2,' ') <> 'FL')) OR                                  -->> Se não for Força de Vendas: Se não for Fora de Linha pode enviar o Produto
                 ((NVL(vvGeraDicionarioForcaVendas,'N') = 'N') AND (NVL(vc_Produto.OBS2,' ') = 'FL') AND (NVL(vnSaldoEstoque,0) > 0)) THEN -->> Se não for Força de Vendas: Se for Fora Restringe, somente pode enviar Produtos com Estoque
  
                -- Se usa Tributação por UF
                IF (NVL(vvUsaTributacaoPorUf,'N') = 'S') THEN
                  -- Pesquisa Tributação por UF
                  BEGIN
                    SELECT CODST
                      INTO vnCodSt
                      FROM PCTABTRIB
                     WHERE (CODPROD     = vc_Produto.CODPROD)
                       AND (UFDESTINO   = vvUfCliente)
                       AND (CODFILIALNF = vc_RegiaoFilial.CODFILIALST);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vnCodSt := NULL;
                  END;
                -- Se NÃO usa Tributação por UF
                ELSE
                  -- Pesquisa Tributação por Região
                  BEGIN
                    SELECT CODST
                      INTO vnCodSt
                      FROM PCTABPR
                     WHERE (CODPROD   = vc_Produto.CODPROD)
                       AND (NUMREGIAO = vc_RegiaoFilial.NUMREGIAO);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vnCodSt := NULL;
                  END;
                END IF; -- Fim Condição v_usatributacaoporuf
  
                -- Dados Complementares do Produto - Tributação
                BEGIN
                  SELECT PCTRIBUT.CODICM
                       , PCTRIBUT.PERCBASERED
                       , PCTRIBUT.PAUTAFONTE
                       , PCTRIBUT.PERDESTAB
                       , PCTRIBUT.IVAFONTE
                       , PCTRIBUT.USAPMCBASEST
                       , PCTRIBUT.BNFNAOCALCULAICMS
                       , PCTRIBUT.USABASEICMSREDUZIDA
                       , PCTRIBUT.ALIQICMS1FONTE
                       , PCTRIBUT.ALIQICMS2FONTE
                       , PCTRIBUT.PERCBASEREDSTFONTE
                       , PCTRIBUT.utilizarstfonteprecific --STP
                    INTO vnPercIcm
                       , vnPercBaseRedIcm
                       , vnPautaFonte
                       , vnPerDesTab
                       , vnIvaFonte
                       , vvUsaPmcBaseSt
                       , vvBnfNaoCalculaIcms
                       , vvUsaBaseIcmsReduzida
                       , vnAliqIcms1Fonte
                       , vnAliqIcms2Fonte
                       , vnPercBaseRedStFonte
                       , vvutilizarstfonteprecific --STP
                    FROM PCTRIBUT
                   WHERE (PCTRIBUT.CODST = vnCodSt);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnPercIcm        := 0;
                    vnPercBaseRedIcm := 0;
                    vnPautaFonte     := 0;
                    vnPerDesTab      := 0;
                    vnIvaFonte       := 0;
                    vvUsaPmcBaseSt   := 'N';
                    vvBnfNaoCalculaIcms   := 'N';
                    vvUsaBaseIcmsReduzida := 'N';
                    vnAliqIcms1Fonte      := 0;
                    vnAliqIcms2Fonte      := 0;
                    vnPercBaseRedStFonte  := 0;
                    vvutilizarstfonteprecific := 'N';  -- STP    
                END;
                IF (NVL(vnPercBaseRedIcm,0) = 0) THEN
                  vnPercBaseRedIcm := 100;
                END IF;
                vnPercBaseRedIcm := (100 - NVL(vnPercBaseRedIcm,0));
                IF (NVL(vnPercBaseRedIcm,0) < 0) THEN
                  vnPercBaseRedIcm := 0;
                END IF;
                -- Zera Desconto Repasse se na Integradora não estiver marcada para Aplicar o Desconto PTabela da Tributação
                IF (vvAplicarDescPtabelaTribut <> 'S') THEN
                  vnPerDesTab := 0;
                END IF;
  
                -- Obtem UF da Região
                BEGIN
                  SELECT PCREGIAO.UF
                    INTO vvUfRegiao
                    FROM PCREGIAO
                   WHERE (PCREGIAO.NUMREGIAO = vc_RegiaoFilial.NUMREGIAO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvUfRegiao := NULL;
                END;
  
                -- Obtém PMC e Preço Fábrica
                PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(vc_RegiaoFilial.CODFILIALST,
                                                     vc_Produto.CODPROD,
                                                     vvUfRegiao,
                                                     vc_RegiaoFilial.NUMREGIAO,
                                                     vnPrecoMaxConsum,
                                                     vnPrecoFabrica,
                                                     vvMensagemPmc);
  
                -- Define o Preço
                IF    (vnNumPr = 1) THEN
                  vnPreco := NVL(vc_Produto.PVENDA1,0);
                ELSIF (vnNumPr = 2) THEN
                  vnPreco := NVL(vc_Produto.PVENDA2,0);
                ELSIF (vnNumPr = 3) THEN
                  vnPreco := NVL(vc_Produto.PVENDA3,0);
                ELSIF (vnNumPr = 4) THEN
                  vnPreco := NVL(vc_Produto.PVENDA4,0);
                ELSIF (vnNumPr = 5) THEN
                  vnPreco := NVL(vc_Produto.PVENDA5,0);
                ELSIF (vnNumPr = 6) THEN
                  vnPreco := NVL(vc_Produto.PVENDA6,0);
                ELSIF (vnNumPr = 7) THEN
                  vnPreco := NVL(vc_Produto.PVENDA7,0);
                ELSE
                  vnPreco := 0;
                END IF;
                -- Tira st fonte da precificaçao -- STP
                IF (vvutilizarstfonteprecific = 'S') AND
                   (vnPreco > 0) THEN
                  vnPreco := NVL(vnPreco,0) - NVL(vc_Produto.VLST,0);  
                END IF;                
              -- Aplica Indice sobre o Preço Tabela
              vnIndicePreco := 0;
              IF (NVL(vvGerarAcordoPreco,'N') = 'S')         AND
                 (NVL(vvAplicarIndiceAcordoPreco,'N') = 'S') AND
                 (NVL(vc_Produto.INDICEPRECO,0) <> 0)        THEN
                vnPreco       := (NVL(vnPreco,0) * NVL(vc_Produto.INDICEPRECO,0));
                vnIndicePreco := NVL(vc_Produto.INDICEPRECO,0);
              END IF;
              -- Guarda o Preço Tabela Original com o Indice de Preco
              vnPrecoTabelaOriginalComIndice := vnPreco;
  
                -- Se Medicamento
                IF (NVL(vc_Produto.TIPOMERC,' ') IN ('M','MA')) OR
                   (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') = 'S') THEN -- MED-2433
                  -- Se Origem Preço é Fábrica
                  IF (NVL(vvOrigemPreco,'F') = 'F') THEN
                    -- Se Zona Franca
                    IF (NVL(vvRegiaoZfm,'N') = 'S') THEN
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREPZFM,0);
                    -- Se NÃO FOR Zona Franca
                    ELSE
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREP,0);
                    END IF;
                    -- Desconto de Repasse
                    IF (vvAplicarDescPtabelaTribut = 'S') THEN
                      vnPreco := round(vnPreco * (1 - (nvl(vnPerDesTab,0) / 100)),vnNumCasasDecVenda);
                    END IF;
                -- Se não for Fábrica, trato as exceções
                ELSE
                  -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela e mandar o Preço Fábrica,
                  -- onde a Integradora tem Origem Preço = Preço Tabela
                  IF (vUSAREGRARECALDESCPTABMED2313 = 'S') THEN
                    ------------------
                    -- Se Zona Franca
                    IF (NVL(vvRegiaoZfm,'N') = 'S') THEN
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREPZFM,0);
                    -- Se NÃO FOR Zona Franca
                    ELSE
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREP,0);
                    END IF;
                    -- Desconto de Repasse
                    IF (vvAplicarDescPtabelaTribut = 'S') THEN
                      vnPreco := round(vnPreco * (1 - (nvl(vnPerDesTab,0) / 100)),vnNumCasasDecVenda);
                    END IF;
                    ------------------
                  END IF;
                END IF;
              END IF;
  
                -- Se Origem Preço é Tabela de Preços, que pode considerar a Bonificação (Estará no PTabela)
                IF (NVL(vvOrigemPreco,'F') = 'T') THEN
  
                  -- Percentual de Bonificação na Venda - PADRÃO
                  IF (NVL(vvUtilizaPercBonifiVendaRegiao,'N') = 'S') THEN
                    vnPercBonificVenda := NVL(vc_Produto.PERCBONIFICVENDA_REG,0);
                  ELSE
                    vnPercBonificVenda := NVL(vc_Produto.PERCBONIFICVENDA_PROD,0);
                  END IF;
    
                  -- Percentual de Bonificação na Venda [33 - Integradora MichaelSoft]
                  -- Soment enviar %bonific nos medicamentos
                  IF (NVL(vnLayout,0) = 33) THEN
                    IF (NVL(vc_Produto.TIPOMERC,' ') NOT IN ('M','MA')) THEN
                      vnPercBonificVenda := 0;
                    END IF;
                  END IF;
  
                ELSE
                
                  -- Origem Preço Fábrica não aplica % Bonificação
                  vnPercBonificVenda := 0;
                
                END IF;
                
                -- Acordo de Mídia - DDMEDICA-545
                BEGIN
                  SELECT PCCONDVENDALINHA.PERCACORDOMIDIA
                    INTO vnPercAcordoMidia
                    FROM PCCONDVENDALINHA
                   WHERE (PCCONDVENDALINHA.CODCONDICAOVENDA = vnCodCondicaoVenda)
                     AND (PCCONDVENDALINHA.CODLINHAPRAZO    = vc_Produto.CODLINHAPRAZO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnPercAcordoMidia := 0;
                END;
  
                -- Inicializa Flag de encontrar o Desconto para o Produto
                vbAchouDescQuant            := FALSE;
                vbAchouDesconto             := FALSE;
                vnPercDesc                  := 0;
                vnPercDesc1                 := 0;
                vnPercDesc2                 := 0;
                vnPercDescFin               := 0;
                vnQtdeMinima                := 1;
                vnCodPromocaoMed            := NULL;
                vnCodPromocaoMedFaixaQtde   := NULL;
                vnPrecoPromocional          := 0;
                vvTipoPromocao              := NULL;
                vvTipoPrecoDesconto         := NULL;
                vvTipoPrecoDescFaixaQtde    := NULL;
                vnPercAcrescAcordo          := NULL;
                vnValorAcordoMidia          := 0; -- DDMEDICA-545
  
  
               /*----------------------------------------------------------------
                Condições de Venda x Produtos x Descontos/Preço Promocional
                IMPORTANTE: Os cursores abaixo buscam pelo código da
                            condição de venda, logo só trazem os preços
                            ou descontos das promoção padrão armazenada
                            na variável vtSistCondVenda(viIdx).vnCodCondicaoVenda
                ----------------------------------------------------------------*/
                -- Verificar se existe Promoção de Preço Fixo (PRIORITARIA)
                FOR vc_PromocaoPreco IN c_PromocaoPreco(pi_vCodSistema,
                                                        vnCodCondicaoVenda,
                                                        vc_Produto.CODPROD,
                                                        vc_Produto.CODFORNEC,
                                                        vc_Produto.CODMARCA,
                                                        vc_Produto.CODLINHAPROD,
                                                        vc_RegiaoFilial.NUMREGIAO,
                                                        vc_Produto.CODEPTO,
                                                        vc_Produto.CODCATEGORIA,
                                                        vc_Produto.CODSEC,
                                                        vc_RegiaoFilial.CODFILIALST) LOOP
                  -- Pega a primeira Promoção e sai
                  vvTipoPromocao      := vc_PromocaoPreco.TIPOPROMOCAO;
                  vnPrecoPromocional  := vc_PromocaoPreco.PRECOPROMOCIONAL;
                  vnPercDescFin       := vc_PromocaoPreco.PERCDESCFIN;
                  vnQtdeMinima        := vc_PromocaoPreco.QTDEMINIMA;
                  vnCodPromocaoMed    := vc_PromocaoPreco.CODPROMOCAOMED;
                  vvTipoPrecoDesconto := 'P';
                  EXIT;
                END LOOP;
  
                -- Se não achou Promoção de Preço Fixo
                IF (vvTipoPromocao IS NULL) THEN
  
                  -- Verificar se existe Promoção de Desconto
                  FOR vc_PromocaoDesconto IN c_PromocaoDesconto(pi_vCodSistema,
                                                                vnCodCondicaoVenda,
                                                                vc_Produto.CODPROD,
                                                                vc_Produto.CODFORNEC,
                                                                vc_Produto.CODMARCA,
                                                                vc_Produto.CODLINHAPROD,
                                                                vc_RegiaoFilial.NUMREGIAO,
                                                                vc_Produto.CODEPTO,
                                                                vc_Produto.CODCATEGORIA,
                                                                vc_Produto.CODSEC,
                                                                vc_RegiaoFilial.CODFILIALST) LOOP
                    -- Pega a primeira Promoção e sai
                    vvTipoPromocao      := vc_PromocaoDesconto.TIPOPROMOCAO;
                    vnPercDesc          := vc_PromocaoDesconto.PERCDESC;
                    vnPercDesc1         := vc_PromocaoDesconto.PERCDESC; -- Guarda o Desconto da Promoção
                    vnPercDescFin       := vc_PromocaoDesconto.PERCDESCFIN;
                    vnQtdeMinima        := vc_PromocaoDesconto.QTDEMINIMA;
                    vnCodPromocaoMed    := vc_PromocaoDesconto.CODPROMOCAOMED;
                    vvTipoPrecoDesconto := 'D';
                    EXIT;
                  END LOOP;
  
                  -- Verifica se possui Acréscimo sobre o Preço (Somente SE NÃO TIVER PREÇO FIXO)
                  -- Medicamento NÃO PODE TER ACRÉSCIMO              
                  IF (NVL(vc_Produto.TIPOMERC,' ') NOT IN ('M','MA')) THEN
                    IF (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') <> 'S') THEN -- MED-2433
                      BEGIN
                        SELECT PCCONDVENDAACRESCACORDO.PERCENTUAL
                          INTO vnPercAcrescAcordo
                          FROM PCCONDVENDAACRESCACORDO
                         WHERE (PCCONDVENDAACRESCACORDO.CODCONDICAOVENDA = vnCodCondicaoVenda)
                           AND (PCCONDVENDAACRESCACORDO.CAMPO            = 'MA')
                           AND (PCCONDVENDAACRESCACORDO.CODIGO           = vc_Produto.CODMARCA);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnPercAcrescAcordo := NULL;
                      END;
                      IF (NVL(vnPercAcrescAcordo,0) > 0) THEN
                        vnPreco := ROUND(NVL(vnPreco,0) * (1 + (NVL(vnPercAcrescAcordo,0) / 100)),vnNumCasasDecVenda);
                      END IF;                                                       
                    END IF;
                  END IF; -- Fim Condição: NÃO é Medicamento
  
                  -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela e mandar o Preço Fábrica,
                  -- onde a Integradora tem Origem Preço = Preço Tabela
                  IF (vUSAREGRARECALDESCPTABMED2313 = 'S') THEN
                    -- Se Medicamento
                    IF (NVL(vc_Produto.TIPOMERC,' ') IN ('M','MA')) OR
                       (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') = 'S') THEN -- MED-2433
                      -- Medicamento com PREÇO
                      IF (NVL(vnPreco,0) > 0) THEN
                        -- Calcula o % Desconto entre o Preço Fábrica e o Preço Tabela com o Indice de Preço
                        vnPercDescPTABMED := ROUND(((NVL(vnPreco,0) - NVL(vnPrecoTabelaOriginalComIndice,0)) / NVL(vnPreco,0)) * 100,2);
                        vnPercDesc2       := vnPercDescPTABMED; -- Guarda o Desconto entre o Preço Fábrica e o Preço Tabela
                        -- Recalcula o Desconto agregando o % Desconto da Promoção com o Desconto entre o Preço Fábrica e o Preço Tabela
                        vnPercDesc        := 100 - ((100*(1-(NVL(vnPercDesc,0)/100))) * (1-(NVL(vnPercDescPTABMED,0)/100)));
                      END IF;
                    END IF;
                  END IF;
  
                -- Se achou Promoção de Preço Fixo - DDMEDICA-3046
                ELSE
                
                  -- Se Integradora Aplica o Preço Fixo nas Tabelas de Preço do OLs - DDMEDICA-3046
                  IF (vUSARPRECOPROMOCAOOPERLOG2313 = 'S') AND
                     (NVL(vnPrecoPromocional,0) > 0)       THEN
                     
                    -- O Arquivo de Preços será com o Preço Promocional
                    vnPreco := vnPrecoPromocional;
                     
                  END IF;
                
                END IF; -- Fim Condição se não achou Promoção de Preço Fixo
  
                -- Se o Produto tem Preço
                IF (NVL(vnPreco,0) > 0) THEN
  
                  -- ST do Preço Bruto
                  vnCodSt := NULL;
                  P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                        vc_Produto.CODPROD,
                                        vc_RegiaoFilial.CODCLIST,
                                        vc_RegiaoFilial.NUMREGIAO,
                                        1,       -- pi_nCondVenda,
                                        100,     -- pi_nPercVenda
                                        vnCodSt,
                                        vnPreco,
                                        0,       -- pi_nValorIpi
                                        0,       -- pi_nPrecoMaxConsum
                                        0,       -- pi_nValorUltEnt
                                        0,       -- pi_nCustoNfSemSt
                                        vnPreco, -- Preço Tabela é o Preço Bruto
                                        'N',     -->> Padrão Não (Simples Nacional)
                                        'S',     -->> Pesquisa Custos
                                        'N',     -->> Não é Item Bonificado
                                        0,       -->> Não passa Frete e Outras Despesas
                                        vnBaseStPrecoBruto,
                                        vnValorStPrecoBruto,
                                        vvMensagemSt,
                                        vvRegimeEspIsenStFonte,
                                        vnAliqIcms1,
                                        vnAliqIcms2,
                                        vnIva,
                                        vnPercBaseRedSt
                                        );            
  
                  -- Calcula Preço Líquido
                  vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vnPercDesc,0)/100));
  
                  -- Calcula ST pelo Preço Promocional
                  IF (NVL(vvTipoPromocao,'D') = 'P') THEN
                  -- Aplica Indice sobre o Preço Promocional
                  IF (NVL(vvGerarAcordoPreco,'N') = 'S')         AND
                     (NVL(vvAplicarIndiceAcordoPreco,'N') = 'S') AND
                     (NVL(vc_Produto.INDICEPRECO,0) <> 0)        THEN
                    vnPrecoPromocional := (NVL(vnPrecoPromocional,0) * NVL(vc_Produto.INDICEPRECO,0));
                    vnIndicePreco      := NVL(vc_Produto.INDICEPRECO,0);
                  END IF;
                  -- Calcula ST
                    vnCodSt := NULL;
                    P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                          vc_Produto.CODPROD,
                                          vc_RegiaoFilial.CODCLIST,
                                          vc_RegiaoFilial.NUMREGIAO,
                                          1,       -- pi_nCondVenda,
                                          100,     -- pi_nPercVenda
                                          vnCodSt,
                                          vnPrecoPromocional,
                                          0,       -- pi_nValorIpi
                                          0,       -- pi_nPrecoMaxConsum
                                          0,       -- pi_nValorUltEnt
                                          0,       -- pi_nCustoNfSemSt
                                          vnPrecoPromocional, -- Preço Tabela é o Preço Promocional
                                          'N',     -->> Padrão Não (Simples Nacional)
                                          'S',     -->> Pesquisa Custos
                                          'N',     -->> Não é Item Bonificado
                                          0,       -->> Não passa Frete e Outras Despesas
                                          vnBaseSt,
                                          vnValorSt,
                                          vvMensagemSt,
                                          vvRegimeEspIsenStFonte,
                                          vnAliqIcms1,
                                          vnAliqIcms2,
                                          vnIva,
                                          vnPercBaseRedSt
                                          );
                  -- Calcula ST pelo Preço Liquido
                  ELSE
                    vnCodSt := NULL;
                    P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                          vc_Produto.CODPROD,
                                          vc_RegiaoFilial.CODCLIST,
                                          vc_RegiaoFilial.NUMREGIAO,
                                          1,       -- pi_nCondVenda,
                                          100,     -- pi_nPercVenda
                                          vnCodSt,
                                          vnPrecoLiquido,
                                          0,       -- pi_nValorIpi
                                          0,       -- pi_nPrecoMaxConsum
                                          0,       -- pi_nValorUltEnt
                                          0,       -- pi_nCustoNfSemSt
                                          vnPreco, -- Preço Tabela
                                          'N',     -->> Padrão Não (Simples Nacional)
                                          'S',     -->> Pesquisa Custos
                                          'N',     -->> Não é Item Bonificado
                                          0,       -->> Não passa Frete e Outras Despesas
                                          vnBaseSt,
                                          vnValorSt,
                                          vvMensagemSt,
                                          vvRegimeEspIsenStFonte,
                                          vnAliqIcms1,
                                          vnAliqIcms2,
                                          vnIva,
                                          vnPercBaseRedSt
                                        );
                  END IF;
  
                  -- Dados Complementares - Regra Farmácia Popular
                  vbRegraFciaPopular := ( (NVL(vvCalcStPautaFarmaciaPopular,'N') = 'S') AND
                                          (NVL(vc_Produto.FARMACIAPOPULAR,'N') = 'S')   AND
                                          (NVL(vvParticipaFarmaciaPopular,'N') = 'S')   AND
                                          (NVL(vnPautaFonte,0) > 0) );
                  IF (vbRegraFciaPopular) THEN
                    vnVlStFarmaciaPopular := vnValorSt;
                  ELSE
                    vnVlStFarmaciaPopular := 0;
                  END IF;
  
                  -- Dados Complementares - Preço Pauta
                  IF (vbRegraFciaPopular) THEN
                    vnPrecoPauta := NVL(vnPautaFonte,0);
                  ELSE
                    IF (NVL(vvUsaPmcBaseSt,'N') = 'S') THEN
                      vnPrecoPauta := vnPrecoMaxConsum;
                    ELSE
                      vnPrecoPauta := 0;
                    END IF;
                  END IF;
  
                  -- Dados Complementares - PIS/COFINS
                  IF (NVL(vvUsaPisCofinsPorFilial,'N') = 'S') THEN
                    BEGIN
                      SELECT PCPRODFILIAL.PERPIS
                           , PCPRODFILIAL.PERCOFINS
                        INTO vnPerPis
                           , vnPerCofins
                        FROM PCPRODFILIAL
                       WHERE (PCPRODFILIAL.CODPROD   = vc_Produto.CODPROD)
                         AND (PCPRODFILIAL.CODFILIAL = vc_RegiaoFilial.CODFILIALST);
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vnPerPis    := 0;
                        vnPerCofins := 0;
                    END;
                  ELSE
                   vnPerPis    := vc_Produto.PERPIS;
                   vnPerCofins := vc_Produto.PERCOFINS;
                  END IF;
  
                  -- Dados Complementares - Produto
                  IF (NVL(vc_Produto.NATUREZAPRODUTO,' ') = 'ME') THEN
                    vvMedicamentoSimNao := 'S';
                    vvPerfumariaSimNao  := 'N';
                  ELSE
                    vvMedicamentoSimNao := 'N';
                    vvPerfumariaSimNao  := 'S';
                  END IF;
  
                  -- Calcula o Repasse
                  PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                     vc_RegiaoFilial.CODCLIST,
                                                     vc_RegiaoFilial.NUMREGIAO,
                                                     1,    -- pi_nCondVenda,
                                                     vc_Produto.CODPROD,
                                                     NULL, --pi_nCodSt
                                                     vnPrecoFabrica,
                                                     (case when ((vnPrecoPromocional > 0) and (vvTipoFv = 'PE')) then vnPrecoPromocional else vnPrecoLiquido end),
                                                     NULL, --pi_vTipoAplicRepasseFilial
                                                     'N',  --pi_vCriticaObrigatorio
                                                     vnIntegradora,
                                                     'F',
                                                     vvTipoFv,
                                                     vvMensagemRepasse,
                                                     vvTipoRepasse,
                                                     vnValorRepasse);
                                          
                  -- Calcula o Valor do Acordo de Mídia sobre Preço Líquido -- DDMEDICA-545
                  IF    (NVL(vvTipoPromocao,'X') = 'P') THEN
                    vnBaseAcordoMidia := NVL(vnPrecoPromocional,0);
                  ELSIF (NVL(vvTipoPromocao,'X') = 'D') THEN
                    vnBaseAcordoMidia := ROUND((NVL(vnPreco,0) * (1 - (NVL(vnPercDesc,0)/100))),vnNumCasasDecVenda);
                  ELSE
                    vnBaseAcordoMidia := NVL(vnPreco,0);
                  END IF;
                  vnValorAcordoMidia := ROUND((vnBaseAcordoMidia * (NVL(vnPercAcordoMidia,0) / 100)),vnNumCasasDecVenda);
  
                  -- Atualiza Campos da Table
                  INSERT INTO PCMED_VIEWOLCONDVENDAPROD_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODPROD
                            , PRECO
                            , PERCDESC
                            , PERCDESCFIN
                            , QTDEMINIMA
                            , CODPROMOCAOMED
                            , BASEST
                            , VLST
                            , CODST
                            , CODFILIALST
                            , CODCLIST
                            , PRECOPROMOCIONAL
                            , TIPOPROMOCAO
                            , CODPLPAGCONDVENDA
                            , PRAZOMEDIO
                            , SALDOESTOQUE
                            , UFREGIAO
                            , ATIVOINATIVO
                            , PERCICM
                            , PERCBASEREDICM
                            , VLSTFARMACIAPOPULAR
                            , MEDICAMENTOSIMNAO
                            , PERFUMARIASIMNAO
                            , PERDESTAB
                            , IVAFONTE
                            , PRECOPAUTA
                            , PERCPIS
                            , PERCCOFINS
                            , PERCBONIFICVENDA
                            , TIPOPRECODESCONTO
                            , VLREPASSE
                            , PRECOFABRICA
                            , PRECOMAXCONSUM
                            , USAPMCBASEST
                            , ALIQICMS1FONTE
                            , ALIQICMS2FONTE
                            , PERCBASEREDSTFONTE
                            , BNFNAOCALCULAICMS
                            , USABASEICMSREDUZIDA
                            , PVENDA1
                            , PVENDA2
                            , PVENDA3
                            , PVENDA4
                            , PVENDA5
                            , PVENDA6
                            , PVENDA7
                            , VLSTPRECO
                            , BASESTPRECO
                            , INDICEPRECO
                            , PERCACRESCACORDO
                            , PERCDESC1
                            , PERCDESC2
                            , PERCACORDOMIDIA  -- DDMEDICA-545
                            , VALORACORDOMIDIA -- DDMEDICA-545
                             )
                     VALUES ( pi_vCodSistema
                            , vc_RegiaoFilial.NUMREGIAO
                            , vnCodCondicaoVenda
                            , vc_Produto.CODPROD
                            , vnPreco
                            , NVL(vnPercDesc,0) -->> NÃO PODE FICAR NULO
                            , NVL(vnPercDescFin,0) -->> NÃO PODE FICAR NULO
                            , vnQtdeMinima
                            , vnCodPromocaoMed
                            , vnBaseSt
                            , vnValorSt
                            , NVL(vnCodSt,vnCodStTribut)
                            , vc_RegiaoFilial.CODFILIALST
                            , vc_RegiaoFilial.CODCLIST
                            , NVL(vnPrecoPromocional,0) -->> NÃO PODE FICAR NULO
                            , vvTipoPromocao
                            , vtListaCondicoes(viIdxCondicao).vnCodPlPag
                            , vtListaCondicoes(viIdxCondicao).vnPrazoMedio
                            , vnSaldoEstoque
                            , vc_RegiaoFilial.UFREGIAO
                            , vc_Produto.ATIVOINATIVO
                            , vnPercIcm
                            , vnPercBaseRedIcm
                            , vnVlStFarmaciaPopular
                            , vvMedicamentoSimNao
                            , vvPerfumariaSimNao
                            , vnPerDesTab
                            , vnIvaFonte
                            , vnPrecoPauta
                            , vnPerPis
                            , vnPerCofins
                            , vnPercBonificVenda
                            , vvTipoPrecoDesconto
                            , vnValorRepasse
                            , vnPrecoFabrica
                            , vnPrecoMaxConsum
                            , vvUsaPmcBaseSt
                            , vnAliqIcms1Fonte
                            , vnAliqIcms2Fonte
                            , vnPercBaseRedStFonte
                            , vvBnfNaoCalculaIcms
                            , vvUsaBaseIcmsReduzida
                            , vc_Produto.PVENDA1
                            , vc_Produto.PVENDA2
                            , vc_Produto.PVENDA3
                            , vc_Produto.PVENDA4
                            , vc_Produto.PVENDA5
                            , vc_Produto.PVENDA6
                            , vc_Produto.PVENDA7                       
                            , vnValorStPrecoBruto
                            , vnBaseStPrecoBruto
                            , vnIndicePreco
                            , vnPercAcrescAcordo
                            , vnPercDesc1
                            , vnPercDesc2
                            , vnPercAcordoMidia     -- DDMEDICA-545
                            , vnValorAcordoMidia ); -- DDMEDICA-545
  
                  ------------------------------------------------------
                  -- Promoções por Faixa de Quantidade - Força de Vendas
                  ------------------------------------------------------
                  IF (vbGeraDicionarioForcaVendas) THEN
  
                    -- Se não for KIT (Kits não enviam as promoções de faixa de quantidade vinculadas à promoção - não são promoções padrões, logo não têm outras promoções vinculadas a ela)
                    IF (NVL(vtListaCondicoes(viIdxCondicao).vvKit,'N') <> 'S') THEN
  
                      -- (Pega todas as Promoções por Faixa de Quantidade independente da condição) ------
                      FOR vc_PrecoPromoc_FV_FaixaQtde IN c_PrecoPromoc_FV_FaixaQtde(pi_vCodSistema,
                                                                                    vnCodCondicaoVenda,
                                                                                    vc_Produto.CODPROD,
                                                                                    vc_Produto.CODFORNEC,
                                                                                    vc_Produto.CODMARCA,
                                                                                    vc_Produto.CODLINHAPROD,
                                                                                    vc_RegiaoFilial.NUMREGIAO,
                                                                                    vc_Produto.CODEPTO,
                                                                                    vc_Produto.CODCATEGORIA,
                                                                                    vc_Produto.CODSEC,
                                                                                    vc_RegiaoFilial.CODFILIALST) LOOP
  
                        -->> ACHOU Preço Promocional por Faixa de Quantidade
                        vvTipoPrecoDescFaixaQtde := 'P';
  
                        -->> Calcula ST
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0),
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                              );
  
                        -- Calcula o Repasse
                        PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                           vc_RegiaoFilial.CODCLIST,
                                                           vc_RegiaoFilial.NUMREGIAO,
                                                           1,    -- pi_nCondVenda,
                                                           vc_Produto.CODPROD,
                                                           NULL, --pi_nCodSt
                                                           vnPrecoFabrica,
                                                           NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0),
                                                           NULL, --pi_vTipoAplicRepasseFilial
                                                           'N',  --pi_vCriticaObrigatorio
                                                           vnIntegradora,
                                                           'F',
                                                           vvTipoFv,
                                                           vvMensagemRepasse,
                                                           vvTipoRepasse,
                                                           vnValorRepasse);
  
                        -- Insere Faixa
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTINICIAL
                                  , QTFINAL
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPOLITICA
                                  , TIPOPRECODESCONTO
                                  , DESCRICAORESUMIDAPROMOCAO
                                  , DESCRICAODETALHADAPROMOCAO
                                  , VLST
                                  , VLREPASSE
                                  , CODFILIALST
                                  , PRECOFABRICA )
                           VALUES ( pi_vCodSistema
                                  , vc_RegiaoFilial.NUMREGIAO
                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_PrecoPromoc_FV_FaixaQtde.QTINICIAL
                                  , vc_PrecoPromoc_FV_FaixaQtde.QTFINAL
                                  , vc_PrecoPromoc_FV_FaixaQtde.CODPROMOCAOMED
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PrecoPromoc_FV_FaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                  , vc_PrecoPromoc_FV_FaixaQtde.TIPOPROMOCAO
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , vc_PrecoPromoc_FV_FaixaQtde.TIPOPOLITICA
                                  , vvTipoPrecoDescFaixaQtde
                                  , vc_PrecoPromoc_FV_FaixaQtde.DESCRICAORESUMIDAPROMOCAO
                                  , vc_PrecoPromoc_FV_FaixaQtde.DESCRICAODETALHADAPROMOCAO
                                  , vnValorSt
                                  , vnValorRepasse
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnPrecoFabrica );
                                  
                        -- Insere Restrição do Produto - DDMEDICA-5511
                        P_INSERE_RESTRICAO_PRODUTO(pi_vCodSistema,
