                                              vnCodSt,
                                              vnPrecoLiquido,
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              vnPreco, -- Preço Tabela
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
