                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                            );
  
                        -- Calcula o Repasse
                        PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                           vc_RegiaoFilial.CODCLIST,
                                                           vc_RegiaoFilial.NUMREGIAO,
                                                           1,    -- pi_nCondVenda,
                                                           vc_Produto.CODPROD,
                                                           NULL, --pi_nCodSt
                                                           vnPrecoFabrica,
                                                           vnPrecoLiquido,
                                                           NULL, --pi_vTipoAplicRepasseFilial
                                                           'N',  --pi_vCriticaObrigatorio
                                                           vnIntegradora,
                                                           'F',
                                                           vvTipoFv,
                                                           vvMensagemRepasse,
                                                           vvTipoRepasse,
                                                           vnValorRepasse);
  
                        -- Insere Faixa
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTINICIAL
                                  , QTFINAL
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
