                                  , vvTipoPrecoDescFaixaQtde
                                  , vc_Desconto_FV_FaixaQtde.DESCRICAORESUMIDAPROMOCAO
                                  , vc_Desconto_FV_FaixaQtde.DESCRICAODETALHADAPROMOCAO
                                  , vnValorSt
                                  , vnValorRepasse
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnPrecoFabrica );
  
                        -- Insere Restrição do Produto - DDMEDICA-5511
                        P_INSERE_RESTRICAO_PRODUTO(pi_vCodSistema,
                                                   vnCodCondicaoVenda,
                                                   vc_Produto.CODPROD,
                                                   vc_Desconto_FV_FaixaQtde.QTINICIAL,
                                                   vc_Desconto_FV_FaixaQtde.QTFINAL,
                                                   vc_Desconto_FV_FaixaQtde.CODPROMOCAOMED,
                                                   vnCodPromocaoMed,
                                                   vREJEITARITEMFORAFAIXAPROMOQT);

                      END LOOP; -- Fim c_Desconto_FV_FaixaQtde
  
                      -- (Pega todas as Promoções Casadinha) ------
                      FOR vc_Desconto_FV_Casadinha IN c_Desconto_FV_Casadinha(pi_vCodSistema,
                                                                              vnCodCondicaoVenda,
                                                                              vc_Produto.CODPROD,
                                                                              vc_Produto.CODFORNEC,
                                                                              vc_Produto.CODMARCA,
                                                                              vc_Produto.CODLINHAPROD,
                                                                              vc_RegiaoFilial.NUMREGIAO,
                                                                              vc_Produto.CODEPTO,
                                                                              vc_Produto.CODCATEGORIA,
                                                                              vc_Produto.CODSEC,
                                                                              vc_RegiaoFilial.CODFILIALST) LOOP
  
                        -->> ACHOU Desconto por Faixa de Quantidade
                        vvTipoPrecoDescFaixaQtde := 'D';
  
                        -- Calcula Preço Líquido
                        vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_Desconto_FV_Casadinha.PERCDESC,0)/100));
  
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              vnPrecoLiquido,
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              vnPreco, -- Preço Tabela
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                            );
  
                        -- Calcula o Repasse
                        PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                           vc_RegiaoFilial.CODCLIST,
                                                           vc_RegiaoFilial.NUMREGIAO,
                                                           1,    -- pi_nCondVenda,
                                                           vc_Produto.CODPROD,
                                                           NULL, --pi_nCodSt
                                                           vnPrecoFabrica,
                                                           vnPrecoLiquido,
                                                           NULL, --pi_vTipoAplicRepasseFilial
                                                           'N',  --pi_vCriticaObrigatorio
                                                           vnIntegradora,
                                                           'F',
                                                           vvTipoFv,
                                                           vvMensagemRepasse,
                                                           vvTipoRepasse,
                                                           vnValorRepasse);
  
                        -- Insere Faixa
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_CTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTINICIAL
                                  , QTFINAL
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPOLITICA
                                  , TIPOPRECODESCONTO
