                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_Desconto_FV_Casadinha.QTINICIAL
                                  , vc_Desconto_FV_Casadinha.QTFINAL
                                  , vc_Desconto_FV_Casadinha.CODPROMOCAOMED
                                  , NVL(vc_Desconto_FV_Casadinha.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_Desconto_FV_Casadinha.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , vc_Desconto_FV_Casadinha.TIPOPROMOCAO
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , vc_Desconto_FV_Casadinha.TIPOPOLITICA
                                  , vvTipoPrecoDescFaixaQtde
                                  , vc_Desconto_FV_Casadinha.DESCRICAORESUMIDAPROMOCAO
                                  , vc_Desconto_FV_Casadinha.DESCRICAODETALHADAPROMOCAO
                                  , vnValorSt
                                  , vnValorRepasse
                                  , vc_RegiaoFilial.CODFILIALST );
  
                      END LOOP; -- Fim c_Desconto_FV_FaixaQtde
  
                    END IF; -- Fim Condição: Não for KIT
  
                  ------------------------------------------------------
                  -- Promoções por Faixa de Quantidade - OL e PE
                  ------------------------------------------------------
                  ELSE
  
                    -- Verificar se existe Promoção de Preço Fixo por Faixa de Quantidade(PRIORITARIA)
                    BEGIN
                      SELECT 'P' TIPOPROMOCAO
                           , PCMED_VIEWOLAUX04.CODPROMOCAOMED
                        INTO vvTipoPrecoDescFaixaQtde
                           , vnCodPromocaoMedFaixaQtde
                        FROM PCMED_VIEWOLAUX04
                       WHERE ((PCMED_VIEWOLAUX04.CODSISTEMA       = pi_vCodSistema))
                         AND ((PCMED_VIEWOLAUX04.CODCONDICAOVENDA = vnCodCondicaoVenda))
                         AND ((PCMED_VIEWOLAUX04.NUMREGIAO        = vc_RegiaoFilial.NUMREGIAO) OR (PCMED_VIEWOLAUX04.NUMREGIAO IS NULL))
                         AND ( ((PCMED_VIEWOLAUX04.CODPROD        = vc_Produto.CODPROD))      OR
                               ((PCMED_VIEWOLAUX04.CODFORNEC      = vc_Produto.CODFORNEC))    OR
                               ((PCMED_VIEWOLAUX04.CODMARCA       = vc_Produto.CODMARCA))     OR
                               ((PCMED_VIEWOLAUX04.CODLINHAPROD   = vc_Produto.CODLINHAPROD)) OR
                               ((PCMED_VIEWOLAUX04.CODEPTO        = vc_Produto.CODEPTO))
                             )
                         AND ((ROWNUM = 1));
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvTipoPrecoDescFaixaQtde  := NULL;
                          vnCodPromocaoMedFaixaQtde := NULL;
                    END;
  
                    -- Se não achou Promoção de Preço Fixo por Faixa de Quantidade
                    IF (vvTipoPrecoDescFaixaQtde IS NULL) THEN
  
                      -- Verificar se existe Promoção de Desconto por Faixa de Quantidade
                      FOR vc_MaiorDescFaixaQtde IN (SELECT 'D' TIPOPROMOCAO
                                                         , PCMED_VIEWOLAUX03.CODPROMOCAOMED
                                                         , PCMED_VIEWOLAUX03.PERCDESC
                                                      FROM PCMED_VIEWOLAUX03
                                                     WHERE ((PCMED_VIEWOLAUX03.CODSISTEMA       = pi_vCodSistema))
                                                       AND ((PCMED_VIEWOLAUX03.CODCONDICAOVENDA = vnCodCondicaoVenda))
                                                       AND ((PCMED_VIEWOLAUX03.NUMREGIAO        = vc_RegiaoFilial.NUMREGIAO)   OR (PCMED_VIEWOLAUX03.NUMREGIAO IS NULL))
                                                       AND ((PCMED_VIEWOLAUX03.CODFILIAL        = vc_RegiaoFilial.CODFILIALST) OR (PCMED_VIEWOLAUX03.CODFILIAL IS NULL))
                                                       AND ( ((PCMED_VIEWOLAUX03.CODPROD        = vc_Produto.CODPROD))     OR
                                                             ((PCMED_VIEWOLAUX03.CODFORNEC      = vc_Produto.CODFORNEC))   OR
                                                             ((PCMED_VIEWOLAUX03.CODMARCA       = vc_Produto.CODMARCA))    OR
                                                             ((PCMED_VIEWOLAUX03.CODLINHAPROD   = vc_Produto.CODLINHAPROD)) OR
                                                             ((PCMED_VIEWOLAUX03.CODEPTO        = vc_Produto.CODEPTO)) )
                                                     ORDER BY PCMED_VIEWOLAUX03.PERCDESC DESC) LOOP -->> Do maior para o menor desconto
                        -- Pega primeira linha do cursor que será o maior desconto e sai do laço
                        vvTipoPrecoDescFaixaQtde  := vc_MaiorDescFaixaQtde.TIPOPROMOCAO;                          
                        vnCodPromocaoMedFaixaQtde := vc_MaiorDescFaixaQtde.CODPROMOCAOMED;                          
                        EXIT; -->> SAI DO LAÇO
                      END LOOP;
  
                    END IF; -- Fim Condição se não achou Promoção de Preço Fixo
  
                    -- Atualiza Campos da Table
                    -- Desconto por Faixa de Quantidade -------------------------------------------------
                    IF (vvTipoPrecoDescFaixaQtde = 'D') THEN
  
                      FOR vc_DescontoFaixaQtde IN c_DescontoFaixaQtde(pi_vCodSistema,
                                                                      vnCodCondicaoVenda,
                                                                      vc_Produto.CODPROD,
                                                                      vc_Produto.CODFORNEC,
                                                                      vc_Produto.CODMARCA,
                                                                      vc_Produto.CODLINHAPROD,
                                                                      vc_Produto.CODEPTO,
                                                                      vc_Produto.CODCATEGORIA,
                                                                      vc_Produto.CODSEC,
                                                                      vnCodPromocaoMedFaixaQtde) LOOP
                                                                      
                        -- Calcula Preço Líquido
                        vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_DescontoFaixaQtde.PERCDESC,0)/100));
  
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              vnPrecoLiquido,
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              vnPreco, -- Preço Tabela
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                            );
                                                                      
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTINICIAL
                                  , QTFINAL
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPRECODESCONTO
                                  , CODFILIALST
                                  , PRECOFABRICA
                                  , VLST )
                           VALUES ( pi_vCodSistema
                                  , vc_RegiaoFilial.NUMREGIAO
                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_DescontoFaixaQtde.QTINICIAL
                                  , vc_DescontoFaixaQtde.QTFINAL
                                  , vc_DescontoFaixaQtde.CODPROMOCAOMED
                                  , NVL(vc_DescontoFaixaQtde.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_DescontoFaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , vvTipoPrecoDescFaixaQtde
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , vvTipoPrecoDescFaixaQtde
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnPrecoFabrica
                                  , vnValorSt );
                                          
                        -- Insere Restrição do Produto - DDMEDICA-5511
                        P_INSERE_RESTRICAO_PRODUTO(pi_vCodSistema,
                                                   vnCodCondicaoVenda,
                                                   vc_Produto.CODPROD,
                                                   vc_DescontoFaixaQtde.QTINICIAL,
                                                   vc_DescontoFaixaQtde.QTFINAL,
                                                   vc_DescontoFaixaQtde.CODPROMOCAOMED,
                                                   vnCodPromocaoMed,
                                                   vREJEITARITEMFORAFAIXAPROMOQT);
                                                                    
                      END LOOP; -- Fim c_DescontoFaixaQtde
  
                    -- Preço Promocional por Faixa de Quantidade ----------------------------------------
                    ELSIF (vvTipoPrecoDescFaixaQtde = 'P') THEN
  
                      FOR vc_PrecoPromocionalFaixaQtde IN c_PrecoPromocionalFaixaQtde(pi_vCodSistema,
                                                                                      vnCodCondicaoVenda,
                                                                                      vc_Produto.CODPROD,
                                                                                      vc_Produto.CODFORNEC,
                                                                                      vc_Produto.CODMARCA,
                                                                                      vc_Produto.CODLINHAPROD,
                                                                                      vc_Produto.CODEPTO,
                                                                                      vc_Produto.CODCATEGORIA,
                                                                                      vc_Produto.CODSEC,
                                                                                      vnCodPromocaoMedFaixaQtde) LOOP
                                     
                        -->> Calcula ST
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0),
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                              );
                                                                                      
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTINICIAL
                                  , QTFINAL
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPRECODESCONTO
                                  , CODFILIALST
                                  , PRECOFABRICA
                                  , VLST )
                           VALUES ( pi_vCodSistema
                                  , vc_RegiaoFilial.NUMREGIAO
                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_PrecoPromocionalFaixaQtde.QTINICIAL
                                  , vc_PrecoPromocionalFaixaQtde.QTFINAL
                                  , vc_PrecoPromocionalFaixaQtde.CODPROMOCAOMED
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PrecoPromocionalFaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                  , vvTipoPrecoDescFaixaQtde
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , vvTipoPrecoDescFaixaQtde
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnPrecoFabrica
                                  , vnValorSt );
                                  
                        -- Insere Restrição do Produto - DDMEDICA-5511
                        P_INSERE_RESTRICAO_PRODUTO(pi_vCodSistema,
                                                   vnCodCondicaoVenda,
                                                   vc_Produto.CODPROD,
                                                   vc_PrecoPromocionalFaixaQtde.QTINICIAL,
                                                   vc_PrecoPromocionalFaixaQtde.QTFINAL,
                                                   vc_PrecoPromocionalFaixaQtde.CODPROMOCAOMED,
                                                   vnCodPromocaoMed,
                                                   vREJEITARITEMFORAFAIXAPROMOQT);
                                  
                      END LOOP; -- Fim c_PrecoPromocionalFaixaQtde
  
                    END IF; -- Fim Condição Tipo de Promoção por Faixa
  
                  END IF; -- Fim Condição Promoções por Faixa de Quantidade - Força de Vendas ou OL/PE
                  
                  ------------------------------------------------------
                  -- Promoções COMBO - OL e PE (Se não for FV)
                  ------------------------------------------------------
                  IF (NOT vbGeraDicionarioForcaVendas) THEN
  
                    -- Combo de Preço Fixo --------------------------------------------------------------
                    FOR vc_PromocaoComboPreco IN c_PromocaoComboPreco(pi_vCodSistema,
                                                                      vnCodCondicaoVenda,
                                                                      vc_Produto.CODPROD,
                                                                      vc_RegiaoFilial.NUMREGIAO,
                                                                      vc_RegiaoFilial.CODFILIALST) LOOP
                                            
                      -->> Se encontrou COMBO
                      IF (NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0) > 0) THEN       
                                                                   
                        -->> Calcula ST
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0),
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                              );
                                              
                        -- Calcula o Repasse
                        PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                           vc_RegiaoFilial.CODCLIST,
                                                           vc_RegiaoFilial.NUMREGIAO,
                                                           1,    -- pi_nCondVenda,
                                                           vc_Produto.CODPROD,
                                                           NULL, --pi_nCodSt
                                                           vnPrecoFabrica,
                                                           vnPrecoLiquido,
                                                           NULL, --pi_vTipoAplicRepasseFilial
                                                           'N',  --pi_vCriticaObrigatorio
                                                           vnIntegradora,
                                                           'F',
                                                           vvTipoFv,
                                                           vvMensagemRepasse,
                                                           vvTipoRepasse,
                                                           vnValorRepasse);
                                                                                                                                    
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_KTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTCOMBO
                                  , OBRIGATORIO
                                  , PERMITIRAUMENTARQTDEKIT
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPRECODESCONTO
                                  , CODFILIALST
                                  , VLST )
                           VALUES ( pi_vCodSistema
                                  , vc_RegiaoFilial.NUMREGIAO
                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_PromocaoComboPreco.QTCOMBO
                                  , vc_PromocaoComboPreco.OBRIGATORIO
                                  , vc_PromocaoComboPreco.PERMITIRAUMENTARQTDEKIT
                                  , vc_PromocaoComboPreco.CODPROMOCAOMED
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PromocaoComboPreco.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                  , 'P'
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , 'P'
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnValorSt );
                                
                      END IF; -- Fim Condição: Se encontrou COMBO
                      
                    END LOOP; -- Fim c_PromocaoComboPreco
  
                    -- Combo de Desconto ----------------------------------------------------------------
                    FOR vc_PromocaoComboDesconto IN c_PromocaoComboDesconto(pi_vCodSistema,
                                                                            vnCodCondicaoVenda,
                                                                            vc_Produto.CODPROD,
                                                                            vc_RegiaoFilial.NUMREGIAO,
                                                                            vc_RegiaoFilial.CODFILIALST) LOOP
                                                                
                      -->> Se encontrou COMBO
                      IF (NVL(vc_PromocaoComboDesconto.PERCDESC,0) <> 0) THEN       
                                                                                    
                        -- Calcula Preço Líquido
                        vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_PromocaoComboDesconto.PERCDESC,0)/100));
    
                        vnCodSt := NULL;
                        P_OBTEM_STFONTE_4PMPF(vc_RegiaoFilial.CODFILIALST,
                                              vc_Produto.CODPROD,
                                              vc_RegiaoFilial.CODCLIST,
                                              vc_RegiaoFilial.NUMREGIAO,
                                              1,       -- pi_nCondVenda,
                                              100,     -- pi_nPercVenda
                                              vnCodSt,
                                              vnPrecoLiquido,
                                              0,       -- pi_nValorIpi
                                              0,       -- pi_nPrecoMaxConsum
                                              0,       -- pi_nValorUltEnt
                                              0,       -- pi_nCustoNfSemSt
                                              vnPreco, -- Preço Tabela
                                              'N',     -->> Padrão Não (Simples Nacional)
                                              'S',     -->> Pesquisa Custos
                                              'N',     -->> Não é Item Bonificado
                                              0,       -->> Não passa Frete e Outras Despesas
                                              vnBaseSt,
                                              vnValorSt,
                                              vvMensagemSt,
                                              vvRegimeEspIsenStFonte,
                                              vnAliqIcms1,
                                              vnAliqIcms2,
                                              vnIva,
                                              vnPercBaseRedSt
                                            );
                                                                  
                        -- Calcula o Repasse
                        PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_RegiaoFilial.CODFILIALST,
                                                           vc_RegiaoFilial.CODCLIST,
                                                           vc_RegiaoFilial.NUMREGIAO,
                                                           1,    -- pi_nCondVenda,
                                                           vc_Produto.CODPROD,
                                                           NULL, --pi_nCodSt
                                                           vnPrecoFabrica,
                                                           vnPrecoLiquido,
                                                           NULL, --pi_vTipoAplicRepasseFilial
                                                           'N',  --pi_vCriticaObrigatorio
                                                           vnIntegradora,
                                                           'F',
                                                           vvTipoFv,
                                                           vvMensagemRepasse,
                                                           vvTipoRepasse,
                                                           vnValorRepasse);
                                                                                                                    
                        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_KTMP
                                  ( CODSISTEMA
                                  , NUMREGIAO
                                  , CODCONDICAOVENDA
                                  , CODPROD
                                  , QTCOMBO
                                  , OBRIGATORIO
                                  , PERMITIRAUMENTARQTDEKIT
                                  , CODPROMOCAOMED
                                  , PERCDESC
                                  , PERCDESCFIN
                                  , PRECOPROMOCIONAL
                                  , TIPOPROMOCAO
                                  , PRECO
                                  , PERCBONIFICVENDA
                                  , TIPOPRECODESCONTO
                                  , CODFILIALST
                                  , VLST )
                           VALUES ( pi_vCodSistema
                                  , vc_RegiaoFilial.NUMREGIAO
                                  , vnCodCondicaoVenda
                                  , vc_Produto.CODPROD
                                  , vc_PromocaoComboDesconto.QTCOMBO
                                  , vc_PromocaoComboDesconto.OBRIGATORIO
                                  , vc_PromocaoComboDesconto.PERMITIRAUMENTARQTDEKIT
                                  , vc_PromocaoComboDesconto.CODPROMOCAOMED
                                  , NVL(vc_PromocaoComboDesconto.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                  , NVL(vc_PromocaoComboDesconto.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                  , 0 -->> NÃO PODE FICAR NULO
                                  , 'D'
                                  , vnPreco
                                  , vnPercBonificVenda
                                  , 'D'
                                  , vc_RegiaoFilial.CODFILIALST
                                  , vnValorSt );
                                
                      END IF; -- Fim Condição: Se encontrou COMBO
                      
                    END LOOP; -- Fim c_PromocaoComboDesconto
                  
                  END IF; -- Fim Condição: Promoções COMBO - OL e PE (Se não for FV)                
  
                  -- Efetiva Transações
                  viContaCommit := NVL(viContaCommit,0) + 1;
                  IF (viContaCommit > 1000) THEN
                    viContaCommit := 0;
                    --COMMIT;
                  END IF;
  
                ELSE
                
                  -- CONTROLE DE RELATÓRIO ---------
                  IF (NVL(vvOrigemPreco,'F') = 'F') THEN
                    P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                     vc_RegiaoFilial.CODFILIALST,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Produto sem Preço (Origem Preço da Integradora = Preço Fábrica)');
                  ELSE
                    P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                     vc_RegiaoFilial.CODFILIALST,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Produto sem Preço (Origem Preço da Integradora = Preço Tabela)');
                  END IF;
                  ----------------------------------              
  
                END IF; -- Fim Condição Se o Produto tem Preço
  
              ELSE
              
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                                 vc_RegiaoFilial.CODFILIALST,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Produto Fora de Linha e sem estoque');
                ----------------------------------              
              
              END IF; -- FIM CONDIÇÃO: Restringe envio de Produtos conforme o Fora de Linha
  
            END IF; -- FIM CONDIÇÃO PODE GRAVAR O PRODUTOS (RESTRIÇÕES)
            
          END LOOP; -- LAÇO DE CONDIÇÕES PARA A REGIÃO E FILIAL
        END IF; -- Fim Condição se Existem CONDIÇÕES PARA A REGIÃO E FILIAL
               
        ---------------------------------------------------------
        -- Se não achou Condição de Venda para o Produto e Região
        ---------------------------------------------------------
        IF (NOT vbAchouCondicaoProduto) THEN
        
          P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                           vc_RegiaoFilial.CODFILIALST,
                           NULL,
                           vc_Produto.CODPROD,
                           'P', -- Critica Por Produto
                           'Condição de Venda não encontrada para o Produto');
        
        END IF;
        
  
      END LOOP; -- Fim do Laço de Processamento dos Produtos POR REGIÃO
      
      ----------------------------------
      -- Se não achou a Tabela de Preços
      ---------------------------------
      IF (NOT vbAchouTabelaPreco) THEN
      
        -- CONTROLE DE RELATÓRIO ---------
        P_INSERE_CRITICA(vc_RegiaoFilial.NUMREGIAO,
                         vc_RegiaoFilial.CODFILIALST,
                         NULL,
                         NULL,
                         'G', -- Critica Geral
                         'Região sem Produtos válidos na Tabela de Preços');
        ----------------------------------              
        
      END IF;
      
    END LOOP; -- LAÇO DE REGIÕES E FILIAIS
    
    -------------------------------------
    -- Críticas das Condições das Filiais
    -------------------------------------
    IF (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') THEN
  
      -- Laço de Condições por Filial da Rotina 2325
      vbAchouCondicaoFilial := FALSE;
      FOR vc_CondicaoFilial IN (SELECT PCCONFIGSISTFILOPERLOG.CODFILIAL 
                                     , PCCONFIGSISTFILOPERLOG.CODCONDICAOVENDA
                                  FROM PCCONFIGSISTFILOPERLOG
                                 WHERE (PCCONFIGSISTFILOPERLOG.CODSISTEMA = pi_vCodSistema)) LOOP
  
        -- Achou Condição Filial
        vbAchouCondicaoFilial := TRUE;
        
        -- VALIDAÇÃO DA REGIÃO --
        -------------------------
        
        -- Se Verifica Cadasro da Região na Rotina 2325
        IF (NVL(vnRotinaSelecaoRegiao,0) = 2325) THEN
  
          -- Valida Cadastro da Rotina 2325 por Região
          BEGIN
            SELECT 'S'
              INTO vvAchouCadastro
              FROM PCCONFIGSISTREGOPERLOG
             WHERE (CODSISTEMA = pi_vCodSistema)
               AND (CODFILIAL  = vc_CondicaoFilial.CODFILIAL)
               AND (ROWNUM     = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvAchouCadastro := 'N';
          END; 
          
          -- Se não encontrou Regiões na Rotina 2325
          IF (NVL(vvAchouCadastro,'N') = 'N') THEN
          
            -- CONTROLE DE RELATÓRIO ---------
            P_INSERE_CRITICA(NULL,
                             vc_CondicaoFilial.CODFILIAL,
                             vc_CondicaoFilial.CODCONDICAOVENDA,
                             NULL,
                             'G', -- Critica Geral
                             'Região não cadastrada na Rotina 2325 para a Filial "' || vc_CondicaoFilial.CODFILIAL  || '"');
            ----------------------------------              
  
          END IF; 
          
        -- Se Verifica Cadastro da Região na Rotina 132
        ELSE
        
          -- Valida Cadastro da Região por Filial na 132
          BEGIN
            SELECT 'S'
              INTO vvAchouCadastro
              FROM PCPARAMFILIAL
             WHERE (PCPARAMFILIAL.CODFILIAL = vc_CondicaoFilial.CODFILIAL)
               AND (PCPARAMFILIAL.NOME      = 'FIL_NUMREGIAOPADRAO')
               AND (PCPARAMFILIAL.VALOR     IS NOT NULL);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvAchouCadastro := 'N';
          END;         
        
          -- Se não encontrou Região Vinculada à Filial na Rotina 132
          IF (NVL(vvAchouCadastro,'N') = 'N') THEN
  
            -- CONTROLE DE RELATÓRIO ---------
            P_INSERE_CRITICA(NULL,
                             vc_CondicaoFilial.CODFILIAL,
                             vc_CondicaoFilial.CODCONDICAOVENDA,
                             NULL,
                             'G', -- Critica Geral
                             'Parâmetro "FIL_NUMREGIAOPADRAO" requerido na Rotina 132 para a Filial "' || vc_CondicaoFilial.CODFILIAL  || '"');
            ----------------------------------              
            
          END IF;
        
        END IF; -- Fim Condição: Se Verifica Cadasro da Região na Rotina 2325 ou 132
        
        -- VALIDAÇÃO DA CONDIÇÃO DE VENDA --
        ------------------------------------         
        
        -- Se Filial sem Condição de Venda
        IF (NVL(vc_CondicaoFilial.CODCONDICAOVENDA,0) = 0) THEN
        
          -- CONTROLE DE RELATÓRIO ---------
          P_INSERE_CRITICA(NULL,
                           vc_CondicaoFilial.CODFILIAL,
                           vc_CondicaoFilial.CODCONDICAOVENDA,
                           NULL,
                           'G', -- Critica Geral
                           'Cadastro da Filial na Rotina 2325 sem Condição de Venda');
          ----------------------------------              
        
        -- Se Filial com Condição de Venda
        ELSE
            
          -- Verifica Vínculo de Condição de Venda
          BEGIN
            SELECT PCCONDICAOVENDA.CODCONDICAOVENDA
              INTO vnCodCondicaoVendaCadastro
              FROM PCCONDICAOVENDA
             WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA  = vc_CondicaoFilial.CODCONDICAOVENDA);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnCodCondicaoVendaCadastro := NULL;
          END; 
          
          -- Sem Condição de Venda Vinculada
          IF (NVL(vnCodCondicaoVendaCadastro,0) = 0) THEN
          
            -- CONTROLE DE RELATÓRIO ---------
            P_INSERE_CRITICA(NULL,
                             vc_CondicaoFilial.CODFILIAL,
                             vc_CondicaoFilial.CODCONDICAOVENDA,
                             NULL,
                             'G', -- Critica Geral
                             'Condição de Venda não encontrada no cadastro de Filiais da Rotina 2325');
            ----------------------------------              
    
          ELSE
          
            -- Verifica problemas de cadastro na Condição de Venda
            vvCriticasCondicaoVenda := FPROBLEMACADASTRALCONDICAO(vnCodCondicaoVendaCadastro,
                                                                  vnIntegradora,
                                                                  vc_CondicaoFilial.CODFILIAL);
                                                                  
            -- Se tem Críticas na Condição de Venda
            IF (vvCriticasCondicaoVenda IS NOT NULL) THEN                                                               
            
              -- CONTROLE DE RELATÓRIO ---------
              P_INSERE_CRITICA(NULL,
                               vc_CondicaoFilial.CODFILIAL,
                               vc_CondicaoFilial.CODCONDICAOVENDA,
                               NULL,
                               'G', -- Critica Geral
                               'Condição de Venda informada no cadastro de Filiais da Rotina 2325 com problemas cadastrais. ' || vvCriticasCondicaoVenda);
              ----------------------------------              
              
            END IF; -- Fim: Se tem Críticas na Condição de Venda
            
          END IF; -- Fim Condição: Vínculo de Condição de Venda
  
        END IF; -- Fim Condição: Se Filial sem Condição de Venda
                                                                                      
      END LOOP; -- Fim: Laço de Condições por Filial da Rotina 2325
      
      IF (NOT vbAchouCondicaoFilial) THEN
      
        -- CONTROLE DE RELATÓRIO ---------
        P_INSERE_CRITICA(NULL,
                         NULL,
                         NULL,
                         NULL,
                         'G', -- Critica Geral
                         'Filiais não cadastradas na Rotina 2325');
        ----------------------------------              
      
      END IF;
      
    END IF; -- Fim: Críticas das Condições das Filiais                                
    
    ----------------------------  
    -- Se não achou as Condições
    ----------------------------  
    IF (NOT vbAchouCondicoes) THEN
       
      -- CONTROLE DE RELATÓRIO ---------
      P_INSERE_CRITICA(NULL,
                       NULL,
                       NULL,
                       NULL,
                       'G', -- Critica Geral
                       'Produtos não foram gerados por configuração incompleta do Sistema de Pedido Eletrônico (Rotina 2325) e/ou Condição de Venda (Rotina 2311)');
      ----------------------------------                  
             
    END IF; -- Fim Condição: Se não achou as Condições
  
    vdDataHoraFinCondVendaProd := SYSDATE;
  
  
  
  
  
   /*********************
    RELATÓRIO DE CRITICAS
    *********************/
    IF (vtRelatorio.COUNT > 0) THEN
      FOR viIdx IN vtRelatorio.FIRST..vtRelatorio.LAST LOOP        
        INSERT INTO PCMED_VIEWOLCONDVENDAPROD_TREL
                  ( CODSISTEMA
                  , NUMREGIAO
                  , CODCONDICAOVENDA
                  , CODPROD
                  , CODFILIAL
                  , ACEITO
                  , OBSNAOACEITO )                    
           VALUES ( pi_vCodSistema
                  , vtRelatorio(viIdx).nNUMREGIAO
                  , vtRelatorio(viIdx).nCODCONDICAOVENDA
                  , vtRelatorio(viIdx).nCODPROD
                  , vtRelatorio(viIdx).vCODFILIAL
                  , vtRelatorio(viIdx).vACEITO
                  , vtRelatorio(viIdx).vOBSNAOACEITO );
      END LOOP;
    END IF;
  
  
  
  
  
  
   /*************************************
    PROCESSAMENTO NECESSÁRIO PARA GRAVAR:
    Condições de Venda x Prazo
    *************************************/
  
    -- Laço de Sistemas x Planos de Pagamento
    IF (vtSistPlPag.COUNT > 0) THEN
      FOR viIdx IN vtSistPlPag.FIRST..vtSistPlPag.LAST LOOP
  
        -- Pesquisa Dados do Plano de Pagamento
        BEGIN
          SELECT PCPLPAG.FORMAPARCELAMENTO
               , PCPLPAG.PRAZO1
               , PCPLPAG.PRAZO2
               , PCPLPAG.PRAZO3
               , PCPLPAG.PRAZO4
               , PCPLPAG.PRAZO5
               , PCPLPAG.PRAZO6
               , PCPLPAG.PRAZO7
               , PCPLPAG.PRAZO8
               , PCPLPAG.PRAZO9
               , PCPLPAG.PRAZO10
               , PCPLPAG.PRAZO11
               , PCPLPAG.PRAZO12
               , PCPLPAG.DTVENC1
               , PCPLPAG.DTVENC2
               , PCPLPAG.DTVENC3
            INTO vvFormaParcelamento
               , vnPrazo1
               , vnPrazo2
               , vnPrazo3
               , vnPrazo4
               , vnPrazo5
               , vnPrazo6
               , vnPrazo7
               , vnPrazo8
               , vnPrazo9
               , vnPrazo10
               , vnPrazo11
               , vnPrazo12
               , vdDtVenc1
               , vdDtVenc2
               , vdDtVenc3
            FROM PCPLPAG
           WHERE (PCPLPAG.CODPLPAG = vtSistPlPag(viIdx).vnCodPlPag);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvFormaParcelamento := NULL;
            vnPrazo1            := NULL;
            vnPrazo2            := NULL;
            vnPrazo3            := NULL;
            vnPrazo4            := NULL;
            vnPrazo5            := NULL;
            vnPrazo6            := NULL;
            vnPrazo7            := NULL;
            vnPrazo8            := NULL;
            vnPrazo9            := NULL;
            vnPrazo10           := NULL;
            vnPrazo11           := NULL;
            vnPrazo12           := NULL;
            vdDtVenc1           := NULL;
            vdDtVenc2           := NULL;
            vdDtVenc3           := NULL;
        END;
  
        -- Se Forma de Parcelamento Customizado
        IF (vvFormaParcelamento = 'C') THEN
  
          -- Se Preencheu os Dias Fixos
          IF ((vdDtVenc1 IS NOT NULL) OR
              (vdDtVenc2 IS NOT NULL) OR
              (vdDtVenc3 IS NOT NULL)) THEN
  
           /*------------------------------
            Condições de Venda x Prazo Fixo
            ------------------------------*/
  
            -- Percorre as Colunas de Data
            viSeqParcela := 0;
            FOR idxPrazo IN 1..3 LOOP
  
              -- Pega da Data da Coluna
              vnDtVencPrazo := NULL;
              IF    ((idxPrazo =  1) AND (vdDtVenc1 IS NOT NULL)) THEN
                vnDtVencPrazo := vdDtVenc1;
              ELSIF ((idxPrazo =  2) AND (vdDtVenc2 IS NOT NULL)) THEN
                vnDtVencPrazo := vdDtVenc2;
              ELSIF ((idxPrazo =  3) AND (vdDtVenc3 IS NOT NULL)) THEN
                vnDtVencPrazo := vdDtVenc3;
              END IF;
  
              -- Se informou Data
              IF (vnDtVencPrazo IS NOT NULL) THEN
  
                -- Incrementa Seq. Parcela
                viSeqParcela := NVL(viSeqParcela,0) + 1;
  
                -- Atualiza Campos da Table
                INSERT INTO PCMED_VIEWOLCONDVENDAPRAZO_TMP
                          ( CODSISTEMA
                          , CODPLPAG
                          , SEQPARCELA
                          , DATAFIXAPRAZO )
                  VALUES ( vtSistPlPag(viIdx).vvCodSistema
                         , vtSistPlPag(viIdx).vnCodPlPag
                         , viSeqParcela
                         , vnDtVencPrazo );
                -- Efetiva Transações
                viContaCommit := NVL(viContaCommit,0) + 1;
                IF (viContaCommit > 1000) THEN
                  viContaCommit := 0;
                  --COMMIT;
                END IF;
  
              END IF; -- Fim Condição Se informou Data
  
            END LOOP; -- Fim Percorre as Colunas de Data
  
          -- Se NÃO Preencheu os Dias Fixos
          ELSE
  
           /*-----------------------------------
            Condições de Venda x Prazo Parcelado
            -----------------------------------*/
  
            -- Percorre as Colunas de Prazo
            viSeqParcela := 0;
            FOR idxPrazo IN 1..12 LOOP
  
              -- Pega os Dias de Prazo da Coluna
              vnDiasPrazo := NULL;
              IF    ((idxPrazo =  1) AND (vnPrazo1  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo1;
              ELSIF ((idxPrazo =  2) AND (vnPrazo2  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo2;
              ELSIF ((idxPrazo =  3) AND (vnPrazo3  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo3;
              ELSIF ((idxPrazo =  4) AND (vnPrazo4  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo4;
              ELSIF ((idxPrazo =  5) AND (vnPrazo5  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo5;
              ELSIF ((idxPrazo =  6) AND (vnPrazo6  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo6;
              ELSIF ((idxPrazo =  7) AND (vnPrazo7  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo7;
              ELSIF ((idxPrazo =  8) AND (vnPrazo8  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo8;
              ELSIF ((idxPrazo =  9) AND (vnPrazo9  IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo9;
              ELSIF ((idxPrazo = 10) AND (vnPrazo10 IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo10;
              ELSIF ((idxPrazo = 11) AND (vnPrazo11 IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo11;
              ELSIF ((idxPrazo = 12) AND (vnPrazo12 IS NOT NULL)) THEN
                vnDiasPrazo := vnPrazo12;
              END IF;
  
              -- Se informou dias de Prazo
              IF (vnDiasPrazo IS NOT NULL) THEN
  
                -- Incrementa Seq. Parcela
                viSeqParcela := NVL(viSeqParcela,0) + 1;
  
                -- Atualiza Campos da Table
                INSERT INTO PCMED_VIEWOLCONDVENDAPRAZO_TMP
                          ( CODSISTEMA
                          , CODPLPAG
                          , SEQPARCELA
                          , QTDEDIASPRAZO )
                  VALUES (    vtSistPlPag(viIdx).vvCodSistema
                         ,  vtSistPlPag(viIdx).vnCodPlPag
                         ,  viSeqParcela
                         ,  vnDiasPrazo );
                -- Efetiva Transações
                viContaCommit := NVL(viContaCommit,0) + 1;
                IF (viContaCommit > 1000) THEN
                  viContaCommit := 0;
                  --COMMIT;
                END IF;
  
              END IF; -- Fim Condição Se informou dias de Prazo
  
            END LOOP; -- Fim Percorre as Colunas de Prazo
  
          END IF; -- Fim Condição Se Preencheu os Dias Fixos
  
        END IF; -- Fim Condição Se Forma de Parcelamento Customizado
  
      END LOOP; -- Fim Laço de Sistemas x Planos de Pagamento
    END IF;
  
   /*****************************************
    PROCESSAMENTO NECESSÁRIO PARA GRAVAR:
    Planos de Plagamento por Cliente e Filial
    *** Mudei para todos os Planos por causa
        dos Planos Ético e Genérico
    *****************************************/
    FOR vc_PlPagCli IN (SELECT DISTINCT
                               CODPLPAG
                          FROM PCPLPAG
                         WHERE (NVL(PCPLPAG.ENVIAPLANOFV,'S') = 'S')
                           AND (PCPLPAG.CODPLPAG NOT IN (SELECT PCMED_VIEWOLCONDVENDAPRAZO_TMP.CODPLPAG FROM PCMED_VIEWOLCONDVENDAPRAZO_TMP))) LOOP
  
  
      -- Pesquisa Dados do Plano de Pagamento
      BEGIN
        SELECT PCPLPAG.FORMAPARCELAMENTO
             , PCPLPAG.PRAZO1
             , PCPLPAG.PRAZO2
             , PCPLPAG.PRAZO3
             , PCPLPAG.PRAZO4
             , PCPLPAG.PRAZO5
             , PCPLPAG.PRAZO6
             , PCPLPAG.PRAZO7
             , PCPLPAG.PRAZO8
             , PCPLPAG.PRAZO9
             , PCPLPAG.PRAZO10
             , PCPLPAG.PRAZO11
             , PCPLPAG.PRAZO12
             , PCPLPAG.DTVENC1
             , PCPLPAG.DTVENC2
             , PCPLPAG.DTVENC3
          INTO vvFormaParcelamento
             , vnPrazo1
             , vnPrazo2
             , vnPrazo3
             , vnPrazo4
             , vnPrazo5
             , vnPrazo6
             , vnPrazo7
             , vnPrazo8
             , vnPrazo9
             , vnPrazo10
             , vnPrazo11
             , vnPrazo12
             , vdDtVenc1
             , vdDtVenc2
             , vdDtVenc3
          FROM PCPLPAG
         WHERE (PCPLPAG.CODPLPAG = vc_PlPagCli.CODPLPAG);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvFormaParcelamento := NULL;
          vnPrazo1            := NULL;
          vnPrazo2            := NULL;
          vnPrazo3            := NULL;
          vnPrazo4            := NULL;
          vnPrazo5            := NULL;
          vnPrazo6            := NULL;
          vnPrazo7            := NULL;
          vnPrazo8            := NULL;
          vnPrazo9            := NULL;
          vnPrazo10           := NULL;
          vnPrazo11           := NULL;
          vnPrazo12           := NULL;
          vdDtVenc1           := NULL;
          vdDtVenc2           := NULL;
          vdDtVenc3           := NULL;
      END;
  
      -- Se Forma de Parcelamento Customizado
      IF (vvFormaParcelamento = 'C') THEN
  
        -- Se Preencheu os Dias Fixos
        IF ((vdDtVenc1 IS NOT NULL) OR
            (vdDtVenc2 IS NOT NULL) OR
            (vdDtVenc3 IS NOT NULL)) THEN
  
         /*------------------------------
          Condições de Venda x Prazo Fixo
          ------------------------------*/
  
          -- Percorre as Colunas de Data
          viSeqParcela := 0;
          FOR idxPrazo IN 1..3 LOOP
  
            -- Pega da Data da Coluna
            vnDtVencPrazo := NULL;
            IF    ((idxPrazo =  1) AND (vdDtVenc1 IS NOT NULL)) THEN
              vnDtVencPrazo := vdDtVenc1;
            ELSIF ((idxPrazo =  2) AND (vdDtVenc2 IS NOT NULL)) THEN
              vnDtVencPrazo := vdDtVenc2;
            ELSIF ((idxPrazo =  3) AND (vdDtVenc3 IS NOT NULL)) THEN
              vnDtVencPrazo := vdDtVenc3;
            END IF;
  
            -- Se informou Data
            IF (vnDtVencPrazo IS NOT NULL) THEN
  
              -- Incrementa Seq. Parcela
              viSeqParcela := NVL(viSeqParcela,0) + 1;
  
              -- Atualiza Campos da Table
              INSERT INTO PCMED_VIEWOLCONDVENDAPRAZO_TMP
                        ( CODSISTEMA
                        , CODPLPAG
                        , SEQPARCELA
                        , DATAFIXAPRAZO )
                VALUES ( pi_vCodSistema
                       , vc_PlPagCli.CODPLPAG
                       , viSeqParcela
                       , vnDtVencPrazo );
              -- Efetiva Transações
              viContaCommit := NVL(viContaCommit,0) + 1;
              IF (viContaCommit > 1000) THEN
                viContaCommit := 0;
                --COMMIT;
              END IF;
  
            END IF; -- Fim Condição Se informou Data
  
          END LOOP; -- Fim Percorre as Colunas de Data
  
        -- Se NÃO Preencheu os Dias Fixos
        ELSE
  
         /*-----------------------------------
          Condições de Venda x Prazo Parcelado
          -----------------------------------*/
  
          -- Percorre as Colunas de Prazo
          viSeqParcela := 0;
          FOR idxPrazo IN 1..12 LOOP
  
            -- Pega os Dias de Prazo da Coluna
            vnDiasPrazo := NULL;
            IF    ((idxPrazo =  1) AND (vnPrazo1  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo1;
            ELSIF ((idxPrazo =  2) AND (vnPrazo2  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo2;
            ELSIF ((idxPrazo =  3) AND (vnPrazo3  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo3;
            ELSIF ((idxPrazo =  4) AND (vnPrazo4  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo4;
            ELSIF ((idxPrazo =  5) AND (vnPrazo5  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo5;
            ELSIF ((idxPrazo =  6) AND (vnPrazo6  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo6;
            ELSIF ((idxPrazo =  7) AND (vnPrazo7  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo7;
            ELSIF ((idxPrazo =  8) AND (vnPrazo8  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo8;
            ELSIF ((idxPrazo =  9) AND (vnPrazo9  IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo9;
            ELSIF ((idxPrazo = 10) AND (vnPrazo10 IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo10;
            ELSIF ((idxPrazo = 11) AND (vnPrazo11 IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo11;
            ELSIF ((idxPrazo = 12) AND (vnPrazo12 IS NOT NULL)) THEN
              vnDiasPrazo := vnPrazo12;
            END IF;
  
            -- Se informou dias de Prazo
            IF (vnDiasPrazo IS NOT NULL) THEN
  
              -- Incrementa Seq. Parcela
              viSeqParcela := NVL(viSeqParcela,0) + 1;
  
              -- Atualiza Campos da Table
              INSERT INTO PCMED_VIEWOLCONDVENDAPRAZO_TMP
                        ( CODSISTEMA
                        , CODPLPAG
                        , SEQPARCELA
                        , QTDEDIASPRAZO )
                VALUES (  pi_vCodSistema
                       ,  vc_PlPagCli.CODPLPAG
                       ,  viSeqParcela
                       ,  vnDiasPrazo );
              -- Efetiva Transações
              viContaCommit := NVL(viContaCommit,0) + 1;
              IF (viContaCommit > 1000) THEN
                viContaCommit := 0;
                --COMMIT;
              END IF;
  
            END IF; -- Fim Condição Se informou dias de Prazo
  
          END LOOP; -- Fim Percorre as Colunas de Prazo
  
        END IF; -- Fim Condição Se Preencheu os Dias Fixos
  
      END IF; -- Fim Condição Se Forma de Parcelamento Customizado
  
    END LOOP; -- Fim Laço Planos de Plagamento por Cliente e Filial
  
   /*-------------------------------
    Dicionário de Dados dos Clientes
    Dicionário de Alvarás
    --------------------------------*/
    IF (vbGeraDicionarioClientes or vbGeraDicionarioAlvaras) THEN
  
      -------------
      -- Parâmetros
      -------------
  
      BEGIN
        SELECT NVL(PCCONSUM.PEREXCEDELIMCRED,0)
          INTO vrParamsDicClientes.nPEREXCEDELIMCRED
          FROM PCCONSUM;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParamsDicClientes.nPEREXCEDELIMCRED := 0;
      END;
  
      BEGIN
        SELECT NVL(VALOR,'N')
          INTO vrParamsDicClientes.vVALIDALVARAPORTIPOCTLVEN
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.NOME      = 'VALIDALVARAPORTIPOCTLVEN')
           AND (PCPARAMFILIAL.CODFILIAL = '99');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParamsDicClientes.vVALIDALVARAPORTIPOCTLVEN := 'N';
      END;
  
      BEGIN
        SELECT NVL(VALOR,'N')
          INTO vrParamsDicClientes.vSOMACREDITOCLIPRINCIPAL
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.NOME      = 'SOMACREDITOCLIPRINCIPAL')
           AND (PCPARAMFILIAL.CODFILIAL = '99');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrParamsDicClientes.vSOMACREDITOCLIPRINCIPAL := 'N';
      END;
  
      --------------------------------------------
      -- Exclui Clientes que não estão mais ativos
      --------------------------------------------
      DELETE FROM PCMED_VIEWOLCLI_TMP
       WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
         AND (PCMED_VIEWOLCLI_TMP.CODCLI IN (SELECT PCCLIENT.CODCLI FROM PCCLIENT WHERE PCCLIENT.DTEXCLUSAO IS NOT NULL));
  
      ---------------------
      -- Cursor de Clientes
      ---------------------
      FOR vc_Clientes IN (SELECT PCCLIENT.CODCLI
                               , PCCLIENT.CODCLIPRINC
                               , PCCLIENT.CGCENT
                               , PCCLIENT.CODCOB
                               , PCCLIENT.LIMCRED
                               , PCCLIENT.DTCADASTRO
                               , PCCLIENT.DTVENCALVARAFUNC
                               , PCCLIENT.DTVENCALVARAANVISA
                               , PCCLIENT.NUMALVARASUS
                               , PCCLIENT.DTVENCCRF
                               , PCCLIENT.DTVENCALVARA
                               , PCCLIENT.DTVENCALVARARETINOICO
                               --
                               , PCCLIENT.NUMCRF
                               , PCCLIENT.NUMALVARAFUNC
                               , PCCLIENT.NUMALVARAANVISA
                               , PCCLIENT.NUMALVARA
                               , PCCLIENT.NUMALVARARETINOICO
                            FROM PCCLIENT
                               , PCMED_VIEWOLCLI_TMP
                           WHERE (PCMED_VIEWOLCLI_TMP.CODCLI = PCCLIENT.CODCLI)) LOOP
  
        -- Define o Valor Minimo Calcula Saldo do Limite de Crédito
         BEGIN
           SELECT PCCONDICAOVENDA.TIPOVALORMINIMO
                , PCCONDICAOVENDA.VALORMINIMOPED
             INTO vrParamsDicClientes.vTIPOVALORMINIMO
                , vrParamsDicClientes.nVALORMINIMOPED
             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                , PCCONDICAOVENDA
            WHERE (PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA = pi_vCodSistema)
              AND (PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI     = vc_Clientes.CODCLI)
              AND (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA)
              AND (ROWNUM                                  = 1); -->> PEGA A PRIMEIRA CONDIÇÃO DE VENDA LIBERADA PARA O CLIENTE
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrParamsDicClientes.vTIPOVALORMINIMO := NULL;
            vrParamsDicClientes.nVALORMINIMOPED  := 0;
        END;
        IF (NVL(vrParamsDicClientes.vTIPOVALORMINIMO,' ') <> 'C')  THEN -->> Se o Valor Mínimo não estiver definido na Condição de Venda
          BEGIN
            SELECT NVL(VLMINPEDIDO, 0)
              INTO vrParamsDicClientes.nVALORMINIMOPED
              FROM PCCOB
             WHERE (CODCOB = vc_Clientes.CODCOB);
          EXCEPTION
            WHEN OTHERS THEN
              vrParamsDicClientes.nVALORMINIMOPED := 0;
          END;
        END IF;
  
        -- Se Soma Crédito de todos os clientes associados ao principal
        IF (NVL(vrParamsDicClientes.vSOMACREDITOCLIPRINCIPAL,'N') = 'S') THEN
          SELECT SUM(NVL(PCCLIENT.LIMCRED,0))
            INTO vnLimiteCredito
            FROM PCCLIENT
           WHERE (NVL(PCCLIENT.CODCLIPRINC, PCCLIENT.CODCLI) = vc_Clientes.CODCLIPRINC);
        -- Se não Soma Crédito de todos os clientes associados ao principal
        ELSE
          vnLimiteCredito := NVL(vc_Clientes.LIMCRED,0);
        END IF;
  
        -- Atualiza Cliente
        UPDATE PCMED_VIEWOLCLI_TMP
          SET CGC              = vc_Clientes.CGCENT
            , DATACADASTRO     = vc_Clientes.DTCADASTRO
            , VALORMINPEDIDO   = vrParamsDicClientes.nVALORMINIMOPED
            , LIMITECREDITO    = vnLimiteCredito
            , PEREXCEDELIMCRED = vrParamsDicClientes.nPEREXCEDELIMCRED
        WHERE (CODSISTEMA = pi_vCodSistema)
          AND (CODCLI     = vc_Clientes.CODCLI);
  
        -- Se não usa Alvará por Controle de Venda
        IF (NVL(vrParamsDicClientes.vVALIDALVARAPORTIPOCTLVEN,'N') <> 'S') THEN
          -- Insere Documentos do Cliente cadastrado na PCCLIENT
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_Clientes.CODCLI,
                               vc_Clientes.CGCENT,
                               'ALVARA FUNCIONAMENTO',
                               vc_Clientes.DTCADASTRO,
                               vc_Clientes.NUMALVARAFUNC,
                               vc_Clientes.DTVENCALVARAFUNC);
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_Clientes.CODCLI,
                               vc_Clientes.CGCENT,
                               'ALVARA ANVISA',
                               vc_Clientes.DTCADASTRO,
                               vc_Clientes.NUMALVARAANVISA,
                               vc_Clientes.DTVENCALVARAANVISA);
          -- SUS não é obrigatório
          --P_INSEREDOCUMCLIENTE(vc_Clientes.CODCLI,
          --                     'ALVARA SUS',
          --                     vc_Clientes.DTCADASTRO,
          --                     vc_Clientes.NUMALVARASUS);
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_Clientes.CODCLI,
                               vc_Clientes.CGCENT,
                               'ALVARA CRF',
                               vc_Clientes.DTCADASTRO,
                               vc_Clientes.NUMCRF,
                               vc_Clientes.DTVENCCRF);
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_Clientes.CODCLI,
                               vc_Clientes.CGCENT,
                               'ALVARA PSICOTROPICOS',
                               vc_Clientes.DTCADASTRO,
                               vc_Clientes.NUMALVARA,
                               vc_Clientes.DTVENCALVARA);
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_Clientes.CODCLI,
                               vc_Clientes.CGCENT,
                               'ALVARA RETINOICOS',
                               vc_Clientes.DTCADASTRO,
                               vc_Clientes.NUMALVARARETINOICO,
                               vc_Clientes.DTVENCALVARARETINOICO);
        END IF; -- Fim Condição Se não usa Alvará por Controle de Venda
  
      END LOOP; -- Fim Cursor de Clientes
  
      --------------------
      -- Resumo de Pedidos
      --------------------
      IF (vbGeraDicionarioClientes) THEN
  
        FOR vc_ResumoPedidos IN (SELECT PCPEDC.CODCLI
                                      , MAX(PCPEDC.DATA) DATA_ULT_COMPRA
                                      , SUM(NVL(PCPEDC.VLATEND, 0)) TOTAL_ATEND
                                      , SUM(CASE WHEN (PCPEDC.POSICAO  IN ('L', 'M')) THEN
                                               NVL(PCPEDC.VLATEND, 0)
                                             ELSE
                                               0
                                             END) TOTAL_A_FATURAR
                                   FROM PCMED_VIEWOLCLI_TMP
                                      , PCPEDC
                                  WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
                                    AND (PCPEDC.CODCLI   = PCMED_VIEWOLCLI_TMP.CODCLI)
                                    AND (PCPEDC.DTCANCEL IS NULL)
                                    AND (PCPEDC.CODCOB   NOT IN ('DESD', 'DEVP', 'DEVT', 'BNF','BNFT','BNTR','BNFR','BNRP'))
                                  GROUP BY PCPEDC.CODCLI) LOOP
  
           -- Atualiza Cliente
           UPDATE PCMED_VIEWOLCLI_TMP
              SET TOTALATEND              = vc_ResumoPedidos.TOTAL_ATEND
                , SALDOPEDIDOSPARAFATURAR = vc_ResumoPedidos.TOTAL_A_FATURAR
                , DATAULTCOMPRA           = vc_ResumoPedidos.DATA_ULT_COMPRA
            WHERE (CODSISTEMA = pi_vCodSistema)
              AND (CODCLI     = vc_ResumoPedidos.CODCLI);
  
        END LOOP; -- Fim Cursor Resumo de Pedidos a Faturar
  
  
        -------------------------------------------------------------------
        -- Resumo de Títulos dos Clientes - OBTER BASE DO LIMITE DE CRÉDITO
        -------------------------------------------------------------------
        FOR vc_ResumoTitulos IN (SELECT PCPREST.CODCLI
                                      , SUM(NVL(PCPREST.VALOR,0)) VALOR_EM_ABERTO
                                   FROM PCMED_VIEWOLCLI_TMP
                                      , PCPREST
                                  WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
                                    AND (PCPREST.CODCLI                 = PCMED_VIEWOLCLI_TMP.CODCLI)
                                    AND (PCPREST.CODCOB NOT IN ('BNF','BNFT','BNTR','BNFR','BNRP'))
                                    AND (PCPREST.DTPAG IS NULL)
                                  GROUP BY PCPREST.CODCLI) LOOP
  
           -- Atualiza Cliente
           UPDATE PCMED_VIEWOLCLI_TMP
             SET VALOREMABERTO      = vc_ResumoTitulos.VALOR_EM_ABERTO
           WHERE (CODSISTEMA = pi_vCodSistema)
             AND (CODCLI     = vc_ResumoTitulos.CODCLI);
  
        END LOOP; -- Fim Laço Resumo de Títulos dos Clientes - OBTER BASE DO LIMITE DE CRÉDITO
  
        ---------------------------------
        -- Resumo de Títulos dos Clientes
        ---------------------------------
        FOR vc_ResumoTitulos IN (SELECT PCPREST.CODCLI
                                      , MAX(PCPREST.DTPAG) DT_ULT_PAG
                                      , NVL(TRUNC(AVG(CASE WHEN (PCPREST.DTPAG > PCPREST.DTVENC) THEN
                                                             PCPREST.DTPAG - PCPREST.DTVENC
                                                           ELSE
                                                             NULL
                                                           END)), 0) MEDIA_ATRASO
                                      , NVL(SUM(CASE WHEN (PCPREST.DTPAG IS NOT NULL) AND
                                                          (TRUNC(SYSDATE) - TRUNC(PCPREST.DTPAG) <= 30) THEN
                                                  PCPREST.VPAGO
                                                ELSE
                                                  0
                                                END), 0) VALOR_PAGO_ULT_30DIAS
                                      , NVL(SUM(CASE WHEN (PCPREST.DTPAG IS NULL) AND
                                                          (TRUNC(PCPREST.DTVENC) < TRUNC(SYSDATE)) THEN
                                                  NVL(PCPREST.VALOR, 0)
                                                ELSE
                                                  0
                                                END), 0) VALOR_VENCIDOS
                                      , NVL(SUM(CASE WHEN (PCPREST.DTPAG IS NULL) AND
                                                          (TRUNC(PCPREST.DTVENC) >= TRUNC(SYSDATE)) THEN
                                                  NVL(PCPREST.VALOR, 0)
                                                ELSE
                                                  0
                                                END), 0) VALOR_VENCER
                                   FROM PCMED_VIEWOLCLI_TMP
                                      , PCPREST
                                  WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
                                    AND (PCPREST.CODCLI                 = PCMED_VIEWOLCLI_TMP.CODCLI)
                                    AND (PCPREST.CODCOB NOT IN ('DESD', 'DEVP', 'DEVT', 'BNF','BNFT','BNTR','BNFR','BNRP'))
                                    AND (PCPREST.VALOR > 0) -->> SOMENTE TÍTULOS COM VALOR POSITIVO
                                  GROUP BY PCPREST.CODCLI) LOOP
  
           -- Atualiza Cliente
           UPDATE PCMED_VIEWOLCLI_TMP
             SET DATAULTPAGAMENTO   = vc_ResumoTitulos.DT_ULT_PAG
               , MEDIAATRASO        = vc_ResumoTitulos.MEDIA_ATRASO
               , VALORPAGOULT30DIAS = vc_ResumoTitulos.VALOR_PAGO_ULT_30DIAS
               , VALORVENCIDOS      = vc_ResumoTitulos.VALOR_VENCIDOS
               , VALORVENCER        = vc_ResumoTitulos.VALOR_VENCER
           WHERE (CODSISTEMA = pi_vCodSistema)
             AND (CODCLI     = vc_ResumoTitulos.CODCLI);
  
        END LOOP; -- Fim Laço Resumo de Títulos dos Clientes
  
        ------------------------------------------
        -- Cursor de Dados Calculados dos Clientes
        ------------------------------------------
        FOR vc_DadosCalcCli IN (SELECT PCMED_VIEWOLCLI_TMP.CODCLI
                                     , PCMED_VIEWOLCLI_TMP.LIMITECREDITO
                                     , PCMED_VIEWOLCLI_TMP.SALDOPEDIDOSPARAFATURAR
                                     , PCMED_VIEWOLCLI_TMP.VALOREMABERTO
                                  FROM PCMED_VIEWOLCLI_TMP
                                 WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)) LOOP
  
           -- Calcula Saldo do Limite de Crédito
           vnSaldoLimiteCredito := ((NVL(vc_DadosCalcCli.LIMITECREDITO, 0) * (1 + (NVL(vrParamsDicClientes.nPEREXCEDELIMCRED, 0) / 100))) -
                                   (NVL(vc_DadosCalcCli.VALOREMABERTO, 0) +
                                    NVL(vc_DadosCalcCli.SALDOPEDIDOSPARAFATURAR, 0)));
           IF (vnSaldoLimiteCredito < 0) THEN
             vnSaldoLimiteCredito := 0;
           END IF;
  
           -- Atualiza Cliente
           UPDATE PCMED_VIEWOLCLI_TMP
             SET SALDOLIMITECREDITO = vnSaldoLimiteCredito
               , PEREXCEDELIMCRED   = vrParamsDicClientes.nPEREXCEDELIMCRED
           WHERE (CODSISTEMA = pi_vCodSistema)
             AND (CODCLI     = vc_DadosCalcCli.CODCLI);
  
        END LOOP; -- Fim Cursor de Clientes
  
        -------------------------------------------
        -- Cursor de Títulos dos Clientes em Atraso
        -------------------------------------------
        FOR vc_TitulosAtraso IN (SELECT PCPREST.CODCLI
                                      , PCMED_VIEWOLCLI_TMP.CGC
                                      , PCPREST.DUPLIC || '-' || PCPREST.PREST DUPLICATA
                                      , PCPREST.DTEMISSAO
                                      , PCPREST.DTVENC
                                      , (TRUNC(SYSDATE) - TRUNC(PCPREST.DTVENC)) DIAS_ATRASO
                                      , NVL(CASE WHEN (PCPREST.DTPAG IS NULL) AND
                                                      (TRUNC(PCPREST.DTVENC) < TRUNC(SYSDATE)) THEN
                                              NVL(PCPREST.VALOR, 0)
                                            ELSE
                                              0
                                            END, 0) VALOR_VENCIDO
                                   FROM PCMED_VIEWOLCLI_TMP
                                      , PCPREST
                                  WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
                                    AND (PCPREST.CODCLI                 = PCMED_VIEWOLCLI_TMP.CODCLI)
                                    AND (PCPREST.CODCOB NOT IN ('DESD', 'DEVP', 'DEVT', 'BNF','BNFT','BNTR','BNFR','BNRP'))
                                    AND (PCPREST.VALOR > 0) -->> SOMENTE TÍTULOS COM VALOR POSITIVO
                                    AND (PCPREST.DTPAG IS NULL)) LOOP
  
          -- Se o Título está com Valor Vencido
          IF (vc_TitulosAtraso.VALOR_VENCIDO > 0) THEN
  
            -- Insere Título
            INSERT INTO PCMED_VIEWOLTITATRASO_TMP
                      ( CODSISTEMA
                      , CODCLI
                      , CGC
                      , DUPLICATA
                      , VALOR
                      , DATAEMISSAO
                      , DATAVENCIMENTO
                      , DIASATRASO )
               VALUES ( pi_vCodSistema
                      , vc_TitulosAtraso.CODCLI
                      , vc_TitulosAtraso.CGC
                      , vc_TitulosAtraso.DUPLICATA
                      , vc_TitulosAtraso.VALOR_VENCIDO
                      , vc_TitulosAtraso.DTEMISSAO
                      , vc_TitulosAtraso.DTVENC
                      , vc_TitulosAtraso.DIAS_ATRASO );
  
          END IF; -- Fim Condição Se o Título está com Valor Vencido
  
        END LOOP; -- Fim Cursor de Títulos dos Clientes em Atraso
  
      END IF; -- (vbGeraDicionarioClientes)
  
      --------------------------------------
      -- Se usa Alvará por Controle de Venda
      --------------------------------------
      IF (NVL(vrParamsDicClientes.vVALIDALVARAPORTIPOCTLVEN,'N') = 'S') THEN
  
        -- Cursor de Documentos de Controle de Venda
        FOR vc_DocControleVenda IN (SELECT PCTIPOCONTROLEVENDA.DESCRICAO
                                         , PCCLICONTROLEVENDA.CODCLI
                                         , PCMED_VIEWOLCLI_TMP.CGC
                                         , PCCLIENT.DTCADASTRO
                                         , PCCLICONTROLEVENDA.NUMDOC
                                         , PCCLICONTROLEVENDA.DTVALIDADE
                                      FROM PCMED_VIEWOLCLI_TMP
                                         , PCCLICONTROLEVENDA
                                         , PCTIPOCONTROLEVENDA
                                         , PCCLIENT
                                     WHERE (PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema)
                                       AND (PCCLIENT.CODCLI                         = PCMED_VIEWOLCLI_TMP.CODCLI)
                                       AND (PCCLICONTROLEVENDA.CODTIPOCONTROLEVENDA = PCTIPOCONTROLEVENDA.CODTIPOCONTROLEVENDA)
                                       AND (PCCLIENT.CODCLI                         = PCCLICONTROLEVENDA.CODCLI)
                                       AND (PCTIPOCONTROLEVENDA.TIPOVALIDACAO      <> '4') -->> Somente Aqueles Que têm Validação
                                       AND ((NVL(PCTIPOCONTROLEVENDA.CRITICANUMDOC,'N')     = 'S') OR
                                            (NVL(PCTIPOCONTROLEVENDA.CRITICADTVALIDADE,'N') = 'S')) -->> Somente Aqueles Que têm Crítica
                                       ) LOOP
          -- Insere Documentos do Cliente cadastrado na PCCLICONTROLEVENDA
          P_INSEREDOCUMCLIENTE(vbGeraDicionarioAlvaras,
                               vc_DocControleVenda.CODCLI,
                               vc_DocControleVenda.CGC,
                               vc_DocControleVenda.DESCRICAO,
                               vc_DocControleVenda.DTCADASTRO,
                               vc_DocControleVenda.NUMDOC,
                               vc_DocControleVenda.DTVALIDADE);
  
        END LOOP; -- Fim -- Cursor de Documentos de Controle de Venda
  
      END IF; -- Fim Condição Se usa Alvará por Controle de Venda
  
    END IF; -- Fim Condição Gera Dicionário Clientes
  
    -------------------------------------------------
    -- Gera Tabela Resumida de Condições Comerciais
    -------------------------------------------------
    IF    (NVL(vvPedidoEletronico,' ') = 'C') THEN -->> COTEFACIL
    
      INSERT INTO PCMED_VIEWOLCONDVENDA_TMP
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , NUMREGIAO
                , DESCRICAO
                , DTVALIDINICIAL
                , DTVALIDFINAL
                , TIPOREQUISITO
                , VALORMINIMOPED
                , FLAGREQUISITOMINIMOITENS
                , ATIVO )
         SELECT DISTINCT
                TB.CODSISTEMA
              , TB.CODCONDICAOVENDA
              , TB.NUMREGIAO
              , PCCONDICAOVENDA.DESCRICAO
              , PCCONDICAOVENDA.DTVALIDINICIAL
              , PCCONDICAOVENDA.DTVALIDFINAL
              , 'VL' TIPOREQUISITO
              , PCCONDICAOVENDA.VALORMINIMOPED
              , 'N' TIPOREQUISITO
              , 'A' ATIVO
           FROM PCMED_VIEWOLCONDVENDACLI_TMP TB
              , PCCONDICAOVENDA
          WHERE (TB.CODCONDICAOVENDA = PCCONDICAOVENDA.CODCONDICAOVENDA);
          
      INSERT INTO PCMED_VIEWOLCONDVENDAFILREG_TM
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , NUMREGIAO
                , CODFILIALST )   
           SELECT DISTINCT
                  TB.CODSISTEMA
                , TB.CODCONDICAOVENDA
                , TB.NUMREGIAO
                , TB.CODFILIALST CODFILIAL
             FROM PCMED_VIEWOLCONDVENDAPROD_TMP TB;  
             
    ELSIF (vbGeraDicionarioForcaVendas) THEN
  
      INSERT INTO PCMED_VIEWOLCONDVENDA_TMP
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , NUMREGIAO
                , DESCRICAO
                , DTVALIDINICIAL
                , DTVALIDFINAL
                , TIPOREQUISITO
                , VALORMINIMOPED
                , FLAGREQUISITOMINIMOITENS
                , ATIVO )
         SELECT DISTINCT
                TB.CODSISTEMA
              , TB.CODCONDICAOVENDA
              , TB.NUMREGIAO
              , PCPROMOCAOMED.DESCRICAORESUMIDA
              , PCPROMOCAOMED.DATAINICIAL
              , PCPROMOCAOMED.DATAFINAL
              , CASE
                  WHEN PCPROMOCAOMED.TIPOPROMOCAO = 'V' THEN
                    'VL'
                  WHEN PCPROMOCAOMED.TIPOPROMOCAO = 'M' THEN
                    'MX'
                  ELSE
                    'SR'
                END TIPOREQUISITO
              , PCPROMOCAOMED.VLRMINITENSPROMOCAO
              , CASE
                  WHEN PCPROMOCAOMED.TIPOPROMOCAO = 'M' THEN
                    'S'
                  ELSE
                    'N'
                END TIPOREQUISITO
              , 'A' ATIVO
           FROM PCMED_VIEWOLCONDVENDACLI_TMP TB
              , PCPROMOCAOMED
          WHERE (TB.CODCONDICAOVENDA = PCPROMOCAOMED.CODPROMOCAOMED);
  
      INSERT INTO PCMED_VIEWOLCONDVENDAFILREG_TM
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , NUMREGIAO
                , CODFILIALST )
           SELECT DISTINCT
                  TB.CODSISTEMA
                , TB.CODCONDICAOVENDA
                , TB.NUMREGIAO
                , TB.CODFILIALST CODFILIAL
             FROM PCMED_VIEWOLCONDVENDAPROD_TMP TB;
  
    END IF; -- Fim Condição Gera Tabela Resumida de Condições Comerciais
  
