             FROM PCMED_VIEWOL_PROMOCAOCLI_TMP
            WHERE (CODSISTEMA = pi_vCodSistema);
  
      -- Resumo de Condições
      INSERT INTO PCMED_VIEWOLSISTCONDVENDA
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , INTEGRADORA
                , CODFILIALST
