            WHERE (CODSISTEMA = pi_vCodSistema);
  
      -- Restrição por RCA na Promoção
      IF (NVL(vnLayout,0) IN (33)) THEN -- [33 - Integradora MichaelSoft]
        -- Carrega Tabela Auxilliar resumida por Promoção x RCA x Supervisor (Otimização)
        INSERT INTO PCMED_VIEWOL_PROMOCAOUSUR_TMP
                  ( CODPROMOCAOMED
