                AND ((PCMED_VIEWOL_PROMOCAOUSUR_TMP.CODUSUR       = PCUSUARI.CODUSUR) OR PCMED_VIEWOL_PROMOCAOUSUR_TMP.CODUSUR IS NULL)
                AND ((PCMED_VIEWOL_PROMOCAOUSUR_TMP.CODSUPERVISOR = PCUSUARI.CODSUPERVISOR) OR PCMED_VIEWOL_PROMOCAOUSUR_TMP.CODSUPERVISOR IS NULL);
      END IF;
      
      -- Restrições de Produtos da Condição - DDMEDICA-5511
      INSERT INTO PCMED_VIEWOLCONDVENDA_RESTPRO
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , CODPROD
                , QTINICIAL
                , QTFINAL
                , CODPROMOCAOMED )
           SELECT CODSISTEMA
                , CODCONDICAOVENDA
                , CODPROD
                , QTINICIAL
                , QTFINAL
                , CODPROMOCAOMED 
            FROM PCMED_VIEWOLCONDVENDA_RESTPR_T
           WHERE (PCMED_VIEWOLCONDVENDA_RESTPR_T.CODSISTEMA = pi_vCodSistema);
            
      -- Tabela de Relatório de Processamento dos Produtos
      INSERT INTO PCMED_VIEWOLCONDVENDAPROD_REL
               ( CODSISTEMA
               , NUMREGIAO
               , CODCONDICAOVENDA
               , CODPROD
               , CODFILIAL
               , ACEITO
               , OBSNAOACEITO
               )
          SELECT CODSISTEMA
               , NUMREGIAO
               , CODCONDICAOVENDA
               , CODPROD
               , CODFILIAL
               , ACEITO
               , OBSNAOACEITO
            FROM PCMED_VIEWOLCONDVENDAPROD_TREL
           WHERE (CODSISTEMA = pi_vCodSistema);    
      
      -- Tabela de Grupo de Prazo e Tabelas de Relacionamentos - DDVENDAS-35908
      P_INSERE_GRUPO_PLANO(pi_vCodSistema);
            
    END IF; -- FIM CONDIÇÃO GRAVA TABELAS DE DADOS
  
    -------------------------------------------------
    -- INSERE LOG
    -------------------------------------------------
    IF (NVL(vvUsaMultiplasCondVenda,'N') = 'S') OR
       (vbGeraDicionarioForcaVendas) THEN
  
        vbDataHoraMsgLog := SYSDATE;
        -- Insere Log
        INSERT INTO PCLOGGERARDADOSVIEWOL
                  ( DATALOG
                  , DATAHORAINI
                  , DATAHORAFIN
                  , DATAHORAMSG
                  , MENSAGEM
                  , DATAHORAINITABTEMPDESC
                  , DATAHORAFINTABTEMPDESC
                  , DATAHORAFINCONDICOESCOMERC
                  , DATAHORAINIGERCLIENTES
                  , DATAHORAFINGERCLIENTES
                  , DATAHORAINIGERDESCONTOS
                  , DATAHORAFINGERDESCONTOS
                  , DATAHORAFINCONDVENDAPROD )
           VALUES ( SYSDATE
                  , vbDataHoraIniLog
                  , vbDataHoraFinLog
                  , vbDataHoraMsgLog
                  , vvMensagemLog
                  , vdDataHoraIniTabTempDesc
                  , vdDataHoraFinTabTempDesc
                  , vdDataHoraFinCondicoesComerc
                  , vdDataHoraIniGerClientes
                  , vdDataHoraFinGerClientes
                  , vdDataHoraIniGerDescontos
                  , vdDataHoraFinGerDescontos
                  , vdDataHoraFinCondVendaProd );
  
    END IF; -- FIM CONDIÇÃO INSERE LOG
  
    -------------------------------------------------
    -- Efetiva Transações NO FINAL (Tabelas de Dados)
    -------------------------------------------------
    COMMIT;
  
  EXCEPTION
    WHEN OTHERS THEN
      RAISE_APPLICATION_ERROR(-20000, DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM);
  END P_CONDCOMERC_SISTOPERLOG;

