      SELECT CASE WHEN (PCMED_VIEWOLAUX01.codprod      IS NOT NULL) THEN 1
                  WHEN (PCMED_VIEWOLAUX01.codfornec    IS NOT NULL) THEN 2
                  WHEN (PCMED_VIEWOLAUX01.codmarca     IS NOT NULL) THEN 3
                  WHEN (PCMED_VIEWOLAUX01.codcategoria IS NOT NULL) THEN 4
                  WHEN (PCMED_VIEWOLAUX01.codsec       IS NOT NULL) THEN 5
                  WHEN (PCMED_VIEWOLAUX01.codlinhaprod IS NOT NULL) THEN 6
                  WHEN (PCMED_VIEWOLAUX01.codepto      IS NOT NULL) THEN 7
                  ELSE 8 END PRIORIDADE
           , 'D' TIPOPROMOCAO
           , PCMED_VIEWOLAUX01.PERCDESC
           , PCMED_VIEWOLAUX01.PERCDESCFIN
           , PCMED_VIEWOLAUX01.QTDEMINIMA
           , PCMED_VIEWOLAUX01.CODPROMOCAOMED
        FROM PCMED_VIEWOLAUX01
       WHERE ((PCMED_VIEWOLAUX01.CODSISTEMA       = pi_vCodSistema))
         AND ((PCMED_VIEWOLAUX01.CODCONDICAOVENDA = pi_nCodCondicaoVenda))
         AND ((PCMED_VIEWOLAUX01.NUMREGIAO        = pi_nNumRegiao)    OR (PCMED_VIEWOLAUX01.NUMREGIAO IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODPROD          = pi_nCodProd)      OR (PCMED_VIEWOLAUX01.CODPROD IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODFORNEC        = pi_nCodFornec)    OR (PCMED_VIEWOLAUX01.CODFORNEC IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODMARCA         = pi_nCodMarca)     OR (PCMED_VIEWOLAUX01.CODMARCA IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODLINHAPROD     = pi_vCodLinhaProd) OR (PCMED_VIEWOLAUX01.CODLINHAPROD IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODEPTO          = pi_nCodepto)      OR (PCMED_VIEWOLAUX01.CODEPTO IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODCATEGORIA     = pi_nCodCategoria) OR (PCMED_VIEWOLAUX01.CODCATEGORIA IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODSEC           = pi_nCodSec)       OR (PCMED_VIEWOLAUX01.CODSEC IS NULL))
         AND ((PCMED_VIEWOLAUX01.CODFILIAL        = pi_vCodFilial)    OR (PCMED_VIEWOLAUX01.CODFILIAL IS NULL)) -- 20170802
       ORDER BY 1 ASC -->> Da maior prioridade para a menor prioridade
              , PCMED_VIEWOLAUX01.PERCDESC DESC; -->> Do maior Desconto para o Menor Desconto
  
