         AND ((PCMED_VIEWOLAUX05.CODLINHAPROD     = pi_vCodLinhaProd)     OR (PCMED_VIEWOLAUX05.CODLINHAPROD IS NULL))
         AND ((PCMED_VIEWOLAUX05.CODEPTO          = pi_nCodepto)          OR (PCMED_VIEWOLAUX05.CODEPTO IS NULL))
         AND ((PCMED_VIEWOLAUX05.CODCATEGORIA     = pi_nCodCategoria)     OR (PCMED_VIEWOLAUX05.CODCATEGORIA IS NULL))
         AND ((PCMED_VIEWOLAUX05.CODSEC           = pi_nCodSec)           OR (PCMED_VIEWOLAUX05.CODSEC IS NULL))
         AND ((PCMED_VIEWOLAUX05.CODFILIAL        = pi_vCodFilial)        OR (PCMED_VIEWOLAUX05.CODFILIAL IS NULL)) -- 20170802
       ORDER BY 1 ASC; -->> Da maior prioridade para a menor prioridade
  
    -- Promoção Combo de Preço
    CURSOR c_PromocaoComboPreco(pi_vCodSistema       IN VARCHAR2,
                                pi_nCodCondicaoVenda IN NUMBER,
                                pi_nCodProd          IN NUMBER,
                                pi_nNumRegiao        IN NUMBER,
                                pi_vCodFilial        IN VARCHAR2) IS -- 20170802
      SELECT 'P' TIPOPROMOCAO
           , PCMED_VIEWOLAUX07.PRECOPROMOCIONAL
           , PCMED_VIEWOLAUX07.PERCDESCFIN
           , PCMED_VIEWOLAUX07.CODPROMOCAOMED
           , PCMED_VIEWOLAUX07.QTCOMBO
           , PCMED_VIEWOLAUX07.OBRIGATORIO
           , PCMED_VIEWOLAUX07.PERMITIRAUMENTARQTDEKIT
        FROM PCMED_VIEWOLAUX07
       WHERE ((PCMED_VIEWOLAUX07.CODSISTEMA       = pi_vCodSistema))
         AND ((PCMED_VIEWOLAUX07.CODCONDICAOVENDA = pi_nCodCondicaoVenda))
         AND ((PCMED_VIEWOLAUX07.NUMREGIAO        = pi_nNumRegiao) OR (PCMED_VIEWOLAUX07.NUMREGIAO IS NULL))
         AND ((PCMED_VIEWOLAUX07.CODPROD          = pi_nCodProd)   OR (PCMED_VIEWOLAUX07.CODPROD IS NULL))
         AND ((PCMED_VIEWOLAUX07.CODFILIAL        = pi_vCodFilial) OR (PCMED_VIEWOLAUX07.CODFILIAL IS NULL)); -- 20170802
  
    -- Promoção Combo de Desconto
    CURSOR c_PromocaoComboDesconto(pi_vCodSistema       IN VARCHAR2,
                                   pi_nCodCondicaoVenda IN NUMBER,
                                   pi_nCodProd          IN NUMBER,
                                   pi_nNumRegiao        IN NUMBER,
                                   pi_vCodFilial        IN VARCHAR2) IS -- 20170802
      SELECT 'D' TIPOPROMOCAO
           , PCMED_VIEWOLAUX06.PERCDESC
           , PCMED_VIEWOLAUX06.PERCDESCFIN
           , PCMED_VIEWOLAUX06.CODPROMOCAOMED
           , PCMED_VIEWOLAUX06.QTCOMBO
           , PCMED_VIEWOLAUX06.OBRIGATORIO
           , PCMED_VIEWOLAUX06.PERMITIRAUMENTARQTDEKIT
        FROM PCMED_VIEWOLAUX06
       WHERE ((PCMED_VIEWOLAUX06.CODSISTEMA       = pi_vCodSistema))
         AND ((PCMED_VIEWOLAUX06.CODCONDICAOVENDA = pi_nCodCondicaoVenda))
         AND ((PCMED_VIEWOLAUX06.NUMREGIAO        = pi_nNumRegiao) OR (PCMED_VIEWOLAUX06.NUMREGIAO IS NULL))
         AND ((PCMED_VIEWOLAUX06.CODPROD          = pi_nCodProd)   OR (PCMED_VIEWOLAUX06.CODPROD IS NULL))
         AND ((PCMED_VIEWOLAUX06.CODFILIAL        = pi_vCodFilial) OR (PCMED_VIEWOLAUX06.CODFILIAL IS NULL)); -- 20170802
    
    ---------------------------------------------
    -- FUNCAO PARA VERFICAR SE O CLIENTE É VALIDO
    ---------------------------------------------
    FUNCTION FCLIENTEVALIDO(pi_vCodSistema IN VARCHAR2,
                            pi_nCodCli     IN NUMBER)
    RETURN VARCHAR2 IS
      vvAchouRestricao VARCHAR2(1);
      vvRetCliValido   VARCHAR2(1);
    BEGIN
      -- Verifica se tem Restrição de Clientes para o Sistema
      BEGIN
        SELECT 'S'
          INTO vvAchouRestricao
          FROM PCCONFIGSISTCLIOPERLOG
         WHERE (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
           AND (ROWNUM                            = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvAchouRestricao := 'N';
      END;
      -- Se Achou Restrição por Cliente
      IF (vvAchouRestricao = 'S') THEN
        -- Verifica se o cliente está na restrição do Sistema
        BEGIN
        SELECT 'S'
          INTO vvRetCliValido
          FROM PCCONFIGSISTCLIOPERLOG
         WHERE (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
           AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = pi_nCodCli);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvRetCliValido := 'N';
        END;
      -- Se não achou Restrição por Cliente
      ELSE
        vvRetCliValido := 'S';
      END IF;
      -- Retorno
      RETURN vvRetCliValido;
    END;
  
    ----------------------------------------------------
    -- PROCEDIMENTO PARA INSERIR DO DOCUMENTO DO CLIENTE
    ----------------------------------------------------
    PROCEDURE P_INSEREDOCUMCLIENTE(pi_bGerarDicionarioAlvaras IN BOOLEAN,
                                   pi_nCodCli                 IN NUMBER,
                                   pi_vCgc                    IN VARCHAR2,
                                   pi_vDescricao              IN VARCHAR2,
                                   pi_dDtCadastro             IN DATE,
                                   pi_vNumDoc                 IN VARCHAR2,
                                   pi_dDtVencimento           IN DATE) IS
    BEGIN
  
      -- Se Gera Dicionário Alvarás Gera Todos Independente de não ter Alvará Válido
      IF (pi_bGerarDicionarioAlvaras) OR
      -- Se NÃO tem Data de Vencimento OU
      -- Se tem Data de Vencimento e Venceu
         ( (pi_dDtVencimento IS NULL) OR
          ((pi_dDtVencimento IS NOT NULL) AND (TRUNC(pi_dDtVencimento) < TRUNC(SYSDATE))) ) THEN
  
          INSERT INTO PCMED_VIEWOLDOCUMCLI_TMP
                    ( CODSISTEMA
                    , CODCLI
                    , CGC
                    , DESCRICAO
                    , DATACADASTRO
                    , NUMDOC
                    , DATAVENCIMENTO )
            VALUES  ( pi_vCodSistema
                    , pi_nCodCli
                    , pi_vCgc
                    , pi_vDescricao
                    , pi_dDtCadastro
                    , pi_vNumDoc
                    , pi_dDtVencimento );
  
      END IF;
  
    END P_INSEREDOCUMCLIENTE;
  
    ---------------------------------------------------------------
    -- FUNCAO PARA RETORNAR PROBLEMA CADASTRAL DA CONDIÇÃO DE VENDA
    ---------------------------------------------------------------
    FUNCTION FPROBLEMACADASTRALCONDICAO(pi_nCodCondicaoVenda IN NUMBER,
                                        pi_nIntegradora      IN NUMBER,
                                        pi_vCodFilial        IN VARCHAR2)
    RETURN VARCHAR2 IS
      vvRetMotivo        VARCHAR2(2000);
      dDTVALIDINICIAL    DATE;
      dDTVALIDFINAL      DATE;
      vvAchouCondicao    VARCHAR2(1);
      vvAchouIntegradora VARCHAR2(1);
      vvAchouFilial      VARCHAR2(1);
    BEGIN
      -- Inicializa Retorno
      vvRetMotivo := NULL;
  
      -- Pesquisa Condição
      BEGIN
        SELECT 'S'
             , DTVALIDINICIAL
             , DTVALIDFINAL
          INTO vvAchouCondicao
             , dDTVALIDINICIAL
             , dDTVALIDFINAL
          FROM PCCONDICAOVENDA
         WHERE (CODCONDICAOVENDA = pi_nCodCondicaoVenda);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvAchouCondicao := 'N';
      END;
  
      -- Se achou a Condição
      IF (NVL(vvAchouCondicao,'N') = 'S') THEN
  
        IF NOT (TRUNC(SYSDATE) BETWEEN dDTVALIDINICIAL AND dDTVALIDFINAL) THEN
  
          vvRetMotivo := 'Condição de Venda "' || NVL(pi_nCodCondicaoVenda,0) || '" expirada';
  
        ELSE
  
          BEGIN
            SELECT 'S'
              INTO vvAchouIntegradora
              FROM PCCONDVENDAINTEGRADORA
             WHERE (CODCONDICAOVENDA  = pi_nCodCondicaoVenda)
               AND (INTEGRADORA       = pi_nIntegradora)
               AND (ROWNUM            = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvAchouIntegradora := 'N';
          END;
  
          -- Se não Achou a Integradora na 2311
          IF (vvAchouIntegradora = 'N') THEN
  
            vvRetMotivo := 'Integradora "' || NVL(pi_nIntegradora,0) || '" não foi informada na Condição de Venda "' || NVL(pi_nCodCondicaoVenda,0) || '"';
  
          ELSE
  
            BEGIN
              SELECT 'S'
                INTO vvAchouFilial
                FROM PCCONDVENDAFILIAL
               WHERE (CODCONDICAOVENDA  = pi_nCodCondicaoVenda)
                 AND (CODFILIAL         = pi_vCodFilial)
                 AND (ROWNUM            = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvAchouFilial := 'N';
            END;
  
            IF (vvAchouFilial = 'N') THEN
  
              vvRetMotivo := 'Filial "' || NVL(pi_vCodFilial,0) || '" não foi informada na Condição de Venda "' || NVL(pi_nCodCondicaoVenda,0) || '"';
  
            END IF;
  
          END IF; -- Fim Condição: Se não Achou a Integradora na 2311
  
        END IF;
  
      -- Se não achou a Condição
      ELSE
  
        vvRetMotivo := 'Condição de Venda "' || NVL(pi_nCodCondicaoVenda,0) || '" não encontrada';
  
      END IF;
  
      -- Finaliza Retorno
      IF (vvRetMotivo IS NOT NULL) THEN
        vvRetMotivo := vvRetMotivo || '. Verifique Rotina 2311.';
      END IF;
  
      -- Retorno
      RETURN vvRetMotivo;
  
    END FPROBLEMACADASTRALCONDICAO;
  
    ----------------------------------------------------
    -- PROCEDIMENTO PARA INSERIR CRITICA
    ----------------------------------------------------
    PROCEDURE P_INSERE_CRITICA(pi_nNumRegiao        IN NUMBER,
                               pi_vCodFilial        IN VARCHAR2,
                               pi_nCodCondicaoVenda IN NUMBER,
                               pi_nCodProd          IN NUMBER,
                               pi_vTipoCritica      IN VARCHAR2,
                               pi_vObsNaoAceito     IN VARCHAR2) IS
      vrAuxRelatorio TRecRelatorio;
    BEGIN
      -- CONTROLE DE RELATÓRIO ---------
      vrAuxRelatorio.nNUMREGIAO        := pi_nNumRegiao;
      vrAuxRelatorio.vCODFILIAL        := pi_vCodFilial;
      vrAuxRelatorio.nCODCONDICAOVENDA := pi_nCodCondicaoVenda;
      vrAuxRelatorio.nCODPROD          := pi_nCodProd;
      vrAuxRelatorio.vACEITO           := pi_vTipoCritica;
      vrAuxRelatorio.vOBSNAOACEITO     := pi_vObsNaoAceito;
      vtRelatorio(NVL(vtRelatorio.COUNT,0) + 1) := vrAuxRelatorio;
      ----------------------------------
    END P_INSERE_CRITICA;
    
  /*********************************
   INICIO DO PROCESSAMENTO PRINCIPAL
   *********************************/
  BEGIN
  
    -- Inicialização: NÃO USA Multiplas Promoções
    vvUsaMultiplasPromocoes := 'N';
  
    -- Inicialização: Rotina da seleção da Região
    vnRotinaSelecaoRegiao   := NULL;
  
    -- Pesquisa Configurações do Sistema de Pedido Eletrônico
    -- ALTER TABLE PCCONFIGSISTOPERLOG ADD USAVIEWSOL VARCHAR2(1);
    -- ALTER TABLE PCCONFIGSISTOPERLOG ADD USAMULTIPLASCONDVENDA VARCHAR2(1);
    BEGIN
      SELECT NVL(PCCONFIGSISTOPERLOG.USAVIEWSOL,'N')
           , NVL(PCCONFIGSISTOPERLOG.USAMULTIPLASCONDVENDA,'N')
           , NVL(PCCONFIGSISTOPERLOG.NUMDICIONARIO,0)
           , PCCONFIGSISTOPERLOG.INTEGRADORA
           , PCCONFIGSISTOPERLOG.PEDIDOELETRONICO
           , PCCONFIGSISTOPERLOG.GERARACORDOPRECO
           , PCCONFIGSISTOPERLOG.APLICARINDICEACORDOPRECO
           , PCCONFIGSISTOPERLOG.TIPOQUEBRA
        INTO vvUsaViewsOL
           , vvUsaMultiplasCondVenda
           , vnNumDicionario
           , vnIntegradora
           , vvPedidoEletronico
           , vvGerarAcordoPreco
           , vvAplicarIndiceAcordoPreco
           , vvTipoQuebra
        FROM PCCONFIGSISTOPERLOG
       WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA = pi_vCodSistema);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUsaViewsOL               := 'N';
        vvUsaMultiplasCondVenda    := 'N';
        vnNumDicionario            := 0;
        vnIntegradora              := NULL;
        vvPedidoEletronico         := NULL;
        vvGerarAcordoPreco         := NULL;
        vvAplicarIndiceAcordoPreco := NULL;
        vvTipoQuebra               := NULL;
    END;
  
    -- Pesquisa o Layout da Integradora
    BEGIN
      SELECT LAYOUT
           , NVL(TIPOFV,'FV')
           , SEQVERSAO
        INTO vnLayout
           , vvTipoFv
           , vnSeqVersao
        FROM PCINTEGRADORA
       WHERE (PCINTEGRADORA.INTEGRADORA = vnIntegradora);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnLayout := NULL;
        vvTipoFv := 'FV';
        vnSeqVersao := NULL;
    END;
  
    -- Parâmetro de Região da Integradora
    BEGIN
      SELECT VALOR
        INTO vvNumRegiaoParamIntegradora
        FROM PCPARAMINTEGRADORAMED
       WHERE (NOME        = 'REGIAODIFERENCIADATABPR')
         AND (INTEGRADORA = vnIntegradora);
      -- Converte para Número Parâmetro da Região da Integradora
      BEGIN
        vnNumRegiaoParamIntegradora := TO_NUMBER(NVL(vvNumRegiaoParamIntegradora,'0'));
      EXCEPTION
        WHEN OTHERS THEN
          vnNumRegiaoParamIntegradora := NULL;
      END;
      -- Pesquisa Região Válida conforme parâmetro da Integradora
      BEGIN
        SELECT NUMREGIAO
          INTO vnNumRegiaoIntegradora
          FROM PCREGIAO
         WHERE (NUMREGIAO = vnNumRegiaoParamIntegradora);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnNumRegiaoIntegradora := NULL;
      END;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnNumRegiaoIntegradora := NULL;
    END;
  
    -- Se usa a 2311 para definir as Condições Comerciais (SERVCON)
    IF (vvUsaMultiplasCondVenda IN ('S','P')) THEN
      vbGeraDicionarioForcaVendas  := FALSE;
      vvGeraDicionarioForcaVendas  := 'N';
      vbGeraDicionarioPorRegiao    := FALSE;
      vbValidaEnviaFv              := TRUE; -- 4663.045085.2018
      vbValidaEstoque              := FALSE;
      vbValidaShelfLife            := FALSE;
      -- Múltiplas Promoções no Sistema substituindo o processo padrão do SERVCON
      BEGIN
        SELECT 'S' USAMULTIPLASPROMOCOES
             , 'P' USAMULTIPLASCONDVENDA
          INTO vvUsaMultiplasPromocoes
             , vvUsaMultiplasCondVenda
          FROM PCCONFIGSISTOPERLOG
         WHERE (CODSISTEMA            = pi_vCodSistema)
           AND (USAMULTIPLASPROMOCOES = 'S');
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          NULL; -->> Não faz nada se o Sisma não estiver configurado para Múltiplas Promoções
      END;
    -->> COTEFACIL
    ELSIF (NVL(vvPedidoEletronico,' ') = 'C') THEN
      vbGeraDicionarioForcaVendas  := FALSE;
      vvGeraDicionarioForcaVendas  := 'N';
      vbGeraDicionarioPorRegiao    := TRUE;
      vbValidaEnviaFv              := FALSE;
      vbValidaEstoque              := TRUE;
      vbValidaShelfLife            := FALSE;
    ELSE
      -- Define se Gera Dicionário por Região/Filial
      IF    (NVL(vnLayout,0) IN (16)) THEN -- [16 - Integradora Winthor]
        -- Usa Multiplas Promoções (Promoção da 2323 como Condição de Venda)
        vvUsaMultiplasPromocoes      := 'S';
        vbGeraDicionarioForcaVendas  := TRUE;
        vvGeraDicionarioForcaVendas  := 'S';
        vbGeraDicionarioPorRegiao    := FALSE;
        vbValidaEnviaFv              := TRUE; -- HIS.01061.2016
        vbValidaEstoque              := FALSE;
        vbValidaShelfLife            := FALSE;
      -- Define se Gera Dicionário por Região
      ELSIF (NVL(vnLayout,0) IN (33)) THEN -- [33 - Integradora MichaelSoft]
        -- Usa Multiplas Promoções (Promoção da 2323 como Condição de Venda)
        vvUsaMultiplasPromocoes      := 'S';
        vbGeraDicionarioForcaVendas  := TRUE;
        vvGeraDicionarioForcaVendas  := 'S';
        vbGeraDicionarioPorRegiao    := TRUE;
        vbValidaEnviaFv              := TRUE; -- HIS.01061.2016
        vbValidaEstoque              := FALSE;
        vbValidaShelfLife            := FALSE;
      ELSE
        -- [5 - Dicionário Angeloni] ou [9 - Dicionário Clamed]
        -- ou [12 - SESI] - HIS.03306.2016
        -- ou já estiver lendo o TIPOQUEBRA Filial/Região cadastrado no Sistema
        IF (NVL(vnNumDicionario,0) IN (5,9, 12)) OR
           (NVL(vvTipoQuebra,'F') IN ('FR'))     THEN
          vbGeraDicionarioForcaVendas  := FALSE;
          vvGeraDicionarioForcaVendas  := 'N';
          vbGeraDicionarioPorRegiao    := TRUE;
          vbValidaEnviaFv              := FALSE; -- HIS.01061.2016
          -- Clamed somente enviará produtos com estoque
          IF (vnNumDicionario = 9) THEN
            vbValidaEstoque            := TRUE;
            vbValidaShelfLife          := TRUE;
          -- 4663.096171.2017 - SESI somente enviará produtos com estoque, mas não validará ShelfLife
          ELSIF (vnNumDicionario = 12) THEN
            vbValidaEstoque            := TRUE;
            vbValidaShelfLife          := FALSE;
          ELSE
            vbValidaEstoque            := FALSE;
            vbValidaShelfLife          := FALSE;
          END IF;
        ELSE
          vbGeraDicionarioForcaVendas  := FALSE;
          vvGeraDicionarioForcaVendas  := 'N';
          vbGeraDicionarioPorRegiao    := FALSE;
          vbValidaEnviaFv              := FALSE; -- HIS.01061.2016
          vbValidaEstoque              := FALSE;
          vbValidaShelfLife            := FALSE;
        END IF;
      END IF;
    END IF; -- Fim Condição usa 2311 para definir as Condições Comerciais
  
    -- Define se Gera Dicionário Clientes (8 - Running)
    IF (NVL(vnNumDicionario,0) IN (8)) THEN
      vbGeraDicionarioClientes := TRUE;
    ELSE
      vbGeraDicionarioClientes := FALSE;
    END IF;
  
    -- Define se Gera Dicionário Alvaras (16 - Integradora Winthor)
    IF (NVL(vnLayout,0) IN (16)) THEN
      vbGeraDicionarioAlvaras := TRUE;
    ELSE
      vbGeraDicionarioAlvaras := FALSE;
    END IF;
  
    -- DDMEDICA-689 - Opções do Layout Customizado de Preços
    IF (vnNumDicionario = 99) AND
       (NVL(pi_vEstoque,'N') <> 'S') THEN
      BEGIN
        EXECUTE IMMEDIATE ' SELECT SOMENTEITENSCOMESTARQPRECOS, VALIDARSHELFLIFEARQPRECOS, VALIDARENVIAFVARQPRECOS
                              FROM PCLAYOUTINTEGRAVERSOPERLOG
                             WHERE LAYOUT = ' || NVL(vnLayout,0) || ' AND SEQVERSAO = ' || NVL(vnSeqVersao,0)
                     INTO vSOMENTEITENSCOMESTARQPRECOS, vVALIDARSHELFLIFEARQPRECOS, vVALIDARENVIAFVARQPRECOS;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vSOMENTEITENSCOMESTARQPRECOS := 'N';
          vVALIDARSHELFLIFEARQPRECOS   := 'N';
          vVALIDARENVIAFVARQPRECOS     := 'N';
        WHEN OTHERS THEN
          vSOMENTEITENSCOMESTARQPRECOS := 'N';
          vVALIDARSHELFLIFEARQPRECOS   := 'N';
          vVALIDARENVIAFVARQPRECOS     := 'N';
      END;
      vbValidaEstoque   := (NVL(vSOMENTEITENSCOMESTARQPRECOS,'N') = 'S');
      vbValidaShelfLife := (NVL(vVALIDARSHELFLIFEARQPRECOS,'N') = 'S');
      vbValidaEnviaFv   := (NVL(vVALIDARENVIAFVARQPRECOS,'N') = 'S');
    END IF;
  
    -- DDMEDICA-5540 - Envia Dicionário de Dados conforme Integradora
    BEGIN
      SELECT VALOR
        INTO vUSARENVIARDICIONARIODADOSMED
        FROM PCPARAMINTEGRADORAMED
       WHERE (INTEGRADORA = vnIntegradora)
         AND (NOME        = 'USARENVIARDICIONARIODADOSMED');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vUSARENVIARDICIONARIODADOSMED := 'N';
    END;
    vbValidaEnviarDicD := (NVL(vUSARENVIARDICIONARIODADOSMED,'N') = 'S');

    -- DDMEDICA-6008 - Calcular Repasse no Envio das Promoções do SERVCON
    vCALCREPASSEVIEWPROMOSERVCON := 'S';
    IF (vvUsaMultiplasCondVenda = 'P') THEN
      vCALCREPASSEVIEWPROMOSERVCON := FOBTEM_REGRA_MEDICAMENTOS('99',
                                                                'CALCREPASSEVIEWPROMOSERVCON',
                                                                'N');
    END IF;                                                              

    -- DDMEDICA-6008 - Utiliza todas as Restrições de Desconto da Promoção - SERVCON
    vUSATODASRESTRVIEWPROMOSERVCON := FOBTEM_REGRA_MEDICAMENTOS('99',
                                                                'USATODASRESTRVIEWPROMOSERVCON',
                                                                'N');
                                                                  
    -- Origem do Pedido utilizada para enviar as Promoções para o SERVCON
    vORIGEMPEDVIEWPROMOSERVCON := FOBTEM_REGRA_MEDICAMENTOS('99',
                                                            'ORIGEMPEDVIEWPROMOSERVCON',
                                                            'W');
    vORIGEMPODEGERARPROMOCAO   := 'F';     
    IF (vORIGEMPEDVIEWPROMOSERVCON IS NULL) THEN
      vORIGEMPEDVIEWPROMOSERVCON := 'W';
      vORIGEMPODEGERARPROMOCAO   := 'F'; 
    END IF;                                                              
    IF (vORIGEMPEDVIEWPROMOSERVCON <> 'W') THEN
      vORIGEMPODEGERARPROMOCAO := vORIGEMPEDVIEWPROMOSERVCON;
    END IF;  

    -- Variáveis do Log
    vbDataHoraIniLog := SYSDATE;
  
    -- LIMPA TABELAS TEMPORARIAS
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX01';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX02';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX03';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX04';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX05';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX06';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLAUX07';
    --
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDA_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCLI_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDACLI_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDACLIREST_T';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPROD_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPROD_FTMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPRAZO_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPROD_CTMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPROD_KTMP';
    --
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLTITATRASO_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLDOCUMCLI_TMP';
    --
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLSISTCONDVENDA_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAFILREG_TM';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDICOESCOMERC_TM';
    --
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOL_PCDESCONTO_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOL_PROMOCAOCLI_TMP';
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOL_PROMOCAOUSUR_TMP';
    --
    EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_VIEWOLCONDVENDAPROD_TREL';
  
    -- LIMPA TABELAS DE DADOS QUANDO USA VIEWS OL
    -- OU
    -- QUANDO GERA DICIONARIO FORÇA DE VENDAS
    -- OU
    -- COTEFACIL
    IF (NVL(vvUsaViewsOL,'N') = 'S')       OR
       (vbGeraDicionarioForcaVendas)       OR
       (NVL(vvPedidoEletronico,' ') = 'C') THEN
      DELETE FROM PCMED_VIEWOLCONDVENDA         WHERE (PCMED_VIEWOLCONDVENDA.CODSISTEMA         = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCLI               WHERE (PCMED_VIEWOLCLI.CODSISTEMA               = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDACLI      WHERE (PCMED_VIEWOLCONDVENDACLI.CODSISTEMA      = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPROD     WHERE (PCMED_VIEWOLCONDVENDAPROD.CODSISTEMA     = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPROD_FXQ WHERE (PCMED_VIEWOLCONDVENDAPROD_FXQ.CODSISTEMA = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPRAZO    WHERE (PCMED_VIEWOLCONDVENDAPRAZO.CODSISTEMA    = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAFILREG   WHERE (PCMED_VIEWOLCONDVENDAFILREG.CODSISTEMA   = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLDOCUMCLI          WHERE (PCMED_VIEWOLDOCUMCLI.CODSISTEMA          = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPROD_CAS WHERE (PCMED_VIEWOLCONDVENDAPROD_CAS.CODSISTEMA = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDICOESCOMERC   WHERE (PCMED_VIEWOLCONDICOESCOMERC.CODSISTEMA   = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOL_PROMOCAOCLI      WHERE (PCMED_VIEWOL_PROMOCAOCLI.CODSISTEMA      = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOL_PROMOCAOUSUR     WHERE (PCMED_VIEWOL_PROMOCAOUSUR.CODSISTEMA     = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLSISTCONDVENDA     WHERE (PCMED_VIEWOLSISTCONDVENDA.CODSISTEMA     = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPROD_KIT WHERE (PCMED_VIEWOLCONDVENDAPROD_KIT.CODSISTEMA = pi_vCodSistema);
      DELETE FROM PCMED_VIEWOLCONDVENDAPROD_REL WHERE (PCMED_VIEWOLCONDVENDAPROD_REL.CODSISTEMA = pi_vCodSistema);
    END IF;
  
    -- Inicializa Contador de COMMITs
    viContaCommit := 0;
  
   /******************
    Regras Específicas
    ******************/
  
    -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela
    vUSAREGRARECALDESCPTABMED2313 := FUSA_REGRA_MEDICAMENTOS('99',
                                                             'USAREGRARECALDESCPTABMED2313');
    -- Integrar Grupo de Faturamento - DDMEDICA-5069
    vINTEGRARGRUPOFATSERVCON      := FUSA_REGRA_MEDICAMENTOS('99',
                                                             'INTEGRARGRUPOFATSERVCON');
  
   /***********************************************************************************
    DEFINIÇÃO DE PESQUISA DOS CLIENTES (GERAL OU SOMENTE OS CADASTRADOS NA ROTINA 2325)
    ***********************************************************************************/
    BEGIN
      SELECT 'E' -->> Pesquisa Específica de Clientes
        INTO vvTipoPesquisaClientes
        FROM PCCONFIGSISTCLIOPERLOG
       WHERE (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
         AND (ROWNUM                            = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        -->> Pesquisa Geral de Clientes
        vvTipoPesquisaClientes := 'G';
    END;
  
   /*********************************************************************************
    DEFINIÇÃO DE PESQUISA DAS MARCAS (GERAL OU SOMENTE OS CADASTRADOS NA ROTINA 2325)
    *********************************************************************************/
    -->> Pesquisa Geral de Marcas (DEFAULT)
    vvTipoPesquisaMarcas := 'G';
    FOR vc_RestricaoMarca IN (SELECT PCCONFIGSISTMARCAOPERLOG.CODMARCA
                                FROM PCCONFIGSISTMARCAOPERLOG
                               WHERE (PCCONFIGSISTMARCAOPERLOG.CODSISTEMA = pi_vCodSistema)) LOOP
      -- Guarda a Restrição de Marca em Array
      vtRestricaoMarca(vc_RestricaoMarca.CODMARCA) := vc_RestricaoMarca.CODMARCA;
      -->> Pesquisa Específica de Marcas
      vvTipoPesquisaMarcas := 'E';
    END LOOP;
  
  
  
  
  
   /**********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
  
    C A R R E G A   A R R A Y   D E    C O N D I Ç Õ E S   C O M E R C I A I S    (CONDICAO x REGIAO x FILIAL)
  
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************
    **********************************************************************************************************/
  
  
  
  
    vdDataHoraIniTabTempDesc := SYSDATE;
  
   /*//////////////////////////////////////////////////////////////////////////////////////
    ///////////////////////////////////////////////////////////////////////////////////////
    ///////////////////////////////////////////////////////////////////////////////////////
    CARREGA ARRAY COM AS CONDIÇÕES DISTINTAS A PARTIR DA CONDIÇÃO DE VENDA (2311) - SERVCON
    ///////////////////////////////////////////////////////////////////////////////////////
    ///////////////////////////////////////////////////////////////////////////////////////
    //////////////////////////////////////////////////////////////////////////////////////*/
    IF (NVL(vvUsaMultiplasCondVenda,'N') = 'S') THEN
  
      -- Cursor para Carga do Array de Condições Distintas da Rotina 2311
      FOR vc_Dados IN (-- Vinculados aos Clientes da PCCLIENT com a Região da PCTABPR
                       SELECT DISTINCT
                            0 PRIORIDADE
                            , PCCONFIGSISTOPERLOG.CODSISTEMA
                            , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                            , PCCONFIGSISTOPERLOG.INTEGRADORA
                            , PCCONDVENDAFILIAL.CODFILIAL
                            , PCCONDICAOVENDA.NUMREGIAO
                            , PCCONDICAOVENDA.CODCLISTPEDIDOELET
                            , PCCONDICAOVENDA.MULTIPLOSPLPAGPEDIDOELET
                         FROM PCCONDICAOVENDA
                            , PCCONDVENDAFILIAL
                            , PCCONDVENDAINTEGRADORA
                            , PCCONFIGSISTOPERLOG
                            , PCCONFIGSISTFILOPERLOG
                            , PCCLIENT
                            , PCTABPRCLI
                        WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA   = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAINTEGRADORA.INTEGRADORA = PCCONFIGSISTOPERLOG.INTEGRADORA)
                          AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA  = PCCONFIGSISTOPERLOG.CODSISTEMA)
                          AND (PCCONFIGSISTFILOPERLOG.CODFILIAL   = PCCONDVENDAFILIAL.CODFILIAL)
                          AND (PCCONDICAOVENDA.NUMREGIAO          = PCTABPRCLI.NUMREGIAO) -->> Join de Condições associadas à Região POR FILIAL do Cliente
                          AND (PCCLIENT.CODCLI                    = PCTABPRCLI.CODCLI)
                          AND (PCCLIENT.DTEXCLUSAO                IS NULL)
                          AND (PCCONDICAOVENDA.ENVIAPEDIDOELET    = 'S')
                          AND (PCCONFIGSISTOPERLOG.CODSISTEMA     = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                       UNION
                       -- Vinculados aos  Clientes da PCCLIENT com a Região da PCPRACA
                       SELECT DISTINCT
                              0 PRIORIDADE
                            , PCCONFIGSISTOPERLOG.CODSISTEMA
                            , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                            , PCCONFIGSISTOPERLOG.INTEGRADORA
                            , PCCONDVENDAFILIAL.CODFILIAL
                            , PCCONDICAOVENDA.NUMREGIAO
                            , PCCONDICAOVENDA.CODCLISTPEDIDOELET
                            , PCCONDICAOVENDA.MULTIPLOSPLPAGPEDIDOELET
                         FROM PCCONDICAOVENDA
                            , PCCONDVENDAFILIAL
                            , PCCONDVENDAINTEGRADORA
                            , PCCONFIGSISTOPERLOG
                            , PCCONFIGSISTFILOPERLOG
                            , PCCLIENT
                            , PCPRACA
                        WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA   = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAINTEGRADORA.INTEGRADORA = PCCONFIGSISTOPERLOG.INTEGRADORA)
                          AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA  = PCCONFIGSISTOPERLOG.CODSISTEMA)
                          AND (PCCONFIGSISTFILOPERLOG.CODFILIAL   = PCCONDVENDAFILIAL.CODFILIAL)
                          AND (PCPRACA.CODPRACA                   = PCCLIENT.CODPRACA)
                          AND (PCCONDICAOVENDA.NUMREGIAO          = PCPRACA.NUMREGIAO) -->> Join de Condições associadas à Região da PRACA do Cliente
                          AND (PCCLIENT.DTEXCLUSAO                IS NULL)
                          AND (PCCONDICAOVENDA.ENVIAPEDIDOELET    = 'S')
                          AND (PCCONFIGSISTOPERLOG.CODSISTEMA     = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                        ) LOOP
  
        -- Guarda em Lista
        viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
        vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
        vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
        vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
        vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
        vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLISTPEDIDOELET;
        vtCondicoesComerc(viIdxCondCom).vvKit                := 'N';
        vtCondicoesComerc(viIdxCondCom).vvTipoCondicao       := 'C';
        vtCondicoesComerc(viIdxCondCom).vvMultiplosPlPag     := NVL(vc_Dados.MULTIPLOSPLPAGPEDIDOELET,'N');
  
        -- Tabela Temp de Auditoria
        INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                  ( CODSISTEMA
                  , CODCONDICAOVENDA
                  , INTEGRADORA
                  , CODFILIAL
                  , NUMREGIAO
                  , CODCLIST
                  , TIPOCONDICAO )
           VALUES ( pi_vCodSistema
                  , vc_Dados.CODCONDICAOVENDA
                  , vc_Dados.INTEGRADORA
                  , vc_Dados.CODFILIAL
                  , vc_Dados.NUMREGIAO
                  , vc_Dados.CODCLISTPEDIDOELET
                  , 'C' );
  
      END LOOP;
  
   /*+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    -->> SE BUSCA TODAS AS CONDIÇÕES DE VENDA ASSOCIADAS À INTEGRADORA - COTEFACIL
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
    ELSIF (NVL(vvPedidoEletronico,' ') = 'C') THEN
  
      -- Rotina da seleção da Região
      vnRotinaSelecaoRegiao := 2325;
  
      FOR vc_Dados IN (-- Vinculados às Regiões do Sistema
                       SELECT DISTINCT
                              2 PRIORIDADE
                            , PCCONFIGSISTOPERLOG.CODSISTEMA
                            , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                            , PCCONFIGSISTOPERLOG.INTEGRADORA
                            , PCCONDVENDAFILIAL.CODFILIAL
                            , PCCONFIGSISTREGOPERLOG.NUMREGIAO -->> Cotefacil pela Região do Sistema
                            , PCCONFIGSISTREGOPERLOG.CODCLIST  CODCLISTPEDIDOELET -->> Cotefacil pela Região do Sistema
                            , PCCONDICAOVENDA.MULTIPLOSPLPAGPEDIDOELET
                         FROM PCCONDICAOVENDA
                            , PCCONDVENDAFILIAL
                            , PCCONDVENDAINTEGRADORA
                            , PCCONFIGSISTOPERLOG
                            , PCCONFIGSISTFILOPERLOG
                            , PCCONFIGSISTREGOPERLOG -->> Cotefacil pela Região do Sistema
                        WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA   = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
                          AND (PCCONDVENDAINTEGRADORA.INTEGRADORA = PCCONFIGSISTOPERLOG.INTEGRADORA)
                          AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA  = PCCONFIGSISTOPERLOG.CODSISTEMA)
                          AND (PCCONFIGSISTFILOPERLOG.CODFILIAL   = PCCONDVENDAFILIAL.CODFILIAL)
                          AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA  = PCCONFIGSISTOPERLOG.CODSISTEMA)  -->> Cotefacil pela Região do Sistema
                          AND (PCCONFIGSISTREGOPERLOG.CODSISTEMA  = PCCONFIGSISTFILOPERLOG.CODSISTEMA) -->> Cotefacil pela Região do Sistema
                          AND (PCCONFIGSISTREGOPERLOG.CODFILIAL   = PCCONFIGSISTFILOPERLOG.CODFILIAL) -->> Cotefacil pela Região do Sistema
                          AND (PCCONFIGSISTOPERLOG.CODSISTEMA     = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                        ORDER BY 1 -->> Ordenado pela Prioridade
                        ) LOOP
  
        -- Guarda em Lista
        viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
        vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
        vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
        vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
        vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
        vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLISTPEDIDOELET;
        vtCondicoesComerc(viIdxCondCom).vvMultiplosPlPag     := NVL(vc_Dados.MULTIPLOSPLPAGPEDIDOELET,'N');
  
        -- Tabela Temp de Auditoria
        INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                  ( CODSISTEMA
                  , CODCONDICAOVENDA
                  , INTEGRADORA
                  , CODFILIAL
                  , NUMREGIAO
                  , CODCLIST )
           VALUES ( pi_vCodSistema
                  , vc_Dados.CODCONDICAOVENDA
                  , vc_Dados.INTEGRADORA
                  , vc_Dados.CODFILIAL
                  , vc_Dados.NUMREGIAO
                  , vc_Dados.CODCLISTPEDIDOELET );
  
      END LOOP;
  
   /*+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    CARREGA ARRAY COM AS CONDIÇÕES DISTINTAS A PARTIR DA PROMOÇÃO (2323)
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
    ELSIF (NVL(vvUsaMultiplasPromocoes,'N') = 'S') THEN
  
      -- Insere todos os descontos Vigentes para o Força de Vendas na Tabela Temporária (Otimização Performance)
      INSERT INTO PCMED_VIEWOL_PCDESCONTO_TMP
                ( CODDESCONTO
                , CODCLI
                , CODEPTO
                , CODSEC
                , CODCATEGORIA
                , CODPROD
                , PERCDESC
                , DTINICIO
                , DTFIM
                , CODFORNEC
                , NUMREGIAO
                , UF
                , CODATIV
                , ORIGEMPED
                , CODPRACA
                , CODPRODPRINC
                , CLASSEVENDA
                , PERCDESCFIN
                , CODFILIAL
                , CODMARCA
                , CODREDE
                , CODCONDICAOVENDA
                , TIPOFV
                , CODPROMOCAOMED
                , SUBCATEGORIA
                , CODLINHAPROD
                , INICIOINTERVALOPROMOCAOMED
                , FIMINTERVALOPROMOCAOMED
                , PRECOFIXOPROMOCAOMED
                , PERCMARKUPMED )
           SELECT CODDESCONTO
                , CODCLI
                , CODEPTO
                , CODSEC
                , CODCATEGORIA
                , CODPROD
                , PERCDESC
                , DTINICIO
                , DTFIM
                , CODFORNEC
                , NUMREGIAO
                , UF
                , CODATIV
                , ORIGEMPED
                , CODPRACA
                , CODPRODPRINC
                , CLASSEVENDA
                , PERCDESCFIN
                , CODFILIAL
                , CODMARCA
                , CODREDE
                , CODCONDICAOVENDA
                , TIPOFV
                , CODPROMOCAOMED
                , SUBCATEGORIA
                , CODLINHAPROD
                , INICIOINTERVALOPROMOCAOMED
                , FIMINTERVALOPROMOCAOMED
                , PRECOFIXOPROMOCAOMED
                , PERCMARKUPMED
             FROM PCDESCONTO
            WHERE (DTINICIO                   <= TRUNC(SYSDATE)) -->> VIGENTES
              AND (DTFIM                      >= TRUNC(SYSDATE))
              AND (PCDESCONTO.ORIGEMPED        = 'F')            -->> FORÇA DE VENDAS
              AND (NVL(PCDESCONTO.TIPOFV,'FV') = vvTipoFv);      -->> TIPO FV da Integradora
  
      -- Com a Normalização da PCDESCONTO, este INSERT será usado mais como auditoria
      -- para verificar se alguma promoção ainda está desnormalizada
      INSERT INTO PCMED_VIEWOL_PROMOCAOCLI_TMP
                ( CODSISTEMA    ,
                  CODPROMOCAOMED,
                  NUMREGIAO     ,
                  CODCLI        ,
                  CODREDE       ,
                  CODATIV )
           SELECT DISTINCT
                  pi_vCodSistema,
                  CODPROMOCAOMED,
                  NUMREGIAO     ,
                  CODCLI        ,
                  CODREDE       ,
                  CODATIV
            FROM PCMED_VIEWOL_PCDESCONTO_TMP;
  
      vdDataHoraFinTabTempDesc := SYSDATE;
  
      -- Rotina da seleção da Região
      vnRotinaSelecaoRegiao := 2325;
  
      -- Cursor para Carga do Array de Condições Distintas usando a Promoção da Rotina 2323 como Condição de Venda
      -->> PROCESSO SERVCON: RESTRINGE A PROMOÇÕES COM ORIGEM = W - E-COMMERCE
      IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
        FOR vc_Dados IN (-- Vinculados às Regiões da PCCONFIGSISTREGOPERLOG
                         SELECT DISTINCT
                                1 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCPROMOCAOMED.CODPROMOCAOMED CODCONDICAOVENDA -->> A PROMOÇÃO ASSUME A FUNÇÃO DE CONDIÇÃO DE VENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONFIGSISTFILOPERLOG.CODFILIAL
                              , PCCONFIGSISTREGOPERLOG.NUMREGIAO
                              , PCCONFIGSISTREGOPERLOG.CODCLIST
                              , PCPROMOCAOMED.DESCRICAORESUMIDA
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONFIGSISTREGOPERLOG
                              , PCPROMOCAOMED
                              , PCPROMOCAOORIGEMMED
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA     = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA  = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODSISTEMA  = PCCONFIGSISTFILOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODFILIAL   = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCPROMOCAOMED.TIPOPROMOCAO        IN ('C','E','R'))  -->> Somente Promoções de Cliente e Encarte e Markup (Combo/Mix/etc ignorar) - DDMEDICA-5980 - Markup
                            AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')    = 'N')            -->> Bloqueadas não entram
                            AND (PCPROMOCAOORIGEMMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                            AND (PCPROMOCAOORIGEMMED.ORIGEMPED      = vORIGEMPEDVIEWPROMOSERVCON)
                            AND (PKG_FUNCOESVENDAS_MED.F_MED_PODEGERARPROMOCAO(PCPROMOCAOMED.CODPROMOCAOMED,
                                                                               PCCONFIGSISTREGOPERLOG.CODFILIAL,
                                                                               PCCONFIGSISTREGOPERLOG.NUMREGIAO,
                                                                               vORIGEMPODEGERARPROMOCAO, -->> Origem do Pedido
                                                                               NULL,
                                                                               NULL) = 'S')
                            -- Fim: Parte Comum à Carga dos Descontos
                          ORDER BY PCPROMOCAOMED.CODPROMOCAOMED, PCCONFIGSISTREGOPERLOG.NUMREGIAO
                          ) LOOP
  
          -- Guarda em Lista
          viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
          vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
          vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
          vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
          vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
          vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLIST;
          vtCondicoesComerc(viIdxCondCom).vvKit                := 'N';
          vtCondicoesComerc(viIdxCondCom).vvTipoCondicao       := 'P';
  
          -- Tabela Temp de Auditoria
          INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                    ( CODSISTEMA
                    , CODCONDICAOVENDA
                    , INTEGRADORA
                    , CODFILIAL
                    , NUMREGIAO
                    , CODCLIST
                    , TIPOCONDICAO )
             VALUES ( pi_vCodSistema
                    , vc_Dados.CODCONDICAOVENDA
                    , vc_Dados.INTEGRADORA
                    , vc_Dados.CODFILIAL
                    , vc_Dados.NUMREGIAO
                    , vc_Dados.CODCLIST
                    , 'P' );
  
        END LOOP; -- FIM LAÇO CONDIÇÕES - INTEGRADORA WINTHOR
      ELSE
        FOR vc_Dados IN (-- Vinculados às Regiões da PCCONFIGSISTREGOPERLOG
                         SELECT DISTINCT
                                1 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCPROMOCAOMED.CODPROMOCAOMED CODCONDICAOVENDA -->> A PROMOÇÃO ASSUME A FUNÇÃO DE CONDIÇÃO DE VENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONFIGSISTFILOPERLOG.CODFILIAL
                              , PCCONFIGSISTREGOPERLOG.NUMREGIAO
                              , PCCONFIGSISTREGOPERLOG.CODCLIST
                              , PCPROMOCAOMED.DESCRICAORESUMIDA
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONFIGSISTREGOPERLOG
                              , PCPROMOCAOMED
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA    = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODSISTEMA = PCCONFIGSISTFILOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODFILIAL  = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCPROMOCAOMED.TIPOPROMOCAO       IN ('C','E','R'))  -->> Somente Promoções de Cliente e Encarte e Markup (Combo/Mix/etc ignorar) -- DDMEDICA-5980 - Markup
                            AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')   = 'N')            -->> Bloqueadas não entram
                            AND (PKG_FUNCOESVENDAS_MED.F_MED_PODEGERARPROMOCAO(PCPROMOCAOMED.CODPROMOCAOMED,
                                                                               PCCONFIGSISTREGOPERLOG.CODFILIAL,
                                                                               PCCONFIGSISTREGOPERLOG.NUMREGIAO,
                                                                               vORIGEMPODEGERARPROMOCAO, -->> Origem do Pedido
                                                                               NULL,
                                                                               NULL) = 'S')
                            -- Fim: Parte Comum à Carga dos Descontos
                          ORDER BY PCPROMOCAOMED.CODPROMOCAOMED, PCCONFIGSISTREGOPERLOG.NUMREGIAO
                          ) LOOP
  
          -- Guarda em Lista
          viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
          vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
          vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
          vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
          vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
          vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLIST;
          vtCondicoesComerc(viIdxCondCom).vvKit                := 'N';
          vtCondicoesComerc(viIdxCondCom).vvTipoCondicao       := 'P';
  
          -- Tabela Temp de Auditoria
          INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                    ( CODSISTEMA
                    , CODCONDICAOVENDA
                    , INTEGRADORA
                    , CODFILIAL
                    , NUMREGIAO
                    , CODCLIST
                    , TIPOCONDICAO )
             VALUES ( pi_vCodSistema
                    , vc_Dados.CODCONDICAOVENDA
                    , vc_Dados.INTEGRADORA
                    , vc_Dados.CODFILIAL
                    , vc_Dados.NUMREGIAO
                    , vc_Dados.CODCLIST
                    , 'P' );
  
        END LOOP; -- FIM LAÇO CONDIÇÕES - INTEGRADORA WINTHOR
      END IF;
  
   /*#################################################################################################
    ##################################################################################################
    ##################################################################################################
    CARREGA ARRAY COM AS CONDIÇÕES DISTINTAS A PARTIR DA CONDIÇÃO DE VENDA (2311) - OPERADOR LOGISTICO
    ##################################################################################################
    ##################################################################################################
    #################################################################################################*/
    ELSE
  
      -- DICIONÁRIO POR REGIÃO
      IF (vbGeraDicionarioPorRegiao) THEN
  
        -- Rotina da seleção da Região
        vnRotinaSelecaoRegiao := 2325;
  
        FOR vc_Dados IN (-- Vinculados aos Clientes da PCCLIENT
                         SELECT DISTINCT
                                1 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONDVENDAFILIAL.CODFILIAL
                              , PCCONFIGSISTREGOPERLOG.NUMREGIAO
                              , PCCONFIGSISTREGOPERLOG.CODCLIST
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONFIGSISTREGOPERLOG
                              , PCCONDVENDAFILIAL
                              , PCCONDICAOVENDA
                              , PCCONDVENDAINTEGRADORA
                              , PCCLIENT
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODFILIAL        = PCCONFIGSISTFILOPERLOG.CODFILIAL) -->> VINCULO DA FILIAL INFORMADA NA REGIAO COM A FILIAL INFORMADA NAS FILIAIS
                            AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA      = PCCONFIGSISTFILOPERLOG.CODCONDICAOVENDA)
                            AND (PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAFILIAL.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDICAOVENDA.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
                            AND (PCCLIENT.DTEXCLUSAO                     IS NULL)
                            AND (vvTipoPesquisaClientes                   = 'G') -->> Pesquisa Geral de Clientes
                         UNION
                         -- Vinculados aos Clientes da PCCONFIGSISTCLIOPERLOG
                         SELECT DISTINCT
                                2 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONDVENDAFILIAL.CODFILIAL
                              , PCCONFIGSISTREGOPERLOG.NUMREGIAO
                              , PCCONFIGSISTREGOPERLOG.CODCLIST
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONFIGSISTREGOPERLOG
                              , PCCONDVENDAFILIAL
                              , PCCONDICAOVENDA
                              , PCCONDVENDAINTEGRADORA
                              , PCCLIENT
                              , PCCONFIGSISTCLIOPERLOG
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONFIGSISTREGOPERLOG.CODFILIAL        = PCCONFIGSISTFILOPERLOG.CODFILIAL) -->> VINCULO DA FILIAL INFORMADA NA REGIAO COM A FILIAL INFORMADA NAS FILIAIS
                            AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA      = PCCONFIGSISTFILOPERLOG.CODCONDICAOVENDA)
                            AND (PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAFILIAL.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDICAOVENDA.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
                            AND (PCCLIENT.DTEXCLUSAO                     IS NULL)
                            AND (vvTipoPesquisaClientes                  = 'E')                            -->> Pesquisa Específica de Clientes
                            AND (PCCONFIGSISTCLIOPERLOG.CODCLI           = PCCLIENT.CODCLI)                -->> Pesquisa Específica de Clientes
                            AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA) -->> Pesquisa Específica de Clientes
                          ORDER BY 1 -->> Ordenado pela Prioridade
                          ) LOOP
  
          -- Guarda em Lista
          viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
          vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
          vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
          vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
          vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
          vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLIST;
          vtCondicoesComerc(viIdxCondCom).vvKit                := 'N';
          vtCondicoesComerc(viIdxCondCom).vvTipoCondicao       := 'C';
  
          -- Tabela Temp de Auditoria
          INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                    ( CODSISTEMA
                    , CODCONDICAOVENDA
                    , INTEGRADORA
                    , CODFILIAL
                    , NUMREGIAO
                    , CODCLIST
                    , TIPOCONDICAO )
             VALUES ( pi_vCodSistema
                    , vc_Dados.CODCONDICAOVENDA
                    , vc_Dados.INTEGRADORA
                    , vc_Dados.CODFILIAL
                    , vc_Dados.NUMREGIAO
                    , vc_Dados.CODCLIST
                    , 'C' );
        END LOOP;
  
      -- DICIONÁRIOS SEM QUEBRA DE REGIÃO
      ELSE
  
        FOR vc_Dados IN (-- Vinculados aos Clientes da PCCLIENT
                         SELECT DISTINCT
                                1 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONDVENDAFILIAL.CODFILIAL
                              , NVL(vnNumRegiaoIntegradora, (SELECT PCPARAMFILIAL.VALOR FROM PCPARAMFILIAL WHERE (PCPARAMFILIAL.CODFILIAL = PCCONDVENDAFILIAL.CODFILIAL) AND (PCPARAMFILIAL.NOME = 'FIL_NUMREGIAOPADRAO'))) NUMREGIAO
                              , (SELECT PCFILIAL.CODCLI     FROM PCFILIAL      WHERE (PCFILIAL.CODIGO = PCCONDVENDAFILIAL.CODFILIAL)) CODCLISTPEDIDOELET
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONDVENDAFILIAL
                              , PCCONDICAOVENDA
                              , PCCONDVENDAINTEGRADORA
                              , PCCLIENT
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA      = PCCONFIGSISTFILOPERLOG.CODCONDICAOVENDA)
                            AND (PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAFILIAL.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDICAOVENDA.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
                            AND (PCCLIENT.DTEXCLUSAO                     IS NULL)
                            AND (vvTipoPesquisaClientes                   = 'G') -->> Pesquisa Geral de Clientes
                         UNION
                         -- Vinculados aos Clientes da PCCONFIGSISTCLIOPERLOG
                         SELECT DISTINCT
                                2 PRIORIDADE
                              , PCCONFIGSISTOPERLOG.CODSISTEMA
                              , PCCONDVENDAFILIAL.CODCONDICAOVENDA
                              , PCCONFIGSISTOPERLOG.INTEGRADORA
                              , PCCONDVENDAFILIAL.CODFILIAL
                              , NVL(vnNumRegiaoIntegradora, (SELECT PCPARAMFILIAL.VALOR FROM PCPARAMFILIAL WHERE (PCPARAMFILIAL.CODFILIAL = PCCONDVENDAFILIAL.CODFILIAL) AND (PCPARAMFILIAL.NOME = 'FIL_NUMREGIAOPADRAO'))) NUMREGIAO
                              , (SELECT PCFILIAL.CODCLI     FROM PCFILIAL      WHERE (PCFILIAL.CODIGO = PCCONDVENDAFILIAL.CODFILIAL)) CODCLISTPEDIDOELET
                           FROM PCCONFIGSISTOPERLOG
                              , PCCONFIGSISTFILOPERLOG
                              , PCCONDVENDAFILIAL
                              , PCCONDICAOVENDA
                              , PCCONDVENDAINTEGRADORA
                              , PCCLIENT
                              , PCCONFIGSISTCLIOPERLOG
                          WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema) -->> SISTEMA PASSADO NO PARÂMETRO
                            AND (PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA)
                            AND (PCCONDVENDAFILIAL.CODCONDICAOVENDA      = PCCONFIGSISTFILOPERLOG.CODCONDICAOVENDA)
                            AND (PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL)
                            AND (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAFILIAL.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDICAOVENDA.CODCONDICAOVENDA)
                            AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
                            AND (PCCLIENT.DTEXCLUSAO                     IS NULL)
                            AND (vvTipoPesquisaClientes                  = 'E')                            -->> Pesquisa Específica de Clientes
                            AND (PCCONFIGSISTCLIOPERLOG.CODCLI           = PCCLIENT.CODCLI)                -->> Pesquisa Específica de Clientes
                            AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA) -->> Pesquisa Específica de Clientes
                          ORDER BY 1 -->> Ordenado pela Prioridade
                          ) LOOP
  
          -- Guarda em Lista
          viIdxCondCom := NVL(vtCondicoesComerc.COUNT,0) + 1;
          vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda   := vc_Dados.CODCONDICAOVENDA;
          vtCondicoesComerc(viIdxCondCom).vnIntegradora        := vc_Dados.INTEGRADORA;
          vtCondicoesComerc(viIdxCondCom).vvCodFilial          := vc_Dados.CODFILIAL;
          vtCondicoesComerc(viIdxCondCom).vnNumRegiao          := vc_Dados.NUMREGIAO;
          vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet := vc_Dados.CODCLISTPEDIDOELET;
          vtCondicoesComerc(viIdxCondCom).vvKit                := 'N';
          vtCondicoesComerc(viIdxCondCom).vvTipoCondicao       := 'C';
  
          -- Tabela Temp de Auditoria
          INSERT INTO PCMED_VIEWOLCONDICOESCOMERC_TM
                    ( CODSISTEMA
                    , CODCONDICAOVENDA
                    , INTEGRADORA
                    , CODFILIAL
                    , NUMREGIAO
                    , CODCLIST
                    , TIPOCONDICAO )
             VALUES ( pi_vCodSistema
                    , vc_Dados.CODCONDICAOVENDA
                    , vc_Dados.INTEGRADORA
                    , vc_Dados.CODFILIAL
                    , vc_Dados.NUMREGIAO
                    , vc_Dados.CODCLISTPEDIDOELET
                    , 'C' );
        END LOOP;
  
      END IF; -- FIM CONDIÇÃO SE GERA DICIONÁRIO POR REGIÃO
  
    END IF; -- FIM CONDIÇÃO PARA GERAÇÃO DE ARRAY COM CONDIÇÕES DISTINTAS CONFORME 2311 ou 2323 ou Operador Logístico
  
    vdDataHoraFinCondicoesComerc := SYSDATE;
  
  
  
  
  
  
  
   /************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
                           C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S
               C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S   x   C O N D I C O E S
                                       E S P E C I F I C O    S E R V C O N
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************/
    IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
  
      -- Restrições de Clientes e Redes em Promoções
      INSERT INTO PCMED_VIEWOLCONDVENDACLIREST_T
                ( CODSISTEMA
                , CODCONDICAOVENDA
                , CODCLI )
           SELECT pi_vCodSistema
                , PCPROMOCAOREDEMED.CODPROMOCAOMED
                , PCCLIENT.CODCLI
             FROM PCCLIENT
                , PCPROMOCAOREDEMED
            WHERE PCCLIENT.CODREDE = PCPROMOCAOREDEMED.CODREDE
            UNION
           SELECT pi_vCodSistema
                , PCPROMOCAOCLIMED.CODPROMOCAOMED
                , PCCLIENT.CODCLI
             FROM PCCLIENT
                , PCPROMOCAOCLIMED
            WHERE PCCLIENT.CODCLI = PCPROMOCAOCLIMED.CODCLI
            UNION
           SELECT pi_vCodSistema
                , PCPROMOCAOCLASSEVENDAMED.CODPROMOCAOMED
                , PCCLIENT.CODCLI
             FROM PCCLIENT
                , PCPROMOCAOCLASSEVENDAMED
            WHERE PCCLIENT.CLASSEVENDA = PCPROMOCAOCLASSEVENDAMED.CLASSEVENDA;
  
  
      -- Insere Clientes e Condições (PROMOÇÕES) que podem ser utilizadas pelo Cliente pela PCTABPRCLI
      INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                ( CODSISTEMA
                , NUMREGIAO
                , CODCONDICAOVENDA
                , CODCLI
                , CODPLPAG )
           SELECT DISTINCT
                  pi_vCodSistema
                , PCPROMOCAOREGIAOMED.NUMREGIAO
                , PCPROMOCAOREGIAOMED.CODPROMOCAOMED
                , PCCLIENT.CODCLI
                , CASE WHEN (NVL(PCCLIENT.UTILIZAPLPAGMEDICAMENTO,'N') = 'S')  THEN
                    -- Se utilizar Plano Etico e Generico, envia como Plano que o cliente pode alterar o Plano Genérico (O Ético será fixo - o do Cliente)
                    PCCLIENT.CODPLPAGGENERICO
                  ELSE
                    PCCLIENT.CODPLPAG
                  END CODPLPAG
             FROM PCCLIENT
                , PCTABPRCLI
                , PCPROMOCAOMED
                , PCPROMOCAOORIGEMMED
                , PCPROMOCAOFILMED
                , PCPROMOCAOREGIAOMED
            WHERE (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOORIGEMMED.CODPROMOCAOMED)
              AND (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOFILMED.CODPROMOCAOMED)
              AND (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOREGIAOMED.CODPROMOCAOMED)
              AND (PCPROMOCAOORIGEMMED.ORIGEMPED              = vORIGEMPEDVIEWPROMOSERVCON) -->> Promoções Liberadas para o SERVCON
              AND (PCTABPRCLI.CODFILIALNF                     = PCPROMOCAOFILMED.CODFILIAL)
              AND (PCTABPRCLI.NUMREGIAO                       = PCPROMOCAOREGIAOMED.NUMREGIAO)
              AND (PCTABPRCLI.CODCLI                          = PCCLIENT.CODCLI)
              AND (PCCLIENT.DTEXCLUSAO                       IS NULL)
              AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
              AND (NVL(PCPROMOCAOMED.USANORMALIZACAODESC,'N') = 'S');
  
      -- Insere Clientes e Condições (PROMOÇÕES) que podem ser utilizadas pelo Cliente pela PCPRACA
      INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                ( CODSISTEMA
                , NUMREGIAO
                , CODCONDICAOVENDA
                , CODCLI
                , CODPLPAG )
           SELECT DISTINCT
                  pi_vCodSistema
                , PCPROMOCAOREGIAOMED.NUMREGIAO
                , PCPROMOCAOREGIAOMED.CODPROMOCAOMED
                , PCCLIENT.CODCLI
                , CASE WHEN (NVL(PCCLIENT.UTILIZAPLPAGMEDICAMENTO,'N') = 'S')  THEN
                    -- Se utilizar Plano Etico e Generico, envia como Plano que o cliente pode alterar o Plano Genérico (O Ético será fixo - o do Cliente)
                    PCCLIENT.CODPLPAGGENERICO
                  ELSE
                    PCCLIENT.CODPLPAG
                  END CODPLPAG
             FROM PCCLIENT
                , PCPRACA
                , PCPROMOCAOMED
                , PCPROMOCAOORIGEMMED
                , PCPROMOCAOFILMED
                , PCPROMOCAOREGIAOMED
            WHERE (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOORIGEMMED.CODPROMOCAOMED)
              AND (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOFILMED.CODPROMOCAOMED)
              AND (PCPROMOCAOMED.CODPROMOCAOMED               = PCPROMOCAOREGIAOMED.CODPROMOCAOMED)
              AND (PCPROMOCAOORIGEMMED.ORIGEMPED              = vORIGEMPEDVIEWPROMOSERVCON) -->> Promoções Liberadas para o SERVCON
              AND (PCPRACA.CODPRACA                           = PCCLIENT.CODPRACA)
              AND (PCPROMOCAOREGIAOMED.NUMREGIAO              = PCPRACA.NUMREGIAO)
              AND (NVL(PCPROMOCAOMED.USANORMALIZACAODESC,'N') = 'S')
              AND (PCCLIENT.DTEXCLUSAO                       IS NULL)
              AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
              AND (NOT EXISTS (SELECT 'S'
                                 FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                  AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = PCPROMOCAOMED.CODPROMOCAOMED
                                  AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Diferente do Servcon, posso ter mais de uma região para a mesma condição comercial (Promoção), não afeta os Unions (usei distinct na View)
  
      -- Insere Clientes associados ao Sistema pela PCPRACA ou PCTABPRCLI
      INSERT INTO PCMED_VIEWOLCLI_TMP
                ( CODSISTEMA
                , CODCLI )
           SELECT DISTINCT
                  pi_vCodSistema
                , PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI
             FROM PCMED_VIEWOLCONDVENDACLI_TMP;
  
      -- Remove Clientes que não estão na Restrição de Clientes ou Redes da Promoção
      DELETE FROM PCMED_VIEWOLCONDVENDACLI_TMP
            WHERE (PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA IN (SELECT PCMED_VIEWOLCONDVENDACLIREST_T.CODCONDICAOVENDA FROM PCMED_VIEWOLCONDVENDACLIREST_T))
              AND (NOT EXISTS (SELECT 'S'
                                 FROM PCMED_VIEWOLCONDVENDACLIREST_T
                                WHERE (PCMED_VIEWOLCONDVENDACLIREST_T.CODSISTEMA       = PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA)
                                  AND (PCMED_VIEWOLCONDVENDACLIREST_T.CODCONDICAOVENDA = PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA)
                                  AND (PCMED_VIEWOLCONDVENDACLIREST_T.CODCLI           = PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI)));
  
    END IF;
  
  
  
  
  
  
   /************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
                           C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S
               C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S   x   C O N D I C O E S
    C A R R E G A   A R R A Y   D E    C O N D I Ç Õ E S   D E F I N I T I V A    (CONDICAO x REGIAO x FILIAL x PLANO PAGTO)
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************
    ************************************************************************************************************************/
  
  
  
  
  
    vdDataHoraIniGerClientes := SYSDATE;
  
    IF (vtCondicoesComerc.COUNT > 0) THEN
      FOR viIdxCondCom IN vtCondicoesComerc.FIRST..vtCondicoesComerc.LAST LOOP
  
        -- Guarda Valores do Array no Record
        vrCondicoesComerc.vnCodCondicaoVenda   := vtCondicoesComerc(viIdxCondCom).vnCodCondicaoVenda;
        vrCondicoesComerc.vnIntegradora        := vtCondicoesComerc(viIdxCondCom).vnIntegradora;
        vrCondicoesComerc.vvCodFilial          := vtCondicoesComerc(viIdxCondCom).vvCodFilial;
        vrCondicoesComerc.vnNumRegiao          := vtCondicoesComerc(viIdxCondCom).vnNumRegiao;
        vrCondicoesComerc.vnCodCliStPedidoElet := vtCondicoesComerc(viIdxCondCom).vnCodCliStPedidoElet;
        vrCondicoesComerc.vvKit                := vtCondicoesComerc(viIdxCondCom).vvKit;
        vrCondicoesComerc.vvTipoCondicao       := vtCondicoesComerc(viIdxCondCom).vvTipoCondicao;
        vrCondicoesComerc.vvMultiplosPlPag     := vtCondicoesComerc(viIdxCondCom).vvMultiplosPlPag;
  
        -- Pesquisa UF da Região
        BEGIN
          SELECT PCREGIAO.UF
            INTO vrCondicoesComerc.vvUfRegiao
            FROM PCREGIAO
           WHERE (PCREGIAO.NUMREGIAO = vrCondicoesComerc.vnNumRegiao);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrCondicoesComerc.vvUfRegiao := NULL;
        END;
  
        -- Chama Procedimento que Valida a Condição de Venda
        --VALIDACONDICAOVENDA(vc_Dados.CODCLI,
        --                    vrCondicoesComerc.vnIntegradora,
        --                    'I',  -- TIPOSELECAOCONDICAO = INTEGRAÇÃO DE CONDIÇÃO DE VENDA
        --                    NULL, -- TIPOPRAZO
        --                    vtCondicoesComerc(viIdxCondCom).vvCodFilial,
        --                    NULL, -- PRAZO
        --                    NULL, -- P_CODPRAZO
        --                    NULL, -- P_CODIGOPROJETO
        --                    vrCondicoesComerc.vnCodCondicaoVenda,
        --                    vnCodCondicaoVendaValida,
        --                    vvMsgRetValidaCondVenda);
        -- Por questões de performance, adotou-se que as Condições Válidas para o Cliente são aquelas que estão cadastradas com a Região do Cliente
        vnCodCondicaoVendaValida := NVL(vrCondicoesComerc.vnCodCondicaoVenda,0);
  
        -- Se a Condição de Venda é Válida para o Cliente
        IF (NVL(vnCodCondicaoVendaValida,0) = NVL(vrCondicoesComerc.vnCodCondicaoVenda,0)) THEN
  
          -- Se informou a Região
          IF (NVL(vrCondicoesComerc.vnNumRegiao,0) > 0) THEN
  
            ---------------------------------------------------
            -- Pesquisa Plano de Pagamento da Condição de Venda
            ---------------------------------------------------
            FOR vc_PlanoCondicao IN (SELECT PCCONDVENDALINHA.CODLINHAPRAZO
                                          , NVL(PCCONDVENDALINHA.CODPLPAG,0) CODPLPAG
                                          , NVL(PCCONDICAOVENDA.TIPOPLPAG,1) TIPOPLPAG
                                       FROM PCCONDVENDALINHA
                                          , PCCONDICAOVENDA
                                      WHERE (PCCONDVENDALINHA.CODCONDICAOVENDA = vnCodCondicaoVendaValida)
                                        AND (PCCONDICAOVENDA.CODCONDICAOVENDA  = PCCONDVENDALINHA.CODCONDICAOVENDA)
                                      ORDER BY PCCONDVENDALINHA.CODLINHAPRAZO) LOOP
              -- Pega a primeira linha e sai
              vnCodPlPag  := vc_PlanoCondicao.CODPLPAG;
              vnTipoPlPag := vc_PlanoCondicao.TIPOPLPAG;
              EXIT;
            END LOOP;
  
            -- Se a Condição de Venda estiver parametrizada para buscar o Plano do Cliente
            IF (NVL(vnTipoPlPag,0) = 2) THEN
              -- Zera o Plano de Pagamento da Condiçao de Venda a associar ao Cliente, forçará a ir buscar do Cliente mais abaixo
              vnCodPlPagCondicaoVenda := NULL;
              vnCodPlPag              := NULL;
            ELSE
              vnCodPlPagCondicaoVenda := vnCodPlPag;
            END IF;
  
            -- Pesquisa Prazo Médio
            BEGIN
              SELECT NVL(PCPLPAG.NUMDIAS,0)
                INTO vnPrazoMedioPlPag
                FROM PCPLPAG
               WHERE (PCPLPAG.CODPLPAG = vnCodPlPag);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnPrazoMedioPlPag := 0;
            END;
  
  
  
  
           /************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
                                                              P A R T E   1
                                                              -------------
                                   C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S
                       C A R R E G A   A   T A B E L A   T E M P.   D E   C L I E N T E S   x   C O N D I C O E S
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************/
            -->> Se Processo Específico Servcon NÃO ENTRA
            IF (NVL(vvUsaMultiplasCondVenda,'N') <> 'P') THEN
  
  
  
  
             /*///////////////////////////////////////////////////////////////////////////////////////////////////////
              ////////////////////////////////////////////////////////////////////////////////////////////////////////
              ////////////////////////////////////////////////////////////////////////////////////////////////////////
              CARGA DA TABELA DE CLIENTES E DA TABELA DE CLIENTES QUE PODEM COMPRAR DA CONDIÇÃO DE VENDA (ROTINA 2311)
              ////////////////////////////////////////////////////////////////////////////////////////////////////////
              ////////////////////////////////////////////////////////////////////////////////////////////////////////
              //////////////////////////////////////////////////////////////////////////////////////////////////////*/
              IF (NVL(vvUsaMultiplasCondVenda,'N') = 'S') THEN
  
               /*----------------------------------------------------------------------------------------
                Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- Insere Clientes associados à Região pela PCTABPRCLI
                INSERT INTO PCMED_VIEWOLCLI_TMP
                          ( CODSISTEMA
                          , CODCLI )
                     SELECT DISTINCT
                            pi_vCodSistema
                          , PCTABPRCLI.CODCLI
                       FROM PCTABPRCLI
                      WHERE (PCTABPRCLI.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                        AND (NOT EXISTS (SELECT 'S'
                                           FROM PCMED_VIEWOLCLI_TMP
                                          WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                            AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCTABPRCLI.CODCLI));
  
                -- Insere Clientes associados à Região pela PCPRACA
                INSERT INTO PCMED_VIEWOLCLI_TMP
                          ( CODSISTEMA
                          , CODCLI )
                     SELECT pi_vCodSistema
                          , PCCLIENT.CODCLI
                       FROM PCCLIENT
                          , PCPRACA
                      WHERE (PCPRACA.CODPRACA  = PCCLIENT.CODPRACA)
                        AND (PCPRACA.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                        AND (NOT EXISTS (SELECT 'S'
                                           FROM PCMED_VIEWOLCLI_TMP
                                          WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                            AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
  
               /*----------------------------------------------------------------------------------------
                Condições de Venda x Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- Se a Condição de Venda utiliza Múltiplos Planos de Pagamento -------------------------
                IF (NVL(vrCondicoesComerc.vvMultiplosPlPag,'N') = 'S') THEN
  
                  -- Insere Clientes e Condições associadas à Região pela PCTABPRCLI
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT DISTINCT -->> IMPORTANTE: Distinct porque pode ter mais de uma Filial para a mesma Região e Cliente
                              pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCTABPRCLI.CODCLI
                            , PCPLPAG_LINHAPLPAG.CODPLPAG
                         FROM PCCLIENT
                            , PCTABPRCLI
                            , PCPLPAG PCPLPAG_CLIENTE
                            , PCCONDVENDALINHAPLPAG
                            , PCPLPAG PCPLPAG_LINHAPLPAG
                        WHERE (PCTABPRCLI.CODCLI                      = PCCLIENT.CODCLI)
                          AND (PCTABPRCLI.NUMREGIAO                   = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG_CLIENTE.CODPLPAG               = DECODE(NVL(PCCLIENT.UTILIZAPLPAGMEDICAMENTO,'N'),'S',PCCLIENT.CODPLPAGGENERICO,PCCLIENT.CODPLPAG)) -->> Usar como referência o Plano Genérico se usar Grupo Faturamento
                          AND (PCCONDVENDALINHAPLPAG.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                          AND (PCPLPAG_LINHAPLPAG.CODPLPAG            = PCCONDVENDALINHAPLPAG.CODPLPAG)
                          AND (PCPLPAG_CLIENTE.NUMDIAS               >= PCPLPAG_LINHAPLPAG.NUMDIAS) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio dos Multiplos Planos
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCTABPRCLI.CODCLI
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODPLPAG         = PCPLPAG_LINHAPLPAG.CODPLPAG)); -->> IMPORTANTE: PRECISEI IGNORAR NESTE CASO A REGRA: "Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs"
  
                  -- Insere Clientes e Condições associadas à Região pela PCPRACA
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT DISTINCT -->> IMPORTANTE: Distinct porque são múltiplos planos de pagamento e podemos ter várias linhas de prazo
                              pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCCLIENT.CODCLI
                            , PCPLPAG_LINHAPLPAG.CODPLPAG
                         FROM PCCLIENT
                            , PCPRACA
                            , PCPLPAG PCPLPAG_CLIENTE
                            , PCCONDVENDALINHAPLPAG
                            , PCPLPAG PCPLPAG_LINHAPLPAG
                        WHERE (PCPRACA.CODPRACA                       = PCCLIENT.CODPRACA)
                          AND (PCPRACA.NUMREGIAO                      = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG_CLIENTE.CODPLPAG               = DECODE(NVL(PCCLIENT.UTILIZAPLPAGMEDICAMENTO,'N'),'S',PCCLIENT.CODPLPAGGENERICO,PCCLIENT.CODPLPAG)) -->> Usar como referência o Plano Genérico se usar Grupo Faturamento
                          AND (PCCONDVENDALINHAPLPAG.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                          AND (PCPLPAG_LINHAPLPAG.CODPLPAG            = PCCONDVENDALINHAPLPAG.CODPLPAG)
                          AND (PCPLPAG_CLIENTE.NUMDIAS               >= PCPLPAG_LINHAPLPAG.NUMDIAS) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio dos Multiplos Planos
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODPLPAG         = PCPLPAG_LINHAPLPAG.CODPLPAG)); -->> IMPORTANTE: PRECISEI IGNORAR NESTE CASO A REGRA: "Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs"
  
                -- Se a Condição de Venda NÃO utiliza Múltiplos Planos de Pagamento ---------------------
                ELSE
  
                  -- Insere Clientes e Condições associadas à Região pela PCTABPRCLI
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT DISTINCT -->> IMPORTANTE: Distinct porque pode ter mais de uma Filial para a mesma Região e Cliente
                              pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCTABPRCLI.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCTABPRCLI
                            , PCPLPAG
                        WHERE (PCTABPRCLI.CODCLI    = PCCLIENT.CODCLI)
                          AND (PCTABPRCLI.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG     = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS     >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCTABPRCLI.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                  -- Insere Clientes e Condições associadas à Região pela PCPRACA
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCCLIENT.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCPRACA
                            , PCPLPAG
                        WHERE (PCPRACA.CODPRACA  = PCCLIENT.CODPRACA)
                          AND (PCPRACA.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG  = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                END IF;
  
                ------------------------------------------
                -- RESTRIÇÃO POR REDE NA CONDIÇÃO DE VENDA
                ------------------------------------------
  
                -- Verifica se Existem Restrições na Condição de Venda
                BEGIN
                   SELECT 'S'
                     INTO vvExisteRestrCondVenda
                     FROM PCCONDVENDABLOQRESTR
                    WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                      AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'R')
                    AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     IN ('1','2','3','7')) -->> Cliente/Rede de Clientes/UF/Praça
                      AND (ROWNUM                                = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvExisteRestrCondVenda := 'N';
                END;
                -- Se Existe Restrições por Rede na Condição de Venda
                IF (NVL(vvExisteRestrCondVenda,'N') = 'S') THEN
                  -- Exclui da Tabela Temporária os Clientes que não pertencem às Restrições de Cliente/Rede na Condição de Venda
                  DELETE FROM PCMED_VIEWOLCONDVENDACLI_TMP
                   WHERE (CODSISTEMA       = pi_vCodSistema)
                     AND (CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda) -->> Condição de Venda do Laço
                     AND (CODCLI             NOT IN (SELECT CODCLI
                                                       FROM PCCLIENT
                                                    WHERE (PCCLIENT.CODCLI  IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                                  FROM PCCONDVENDABLOQRESTR
                                                                                 WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'R')
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '1'))) -->> Clientes
                                                       OR (PCCLIENT.CODREDE IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                                  FROM PCCONDVENDABLOQRESTR
                                                                                 WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'R')
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '2'))) -->> Rede de Clientes
                                                       OR (PCCLIENT.ESTENT  IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                                  FROM PCCONDVENDABLOQRESTR
                                                                                 WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'R')
                                                                                   AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '3'))) -->> UF
                                                       OR (PCCLIENT.CODPRACA IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                                   FROM PCCONDVENDABLOQRESTR
                                                                                  WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                                    AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'R')
                                                                                    AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '7'))) -->> PRACA
                                                                                   )); 
                END IF;
  
                --------------------------------------------------------
                -- BLOQUEIO POR REDE NA CONDIÇÃO DE VENDA - DDMEDICA-944
                --------------------------------------------------------
  
                -- Verifica se Existem Bloqueios na Condição de Venda
                BEGIN
                   SELECT 'S'
                     INTO vvExisteRestrCondVenda
                     FROM PCCONDVENDABLOQRESTR
                    WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                      AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'B')
                      AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     IN ('1','2','3','7')) -->> Cliente/Rede de Clientes/UF/Praça
                      AND (ROWNUM                                = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvExisteRestrCondVenda := 'N';
                END;
                -- Se Existe Bloqueios por Rede na Condição de Venda
                IF (NVL(vvExisteRestrCondVenda,'N') = 'S') THEN
                  -- Exclui da Tabela Temporária os Clientes que não pertencem aos Bloqueios de Cliente/Rede na Condição de Venda
                  DELETE FROM PCMED_VIEWOLCONDVENDACLI_TMP
                   WHERE (CODSISTEMA       = pi_vCodSistema)
                     AND (CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda) -->> Condição de Venda do Laço
                     AND (CODCLI           IN (SELECT CODCLI
                                                 FROM PCCLIENT
                                                WHERE (PCCLIENT.CODCLI  IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                              FROM PCCONDVENDABLOQRESTR
                                                                             WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'B')
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '1'))) -->> Clientes
                                                   OR (PCCLIENT.CODREDE IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                              FROM PCCONDVENDABLOQRESTR
                                                                             WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'B')
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '2'))) -->> Rede de Clientes
                                                   OR (PCCLIENT.ESTENT  IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                              FROM PCCONDVENDABLOQRESTR
                                                                             WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'B')
                                                                               AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '3'))) -->> UF
                                                   OR (PCCLIENT.CODPRACA IN (SELECT PCCONDVENDABLOQRESTR.CODUNIVERSO
                                                                               FROM PCCONDVENDABLOQRESTR
                                                                              WHERE (PCCONDVENDABLOQRESTR.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda)
                                                                                AND (PCCONDVENDABLOQRESTR.TIPOEVENTO       = 'B')
                                                                                AND (PCCONDVENDABLOQRESTR.TIPOUNIVERSO     = '7'))) -->> PRACA
                                                                               )); 
                END IF;
  
             /*++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
              +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
              +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
              CARGA DA TABELA DE CLIENTES E DA TABELA DE CLIENTES QUE PODEM COMPRAR DA CONDIÇÃO (PROMOÇÕES DA 2323)
              +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
              +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
              ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++*/
              ELSIF (NVL(vvUsaMultiplasPromocoes,'N') = 'S') THEN
  
               /*----------------------------------------------------------------------------------------
                Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- Insere Clientes associados à Região pela PCTABPRCLI
                INSERT INTO PCMED_VIEWOLCLI_TMP
                          ( CODSISTEMA
                          , CODCLI )
                     SELECT DISTINCT
                            pi_vCodSistema
                          , PCTABPRCLI.CODCLI
                       FROM PCTABPRCLI
                      WHERE (PCTABPRCLI.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                        AND (NOT EXISTS (SELECT 'S'
                                           FROM PCMED_VIEWOLCLI_TMP
                                          WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                            AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCTABPRCLI.CODCLI));
  
                -- Insere Clientes associados à Região pela PCPRACA
                INSERT INTO PCMED_VIEWOLCLI_TMP
                          ( CODSISTEMA
                          , CODCLI )
                     SELECT pi_vCodSistema
                          , PCCLIENT.CODCLI
                       FROM PCCLIENT
                          , PCPRACA
                      WHERE (PCPRACA.CODPRACA  = PCCLIENT.CODPRACA)
                        AND (PCPRACA.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                        AND (NOT EXISTS (SELECT 'S'
                                           FROM PCMED_VIEWOLCLI_TMP
                                          WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                            AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
  
               /*----------------------------------------------------------------------------------------
                Condições de Venda x Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- Insere Clientes e Condições (PROMOÇÕES) que podem ser utilizadas pelo Cliente
                INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                          ( CODSISTEMA
                          , NUMREGIAO
                          , CODCONDICAOVENDA
                          , CODCLI
                          , CODPLPAG )
                     SELECT DISTINCT
                            pi_vCodSistema
                          , vrCondicoesComerc.vnNumRegiao
                          , vrCondicoesComerc.vnCodCondicaoVenda
                          , PCCLIENT.CODCLI
                          , CASE WHEN (NVL(PCCLIENT.UTILIZAPLPAGMEDICAMENTO,'N') = 'S')  THEN
                              -- Se utilizar Plano Etico e Generico, envia como Plano que o cliente pode alterar o Plano Genérico (O Ético será fixo - o do Cliente)
                              PCCLIENT.CODPLPAGGENERICO
                            ELSE
                              PCCLIENT.CODPLPAG
                            END CODPLPAG
                       FROM PCCLIENT
                          , PCPROMOCAOMED
                      WHERE (PCPROMOCAOMED.CODPROMOCAOMED               = vrCondicoesComerc.vnCodCondicaoVenda) -->> Condição de Venda do Laço (PROMOÇÃO)
                        AND (NVL(PCPROMOCAOMED.USANORMALIZACAODESC,'N') = 'S')                                  -->> COM NORMALIZAÇÃO
                        AND (PKG_FUNCOESVENDAS_MED.F_MED_PODEGERARPROMOCAO(PCPROMOCAOMED.CODPROMOCAOMED,
                                                                           vrCondicoesComerc.vvCodFilial,
                                                                           vrCondicoesComerc.vnNumRegiao,
                                                                           vORIGEMPODEGERARPROMOCAO, -->> Origem do Pedido
                                                                           NULL,
                                                                           PCCLIENT.CODCLI) = 'S')
                        AND (NOT EXISTS (SELECT 'S'
                                           FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                          WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                            AND PCMED_VIEWOLCONDVENDACLI_TMP.NUMREGIAO        = vrCondicoesComerc.vnNumRegiao
                                            AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                            AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Diferente do Servcon, posso ter mais de uma região para a mesma condição comercial (Promoção), não afeta os Unions (usei distinct na View)
  
             /*#####################################################################################################
              ######################################################################################################
              ######################################################################################################
              CARGA DA TABELA DE CLIENTES E DA TABELA DE CLIENTES QUE PODEM COMPRAR DA CONDIÇÃO (OPERADOR LOGISTICO)
              ######################################################################################################
              ######################################################################################################
              #####################################################################################################*/
              ELSE
  
               /*----------------------------------------------------------------------------------------
                Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- PESQUISA GERAL DE CLIENTES
                IF   (vvTipoPesquisaClientes = 'G') THEN
  
                   -- Insere Clientes associados à Região pela PCTABPRCLI
                   INSERT INTO PCMED_VIEWOLCLI_TMP
                             ( CODSISTEMA
                             , CODCLI )
                        SELECT DISTINCT
                               pi_vCodSistema
                             , PCTABPRCLI.CODCLI
                          FROM PCTABPRCLI
                         WHERE (PCTABPRCLI.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                           AND (NOT EXISTS (SELECT 'S'
                                              FROM PCMED_VIEWOLCLI_TMP
                                             WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                               AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCTABPRCLI.CODCLI));
  
                   -- Insere Clientes associados à Região pela PCPRACA
                   INSERT INTO PCMED_VIEWOLCLI_TMP
                             ( CODSISTEMA
                             , CODCLI )
                        SELECT pi_vCodSistema
                             , PCCLIENT.CODCLI
                          FROM PCCLIENT
                             , PCPRACA
                         WHERE (PCPRACA.CODPRACA  = PCCLIENT.CODPRACA)
                           AND (PCPRACA.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                           AND (NOT EXISTS (SELECT 'S'
                                              FROM PCMED_VIEWOLCLI_TMP
                                             WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                               AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
  
                  -- Só quando não gera dicionário por região pode contemplar os clientes de outras regiões
                  IF NOT (vbGeraDicionarioPorRegiao) THEN
                    INSERT INTO PCMED_VIEWOLCLI_TMP
                              ( CODSISTEMA
                              , CODCLI )
                         SELECT pi_vCodSistema
                              , PCCLIENT.CODCLI
                           FROM PCCLIENT
                          WHERE (NOT EXISTS (SELECT 'S'
                                               FROM PCMED_VIEWOLCLI_TMP
                                              WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                                AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
                  END IF;
  
                -- PESQUISA ESPECIFICA DE CLIENTES
                ELSIF (vvTipoPesquisaClientes = 'E') THEN
  
                  -- Insere Clientes da PCCONFIGSISTCLIOPERLOG associados à Região pela PCTABPRCLI
                  INSERT INTO PCMED_VIEWOLCLI_TMP
                            ( CODSISTEMA
                            , CODCLI )
                       SELECT DISTINCT
                              pi_vCodSistema
                            , PCTABPRCLI.CODCLI
                         FROM PCTABPRCLI
                            , PCCONFIGSISTCLIOPERLOG
                        WHERE (PCTABPRCLI.NUMREGIAO              = vrCondicoesComerc.vnNumRegiao)
                          AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCTABPRCLI.CODCLI)
                          AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCLI_TMP
                                            WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                              AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCTABPRCLI.CODCLI));
  
                  -- Insere Clientes da PCCONFIGSISTCLIOPERLOG associados à Região pela PCPRACA
                  INSERT INTO PCMED_VIEWOLCLI_TMP
                            ( CODSISTEMA
                            , CODCLI )
                       SELECT pi_vCodSistema
                            , PCCLIENT.CODCLI
                         FROM PCCLIENT
                            , PCPRACA
                            , PCCONFIGSISTCLIOPERLOG
                        WHERE (PCPRACA.CODPRACA                  = PCCLIENT.CODPRACA)
                          AND (PCPRACA.NUMREGIAO                 = vrCondicoesComerc.vnNumRegiao)
                          AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCCLIENT.CODCLI)
                          AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCLI_TMP
                                            WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                              AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
  
                  -- Só quando não gera dicionário por região pode contemplar os clientes de outras regiões
                  IF NOT (vbGeraDicionarioPorRegiao) THEN
                    INSERT INTO PCMED_VIEWOLCLI_TMP
                              ( CODSISTEMA
                              , CODCLI )
                         SELECT pi_vCodSistema
                              , PCCLIENT.CODCLI
                           FROM PCCLIENT
                              , PCCONFIGSISTCLIOPERLOG
                          WHERE (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCCLIENT.CODCLI)
                            AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                            AND (NOT EXISTS (SELECT 'S'
                                               FROM PCMED_VIEWOLCLI_TMP
                                              WHERE PCMED_VIEWOLCLI_TMP.CODSISTEMA = pi_vCodSistema
                                                AND PCMED_VIEWOLCLI_TMP.CODCLI     = PCCLIENT.CODCLI));
                  END IF;
  
                END IF; -- FIM CONDIÇÃO TIPO PESQUISA DE CLIENTES
  
               /*----------------------------------------------------------------------------------------
                Condições de Venda x Clientes
                ----------------------------------------------------------------------------------------*/
  
                -- PESQUISA GERAL DE CLIENTES -----------------------------------------------------------
                IF   (vvTipoPesquisaClientes = 'G') THEN
  
                  -- Insere Clientes e Condições associadas à Região pela PCTABPRCLI
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT DISTINCT -->> IMPORTANTE: Distinct porque pode ter mais de uma Filial para a mesma Região e Cliente
                              pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCTABPRCLI.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCTABPRCLI
                            , PCPLPAG
                        WHERE (PCTABPRCLI.CODCLI    = PCCLIENT.CODCLI)
                          AND (PCTABPRCLI.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG     = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS     >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCTABPRCLI.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                  -- Insere Clientes e Condições associadas à Região pela PCPRACA
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCCLIENT.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCPRACA
                            , PCPLPAG
                        WHERE (PCPRACA.CODPRACA  = PCCLIENT.CODPRACA)
                          AND (PCPRACA.NUMREGIAO = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG  = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                  -- Só quando não gera dicionário por região pode contemplar os clientes de outras regiões
                  IF NOT (vbGeraDicionarioPorRegiao) THEN
                    INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                              ( CODSISTEMA
                              , NUMREGIAO
                              , CODCONDICAOVENDA
                              , CODCLI
                              , CODPLPAG )
                         SELECT pi_vCodSistema
                              , vrCondicoesComerc.vnNumRegiao
                              , vrCondicoesComerc.vnCodCondicaoVenda
                              , PCCLIENT.CODCLI
                              , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                  NVL(vnCodPlPagCondicaoVenda,0)
                                ELSE
                                  CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                    PCCLIENT.CODPLPAGGENERICO
                                  ELSE
                                    PCCLIENT.CODPLPAG
                                  END
                                END CODPLPAG
                           FROM PCCLIENT
                              , PCPLPAG
                          WHERE (PCPLPAG.CODPLPAG  = PCCLIENT.CODPLPAG)
                            AND (PCPLPAG.NUMDIAS  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                            AND (NOT EXISTS (SELECT 'S'
                                               FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                              WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                                AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                                AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
                  END IF;
  
                -- PESQUISA ESPECIFICA DE CLIENTES ------------------------------------------------------
                ELSIF (vvTipoPesquisaClientes = 'E') THEN
  
                  -- Insere Clientes da PCCONFIGSISTCLIOPERLOG e Condições associadas à Região pela PCTABPRCLI
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT DISTINCT -->> IMPORTANTE: Distinct porque pode ter mais de uma Filial para a mesma Região e Cliente
                              pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCTABPRCLI.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCTABPRCLI
                            , PCPLPAG
                            , PCCONFIGSISTCLIOPERLOG
                        WHERE (PCTABPRCLI.CODCLI                 = PCCLIENT.CODCLI)
                          AND (PCTABPRCLI.NUMREGIAO              = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG                  = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS                  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCTABPRCLI.CODCLI)
                          AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCTABPRCLI.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                  -- Insere Clientes da PCCONFIGSISTCLIOPERLOG e Condições associadas à Região pela PCPRACA
                  INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                            ( CODSISTEMA
                            , NUMREGIAO
                            , CODCONDICAOVENDA
                            , CODCLI
                            , CODPLPAG )
                       SELECT pi_vCodSistema
                            , vrCondicoesComerc.vnNumRegiao
                            , vrCondicoesComerc.vnCodCondicaoVenda
                            , PCCLIENT.CODCLI
                            , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                NVL(vnCodPlPagCondicaoVenda,0)
                              ELSE
                                CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                  PCCLIENT.CODPLPAGGENERICO
                                ELSE
                                  PCCLIENT.CODPLPAG
                                END
                              END CODPLPAG
                         FROM PCCLIENT
                            , PCPRACA
                            , PCPLPAG
                            , PCCONFIGSISTCLIOPERLOG
                        WHERE (PCPRACA.CODPRACA                  = PCCLIENT.CODPRACA)
                          AND (PCPRACA.NUMREGIAO                 = vrCondicoesComerc.vnNumRegiao)
                          AND (PCPLPAG.CODPLPAG                  = PCCLIENT.CODPLPAG)
                          AND (PCPLPAG.NUMDIAS                  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                          AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCCLIENT.CODCLI)
                          AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                          AND (NOT EXISTS (SELECT 'S'
                                             FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                            WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                              AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
  
                  -- Só quando não gera dicionário por região pode contemplar os clientes de outras regiões
                  IF NOT (vbGeraDicionarioPorRegiao) THEN
                    INSERT INTO PCMED_VIEWOLCONDVENDACLI_TMP
                              ( CODSISTEMA
                              , NUMREGIAO
                              , CODCONDICAOVENDA
                              , CODCLI
                              , CODPLPAG )
                         SELECT pi_vCodSistema
                              , vrCondicoesComerc.vnNumRegiao
                              , vrCondicoesComerc.vnCodCondicaoVenda
                              , PCCLIENT.CODCLI
                              , CASE WHEN (NVL(vnCodPlPagCondicaoVenda,0) > 0) THEN
                                  NVL(vnCodPlPagCondicaoVenda,0)
                                ELSE
                                  CASE WHEN (NVL(PCCLIENT.CODPLPAG,0) = 99) AND (NVL(PCCLIENT.CODPLPAGGENERICO,0) > 0) THEN
                                    PCCLIENT.CODPLPAGGENERICO
                                  ELSE
                                    PCCLIENT.CODPLPAG
                                  END
                                END CODPLPAG
                           FROM PCCLIENT
                              , PCPLPAG
                              , PCCONFIGSISTCLIOPERLOG
                          WHERE (PCPLPAG.CODPLPAG                  = PCCLIENT.CODPLPAG)
                            AND (PCPLPAG.NUMDIAS                  >= vnPrazoMedioPlPag) -->> O Prazo Médio do Cliente deverá ser maior ou igual ao Prazo Médio da Condição
                            AND (PCCONFIGSISTCLIOPERLOG.CODCLI     = PCCLIENT.CODCLI)
                            AND (PCCONFIGSISTCLIOPERLOG.CODSISTEMA = pi_vCodSistema)
                            AND (NOT EXISTS (SELECT 'S'
                                               FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                              WHERE PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA       = pi_vCodSistema
                                                AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCONDICAOVENDA = vrCondicoesComerc.vnCodCondicaoVenda
                                                AND PCMED_VIEWOLCONDVENDACLI_TMP.CODCLI           = PCCLIENT.CODCLI)); -->> IMPORTANTE: Não posso ter para o mesmo Cliente Condição de Venda repetida devido aos UNIONs
                  END IF;
  
                END IF; -- FIM CONDIÇÃO: PESQUISA DE CLIENTES GERAL OU ESPECÍFICA
  
              END IF; -- FIM CONDIÇÃO: (CARGA DA TABELA DE CLIENTES E DA TABELA DE CLIENTES CONFORME 2311 ou 2323 ou Operador Logístico)
  
  
  
            END IF; -- END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA (Geração de Clientes)
           /************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
                                                              P A R T E   2
                                                              -------------
            C A R R E G A   A R R A Y   D E    C O N D I Ç Õ E S   D E F I N I T I V A    (CONDICAO x REGIAO x FILIAL x PLANO PAGTO)
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************
            ************************************************************************************************************************/
  
  
  
  
           /*//////////////////////////////////////////////////////////////
            ///////////////////////////////////////////////////////////////
            ///////////////////////////////////////////////////////////////
            -- SE COTEFÁCIL (TEM TRATAMENTO DIFERENCIADO
            -- Sistemas x Condições de Venda x Regiões x Filiais Distintas)
            ///////////////////////////////////////////////////////////////
            ///////////////////////////////////////////////////////////////
            //////////////////////////////////////////////////////////////*/
            IF (NVL(vvPedidoEletronico,' ') = 'C') THEN
              -- Guarda os Sistemas x Condições de Venda x Regiões Distintas x Filiais Distintas
              viIdxSistCv := 0;
              IF (vtSistCondVenda.COUNT > 0) THEN
                FOR viIdx IN vtSistCondVenda.FIRST..vtSistCondVenda.LAST LOOP
                  IF ((vtSistCondVenda(viIdx).vvCodSistema          = pi_vCodSistema) AND
                      (vtSistCondVenda(viIdx).vnCodCondicaoVenda    = vrCondicoesComerc.vnCodCondicaoVenda) AND
                      (vtSistCondVenda(viIdx).vnNumRegiao           = vrCondicoesComerc.vnNumRegiao) AND
                      (vtSistCondVenda(viIdx).vvCodFilialParaCalcSt = vrCondicoesComerc.vvCodFilial)) THEN
                    viIdxSistCv := viIdx;
                  END IF;
                END LOOP;
              END IF;
           /*/////////////////////////////////////
            //////////////////////////////////////
            //////////////////////////////////////
            SE MULTIPLAS CONDIÇÕES DE VENDA (2311)
            //////////////////////////////////////
            //////////////////////////////////////
            /////////////////////////////////////*/
            ELSIF (NVL(vvUsaMultiplasCondVenda,'N') = 'S') THEN
               -- Guarda os Sistemas x Condições de Venda Distintos
               viIdxSistCv := 0;
               IF (vtSistCondVenda.COUNT > 0) THEN
                 FOR viIdx IN vtSistCondVenda.FIRST..vtSistCondVenda.LAST LOOP
                   IF ((vtSistCondVenda(viIdx).vvCodSistema       = pi_vCodSistema) AND
                       (vtSistCondVenda(viIdx).vnCodCondicaoVenda = vrCondicoesComerc.vnCodCondicaoVenda)) THEN
                     viIdxSistCv := viIdx;
                   END IF;
                 END LOOP;
               END IF;
           /*++++++++++++++++++++++++++++
            +++++++++++++++++++++++++++++
            +++++++++++++++++++++++++++++
            SE MULTIPLAS PROMOÇÕES (2323)
            +++++++++++++++++++++++++++++
            +++++++++++++++++++++++++++++
            ++++++++++++++++++++++++++++*/
            ELSIF (NVL(vvUsaMultiplasPromocoes,'N') = 'S') THEN
              -- Guarda os Sistemas x Condições de Venda x Regiões Distintas x Filiais Distintas
              viIdxSistCv := 0;
              IF (vtSistCondVenda.COUNT > 0) THEN
                FOR viIdx IN vtSistCondVenda.FIRST..vtSistCondVenda.LAST LOOP
                  IF ((vtSistCondVenda(viIdx).vvCodSistema          = pi_vCodSistema) AND
                      (vtSistCondVenda(viIdx).vnCodCondicaoVenda    = vrCondicoesComerc.vnCodCondicaoVenda) AND
                      (vtSistCondVenda(viIdx).vnNumRegiao           = vrCondicoesComerc.vnNumRegiao) AND
                      (vtSistCondVenda(viIdx).vvCodFilialParaCalcSt = vrCondicoesComerc.vvCodFilial)) THEN
                    viIdxSistCv := viIdx;
                  END IF;
                END LOOP;
              END IF;
           /*####################
            #####################
            #####################
            SE OPERADOR LOGISTICO
            #####################
            #####################
            ####################*/
            ELSE
              -- SE GERA DICIONÁRIO POR REGIÃO
              IF (vbGeraDicionarioPorRegiao) THEN
                -- Guarda os Sistemas x Condições de Venda x Regiões Distintas
                viIdxSistCv := 0;
                IF (vtSistCondVenda.COUNT > 0) THEN
                  FOR viIdx IN vtSistCondVenda.FIRST..vtSistCondVenda.LAST LOOP
                    IF ((vtSistCondVenda(viIdx).vvCodSistema       = pi_vCodSistema) AND
                        (vtSistCondVenda(viIdx).vnCodCondicaoVenda = vrCondicoesComerc.vnCodCondicaoVenda) AND
                        (vtSistCondVenda(viIdx).vnNumRegiao        = vrCondicoesComerc.vnNumRegiao)) THEN
                      viIdxSistCv := viIdx;
                    END IF;
                  END LOOP;
                END IF;
              -- SE NÃO GERA DICIONÁRIO POR REGIÃO
              ELSE
                -- Guarda os Sistemas x Condições de Venda Distintos
                viIdxSistCv := 0;
                IF (vtSistCondVenda.COUNT > 0) THEN
                  FOR viIdx IN vtSistCondVenda.FIRST..vtSistCondVenda.LAST LOOP
                    IF ((vtSistCondVenda(viIdx).vvCodSistema       = pi_vCodSistema) AND
                        (vtSistCondVenda(viIdx).vnCodCondicaoVenda = vrCondicoesComerc.vnCodCondicaoVenda) AND
                        /*
                        4415.075447.2016
                        RUBENS PINHEIRO
                        O QUE FOI FEITO: FOI ADICIONADO A VALIDAÇÃO DA FILIAL
                        MOTIVO         : CASO EXISTA DUAS OU MAIS FILIAIS COM A MESMA CONDIÇÃO DE VENDA PARA O MESMO COD. SISTEMA,
                                         O viIdx SEMPRE FICA NA PRIMEIRA OCORRENCIA ENCONTRADA, GERANDO A TABELA TEMPORÁRIA PCMED_VIEWOLCONDVENDAPROD_TMP
                                         SEMPRE COM A MESMA FILIAL.
                        */
                        (vtSistCondVenda(viIdx).vvCodFilialParaCalcSt = vrCondicoesComerc.vvCodFilial)
                        ) THEN
                      viIdxSistCv := viIdx;
                    END IF;
                  END LOOP;
                END IF;
              END IF; -- FIM CONDIÇÃO SE GERA DICIONÁRIO POR REGIÃO
            END IF; -- FIM CONDIÇÃO: (NVL(vvUsaMultiplasPromocoes,'N') = 'S')
  
            IF (NVL(viIdxSistCv,0) = 0) THEN -- Se não existe ainda no Array
             -- Se tem Código do Cliente para Cálculo do ST
             IF (NVL(vrCondicoesComerc.vnCodCliStPedidoElet,0) > 0) THEN
               vnCodCliRegiao := vrCondicoesComerc.vnCodCliStPedidoElet;
             -- Se NÃO tem Código do Cliente para Cálculo do ST, busca um da Região
             ELSE
               -- Código do Cliente da Região
               BEGIN
                 SELECT CODCLI
                   INTO vnCodCliRegiao
                   FROM PCMED_VIEWOLCONDVENDACLI_TMP
                  WHERE (CODSISTEMA = pi_vCodSistema)
                    AND (NUMREGIAO  = vrCondicoesComerc.vnNumRegiao)
                    AND (ROWNUM     = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnCodCliRegiao := NULL;
                END;
              END IF;
              -- Preenche Array
              viIdxSistCv                                        := NVL(vtSistCondVenda.COUNT,0) + 1;
              vtSistCondVenda(viIdxSistCv).vvCodSistema          := pi_vCodSistema;
              vtSistCondVenda(viIdxSistCv).vnCodCondicaoVenda    := vrCondicoesComerc.vnCodCondicaoVenda;
              vtSistCondVenda(viIdxSistCv).vnNumRegiao           := vrCondicoesComerc.vnNumRegiao;
              vtSistCondVenda(viIdxSistCv).vnIntegradora         := vrCondicoesComerc.vnIntegradora;
              vtSistCondVenda(viIdxSistCv).vnCodPlPag            := NVL(vnCodPlPag,0);             -->> CÓDIGO DO PLANO DE PAGAMENTO PARA DEFINIR O PREÇO COM BASE NA COLUNA DE PRAZO
              vtSistCondVenda(viIdxSistCv).vnCodCliParaCalcSt    := vnCodCliRegiao;                -->> CÓDIGO DO CLIENTE PARA REFERÊNCIA DO CÁLCULO DO ST
              vtSistCondVenda(viIdxSistCv).vvCodFilialParaCalcSt := vrCondicoesComerc.vvCodFilial; -->> CÓDIGO DA FILIAL PARA REFERÊNCIA DO CÁLCULO DO ST
              vtSistCondVenda(viIdxSistCv).vnPrazoMedio          := NVL(vnPrazoMedioPlPag,0);
              vtSistCondVenda(viIdxSistCv).vvUfRegiao            := vrCondicoesComerc.vvUfRegiao;
              vtSistCondVenda(viIdxSistCv).vvKit                 := vrCondicoesComerc.vvKit;
              vtSistCondVenda(viIdxSistCv).vvTipoCondicao        := vrCondicoesComerc.vvTipoCondicao;
              -- Guarda em Tabela para Auditoria
              INSERT INTO PCMED_VIEWOLSISTCONDVENDA_TMP
                        ( CODSISTEMA
                        , CODCONDICAOVENDA
                        , INTEGRADORA
                        , NUMREGIAO
                        , CODFILIALST
                        , CODCLIST
                        , CODPLPAG
                        , PRAZOMEDIO
                        , TIPOCONDICAO
                        , UFREGIAO
                        , KIT )
                 VALUES ( vtSistCondVenda(viIdxSistCv).vvCodSistema
                        , vtSistCondVenda(viIdxSistCv).vnCodCondicaoVenda
                        , vtSistCondVenda(viIdxSistCv).vnIntegradora
                        , vtSistCondVenda(viIdxSistCv).vnNumRegiao
                        , vtSistCondVenda(viIdxSistCv).vvCodFilialParaCalcSt
                        , vtSistCondVenda(viIdxSistCv).vnCodCliParaCalcSt
                        , vtSistCondVenda(viIdxSistCv).vnCodPlPag
                        , vtSistCondVenda(viIdxSistCv).vnPrazoMedio
                        , vtSistCondVenda(viIdxSistCv).vvTipoCondicao
                        , vtSistCondVenda(viIdxSistCv).vvUfRegiao
                        , vtSistCondVenda(viIdxSistCv).vvKit );
            END IF;
  
            -- Guarda os Sistemas x Planos de Pagamento Distintos
            viIdxSistPlPag := 0;
            IF (vtSistPlPag.COUNT > 0) THEN
              FOR viIdx IN vtSistPlPag.FIRST..vtSistPlPag.LAST LOOP
                IF ((vtSistPlPag(viIdx).vvCodSistema = pi_vCodSistema) AND
                    (vtSistPlPag(viIdx).vnCodPlPag   = NVL(vnCodPlPag,0))) THEN
                  viIdxSistPlPag := viIdx;
                END IF;
              END LOOP;
            END IF;
            IF (NVL(viIdxSistPlPag,0) = 0) THEN -- Se não existe ainda no Array
              -- Preenche Array
              viIdxSistPlPag                           := NVL(vtSistPlPag.COUNT,0) + 1;
              vtSistPlPag(viIdxSistPlPag).vvCodSistema := pi_vCodSistema;
              vtSistPlPag(viIdxSistPlPag).vnCodPlPag   := vnCodPlPag;
            END IF;
  
          END IF; -- Fim Condição Se achou a Região
  
        END IF; -- Fim Condição se a Condição de Venda é Válida para o Cliente
  
      END LOOP; -- Fim do Laço de Processamento do ARRAY de Condições
    END IF;
  
    vdDataHoraFinGerClientes := SYSDATE;
  
    -- COMPLEMENTAÇÃO ESPECÍFICA PARA O FORÇA DE VENDAS:
    ---------------------------------------------------
    -- SE GERA DICIONÁRIO PARA FORÇA DE VENDAS,
    -- REFAZ ARRAY DE PLANOS DE PAGAMENTOS.
    -- OS PLANOS DE PAGAMENTO SERÃO GERADOS DE FORMA DIFERENCIADA
    IF (vbGeraDicionarioForcaVendas) THEN
  
      -- Limpa Array
      vtSistPlPag.DELETE;
  
      -- Laço de Planos de Pagamento Distintos
      FOR vc_PlPagCondVendaCli IN (SELECT DISTINCT
                                          CODPLPAG
                                     FROM PCMED_VIEWOLCONDVENDACLI_TMP
                                    WHERE (PCMED_VIEWOLCONDVENDACLI_TMP.CODSISTEMA = pi_vCodSistema)) LOOP
        -- Preenche Array
        viIdxSistPlPag                           := NVL(vtSistPlPag.COUNT,0) + 1;
        vtSistPlPag(viIdxSistPlPag).vvCodSistema := pi_vCodSistema;
        vtSistPlPag(viIdxSistPlPag).vnCodPlPag   := vc_PlPagCondVendaCli.CODPLPAG;
      END LOOP;
  
    END IF; -- FIM CONDIÇÃO SE GERA DICIONÁRIO PARA FORÇA DE VENDAS - para gerar Planos de Pagamento
  
  
  
  
  
   /*****************************************
    PROCESSAMENTO NECESSÁRIO PARA GRAVAR:
    Condições de Venda x Produtos x Descontos
    *****************************************/
  
    -- Parâmetro Farmácia Popular
    BEGIN
      SELECT NVL(VALOR,'N') VALOR
        INTO vvCalcStPautaFarmaciaPopular
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'CALCSTPAUTAFARMACIAPOPULAR');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvCalcStPautaFarmaciaPopular := 'N';
    END;
  
    -- Parâmetro Usa Tributação por UF e Usa PisCofins por Filial
    BEGIN
      SELECT NVL(USATRIBUTACAOPORUF,'N') USATRIBUTACAOPORUF
           , PCCONSUM.NUMCASASDECVENDA
           , PCCONSUM.USAPISCOFINSPORFILIAL
        INTO vvUsaTributacaoPorUf
           , vnNumCasasDecVenda
           , vvUsaPisCofinsPorFilial
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUsaTributacaoPorUf    := 'N';
        vnNumCasasDecVenda      := 2;
        vvUsaPisCofinsPorFilial := 'N';
    END;
  
    -- Pesquisa Parâmetro Usa PMC por UF
    BEGIN
      SELECT NVL(VALOR,'N') VALOR
        INTO vvUsaPmcUf
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'UTILIZAPMCUF');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUsaPmcUf := 'N';
    END;
  
    -- Pesquisa Parâmetro Utiliza Percentual de Bonificação na Venda por Região
    BEGIN
      SELECT NVL(VALOR,'N') VALOR
        INTO vvUtilizaPercBonifiVendaRegiao
        FROM PCPARAMFILIAL
       WHERE (CODFILIAL = '99')
         AND (NOME      = 'UTILIZAPERCBONIFIVENDAREGIAO');
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUtilizaPercBonifiVendaRegiao := 'N';
    END;
  
  
  
  
  
