           , PCMED_VIEWOL_PCDESCONTO_TMP PCDESCONTO                 -->> Usando Tabela Temp
       WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA    = pi_vCodSistema)   -->> SISTEMA PASSADO NO PARÂMETRO
         AND (PCDESCONTO.CODPROMOCAOMED         = PCPROMOCAOMED.CODPROMOCAOMED)
