           , PCMED_VIEWOL_PCDESCONTO_TMP PCDESCONTO                 -->> Usando Tabela Temp
       WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA    = pi_vCodSistema)   -->> SISTEMA PASSADO NO PARÂMETRO
         AND (PCDESCONTO.CODPROMOCAOMED         = PCPROMOCAOMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED      = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED      = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
         AND (PCPROMOCAOMED.TIPOPROMOCAO       IN ('C','E'))      -->> Somente Promoções de Cliente (Combo/Mix/etc ignorar)
         AND (PCDESCONTO.ORIGEMPED              = 'F')
         AND (NVL(PCDESCONTO.TIPOFV,'FV')       = vvTipoFv)         -->> TIPO FV da Integradora
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')   = 'N')              -->> Bloqueadas não entram
          -- Fim: Parte Comum à Carga dos Descontos
         AND (PCPROMOCAOMED.TIPOPOLITICA        IN ('Q'));         -->> Promoção de Desconto por Faixa de Quantidade
  
      -- Carrega Tabelas com Informações de Condições x Promoções de Preço Fixo por Faixa de Quantidade
