                , NUMREGIAO
                , CODFILIAL ) -- 20170802
      SELECT DISTINCT -->> Precisa pq não tem regra de prioridade no Combo
             PCCONFIGSISTOPERLOG.CODSISTEMA
           , PCCONDICAOVENDA.CODCONDICAOVENDA
           , PCDESCONTO.PRECOFIXOPROMOCAOMED
           , PCDESCONTO.PERCDESCFIN
           , PCDESCONTO.CODPROD
           , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
           , NVL(PCDESCONTO.PROMOCAOMEDOBRIGATORIO,'S')
           , NVL(PCDESCONTO.PERMITIRAUMENTARQTDEKITMED,'N')
           , PCDESCONTO.CODFORNEC
           , PCDESCONTO.CODMARCA
           , PCDESCONTO.CODCATEGORIA
           , PCDESCONTO.CODSEC
           , PCDESCONTO.CODLINHAPROD
           , PCDESCONTO.CODEPTO
           , CASE WHEN PCDESCONTO.CODPROD      IS NOT NULL THEN 1
                  WHEN PCDESCONTO.CODFORNEC    IS NOT NULL THEN 2
                  WHEN PCDESCONTO.CODMARCA     IS NOT NULL THEN 3
                  WHEN PCDESCONTO.CODCATEGORIA IS NOT NULL THEN 4
                  WHEN PCDESCONTO.CODSEC       IS NOT NULL THEN 5
                  WHEN PCDESCONTO.CODLINHAPROD IS NOT NULL THEN 6
                  WHEN PCDESCONTO.CODEPTO      IS NOT NULL THEN 7
                  ELSE 8 END PRIORIDADE
           , PCDESCONTO.CODPROMOCAOMED
           , NVL(PCPROMOCAOREGIAOMED.NUMREGIAO,PCDESCONTO.NUMREGIAO) NUMREGIAO
           , NVL(PCPROMOCAOFILMED.CODFILIAL,PCDESCONTO.CODFILIAL) CODFILIAL -- 20170802
        FROM PCCONDICAOVENDA
           , PCCONDVENDAINTEGRADORA
           , PCCONFIGSISTOPERLOG
           , PCDESCONTO
           , PCPROMOCAOMED
           , PCPROMOCAOCONDVENDAMED
           , PCPROMOCAOREGIAOMED -- 20170802
           , PCPROMOCAOFILMED -- 20170802
       WHERE (PCCONDICAOVENDA.CODCONDICAOVENDA        = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA)
         AND (PCCONDVENDAINTEGRADORA.INTEGRADORA      = PCCONFIGSISTOPERLOG.INTEGRADORA)
         --
         AND (PCPROMOCAOCONDVENDAMED.CODCONDICAOVENDA = PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA) -->> VÍNCULO DA PROMOÇÃO COM A CONDIÇÃO DE VENDA
         AND (PCDESCONTO.CODPROMOCAOMED               = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOCONDVENDAMED.CODPROMOCAOMED)
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOREGIAOMED.CODPROMOCAOMED(+)) -- 20170802
         AND (PCPROMOCAOMED.CODPROMOCAOMED            = PCPROMOCAOFILMED.CODPROMOCAOMED(+)) -- 20170802
         --
         AND (PCPROMOCAOMED.TIPOPOLITICA              IN ('P'))          -->> Promoção de Preço Fixo
         AND (PCPROMOCAOMED.TIPOPROMOCAO              IN ('K'))          -->> Promoção Combo
         AND ( ((NVL(vvUsaMultiplasCondVenda,'N') = 'S') AND (PCCONDICAOVENDA.ENVIAPEDIDOELET = 'S')) OR (NVL(vvUsaMultiplasCondVenda,'N') <> 'S') )
         AND (NVL(PCDESCONTO.TIPOFV,'FV')             = vvTipoFv)        -->> TIPO FV da Integradora
         AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL) -->> Somente Promoções Vigentes
         AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N')         = 'N')             -->> Bloqueadas não entram
         AND (PCCONFIGSISTOPERLOG.CODSISTEMA          = pi_vCodSistema); -->> Somente Sistema passado no Parâmetro
  
    END IF; -- FIM CONDIÇÃO PROMOÇÕES PARA FORÇA DE VENDAS OU OL/PE
  
    vdDataHoraFinGerDescontos := SYSDATE;
  
  
  
  
  
  
    END IF; -->> Processo Específico SERVCON NÃO ENTRA
   /*************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    G E R A C A O   D O S   I T E N S   D A S   C O N D I C O E S   -   PCMED_VIEWOLCONDVENDAPROD_TMP
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************
    *************************************************************************************************/
  
  
  
  
  
    -------------------------------------------------------------------------------------------------
    -------------------------------------------------------------------------------------------------
    -- LAÇO DE REGIÕES E FILIAIS
    ----------------------------
    ----------------------------
    vbAchouCondicoes := FALSE;
    FOR vc_RegiaoFilial IN (-- Processo Específico SERVCON
                            SELECT DISTINCT -- Precisa do Distinct por causa das Condições de Venda
                                   TO_NUMBER(NULL)                           NUMREGIAOPADRAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST CODFILIALPADRAO
                                 , TO_NUMBER(NULL)                           CODCLIPADRAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.INTEGRADORA INTEGRADORAPADRAO
                                 , NULL                                      UFREGIAOPADRAO
                              FROM PCMED_VIEWOLSISTCONDVENDA_TMP
                             WHERE (NVL(vvUsaMultiplasCondVenda,'N') = 'P') -->> Processo Específico SERVCON
                               AND (PCMED_VIEWOLSISTCONDVENDA_TMP.CODSISTEMA = pi_vCodSistema)
                             UNION
                            SELECT DISTINCT -- Precisa do Distinct por causa das Condições de Venda
                                   PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO     NUMREGIAOPADRAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST   CODFILIALPADRAO
                                 , MAX(PCMED_VIEWOLSISTCONDVENDA_TMP.CODCLIST) CODCLIPADRAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.INTEGRADORA   INTEGRADORAPADRAO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.UFREGIAO      UFREGIAOPADRAO
                              FROM PCMED_VIEWOLSISTCONDVENDA_TMP
                             WHERE (NVL(vvUsaMultiplasCondVenda,'N') <> 'P') -->> Processo Diferente de SERVCON
                               AND (PCMED_VIEWOLSISTCONDVENDA_TMP.CODSISTEMA = pi_vCodSistema)
                             GROUP BY PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.INTEGRADORA
                                    , PCMED_VIEWOLSISTCONDVENDA_TMP.UFREGIAO
                             ORDER BY NUMREGIAOPADRAO
                                    , CODFILIALPADRAO
                             ) LOOP
  
      -- Achou Condições
      vbAchouCondicoes := TRUE;
  
      -- Pesquisa o Tipo de Preço da Integradora
      BEGIN
        SELECT NVL(PCINTEGRADORA.ORIGEMPRECO,'F')
             , LAYOUT
             , NVL(APLICARDESCPTABELATRIBUT,'N')
          INTO vvOrigemPreco
             , vnLayout
             , vvAplicarDescPtabelaTribut
          FROM PCINTEGRADORA
         WHERE (PCINTEGRADORA.INTEGRADORA = vc_RegiaoFilial.INTEGRADORAPADRAO);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvOrigemPreco              := 'F';
          vnLayout                   := NULL;
          vvAplicarDescPtabelaTribut := 'N';
      END;
  
      ---------------------------------------
      -- Informação de Estoque, carrega Array
      ---------------------------------------
      -- DDMEDICA-6952 - Tipo de Custo da Promoção de Markup
      POBTEM_PARAMFILIAL_STRING(vc_RegiaoFilial.CODFILIALPADRAO,
                                'CUSTO_PROM_MARKUP_ST',
                                '8',
                                vvOpcaoCusto);      
      -- Verifica se Usará a Filial Retira - DDMEDICA-5782
      BEGIN
        SELECT CODFILIALRETIRA
          INTO vvCodFilialRetira
          FROM PCFILIALRETIRA
         WHERE (CODFILIALVENDA = vc_RegiaoFilial.CODFILIALPADRAO)
           AND ((SELECT VALOR 
                   FROM PCREGRASEXCECAOMED
                  WHERE PCREGRASEXCECAOMED.NOME = 'USAFILIALRETIRADICDADOS' 
                    AND PCREGRASEXCECAOMED.CODFILIAL = '99') = 'S')
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvCodFilialRetira := vc_RegiaoFilial.CODFILIALPADRAO; -- Padrão
      END;
      vtEstoque_CodProd.DELETE;
      vtEstoque_Saldo.DELETE;
      vtEstoque_Custo.DELETE; -- DDMEDICA-5980
      vtEstoque_CodProd_Saldo.DELETE;
      vtEstoque_CodProd_Custo.DELETE; -- DDMEDICA-5980
      SELECT CODPROD
           , (NVL(QTESTGER,0) - NVL(QTRESERV,0) - NVL(QTBLOQUEADA,0))
           , CASE 
                   WHEN vvOpcaoCusto = '1'  THEN -- Última entrada
                     CUSTOULTENT
                   WHEN vvOpcaoCusto = '2'  THEN -- Última entrada financeira
                     CUSTOULTENTFIN
                   WHEN vvOpcaoCusto = '3'  THEN -- Custo da NF sem ST
                     CUSTONFSEMST
                   WHEN vvOpcaoCusto = '4'  THEN -- Contábil
                     CUSTOCONT
                   WHEN vvOpcaoCusto = '5'  THEN -- (Real+ICMS)
                     CUSTOREP
                   WHEN vvOpcaoCusto = '6'  THEN -- Custo Real sem ST
                     CUSTOREALSEMST
                   WHEN vvOpcaoCusto = '7'  THEN -- Real
                     CUSTOREAL
                   WHEN vvOpcaoCusto = '8'  THEN -- Financeiro
                     CUSTOFIN
                   WHEN vvOpcaoCusto = '9'  THEN -- Última entrada cont. sem ST
                     VLULTENTCONTSEMST
                   WHEN vvOpcaoCusto = '10' THEN -- Custo Financeiro Sem ST
                     CUSTOFINSEMST
                   WHEN vvOpcaoCusto = '11' THEN -- Custo Ult. Ent. Sem ST 
                     CUSTOULTENTSEMST
                   WHEN vvOpcaoCusto = '12' THEN -- Custo Real Liquido 
                     CUSTOREALLIQ
                   WHEN vvOpcaoCusto = '13' THEN -- Custo Ult. Ent. Líquido
                     CUSTOULTENTLIQ
                   WHEN vvOpcaoCusto = '14' THEN -- Custo Ult. Ent. Fin. Sem ST
                     CUSTOULTENTFINSEMST
                   ELSE                          -- Padrão: Financeiro
                     CUSTOFIN
                 END CUSTOFIN -- DDMEDICA-5980
      BULK COLLECT INTO vtEstoque_CodProd
                      , vtEstoque_Saldo
                      , vtEstoque_Custo -- DDMEDICA-5980
       FROM PCEST
      WHERE (CODFILIAL = vvCodFilialRetira); -- DDMEDICA-5782
      -- Carrega Array Indexado pelo Produto
      IF (vtEstoque_CodProd.COUNT > 0) THEN
        FOR viIdxEstoque IN vtEstoque_CodProd.FIRST..vtEstoque_CodProd.LAST LOOP
          -- INDICE
          IF (vtEstoque_Saldo(viIdxEstoque) < 0) THEN
            vtEstoque_CodProd_Saldo(vtEstoque_CodProd(viIdxEstoque)) := 0;
          ELSE
            vtEstoque_CodProd_Saldo(vtEstoque_CodProd(viIdxEstoque)) := vtEstoque_Saldo(viIdxEstoque);
          END IF;
          -- CUSTO - DDMEDICA-5980
          vtEstoque_CodProd_Custo(vtEstoque_CodProd(viIdxEstoque)) := vtEstoque_Custo(viIdxEstoque);
        END LOOP;
      END IF;
  
      ----------------------------------------------------------
      -- Informação de ShelfLife, carrega Array - HIS.02727.2016
      ----------------------------------------------------------
      IF (vbValidaShelfLife) THEN
  
        -- Pesquisa ShelfLife do Cliente
        BEGIN
          SELECT TRUNC(SYSDATE) + NVL(PRAZOMAXVALIDADE,0)
            INTO vdShelfLifeCliente
            FROM PCCLIENT
           WHERE (CODCLI = vc_RegiaoFilial.CODCLIPADRAO);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vdShelfLifeCliente := TRUNC(SYSDATE);
        END;
  
        vtProShelfLife_CodProd.DELETE;
        vtProShelfLife.DELETE;
        SELECT CODPROD
          BULK COLLECT INTO vtProShelfLife_CodProd
          FROM PCLOTE
         WHERE (CODFILIAL   = vc_RegiaoFilial.CODFILIALPADRAO)
           AND (DTVALIDADE >= vdShelfLifeCliente)
         GROUP BY CODPROD
        HAVING (SUM(GREATEST(NVL(QT,0) - NVL(QTRESERV,0),0)) > 0);
        -- Carrega Array Indexado pelo Produto
        IF (vtProShelfLife_CodProd.COUNT > 0) THEN
          FOR viIdxEstoque IN vtProShelfLife_CodProd.FIRST..vtProShelfLife_CodProd.LAST LOOP
            -- INDICE
            vtProShelfLife(vtProShelfLife_CodProd(viIdxEstoque)) := 0;
          END LOOP;
        END IF;
  
      END IF; -- FIM: (vbValidaShelfLife)
  
     /*
      -- Itens KIT
      vtItensKit.DELETE;
      IF (vtSistCondVenda(viIdx).vvKit = 'S') THEN
        FOR vc_ItensKit IN (SELECT DISTINCT CODPROD
                              FROM PCDESCONTO
                             WHERE (CODPROMOCAOMED = vnCodCondicaoVenda)) LOOP
          vtItensKit(vc_ItensKit.CODPROD) := vc_ItensKit.CODPROD;
        END LOOP;
      END IF;
      */
  
      -- HIS.01061.2016 - Envia FV
      -- DDMEDICA-5540 - Envia Dicionário de Dados
      IF (vbValidaEnviaFv) OR
         (vbValidaEnviarDicD) THEN
        SELECT CODPROD
             , NVL(ENVIARFORCAVENDAS,'N')
             , NVL(ENVIARDICIONARIODADOSMED,'N')
        BULK COLLECT INTO vtProdFilial_CodProd
                        , vtProdFilial_EnviaFv
                        , vtProdFilial_EnviarDicD
         FROM PCPRODFILIAL
        WHERE (CODFILIAL = vc_RegiaoFilial.CODFILIALPADRAO);
        -- Carrega Array Indexado pelo Produto
        IF (vtProdFilial_CodProd.COUNT > 0) THEN
          FOR viIdxProdFil IN vtProdFilial_CodProd.FIRST..vtProdFilial_CodProd.LAST LOOP
            -- INDICE ENVIA FV
            IF (vbValidaEnviaFv) THEN
              vtEstoque_CodProd_EnviaFv(vtProdFilial_CodProd(viIdxProdFil)) := vtProdFilial_EnviaFv(viIdxProdFil);
            END IF;
            -- INDICE ENVIA DICIONARIO DE DADOS
            IF (vbValidaEnviarDicD) THEN
              vtEstoque_CodProd_EnviarDicD(vtProdFilial_CodProd(viIdxProdFil)) := vtProdFilial_EnviarDicD(viIdxProdFil);
            END IF;
          END LOOP;
        END IF;
      END IF;

      ----------------------------------------------------
      -- Carrega Lista de Condições para a Região e Filial
      ----------------------------------------------------
  
      -->> Processo Específico SERVCON
      IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
  
        -- Vai gerar as Condições a partir do Select Gerar PCDESCONTO x PCTABPR,
        -- para compatibilidade gera somente uma linha no Array
        vtListaCondicoes.DELETE;
        viIdxCondicao := NVL(vtListaCondicoes.COUNT,0) + 1;
        vtListaCondicoes(viIdxCondicao).vnCodCondicaoVenda := NULL;
        vtListaCondicoes(viIdxCondicao).vnCodPlPag         := NULL;
        vtListaCondicoes(viIdxCondicao).vnPrazoMedio       := NULL;
        vtListaCondicoes(viIdxCondicao).vvKit              := 'N';
  
      -->> Demais Processos
      ELSE
  
        vtListaCondicoes.DELETE;
        FOR vc_Condicao IN (SELECT DISTINCT
                                   PCMED_VIEWOLSISTCONDVENDA_TMP.CODCONDICAOVENDA
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.CODPLPAG
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.PRAZOMEDIO
                                 , PCMED_VIEWOLSISTCONDVENDA_TMP.KIT
                              FROM PCMED_VIEWOLSISTCONDVENDA_TMP
                             WHERE (PCMED_VIEWOLSISTCONDVENDA_TMP.CODSISTEMA  = pi_vCodSistema)
                               AND (PCMED_VIEWOLSISTCONDVENDA_TMP.NUMREGIAO   = vc_RegiaoFilial.NUMREGIAOPADRAO)
                               AND (PCMED_VIEWOLSISTCONDVENDA_TMP.CODFILIALST = vc_RegiaoFilial.CODFILIALPADRAO)) LOOP
          viIdxCondicao := NVL(vtListaCondicoes.COUNT,0) + 1;
          vtListaCondicoes(viIdxCondicao).vnCodCondicaoVenda := vc_Condicao.CODCONDICAOVENDA;
          vtListaCondicoes(viIdxCondicao).vnCodPlPag         := vc_Condicao.CODPLPAG;
          vtListaCondicoes(viIdxCondicao).vnPrazoMedio       := vc_Condicao.PRAZOMEDIO;
          vtListaCondicoes(viIdxCondicao).vvKit              := vc_Condicao.KIT;
        END LOOP;
  
      END IF;
  
      ---------------------------------------------------------------------------------------------
      --                    Laço de Processamento dos Produtos POR REGIÃO                        --
      ---------------------------------------------------------------------------------------------
      -- Controle de Prioridade da Restrição da Promoção (Ex: Produto é prioritário que Marca) - DDMEDICA-6008
      vvQuebraPrioridadeRestrPromo := '@';
      vbAchouTabelaPreco           := FALSE;
      FOR vc_Produto IN (-- Processo Específico SERVCON Filtrando Só pelo Produto
                         SELECT PCDESCONTO.CODPROMOCAOMED
                              , PCPROMOCAOFILMED.CODFILIAL
                              , PCPROMOCAOREGIAOMED.NUMREGIAO
                              , PCDESCONTO.PERCDESC
                              , PCDESCONTO.PERCDESCFIN
                              , PCDESCONTO.PRECOFIXOPROMOCAOMED
                              , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                              , PCDESCONTO.FIMINTERVALOPROMOCAOMED -- DDVENDAS-32698
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) THEN -- DDMEDICA-5980 - Markup
                                  'R'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('P','F')) THEN
                                  'P'
                                ELSE
                                  'D'
                                END TIPOPROMOCAO
                              , PCPROMOCAOMED.TIPOPOLITICA -- DDMEDICA-6952  
                              , (SELECT PCCONFIGSISTREGOPERLOG.CODCLIST
                                   FROM PCCONFIGSISTREGOPERLOG
                                  WHERE (PCCONFIGSISTREGOPERLOG.CODSISTEMA = pi_vCodSistema)
                                    AND (PCCONFIGSISTREGOPERLOG.NUMREGIAO  = PCPROMOCAOREGIAOMED.NUMREGIAO)
                                    AND (PCCONFIGSISTREGOPERLOG.CODFILIAL  = PCPROMOCAOFILMED.CODFILIAL)) CODCLIST
                              , (SELECT PCREGIAO.UF
                                   FROM PCREGIAO
                                  WHERE (PCREGIAO.NUMREGIAO = PCPROMOCAOREGIAOMED.NUMREGIAO)) UFREGIAO
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) AND -- DDMEDICA-5980 - Markup
                                     (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P','M')) THEN -- DDMEDICA-6952 - Markup sem Faixa de Quantidade
                                  'S'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P')) THEN
                                  'S'
                                ELSE
                                  CASE WHEN (NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0) = 1) THEN
                                    'S'
                                  ELSE
                                    'N'
                                  END
                                END ACEITA_PRINCIPAL
                              --
                              , PCPRODUT.CODPROD
                              , PCPRODUT.CODFORNEC
                              , PCPRODUT.CODMARCA
                              , PCPRODUT.CODCATEGORIA
                              , PCPRODUT.CODSEC
                              , PCPRODUT.CODLINHAPROD
                              , PCPRODUT.CODEPTO
                              , PCTABPR.PVENDA
                              , PCTABPR.PVENDA1
                              , PCTABPR.PVENDA2
                              , PCTABPR.PVENDA3
                              , PCTABPR.PVENDA4
                              , PCTABPR.PVENDA5
                              , PCTABPR.PVENDA6
                              , PCTABPR.PVENDA7
                              , PCPRODUT.CUSTOREP
                              , PCPRODUT.CUSTOREPZFM
                              , PCPRODUT.TIPOMERC
                              , PCPRODUT.UTILIZAPRECOFABRICA -- MED-2433
                              , 'A' ATIVOINATIVO
                              , PCPRODUT.FARMACIAPOPULAR
                              , PCPRODUT.NATUREZAPRODUTO
                              , PCPRODUT.PERPIS
                              , PCPRODUT.PERCOFINS
                              , PCPRODUT.PERCBONIFICVENDA PERCBONIFICVENDA_PROD
                              , PCTABPR.PERCBONIFICVENDA PERCBONIFICVENDA_REG
                              , PCPRODUT.OBS2
                              , PCTABPR.INDICEPRECO
                              , PCPRODUT.ESTOQUEPORLOTE -- 2956.004535.2018
                              , PCPRODUT.OBS
                              , PCPRODUT.CODLINHAPRAZO -- DDMEDICA-545
                              , PCDEPTO.TIPOMERC TIPOMERCDEP
                              , PCDESCONTO.PERCMARKUPMED           -- DDMEDICA-5980
                              , TO_NUMBER(NULL) PRIORIDADE_PRODUTO -- DDMEDICA-5980
                              , PCTABPR.VLST -- STP
                           FROM PCPRODUT
                              , PCTABPR
                              , PCDEPTO
                              --
                              , PCDESCONTO
                              , PCPROMOCAOMED
                              , PCPROMOCAOORIGEMMED
                              , PCPROMOCAOREGIAOMED
                              , PCPROMOCAOFILMED
                              --
                         WHERE (NVL(vvUsaMultiplasCondVenda,'N')        = 'P') -->> Processo Específico SERVCON
                           AND (NVL(vUSATODASRESTRVIEWPROMOSERVCON,'N') = 'N') -->> Mantém Processo Específico Filtrando só pelo Produto - DDMEDICA-5980
                           AND (PCDESCONTO.CODPROMOCAOMED          = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOREGIAOMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOFILMED.CODPROMOCAOMED    = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.ORIGEMPED      = 'W')       -->> Aqui continua W porque é o projeto específico
                           AND (PCDESCONTO.ORIGEMPED               = 'W')       -->> Aqui continua W porque é o projeto específico
                           AND (PCPROMOCAOMED.TIPOPROMOCAO        IN ('C','E','R')) -- DDMEDICA-5980 - Incluído Markup
                           AND (PCPROMOCAOREGIAOMED.NUMREGIAO      = PCTABPR.NUMREGIAO)
                           AND (PCTABPR.CODPROD                    = PCDESCONTO.CODPROD)
                           AND (PCPROMOCAOFILMED.CODFILIAL         = vc_RegiaoFilial.CODFILIALPADRAO) -->> Filial do Laço
                           --
                           AND (PCTABPR.CODPROD = PCPRODUT.CODPROD)
                           AND (PCPRODUT.CODEPTO  = PCDEPTO.CODEPTO(+))
                           AND (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                           AND (PCPRODUT.DTEXCLUSAO IS NULL)
                           AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
                         UNION  
                         -- DDMEDICA-6008 - Processo Específico SERVCON Filtrando por Depto, Seção, Categoria, Marca, Fornecedor ... e Origem E - Pedido Eletrônico
                         SELECT PCDESCONTO.CODPROMOCAOMED
                              , PCPROMOCAOFILMED.CODFILIAL
                              , PCPROMOCAOREGIAOMED.NUMREGIAO
                              , PCDESCONTO.PERCDESC
                              , PCDESCONTO.PERCDESCFIN
                              , PCDESCONTO.PRECOFIXOPROMOCAOMED
                              , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                              , PCDESCONTO.FIMINTERVALOPROMOCAOMED -- DDVENDAS-32698
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) THEN -- DDMEDICA-5980 - Markup
                                  'R'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('P','F')) THEN
                                  'P'
                                ELSE
                                  'D'
                                END TIPOPROMOCAO
                              , PCPROMOCAOMED.TIPOPOLITICA -- DDMEDICA-6952  
                              , (SELECT PCCONFIGSISTREGOPERLOG.CODCLIST
                                   FROM PCCONFIGSISTREGOPERLOG
                                  WHERE (PCCONFIGSISTREGOPERLOG.CODSISTEMA = pi_vCodSistema)
                                    AND (PCCONFIGSISTREGOPERLOG.NUMREGIAO  = PCPROMOCAOREGIAOMED.NUMREGIAO)
                                    AND (PCCONFIGSISTREGOPERLOG.CODFILIAL  = PCPROMOCAOFILMED.CODFILIAL)) CODCLIST
                              , (SELECT PCREGIAO.UF
                                   FROM PCREGIAO
                                  WHERE (PCREGIAO.NUMREGIAO = PCPROMOCAOREGIAOMED.NUMREGIAO)) UFREGIAO
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) AND -- DDMEDICA-5980 - Markup
                                     (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P','M')) THEN -- DDMEDICA-6952 - Markup sem Faixa de Quantidade
                                  'S'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P')) THEN
                                  'S'
                                ELSE
                                  CASE WHEN (NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0) = 1) THEN
                                    'S'
                                  ELSE
                                    'N'
                                  END
                                END ACEITA_PRINCIPAL
                              --
                              , PCPRODUT.CODPROD
                              , PCPRODUT.CODFORNEC
                              , PCPRODUT.CODMARCA
                              , PCPRODUT.CODCATEGORIA
                              , PCPRODUT.CODSEC
                              , PCPRODUT.CODLINHAPROD
                              , PCPRODUT.CODEPTO
                              , PCTABPR.PVENDA
                              , PCTABPR.PVENDA1
                              , PCTABPR.PVENDA2
                              , PCTABPR.PVENDA3
                              , PCTABPR.PVENDA4
                              , PCTABPR.PVENDA5
                              , PCTABPR.PVENDA6
                              , PCTABPR.PVENDA7
                              , PCPRODUT.CUSTOREP
                              , PCPRODUT.CUSTOREPZFM
                              , PCPRODUT.TIPOMERC
                              , PCPRODUT.UTILIZAPRECOFABRICA -- MED-2433
                              , 'A' ATIVOINATIVO
