                              --
                         WHERE (NVL(vvUsaMultiplasCondVenda,'N')        = 'P') -->> Processo Específico SERVCON
                           AND (NVL(vUSATODASRESTRVIEWPROMOSERVCON,'N') = 'S') -->> Mantém Processo Específico Filtrando por Tudo - DDMEDICA-5980
                           AND (PCDESCONTO.CODPROMOCAOMED          = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOREGIAOMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOFILMED.CODPROMOCAOMED    = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.ORIGEMPED      = vORIGEMPEDVIEWPROMOSERVCON)
                           AND (PCDESCONTO.ORIGEMPED               = 'F')
                           AND (PCDESCONTO.TIPOFV                  = 'PE')
                           AND (vORIGEMPEDVIEWPROMOSERVCON         = 'E')
                           AND (PCPROMOCAOMED.TIPOPROMOCAO        IN ('C','E','R')) -- DDMEDICA-5980 - Incluído Markup
                           AND (PCPROMOCAOREGIAOMED.NUMREGIAO      = PCTABPR.NUMREGIAO)
                           AND ((PCPRODUT.CODPROD                  = PCDESCONTO.CODPROD)      OR
                                (PCPRODUT.CODEPTO                  = PCDESCONTO.CODEPTO)      OR 
                                (PCPRODUT.CODSEC                   = PCDESCONTO.CODSEC)       OR 
                                (PCPRODUT.CODCATEGORIA             = PCDESCONTO.CODCATEGORIA) OR 
                                (PCPRODUT.CODMARCA                 = PCDESCONTO.CODMARCA)     OR 
                                (PCPRODUT.CODFORNEC                = PCDESCONTO.CODFORNEC)    OR 
                                (PCPRODUT.CODLINHAPROD             = PCDESCONTO.CODLINHAPROD) OR
                                ((PCDESCONTO.TIPOGRUPOREST         = 'GP') AND (PCDESCONTO.CODGRUPOREST = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                                                                                             FROM PCGRUPOSCAMPANHAI
                                                                                                            WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                                                                              AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                                                                                              AND PCGRUPOSCAMPANHAI.CODITEM  = PCPRODUT.CODPROD))))
                           AND (PCPROMOCAOFILMED.CODFILIAL         = vc_RegiaoFilial.CODFILIALPADRAO) -->> Filial do Laço
                           --
                           AND (PCTABPR.CODPROD = PCPRODUT.CODPROD)
                           AND (PCPRODUT.CODEPTO  = PCDEPTO.CODEPTO(+))
                           AND (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                           AND (PCPRODUT.DTEXCLUSAO IS NULL)
                           AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
                         UNION
                         -- DDMEDICA-6008 - Processo Específico SERVCON Filtrando por Depto, Seção, Categoria, Marca, Fornecedor ... e Origem W - ECommerce 
                         SELECT PCDESCONTO.CODPROMOCAOMED
                              , PCPROMOCAOFILMED.CODFILIAL
                              , PCPROMOCAOREGIAOMED.NUMREGIAO
                              , PCDESCONTO.PERCDESC
                              , PCDESCONTO.PERCDESCFIN
                              , PCDESCONTO.PRECOFIXOPROMOCAOMED
                              , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                              , PCDESCONTO.FIMINTERVALOPROMOCAOMED -- DDVENDAS-32698
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) THEN -- DDMEDICA-5980 - Markup
                                  'R'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('P','F')) THEN
                                  'P'
                                ELSE
                                  'D'
                                END TIPOPROMOCAO
                              , PCPROMOCAOMED.TIPOPOLITICA -- DDMEDICA-6952  
                              , (SELECT PCCONFIGSISTREGOPERLOG.CODCLIST
                                   FROM PCCONFIGSISTREGOPERLOG
                                  WHERE (PCCONFIGSISTREGOPERLOG.CODSISTEMA = pi_vCodSistema)
                                    AND (PCCONFIGSISTREGOPERLOG.NUMREGIAO  = PCPROMOCAOREGIAOMED.NUMREGIAO)
                                    AND (PCCONFIGSISTREGOPERLOG.CODFILIAL  = PCPROMOCAOFILMED.CODFILIAL)) CODCLIST
                              , (SELECT PCREGIAO.UF
                                   FROM PCREGIAO
                                  WHERE (PCREGIAO.NUMREGIAO = PCPROMOCAOREGIAOMED.NUMREGIAO)) UFREGIAO
                              , CASE 
                                WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('R')) AND -- DDMEDICA-5980 - Markup
                                     (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P','M')) THEN -- DDMEDICA-6952 - Markup sem Faixa de Quantidade
                                  'S'
                                WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('D','P')) THEN
                                  'S'
                                ELSE
                                  CASE WHEN (NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0) = 1) THEN
                                    'S'
                                  ELSE
                                    'N'
                                  END
                                END ACEITA_PRINCIPAL
                              --
                              , PCPRODUT.CODPROD
                              , PCPRODUT.CODFORNEC
                              , PCPRODUT.CODMARCA
                              , PCPRODUT.CODCATEGORIA
                              , PCPRODUT.CODSEC
                              , PCPRODUT.CODLINHAPROD
                              , PCPRODUT.CODEPTO
                              , PCTABPR.PVENDA
                              , PCTABPR.PVENDA1
                              , PCTABPR.PVENDA2
                              , PCTABPR.PVENDA3
                              , PCTABPR.PVENDA4
                              , PCTABPR.PVENDA5
                              , PCTABPR.PVENDA6
                              , PCTABPR.PVENDA7
                              , PCPRODUT.CUSTOREP
                              , PCPRODUT.CUSTOREPZFM
                              , PCPRODUT.TIPOMERC
                              , PCPRODUT.UTILIZAPRECOFABRICA -- MED-2433
                              , 'A' ATIVOINATIVO
                              , PCPRODUT.FARMACIAPOPULAR
                              , PCPRODUT.NATUREZAPRODUTO
                              , PCPRODUT.PERPIS
                              , PCPRODUT.PERCOFINS
                              , PCPRODUT.PERCBONIFICVENDA PERCBONIFICVENDA_PROD
                              , PCTABPR.PERCBONIFICVENDA PERCBONIFICVENDA_REG
                              , PCPRODUT.OBS2
                              , PCTABPR.INDICEPRECO
                              , PCPRODUT.ESTOQUEPORLOTE -- 2956.004535.2018
                              , PCPRODUT.OBS
                              , PCPRODUT.CODLINHAPRAZO -- DDMEDICA-545
                              , PCDEPTO.TIPOMERC TIPOMERCDEP
                              , PCDESCONTO.PERCMARKUPMED -- DDMEDICA-5980
                              , CASE WHEN (PCDESCONTO.CODPROD      IS NOT NULL) THEN 1
                                     WHEN ((PCDESCONTO.TIPOGRUPOREST = 'GP') AND (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                                                                    FROM PCGRUPOSCAMPANHAI
                                                                                   WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                                                     AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                                                                     AND PCGRUPOSCAMPANHAI.CODITEM  = PCPRODUT.CODPROD) IS NOT NULL) THEN 1.5
                                     WHEN (PCDESCONTO.CODFORNEC    IS NOT NULL) THEN 2
                                     WHEN (PCDESCONTO.CODMARCA     IS NOT NULL) THEN 3
                                     WHEN (PCDESCONTO.CODCATEGORIA IS NOT NULL) THEN 4
                                     WHEN (PCDESCONTO.CODSEC       IS NOT NULL) THEN 5
                                     WHEN (PCDESCONTO.CODLINHAPROD IS NOT NULL) THEN 6
                                     WHEN (PCDESCONTO.CODEPTO      IS NOT NULL) THEN 7
                                     ELSE 8
                                END PRIORIDADE_PRODUTO
                              , PCTABPR.VLST -- STP
                           FROM PCPRODUT
                              , PCTABPR
                              , PCDEPTO
                              --
                              , PCDESCONTO
                              , PCPROMOCAOMED
                              , PCPROMOCAOORIGEMMED
                              , PCPROMOCAOREGIAOMED
                              , PCPROMOCAOFILMED
                              --
                         WHERE (NVL(vvUsaMultiplasCondVenda,'N')        = 'P') -->> Processo Específico SERVCON
                           AND (NVL(vUSATODASRESTRVIEWPROMOSERVCON,'N') = 'S') -->> Mantém Processo Específico Filtrando por Tudo - DDMEDICA-5980
                           AND (PCDESCONTO.CODPROMOCAOMED          = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOREGIAOMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOFILMED.CODPROMOCAOMED    = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCPROMOCAOORIGEMMED.ORIGEMPED      = vORIGEMPEDVIEWPROMOSERVCON)
                           AND (PCDESCONTO.ORIGEMPED               = vORIGEMPEDVIEWPROMOSERVCON)
                           AND (vORIGEMPEDVIEWPROMOSERVCON         = 'W')
                           AND (PCPROMOCAOMED.TIPOPROMOCAO        IN ('C','E','R')) -- DDMEDICA-5980 - Incluído Markup
                           AND (PCPROMOCAOREGIAOMED.NUMREGIAO      = PCTABPR.NUMREGIAO)
                           AND ((PCPRODUT.CODPROD                  = PCDESCONTO.CODPROD)      OR
                                (PCPRODUT.CODEPTO                  = PCDESCONTO.CODEPTO)      OR 
                                (PCPRODUT.CODSEC                   = PCDESCONTO.CODSEC)       OR 
                                (PCPRODUT.CODCATEGORIA             = PCDESCONTO.CODCATEGORIA) OR 
                                (PCPRODUT.CODMARCA                 = PCDESCONTO.CODMARCA)     OR 
                                (PCPRODUT.CODFORNEC                = PCDESCONTO.CODFORNEC)    OR 
                                (PCPRODUT.CODLINHAPROD             = PCDESCONTO.CODLINHAPROD) OR
                                ((PCDESCONTO.TIPOGRUPOREST         = 'GP') AND (PCDESCONTO.CODGRUPOREST = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                                                                                             FROM PCGRUPOSCAMPANHAI
                                                                                                            WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                                                                              AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                                                                                              AND PCGRUPOSCAMPANHAI.CODITEM  = PCPRODUT.CODPROD))))
                           AND (PCPROMOCAOFILMED.CODFILIAL         = vc_RegiaoFilial.CODFILIALPADRAO) -->> Filial do Laço
                           --
                           AND (PCTABPR.CODPROD = PCPRODUT.CODPROD)
                           AND (PCPRODUT.CODEPTO  = PCDEPTO.CODEPTO(+))
                           AND (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                           AND (PCPRODUT.DTEXCLUSAO IS NULL)
                           AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
                         UNION
                         -- Demais Processos
                         SELECT TO_NUMBER(NULL)                 CODPROMOCAOMED
                              , vc_RegiaoFilial.CODFILIALPADRAO CODFILIAL
                              , vc_RegiaoFilial.NUMREGIAOPADRAO NUMREGIAO
                              , TO_NUMBER(NULL)                 PERCDESC
                              , TO_NUMBER(NULL)                 PERCDESCFIN
                              , TO_NUMBER(NULL)                 PRECOFIXOPROMOCAOMED
                              , TO_NUMBER(NULL)                 INICIOINTERVALOPROMOCAOMED
                              , TO_NUMBER(NULL)                 FIMINTERVALOPROMOCAOMED -- DDVENDAS-32698
                              , NULL                            TIPOPROMOCAO
                              , NULL                            TIPOPOLITICA
                              , vc_RegiaoFilial.CODCLIPADRAO    CODCLIST
                              , vc_RegiaoFilial.UFREGIAOPADRAO  UFREGIAO
                              , 'S'                             ACEITA_PRINCIPAL
                              --
                              , PCPRODUT.CODPROD
                              , PCPRODUT.CODFORNEC
                              , PCPRODUT.CODMARCA
                              , PCPRODUT.CODCATEGORIA
                              , PCPRODUT.CODSEC
                              , PCPRODUT.CODLINHAPROD
                              , PCPRODUT.CODEPTO
                              , PCTABPR.PVENDA
                              , PCTABPR.PVENDA1
                              , PCTABPR.PVENDA2
                              , PCTABPR.PVENDA3
                              , PCTABPR.PVENDA4
                              , PCTABPR.PVENDA5
                              , PCTABPR.PVENDA6
                              , PCTABPR.PVENDA7
                              , PCPRODUT.CUSTOREP
                              , PCPRODUT.CUSTOREPZFM
                              , PCPRODUT.TIPOMERC
                              , PCPRODUT.UTILIZAPRECOFABRICA -- MED-2433
                              , 'A' ATIVOINATIVO
                              , PCPRODUT.FARMACIAPOPULAR
                              , PCPRODUT.NATUREZAPRODUTO
                              , PCPRODUT.PERPIS
                              , PCPRODUT.PERCOFINS
                              , PCPRODUT.PERCBONIFICVENDA PERCBONIFICVENDA_PROD
                              , PCTABPR.PERCBONIFICVENDA PERCBONIFICVENDA_REG
                              , PCPRODUT.OBS2
                              , PCTABPR.INDICEPRECO
                              , PCPRODUT.ESTOQUEPORLOTE -- 2956.004535.2018
                              , PCPRODUT.OBS
                              , PCPRODUT.CODLINHAPRAZO -- DDMEDICA-545
                              , PCDEPTO.TIPOMERC TIPOMERCDEP
                              , TO_NUMBER(NULL) PERCMARKUPMED -- DDMEDICA-5980
                              , TO_NUMBER(NULL) PRIORIDADE_PRODUTO -- DDMEDICA-5980
                              , PCTABPR.VLST -- STP
                           FROM PCPRODUT
                              , PCTABPR
                              , PCDEPTO
                         WHERE (NVL(vvUsaMultiplasCondVenda,'N') <> 'P')             -->> Demais Processos diferentes do SERVCON
                           AND (PCTABPR.CODPROD = PCPRODUT.CODPROD)
                           AND (PCPRODUT.CODEPTO = PCDEPTO.CODEPTO(+))
                           AND (PCTABPR.NUMREGIAO = vc_RegiaoFilial.NUMREGIAOPADRAO) --> REGIÃO DO LAÇO PARA PESQUISAR O PREÇO
                           AND (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                           AND (PCPRODUT.DTEXCLUSAO IS NULL)
                          -- DDMEDICA-6008 - Ordenação requerida na priorização do desconto dentro da própria promoção
                         ORDER BY CODPROMOCAOMED
                                , NUMREGIAO
                                , CODPROD
                                , PRIORIDADE_PRODUTO
                                , INICIOINTERVALOPROMOCAOMED -- DDVENDAS-32698
                         ) LOOP
  
        -- Achou Tabela de Preços
        vbAchouTabelaPreco := TRUE;
  
          -- Iniciar TRUE DDMEDICA-2494
        vbGravarProduto    := TRUE;

        -------------------------------------
        -- Validação dos Atributos do Produto
        -------------------------------------
        IF (NVL(vc_Produto.TIPOMERC,'X') IN ('IM','CI','RD')) THEN
          vbGravarProduto := FALSE;
          -- CONTROLE DE RELATÓRIO ---------
          P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                           vc_Produto.CODFILIAL,
                           NULL,
                           vc_Produto.CODPROD,
                           'P', -- Critica Por Produto
                           'Tipo Mercadoria de Produto "IM" ou "CI" ou "RD" não permitidos');
        ----------------------------------
        ELSIF (NVL(vc_Produto.TIPOMERCDEP,'X') IN ('IM','CI','RD')) THEN
          vbGravarProduto := FALSE;
          -- CONTROLE DE RELATÓRIO ---------
          P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                           vc_Produto.CODFILIAL,
                           NULL,
                           vc_Produto.CODPROD,
                           'P', -- Critica Por Produto
                           'Tipo Mercadoria de Depto "IM" ou "CI" ou "RD" não permitidos');
          ----------------------------------
        ELSE
          IF (NVL(vc_Produto.OBS,'X') = 'PV') THEN
            vbGravarProduto := FALSE;
            -- CONTROLE DE RELATÓRIO ---------
            P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                             vc_Produto.CODFILIAL,
                             NULL,
                             vc_Produto.CODPROD,
                             'P', -- Critica Por Produto
                             'Produto Proibido para Venda');
            ----------------------------------
          ELSE
            IF (NVL(vc_Produto.OBS,'X') = 'EQ') THEN
            vbGravarProduto := FALSE;
              -- CONTROLE DE RELATÓRIO ---------
              P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                               vc_Produto.CODFILIAL,
                               NULL,
                               vc_Produto.CODPROD,
                               'P', -- Critica Por Produto
                               'Produto cadastrado com Observação EQ-Equipamento');
            END IF;
          END IF;
        END IF;
  
        ---------------------------------------------------------------------------------------------
        ---------------------------------------------------------------------------------------------
        -- LAÇO DE CONDIÇÕES PARA A REGIÃO E FILIAL
        -------------------------------------------
        -------------------------------------------
        vbAchouCondicaoProduto := FALSE;
        IF (vtListaCondicoes.COUNT > 0) THEN
          FOR viIdxCondicao IN vtListaCondicoes.FIRST..vtListaCondicoes.LAST LOOP
            
            -- Achou Condição de Venda para o Produto
            vbAchouCondicaoProduto := TRUE;
  
            -----------------------------------------------------------------------------------------
            -- DEFINIÇÃO DA CONDIÇÃO
            -----------------------------------------------------------------------------------------
            -->> Processo Específico SERVCON
            IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
  
              -- Vai gerar as Condições a partir do Select Gerar PCDESCONTO x PCTABPR
              vnCodCondicaoVenda := vc_Produto.CODPROMOCAOMED;
                
            -->> Demais Processos
            ELSE
  
              -- Pega o Código da Condição
              vnCodCondicaoVenda := vtListaCondicoes(viIdxCondicao).vnCodCondicaoVenda;
  
            END IF;
            -----------------------------------------------------------------------------------------
  
            -- Pesquisa Coluna da Tabela de Preços do Plano de Pagamento da Condição de Venda
            BEGIN
              SELECT PCPLPAG.NUMPR
                INTO vnNumPr
               FROM PCPLPAG
               WHERE (PCPLPAG.CODPLPAG = vtListaCondicoes(viIdxCondicao).vnCodPlPag);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnNumPr := 1;
            END;
            IF (NVL(vnNumPr,0) = 0) THEN -- Garante ao menos a Coluna 1 se não tiver preenchido
              vnNumPr := 1;
            END IF;
  
            IF (vbGravarProduto) THEN -- Se passou pela validação anterior
            -- Restrição de Marcas
            IF    (vvTipoPesquisaMarcas = 'G') THEN
              -->> Pesquisa Geral de Marcas, considera TODOS os Produtos
              vbGravarProduto := TRUE;
            ELSIF (vvTipoPesquisaMarcas = 'E') THEN
              -->> Pesquisa Específica de Marcas, somente considera as Marcas Cadastradas na Rotina 2325
              IF (vtRestricaoMarca.EXISTS(vc_Produto.CODMARCA)) THEN
                vbGravarProduto := TRUE;
              ELSE
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                 vc_Produto.CODFILIAL,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Restrição de Marca da Rotina 2325');
                ----------------------------------
                END IF;
              END IF;
            END IF;
  
           /*
            -- Restrição de KIT
            IF (vbGravarProduto) THEN -- Se passou pela validação anterior
              IF (vtSistCondVenda(viIdx).vvKit = 'S') THEN
                -- Se existe o Produto no Array de Itens de Kit
                IF (vtItensKit.EXISTS(vc_Produto.CODPROD)) THEN
                  vbGravarProduto := TRUE;
                ELSE
                  vbGravarProduto := FALSE;
                END IF;
              END IF;
            END IF;
            */
  
            -- HIS.01061.2016 - Envia FV
            IF (vbValidaEnviaFv) THEN -->> Somente SE VALIDAR O CAMPO ENVIA FV
              IF (vbGravarProduto) THEN -- Se passou pela validação anterior
                IF (vtEstoque_CodProd_EnviaFv.EXISTS(vc_Produto.CODPROD)) THEN
                  IF (vtEstoque_CodProd_EnviaFv(vc_Produto.CODPROD) = 'S') THEN
                    vbGravarProduto := TRUE;
                  ELSE
                    vbGravarProduto := FALSE;
                    -- CONTROLE DE RELATÓRIO ---------
                    P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                     vc_Produto.CODFILIAL,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Campo "Enviar para Força de Vendas" = Não (Cadastro do Produto por Filial)');
                    ----------------------------------
                  END IF;
                ELSE
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                   vc_Produto.CODFILIAL,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Campo "Enviar para Força de Vendas" = Não (Cadastro do Produto por Filial)');
                  ----------------------------------
                END IF;
              END IF;
            END IF;
  
            -- DDMEDICA-5540 - Envia Dicionário de Dados
            IF (vbValidaEnviarDicD) THEN -->> Somente SE VALIDAR O CAMPO Envia Dicionário de Dados
              IF (vbGravarProduto) THEN -- Se passou pela validação anterior
                IF (vtEstoque_CodProd_EnviarDicD.EXISTS(vc_Produto.CODPROD)) THEN
                  IF (vtEstoque_CodProd_EnviarDicD(vc_Produto.CODPROD) = 'S') THEN
                    vbGravarProduto := TRUE;
                  ELSE
                    vbGravarProduto := FALSE;
                    -- CONTROLE DE RELATÓRIO ---------
                    P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                     vc_Produto.CODFILIAL,
                                     vnCodCondicaoVenda,
                                     vc_Produto.CODPROD,
                                     'P', -- Critica Por Produto
                                     'Campo "Enviar para no Dicionário de Dados Farma" = Não (Cadastro do Produto por Filial)');
                    ----------------------------------
                  END IF;
                ELSE
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                   vc_Produto.CODFILIAL,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Campo "Enviar para no Dicionário de Dados Farma" = Não (Cadastro do Produto por Filial)');
                  ----------------------------------
                END IF;
              END IF;
            END IF;

            ----------------
            -- Saldo Estoque
            ----------------
            IF (vtEstoque_CodProd_Saldo.EXISTS(vc_Produto.CODPROD)) THEN
              vnSaldoEstoque := NVL(vtEstoque_CodProd_Saldo(vc_Produto.CODPROD),0);
            ELSE
              vnSaldoEstoque := NULL;
            END IF;
  
            -- Validação Estoque
            IF (vbValidaEstoque) THEN
              IF (NVL(vnSaldoEstoque,0) <= 0) THEN
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                 vc_Produto.CODFILIAL,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Produto sem Estoque Disponível para Venda');
                ----------------------------------
              END IF;
            END IF;
  
            -----------------------------------
            -- Custo do Produto - DDMEDICA-5980
            -----------------------------------
            IF (vtEstoque_CodProd_Custo.EXISTS(vc_Produto.CODPROD)) THEN
              vnCustoFinanceiro := NVL(vtEstoque_CodProd_Custo(vc_Produto.CODPROD),0);
            ELSE
              vnCustoFinanceiro := 0;
            END IF;

            ---------------------------------------
            -- Validação ShelfLife - HIS.02727.2016
            ---------------------------------------
            IF (vbValidaShelfLife) AND
               (NVL(vc_Produto.ESTOQUEPORLOTE,'N') = 'S') THEN -- Somente Produtos com Estoque por Lote - 2956.004535.2018
  
              -- Pesquisa ShelfLife
              IF (NOT vtProShelfLife.EXISTS(vc_Produto.CODPROD)) THEN
                vbGravarProduto := FALSE;
                -- CONTROLE DE RELATÓRIO ---------
                P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                 vc_Produto.CODFILIAL,
                                 vnCodCondicaoVenda,
                                 vc_Produto.CODPROD,
                                 'P', -- Critica Por Produto
                                 'Produto sem Estoque por Lote conforme Shelf Life do Cliente (Prazo de Validade minímo do lote)');
                ----------------------------------
              END IF;
  
            END IF; -- FIM: (vbValidaShelfLife)
            
            --------------------------------------------------------------------------------------------------------------------------------------------------
            -- DDMEDICA-6008 - A Cada Região + Promoção que muda eu limpo o Array de Prioridade da Restrição da Promoção (Ex: Produto é prioritário que Marca)
            -- Se envia a Promoção para o Servcon serão lidos os descontos por Depto, Seção, Categoria, Marca ...
            --------------------------------------------------------------------------------------------------------------------------------------------------
            IF (NVL(vvUsaMultiplasCondVenda,'N')       = 'P')  AND
               (NVL(vUSATODASRESTRVIEWPROMOSERVCON,'N') = 'S') THEN
              IF (vvQuebraPrioridadeRestrPromo <> (TO_CHAR(vc_Produto.NUMREGIAO) || '|' || TO_CHAR(vc_Produto.CODPROMOCAOMED))) THEN
                vtPrioridadeRestrPromocao.DELETE;
                vtControleEscalonamento.DELETE;  -- DDVENDAS-32698
                DELETE FROM PCTEMP_SELECIONADOS; -- DDVENDAS-32698
                vvQuebraPrioridadeRestrPromo := (TO_CHAR(vc_Produto.NUMREGIAO) || '|' || TO_CHAR(vc_Produto.CODPROMOCAOMED));
              END IF;  
              -- DDVENDAS-32698 - INICIO: Controle por Inicio Intervalo Quantidade + Código do Produto
              vnIdxPrioridade := NVL(vc_Produto.INICIOINTERVALOPROMOCAOMED,0);
              IF (NVL(vnIdxPrioridade,0) = 0) THEN
                vnIdxPrioridade := 1;
              END IF;
              vnIdxPrioridade := TO_NUMBER(TO_CHAR(vnIdxPrioridade) || TO_CHAR(vc_Produto.CODPROD)); 
              -- Tenta usar a memória que é mais rápido enquanto não excede o Binary Integer
              IF (vnIdxPrioridade <= 1999999999) THEN
                -- Se já processou o Desconto Prioritário para o Produto 
                IF (vtPrioridadeRestrPromocao.EXISTS(vnIdxPrioridade)) THEN
                  -- Não grava o Produto (já foi gravado com um desconto de maior prioridade)
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                   vc_Produto.CODFILIAL,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Tipo de Desconto de prioridade ' || vc_Produto.PRIORIDADE_PRODUTO || ' ignorada. Já foi aplicado o de prioridade ' || vtPrioridadeRestrPromocao(vnIdxPrioridade) || ' [' || vc_Produto.INICIOINTERVALOPROMOCAOMED || ', ' || vc_Produto.CODPROD || ']');
                  ----------------------------------
                ELSE
                  -- Registra o Inicio Intervalo Quantidade + Produto no Array para não deixar gravar ele novamente com um desconto de menor prioridade na Promoção
                  vtPrioridadeRestrPromocao(vnIdxPrioridade) := vc_Produto.PRIORIDADE_PRODUTO;
                END IF;
              -- Se ultrapassar o Binary Integer, usa Tabela em BD
              ELSE
                BEGIN
                  SELECT LETRAS
                    INTO vvValorPrioridade
                    FROM PCTEMP_SELECIONADOS
                   WHERE (NUMERO = vnIdxPrioridade);
                  -- Se já processou o Desconto Prioritário para o Produto 
                  -- Não grava o Produto (já foi gravado com um desconto de maior prioridade)
                  vbGravarProduto := FALSE;
                  -- CONTROLE DE RELATÓRIO ---------
                  P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                   vc_Produto.CODFILIAL,
                                   vnCodCondicaoVenda,
                                   vc_Produto.CODPROD,
                                   'P', -- Critica Por Produto
                                   'Tipo de Desconto de prioridade ' || vc_Produto.PRIORIDADE_PRODUTO || ' ignorada. Já foi aplicado o de prioridade ' || vvValorPrioridade || ' [' || vc_Produto.INICIOINTERVALOPROMOCAOMED || ', ' || vc_Produto.CODPROD || ']');
                  ----------------------------------                   
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    -- Registra o Inicio Intervalo Quantidade + Produto no Array para não deixar gravar ele novamente com um desconto de menor prioridade na Promoção
                    INSERT INTO PCTEMP_SELECIONADOS
                              ( NUMERO
                              , LETRAS )
                       VALUES ( vnIdxPrioridade 
                              , vc_Produto.PRIORIDADE_PRODUTO );
                END;
              END IF;                
              -- DDVENDAS-32698 - FIM: Controle por Inicio Intervalo Quantidade + Código do Produto
            END IF;
  
           /************************
            SE PODE GRAVAR O PRODUTO
            ************************/
            IF (vbGravarProduto) THEN
  
              ------------------------------------------------------------------------
              -- Restringe envio de Produtos conforme o Fora de Linha - HIS.03857.2015
              ------------------------------------------------------------------------
              IF (NVL(vvGeraDicionarioForcaVendas,'N') = 'S') OR                                                                           -->> Se Força de Vendas envia todos os produtos independentemente de ser Fora de Linha
                 ((NVL(vvGeraDicionarioForcaVendas,'N') = 'N') AND (NVL(vc_Produto.OBS2,' ') <> 'FL')) OR                                  -->> Se não for Força de Vendas: Se não for Fora de Linha pode enviar o Produto
                 ((NVL(vvGeraDicionarioForcaVendas,'N') = 'N') AND (NVL(vc_Produto.OBS2,' ') = 'FL') AND (NVL(vnSaldoEstoque,0) > 0)) THEN -->> Se não for Força de Vendas: Se for Fora Restringe, somente pode enviar Produtos com Estoque
  
                -- Verifica se a Região é Zona Franca
                BEGIN
                  SELECT PCREGIAO.REGIAOZFM
                    INTO vvRegiaoZfm
                    FROM PCREGIAO
                   WHERE (PCREGIAO.NUMREGIAO = vc_Produto.NUMREGIAO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvRegiaoZfm := 'N';
                END;
  
                -- Dados Complementares - Cliente ST
                BEGIN
                  SELECT PARTICIPAFARMACIAPOPULAR
                       , ESTENT
                    INTO vvParticipaFarmaciaPopular
                       , vvUfCliente
                    FROM PCCLIENT
                   WHERE (CODCLI = vc_Produto.CODCLIST);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                   vvParticipaFarmaciaPopular := 'N';
                   vvUfCliente                := NULL;
                END;
  
                -- Se usa Tributação por UF
                IF (NVL(vvUsaTributacaoPorUf,'N') = 'S') THEN
                  -- Pesquisa Tributação por UF
                  BEGIN
                    SELECT CODST
                      INTO vnCodSt
                      FROM PCTABTRIB
                     WHERE (CODPROD     = vc_Produto.CODPROD)
                       AND (UFDESTINO   = vvUfCliente)
                       AND (CODFILIALNF = vc_Produto.CODFILIAL);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vnCodSt := NULL;
                  END;
                -- Se NÃO usa Tributação por UF
                ELSE
                  -- Pesquisa Tributação por Região
                  BEGIN
                    SELECT CODST
                      INTO vnCodSt
                      FROM PCTABPR
                     WHERE (CODPROD   = vc_Produto.CODPROD)
                       AND (NUMREGIAO = vc_Produto.NUMREGIAO);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vnCodSt := NULL;
                  END;
                END IF; -- Fim Condição v_usatributacaoporuf
  
                -- Dados Complementares do Produto - Tributação
                BEGIN
                  SELECT PCTRIBUT.CODICM
                       , PCTRIBUT.PERCBASERED
                       , PCTRIBUT.PAUTAFONTE
                       , PCTRIBUT.PERDESTAB
                       , PCTRIBUT.IVAFONTE
                       , PCTRIBUT.USAPMCBASEST
                       , PCTRIBUT.BNFNAOCALCULAICMS
                       , PCTRIBUT.USABASEICMSREDUZIDA
                       , PCTRIBUT.ALIQICMS1FONTE
                       , PCTRIBUT.ALIQICMS2FONTE
                       , PCTRIBUT.PERCBASEREDSTFONTE
                       , PCTRIBUT.utilizarstfonteprecific --STP
                    INTO vnPercIcm
                       , vnPercBaseRedIcm
                       , vnPautaFonte
                       , vnPerDesTab
                       , vnIvaFonte
                       , vvUsaPmcBaseSt
                       , vvBnfNaoCalculaIcms
                       , vvUsaBaseIcmsReduzida
                       , vnAliqIcms1Fonte
                       , vnAliqIcms2Fonte
                       , vnPercBaseRedStFonte
                       , vvutilizarstfonteprecific --STP
                    FROM PCTRIBUT
                   WHERE (PCTRIBUT.CODST = vnCodSt);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnPercIcm        := 0;
                    vnPercBaseRedIcm := 0;
                    vnPautaFonte     := 0;
                    vnPerDesTab      := 0;
                    vnIvaFonte       := 0;
                    vvUsaPmcBaseSt   := 'N';
                    vvBnfNaoCalculaIcms   := 'N';
                    vvUsaBaseIcmsReduzida := 'N';
                    vnAliqIcms1Fonte      := 0;
                    vnAliqIcms2Fonte      := 0;
                    vnPercBaseRedStFonte  := 0;
                    vvutilizarstfonteprecific := 'N';  -- STP  
                END;
                IF (NVL(vnPercBaseRedIcm,0) = 0) THEN
                  vnPercBaseRedIcm := 100;
                END IF;
                vnPercBaseRedIcm := (100 - NVL(vnPercBaseRedIcm,0));
                IF (NVL(vnPercBaseRedIcm,0) < 0) THEN
                  vnPercBaseRedIcm := 0;
                END IF;
                -- Zera Desconto Repasse se na Integradora não estiver marcada para Aplicar o Desconto PTabela da Tributação
                IF (vvAplicarDescPtabelaTribut <> 'S') THEN
                  vnPerDesTab := 0;
                END IF;
  
                -- Obtem UF da Região
                BEGIN
                  SELECT PCREGIAO.UF
                    INTO vvUfRegiao
                    FROM PCREGIAO
                   WHERE (PCREGIAO.NUMREGIAO = vc_Produto.NUMREGIAO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvUfRegiao := NULL;
                END;
  
                -- Obtém PMC e Preço Fábrica
                PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(vc_Produto.CODFILIAL,
                                                     vc_Produto.CODPROD,
                                                     vvUfRegiao,
                                                     vc_Produto.NUMREGIAO,
                                                     vnPrecoMaxConsum,
                                                     vnPrecoFabrica,
                                                     vvMensagemPmc);
  
                -- Define o Preço
                IF    (vnNumPr = 1) THEN
                  vnPreco := NVL(vc_Produto.PVENDA1,0);
                ELSIF (vnNumPr = 2) THEN
                  vnPreco := NVL(vc_Produto.PVENDA2,0);
                ELSIF (vnNumPr = 3) THEN
                  vnPreco := NVL(vc_Produto.PVENDA3,0);
                ELSIF (vnNumPr = 4) THEN
                  vnPreco := NVL(vc_Produto.PVENDA4,0);
                ELSIF (vnNumPr = 5) THEN
                  vnPreco := NVL(vc_Produto.PVENDA5,0);
                ELSIF (vnNumPr = 6) THEN
                  vnPreco := NVL(vc_Produto.PVENDA6,0);
                ELSIF (vnNumPr = 7) THEN
                  vnPreco := NVL(vc_Produto.PVENDA7,0);
                ELSE
                  vnPreco := 0;
                END IF;
                -- Tira st fonte da precificaçao -- STP
                IF (vvutilizarstfonteprecific = 'S') AND
                   (vnPreco > 0) THEN
                  vnPreco := NVL(vnPreco,0) - NVL(vc_Produto.VLST,0);  
                END IF;
              -- Aplica Indice sobre o Preço Tabela
              vnIndicePreco := 0;
              IF (NVL(vvGerarAcordoPreco,'N') = 'S')         AND
                 (NVL(vvAplicarIndiceAcordoPreco,'N') = 'S') AND
                 (NVL(vc_Produto.INDICEPRECO,0) <> 0)        THEN
                vnPreco       := (NVL(vnPreco,0) * NVL(vc_Produto.INDICEPRECO,0));
                vnIndicePreco := NVL(vc_Produto.INDICEPRECO,0);
              END IF;
              -- Guarda o Preço Tabela Original com o Indice de Preco
              vnPrecoTabelaOriginalComIndice := vnPreco;
  
                -- Se Medicamento
                IF (NVL(vc_Produto.TIPOMERC,' ') IN ('M','MA')) OR
                   (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') = 'S') THEN -- MED-2433
                  -- Se Origem Preço é Fábrica
                  IF (NVL(vvOrigemPreco,'F') = 'F') THEN
                    -- Se Zona Franca
                    IF (NVL(vvRegiaoZfm,'N') = 'S') THEN
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREPZFM,0);
                    -- Se NÃO FOR Zona Franca
                    ELSE
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREP,0);
                    END IF;
                    -- Desconto de Repasse
                    IF (vvAplicarDescPtabelaTribut = 'S') THEN
                      vnPreco := round(vnPreco * (1 - (nvl(vnPerDesTab,0) / 100)),vnNumCasasDecVenda);
                    END IF;
                -- Se não for Fábrica, trato as exceções
                ELSE
                  -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela e mandar o Preço Fábrica,
                  -- onde a Integradora tem Origem Preço = Preço Tabela
                  IF (vUSAREGRARECALDESCPTABMED2313 = 'S') THEN
                    ------------------
                    -- Se Zona Franca
                    IF (NVL(vvRegiaoZfm,'N') = 'S') THEN
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREPZFM,0);
                    -- Se NÃO FOR Zona Franca
                    ELSE
                      vnPreco := NVL(vnPrecoFabrica,0); --NVL(vc_Produto.CUSTOREP,0);
                    END IF;
                    -- Desconto de Repasse
                    IF (vvAplicarDescPtabelaTribut = 'S') THEN
                      vnPreco := round(vnPreco * (1 - (nvl(vnPerDesTab,0) / 100)),vnNumCasasDecVenda);
                    END IF;
                    ------------------
                  END IF;
                END IF;
              END IF;
  
                -- Se Origem Preço é Tabela de Preços, que pode considerar a Bonificação (Estará no PTabela)
                IF (NVL(vvOrigemPreco,'F') = 'T') THEN
  
                  -- Percentual de Bonificação na Venda - PADRÃO
                  IF (NVL(vvUtilizaPercBonifiVendaRegiao,'N') = 'S') THEN
                    vnPercBonificVenda := NVL(vc_Produto.PERCBONIFICVENDA_REG,0);
                  ELSE
                    vnPercBonificVenda := NVL(vc_Produto.PERCBONIFICVENDA_PROD,0);
                  END IF;
  
                  -- Percentual de Bonificação na Venda [33 - Integradora MichaelSoft]
                  -- Soment enviar %bonific nos medicamentos
                  IF (NVL(vnLayout,0) = 33) THEN
                    IF (NVL(vc_Produto.TIPOMERC,' ') NOT IN ('M','MA')) THEN
                      vnPercBonificVenda := 0;
                    END IF;
                  END IF;
  
                ELSE
  
                  -- Origem Preço Fábrica não aplica % Bonificação
                  vnPercBonificVenda := 0;
  
                END IF;
  
                -- Acordo de Mídia - DDMEDICA-545
                BEGIN
                  SELECT PCCONDVENDALINHA.PERCACORDOMIDIA
                    INTO vnPercAcordoMidia
                    FROM PCCONDVENDALINHA
                   WHERE (PCCONDVENDALINHA.CODCONDICAOVENDA = vnCodCondicaoVenda)
                     AND (PCCONDVENDALINHA.CODLINHAPRAZO    = vc_Produto.CODLINHAPRAZO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnPercAcordoMidia := 0;
                END;
  
                -- Inicializa Flag de encontrar o Desconto para o Produto
                vbAchouDescQuant            := FALSE;
                vbAchouDesconto             := FALSE;
                vnPercDesc                  := 0;
                vnPercDesc1                 := 0;
                vnPercDesc2                 := 0;
                vnPercDescFin               := 0;
                vnQtdeMinima                := 1;
                vnCodPromocaoMed            := NULL;
                vnCodPromocaoMedFaixaQtde   := NULL;
                vnPrecoPromocional          := 0;
                vvTipoPromocao              := NULL;
                vvTipoPrecoDesconto         := NULL;
                vvTipoPrecoDescFaixaQtde    := NULL;
                vnPercAcrescAcordo          := NULL;
                vnValorAcordoMidia          := 0; -- DDMEDICA-545
                vnPercMarkupMed             := NULL; -- DDMEDICA-5980  
                vnCustoFinanceiroMkp        := NULL; -- DDMEDICA-5980  
  
               /*----------------------------------------------------------------
                Condições de Venda x Produtos x Descontos/Preço Promocional
                IMPORTANTE: Os cursores abaixo buscam pelo código da
                            condição de venda, logo só trazem os preços
                            ou descontos das promoção padrão armazenada
                            na variável vtSistCondVenda(viIdx).vnCodCondicaoVenda
                ----------------------------------------------------------------*/
                -->> Se Processo Específico Servcon
                IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
                  -- Se Promoção de Preço
                  IF (vc_Produto.TIPOPROMOCAO = 'P') THEN
                    vvTipoPromocao      := vc_Produto.TIPOPROMOCAO;
                    vnPrecoPromocional  := vc_Produto.PRECOFIXOPROMOCAOMED;
                    vnPercDescFin       := vc_Produto.PERCDESCFIN;
                    vnQtdeMinima        := vc_Produto.INICIOINTERVALOPROMOCAOMED;
                    vnCodPromocaoMed    := vc_Produto.CODPROMOCAOMED;
                    vvTipoPrecoDesconto := 'P';
                  END IF;
                -->> Demais Processos
                ELSE
                  -- Verificar se existe Promoção de Preço Fixo (PRIORITARIA)
                  FOR vc_PromocaoPreco IN c_PromocaoPreco(pi_vCodSistema,
                                                          vnCodCondicaoVenda,
                                                          vc_Produto.CODPROD,
                                                          vc_Produto.CODFORNEC,
                                                          vc_Produto.CODMARCA,
                                                          vc_Produto.CODLINHAPROD,
                                                          vc_Produto.NUMREGIAO,
                                                          vc_Produto.CODEPTO,
                                                          vc_Produto.CODCATEGORIA,
                                                          vc_Produto.CODSEC,
                                                          vc_Produto.CODFILIAL) LOOP
                    -- Pega a primeira Promoção e sai
                    vvTipoPromocao      := vc_PromocaoPreco.TIPOPROMOCAO;
                    vnPrecoPromocional  := vc_PromocaoPreco.PRECOPROMOCIONAL;
                    vnPercDescFin       := vc_PromocaoPreco.PERCDESCFIN;
                    vnQtdeMinima        := vc_PromocaoPreco.QTDEMINIMA;
                    vnCodPromocaoMed    := vc_PromocaoPreco.CODPROMOCAOMED;
                    vvTipoPrecoDesconto := 'P';
                    EXIT;
                  END LOOP;
                END IF;
  
                -- Se não achou Promoção de Preço Fixo
                IF (vvTipoPromocao IS NULL) THEN
                  -->> Se Processo Específico Servcon
                  IF (NVL(vvUsaMultiplasCondVenda,'N') = 'P') THEN
                    -- Se Promoção de Desconto
                    IF    (vc_Produto.TIPOPROMOCAO = 'D') THEN
                      vvTipoPromocao      := vc_Produto.TIPOPROMOCAO;
                      vnPercDesc          := vc_Produto.PERCDESC;
                      vnPercDesc1         := vc_Produto.PERCDESC; -- Guarda o Desconto da Promoção
                      vnPercDescFin       := vc_Produto.PERCDESCFIN;
                      vnQtdeMinima        := vc_Produto.INICIOINTERVALOPROMOCAOMED;
                      vnCodPromocaoMed    := vc_Produto.CODPROMOCAOMED;
                      vvTipoPrecoDesconto := 'D';
                    -- Se Promoção de Markup - DDMEDICA-5980
                    ELSIF (vc_Produto.TIPOPROMOCAO = 'R') THEN
                      vvTipoPromocao           := vc_Produto.TIPOPROMOCAO;
                      IF    NVL(vc_Produto.PERCMARKUPMED,0) = 0 THEN
                          vnPercDesc           := 0;
                      ELSIF NVL(vnPreco,0) = 0 THEN  -->> Se não tiver preço não pode calcular desconto
                          vnPercDesc           := 0;
                      ELSIF NVL(vnCustoFinanceiro,0) = 0 THEN
                          vnPercDesc           := 0;
                          vnPreco              := 0; -->> Se não tiver custo não pode considerar o produto
                      ELSE
                          IF (NVL(vnCustoFinanceiro,0) = 0) THEN
                            vnPercDesc         := 0;
                          ELSE
                            vnPrecoVendaMarkup := vnCustoFinanceiro * (1+(NVL(vc_Produto.PERCMARKUPMED,0) * 0.01));
                            vnPercDesc         := (1-(vnPrecoVendaMarkup/vnPreco))*100;
                          END IF;
                      END IF;
                      -- Promoção de Markup com Preço Fixo com ou sem faixa de quantidade - DDMEDICA-6952
                      IF (vc_Produto.TIPOPOLITICA IN ('P','F')) THEN
                        IF (NVL(vnPercDesc,0) = 0) THEN
                          vnPrecoPromocional := 0;
                        ELSE                         
                          vnPrecoPromocional := NVL(vnPrecoVendaMarkup,0);
                        END IF;
                        -- Não tem desconto (já vai aplicado no Preço Promocional)
                        vnPercDesc := 0;
                      END IF;                                      
                      vnPercDesc1          := vnPercDesc; -- Guarda o Desconto da Promoção
                      vnPercDescFin        := vc_Produto.PERCDESCFIN;
                      vnQtdeMinima         := vc_Produto.INICIOINTERVALOPROMOCAOMED;
                      vnCodPromocaoMed     := vc_Produto.CODPROMOCAOMED;
                      vvTipoPrecoDesconto  := 'M'; -- Markup
                      vnPercMarkupMed      := vc_Produto.PERCMARKUPMED; -- DDMEDICA-5980
                      vnCustoFinanceiroMkp := vnCustoFinanceiro;
                    END IF;
                  -->> Demais Processos
                  ELSE
                    -- Verificar se existe Promoção de Desconto
                    FOR vc_PromocaoDesconto IN c_PromocaoDesconto(pi_vCodSistema,
                                                                  vnCodCondicaoVenda,
                                                                  vc_Produto.CODPROD,
                                                                  vc_Produto.CODFORNEC,
                                                                  vc_Produto.CODMARCA,
                                                                  vc_Produto.CODLINHAPROD,
                                                                  vc_Produto.NUMREGIAO,
                                                                  vc_Produto.CODEPTO,
                                                                  vc_Produto.CODCATEGORIA,
                                                                  vc_Produto.CODSEC,
                                                                  vc_Produto.CODFILIAL) LOOP
                      -- Pega a primeira Promoção e sai
                      vvTipoPromocao      := vc_PromocaoDesconto.TIPOPROMOCAO;
                      vnPercDesc          := vc_PromocaoDesconto.PERCDESC;
                      vnPercDesc1         := vc_PromocaoDesconto.PERCDESC; -- Guarda o Desconto da Promoção
                      vnPercDescFin       := vc_PromocaoDesconto.PERCDESCFIN;
                      vnQtdeMinima        := vc_PromocaoDesconto.QTDEMINIMA;
                      vnCodPromocaoMed    := vc_PromocaoDesconto.CODPROMOCAOMED;
                      vvTipoPrecoDesconto := 'D';
                      EXIT;
                    END LOOP;
                  END IF;
  
                  -- Verifica se possui Acréscimo sobre o Preço (Somente SE NÃO TIVER PREÇO FIXO)
                  -- Medicamento NÃO PODE TER ACRÉSCIMO
                  IF (NVL(vc_Produto.TIPOMERC,' ') NOT IN ('M','MA')) THEN
                    IF (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') <> 'S') THEN -- MED-2433
                      BEGIN
                        SELECT PCCONDVENDAACRESCACORDO.PERCENTUAL
                          INTO vnPercAcrescAcordo
                          FROM PCCONDVENDAACRESCACORDO
                         WHERE (PCCONDVENDAACRESCACORDO.CODCONDICAOVENDA = vnCodCondicaoVenda)
                           AND (PCCONDVENDAACRESCACORDO.CAMPO            = 'MA')
                           AND (PCCONDVENDAACRESCACORDO.CODIGO           = vc_Produto.CODMARCA);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vnPercAcrescAcordo := NULL;
                      END;
                      IF (NVL(vnPercAcrescAcordo,0) > 0) THEN
                        vnPreco := ROUND(NVL(vnPreco,0) * (1 + (NVL(vnPercAcrescAcordo,0) / 100)),vnNumCasasDecVenda);
                      END IF;
                    END IF;
                  END IF; -- Fim Condição: NÃO é Medicamento
  
                  -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela e mandar o Preço Fábrica,
                  -- onde a Integradora tem Origem Preço = Preço Tabela
                  IF (vUSAREGRARECALDESCPTABMED2313 = 'S') THEN
                    -- Se Medicamento
                    IF (NVL(vc_Produto.TIPOMERC,' ') IN ('M','MA')) OR
                       (NVL(vc_Produto.UTILIZAPRECOFABRICA,'N') = 'S') THEN -- MED-2433
                      -- Medicamento com PREÇO
                      IF (NVL(vnPreco,0) > 0) THEN
                        -- Calcula o % Desconto entre o Preço Fábrica e o Preço Tabela com o Indice de Preço
                        vnPercDescPTABMED := ROUND(((NVL(vnPreco,0) - NVL(vnPrecoTabelaOriginalComIndice,0)) / NVL(vnPreco,0)) * 100,2);
                        vnPercDesc2       := vnPercDescPTABMED; -- Guarda o Desconto entre o Preço Fábrica e o Preço Tabela
                        -- Recalcula o Desconto agregando o % Desconto da Promoção com o Desconto entre o Preço Fábrica e o Preço Tabela
                        vnPercDesc        := 100 - ((100*(1-(NVL(vnPercDesc,0)/100))) * (1-(NVL(vnPercDescPTABMED,0)/100)));
                      END IF;
                    END IF;
                  END IF;
  
                END IF; -- Fim Condição se não achou Promoção de Preço Fixo
  
                -----------------------------------------------------------------------------
                -- Se Aceita Principal
                -----------------------------------------------------------------------------
                IF (NVL(vc_Produto.ACEITA_PRINCIPAL,'N') = 'S') THEN
                
                  -- DDVENDAS-32698 - Controle do Escalonamento a partir da primeira faixa quando ela é Principal
                  vtControleEscalonamento(vc_Produto.CODPROD) := vc_Produto.INICIOINTERVALOPROMOCAOMED;
  
                  -- Se o Produto tem Preço
                  IF (NVL(vnPreco,0) > 0) THEN
  
                    -- ST do Preço Bruto
                    vnCodSt := NULL;
                    P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                          vc_Produto.CODPROD,
                                          vc_Produto.CODCLIST,
                                          vc_Produto.NUMREGIAO,
                                          1,       -- pi_nCondVenda,
                                          100,     -- pi_nPercVenda
                                          vnCodSt,
                                          vnPreco,
                                          0,       -- pi_nValorIpi
                                          0,       -- pi_nPrecoMaxConsum
                                          0,       -- pi_nValorUltEnt
                                          0,       -- pi_nCustoNfSemSt
                                          vnPreco, -- Preço Tabela é o Preço Bruto
                                          'N',     -->> Padrão Não (Simples Nacional)
                                          'S',     -->> Pesquisa Custos
                                          'N',     -->> Não é Item Bonificado
                                          0,       -->> Não passa Frete e Outras Despesas
                                          vnBaseStPrecoBruto,
                                          vnValorStPrecoBruto,
                                          vvMensagemSt,
                                          vvRegimeEspIsenStFonte,
                                          vnAliqIcms1,
                                          vnAliqIcms2,
                                          vnIva,
                                          vnPercBaseRedSt
                                          );
  
                    -- Calcula Preço Líquido
                    vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vnPercDesc,0)/100));
  
                    -- Calcula ST pelo Preço Promocional
                    IF (NVL(vvTipoPromocao,'D') = 'P') THEN
                      -- Aplica Indice sobre o Preço Promocional
                      IF (NVL(vvGerarAcordoPreco,'N') = 'S')         AND
                         (NVL(vvAplicarIndiceAcordoPreco,'N') = 'S') AND
                         (NVL(vc_Produto.INDICEPRECO,0) <> 0)        THEN
                        vnPrecoPromocional := (NVL(vnPrecoPromocional,0) * NVL(vc_Produto.INDICEPRECO,0));
                        vnIndicePreco      := NVL(vc_Produto.INDICEPRECO,0);
                      END IF;
                      -- Calcula ST
                      vnCodSt := NULL;
                      P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                            vc_Produto.CODPROD,
                                            vc_Produto.CODCLIST,
                                            vc_Produto.NUMREGIAO,
                                            1,       -- pi_nCondVenda,
                                            100,     -- pi_nPercVenda
                                            vnCodSt,
                                            vnPrecoPromocional,
                                            0,       -- pi_nValorIpi
                                            0,       -- pi_nPrecoMaxConsum
                                            0,       -- pi_nValorUltEnt
                                            0,       -- pi_nCustoNfSemSt
                                            vnPrecoPromocional, -- Preço Tabela é o Preço Promocional
                                            'N',     -->> Padrão Não (Simples Nacional)
                                            'S',     -->> Pesquisa Custos
                                            'N',     -->> Não é Item Bonificado
                                            0,       -->> Não passa Frete e Outras Despesas
                                            vnBaseSt,
                                            vnValorSt,
                                            vvMensagemSt,
                                            vvRegimeEspIsenStFonte,
                                            vnAliqIcms1,
                                            vnAliqIcms2,
                                            vnIva,
                                            vnPercBaseRedSt
                                            );
                    -- Calcula ST pelo Preço Liquido
                    ELSE
                      vnCodSt := NULL;
                      P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                            vc_Produto.CODPROD,
                                            vc_Produto.CODCLIST,
                                            vc_Produto.NUMREGIAO,
                                            1,       -- pi_nCondVenda,
                                            100,     -- pi_nPercVenda
                                            vnCodSt,
                                            vnPrecoLiquido,
                                            0,       -- pi_nValorIpi
                                            0,       -- pi_nPrecoMaxConsum
                                            0,       -- pi_nValorUltEnt
                                            0,       -- pi_nCustoNfSemSt
                                            vnPreco, -- Preço Tabela
                                            'N',     -->> Padrão Não (Simples Nacional)
                                            'S',     -->> Pesquisa Custos
                                            'N',     -->> Não é Item Bonificado
                                            0,       -->> Não passa Frete e Outras Despesas
                                            vnBaseSt,
                                            vnValorSt,
                                            vvMensagemSt,
                                            vvRegimeEspIsenStFonte,
                                            vnAliqIcms1,
                                            vnAliqIcms2,
                                            vnIva,
                                            vnPercBaseRedSt
                                          );
                    END IF;
  
                    -- Dados Complementares - Regra Farmácia Popular
                    vbRegraFciaPopular := ( (NVL(vvCalcStPautaFarmaciaPopular,'N') = 'S') AND
                                            (NVL(vc_Produto.FARMACIAPOPULAR,'N') = 'S')   AND
                                            (NVL(vvParticipaFarmaciaPopular,'N') = 'S')   AND
                                            (NVL(vnPautaFonte,0) > 0) );
                    IF (vbRegraFciaPopular) THEN
                      vnVlStFarmaciaPopular := vnValorSt;
                    ELSE
                      vnVlStFarmaciaPopular := 0;
                    END IF;
  
                    -- Dados Complementares - Preço Pauta
                    IF (vbRegraFciaPopular) THEN
                      vnPrecoPauta := NVL(vnPautaFonte,0);
                    ELSE
                      IF (NVL(vvUsaPmcBaseSt,'N') = 'S') THEN
                        vnPrecoPauta := vnPrecoMaxConsum;
                      ELSE
                        vnPrecoPauta := 0;
                      END IF;
                    END IF;
  
                    -->> Se Processo Específico Servcon NÃO ENTRA
                    IF (NVL(vvUsaMultiplasCondVenda,'N') <> 'P') THEN
                      -- Dados Complementares - PIS/COFINS
                      IF (NVL(vvUsaPisCofinsPorFilial,'N') = 'S') THEN
                        BEGIN
                          SELECT PCPRODFILIAL.PERPIS
                               , PCPRODFILIAL.PERCOFINS
                            INTO vnPerPis
                               , vnPerCofins
                            FROM PCPRODFILIAL
                           WHERE (PCPRODFILIAL.CODPROD   = vc_Produto.CODPROD)
                             AND (PCPRODFILIAL.CODFILIAL = vc_Produto.CODFILIAL);
                        EXCEPTION
                          WHEN NO_DATA_FOUND THEN
                            vnPerPis    := 0;
                            vnPerCofins := 0;
                        END;
                      ELSE
                       vnPerPis    := vc_Produto.PERPIS;
                       vnPerCofins := vc_Produto.PERCOFINS;
                      END IF;
                    END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA
  
                    -- Dados Complementares - Produto
                    IF (NVL(vc_Produto.NATUREZAPRODUTO,' ') = 'ME') THEN
                      vvMedicamentoSimNao := 'S';
                      vvPerfumariaSimNao  := 'N';
                    ELSE
                      vvMedicamentoSimNao := 'N';
                      vvPerfumariaSimNao  := 'S';
                    END IF;
  
                    -->> DDMEDICA-6008 - Verifica se envia o Repasse - DDMEDICA-5980
                    IF (NVL(vCALCREPASSEVIEWPROMOSERVCON,'N') = 'S') THEN
                      -- Calcula o Repasse
                      PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                         vc_Produto.CODCLIST,
                                                         vc_Produto.NUMREGIAO,
                                                         1,    -- pi_nCondVenda,
                                                         vc_Produto.CODPROD,
                                                         NULL, --pi_nCodSt
                                                         vnPrecoFabrica,
                                                         vnPrecoLiquido,
                                                         NULL, --pi_vTipoAplicRepasseFilial
                                                         'N',  --pi_vCriticaObrigatorio
                                                         vnIntegradora,
                                                         'F',
                                                         vvTipoFv,
                                                         vvMensagemRepasse,
                                                         vvTipoRepasse,
                                                         vnValorRepasse);
                    END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA
  
                    -- Calcula o Valor do Acordo de Mídia sobre Preço Líquido -- DDMEDICA-545
                    IF    (NVL(vvTipoPromocao,'X') = 'P') THEN
                      vnBaseAcordoMidia := NVL(vnPrecoPromocional,0);
                    ELSIF (NVL(vvTipoPromocao,'X') = 'D') THEN
                      vnBaseAcordoMidia := ROUND((NVL(vnPreco,0) * (1 - (NVL(vnPercDesc,0)/100))),vnNumCasasDecVenda);
                    ELSE
                      vnBaseAcordoMidia := NVL(vnPreco,0);
                    END IF;
                    vnValorAcordoMidia := ROUND((vnBaseAcordoMidia * (NVL(vnPercAcordoMidia,0) / 100)),vnNumCasasDecVenda);
  
                    -- Atualiza Campos da Table
                    INSERT INTO PCMED_VIEWOLCONDVENDAPROD_TMP
                              ( CODSISTEMA
                              , NUMREGIAO
                              , CODCONDICAOVENDA
                              , CODPROD
                              , PRECO
                              , PERCDESC
                              , PERCDESCFIN
                              , QTDEMINIMA
                              , CODPROMOCAOMED
                              , BASEST
                              , VLST
                              , CODST
                              , CODFILIALST
                              , CODCLIST
                              , PRECOPROMOCIONAL
                              , TIPOPROMOCAO
                              , CODPLPAGCONDVENDA
                              , PRAZOMEDIO
                              , SALDOESTOQUE
                              , UFREGIAO
                              , ATIVOINATIVO
                              , PERCICM
                              , PERCBASEREDICM
                              , VLSTFARMACIAPOPULAR
                              , MEDICAMENTOSIMNAO
                              , PERFUMARIASIMNAO
                              , PERDESTAB
                              , IVAFONTE
                              , PRECOPAUTA
                              , PERCPIS
                              , PERCCOFINS
                              , PERCBONIFICVENDA
                              , TIPOPRECODESCONTO
                              , VLREPASSE
                              , PRECOFABRICA
                              , PRECOMAXCONSUM
                              , USAPMCBASEST
                              , ALIQICMS1FONTE
                              , ALIQICMS2FONTE
                              , PERCBASEREDSTFONTE
                              , BNFNAOCALCULAICMS
                              , USABASEICMSREDUZIDA
                              , PVENDA1
                              , PVENDA2
                              , PVENDA3
                              , PVENDA4
                              , PVENDA5
                              , PVENDA6
                              , PVENDA7
                              , VLSTPRECO
                              , BASESTPRECO
                              , INDICEPRECO
                              , PERCACRESCACORDO
                              , PERCDESC1
                              , PERCDESC2
                              , PERCACORDOMIDIA  -- DDMEDICA-545
                              , VALORACORDOMIDIA -- DDMEDICA-545
                              , CUSTOFINANCEIRO  -- DDMEDICA-5980
                              , PERCMARKUPMED )  -- DDMEDICA-5980
                       VALUES ( pi_vCodSistema
                              , vc_Produto.NUMREGIAO
                              , vnCodCondicaoVenda
                              , vc_Produto.CODPROD
                              , vnPreco
                              , NVL(vnPercDesc,0) -->> NÃO PODE FICAR NULO
                              , NVL(vnPercDescFin,0) -->> NÃO PODE FICAR NULO
                              , vnQtdeMinima
                              , vnCodPromocaoMed
                              , vnBaseSt
                              , vnValorSt
                              , vnCodSt
                              , vc_Produto.CODFILIAL
                              , vc_Produto.CODCLIST
                              , NVL(vnPrecoPromocional,0) -->> NÃO PODE FICAR NULO
                              , vvTipoPromocao
                              , vtListaCondicoes(viIdxCondicao).vnCodPlPag
                              , vtListaCondicoes(viIdxCondicao).vnPrazoMedio
                              , vnSaldoEstoque
                              , vc_Produto.UFREGIAO
                              , vc_Produto.ATIVOINATIVO
                              , vnPercIcm
                              , vnPercBaseRedIcm
                              , vnVlStFarmaciaPopular
                              , vvMedicamentoSimNao
                              , vvPerfumariaSimNao
                              , vnPerDesTab
                              , vnIvaFonte
                              , vnPrecoPauta
                              , vnPerPis
                              , vnPerCofins
                              , vnPercBonificVenda
                              , vvTipoPrecoDesconto
                              , vnValorRepasse
                              , vnPrecoFabrica
                              , vnPrecoMaxConsum
                              , vvUsaPmcBaseSt
                              , vnAliqIcms1Fonte
                              , vnAliqIcms2Fonte
                              , vnPercBaseRedStFonte
                              , vvBnfNaoCalculaIcms
                              , vvUsaBaseIcmsReduzida
                              , vc_Produto.PVENDA1
                              , vc_Produto.PVENDA2
                              , vc_Produto.PVENDA3
                              , vc_Produto.PVENDA4
                              , vc_Produto.PVENDA5
                              , vc_Produto.PVENDA6
                              , vc_Produto.PVENDA7
                              , vnValorStPrecoBruto
                              , vnBaseStPrecoBruto
                              , vnIndicePreco
                              , vnPercAcrescAcordo
                              , vnPercDesc1
                              , vnPercDesc2
                              , vnPercAcordoMidia    -- DDMEDICA-545
                              , vnValorAcordoMidia   -- DDMEDICA-545
                              , vnCustoFinanceiroMkp -- DDMEDICA-5980
                              , vnPercMarkupMed );   -- DDMEDICA-5980
  
                    ------------------------------------------------------
                    -- Promoções por Faixa de Quantidade - Força de Vendas
                    ------------------------------------------------------
                    -->> Se Processo Específico Servcon NÃO ENTRA
                    IF (NVL(vvUsaMultiplasCondVenda,'N') <> 'P') THEN
                      IF (vbGeraDicionarioForcaVendas) THEN
  
                        -- Se não for KIT (Kits não enviam as promoções de faixa de quantidade vinculadas à promoção - não são promoções padrões, logo não têm outras promoções vinculadas a ela)
                        IF (NVL(vtListaCondicoes(viIdxCondicao).vvKit,'N') <> 'S') THEN
  
                          -- (Pega todas as Promoções por Faixa de Quantidade independente da condição) ------
                          FOR vc_PrecoPromoc_FV_FaixaQtde IN c_PrecoPromoc_FV_FaixaQtde(pi_vCodSistema,
                                                                                        vnCodCondicaoVenda,
                                                                                        vc_Produto.CODPROD,
                                                                                        vc_Produto.CODFORNEC,
                                                                                        vc_Produto.CODMARCA,
                                                                                        vc_Produto.CODLINHAPROD,
                                                                                        vc_Produto.NUMREGIAO,
                                                                                        vc_Produto.CODEPTO,
                                                                                        vc_Produto.CODCATEGORIA,
                                                                                        vc_Produto.CODSEC,
                                                                                        vc_Produto.CODFILIAL) LOOP
  
                            -->> ACHOU Preço Promocional por Faixa de Quantidade
                            vvTipoPrecoDescFaixaQtde := 'P';
  
                            -->> Calcula ST
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0),
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                  );
  
                            -- Calcula o Repasse
                            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                               vc_Produto.CODCLIST,
                                                               vc_Produto.NUMREGIAO,
                                                               1,    -- pi_nCondVenda,
                                                               vc_Produto.CODPROD,
                                                               NULL, --pi_nCodSt
                                                               vnPrecoFabrica,
                                                               NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0),
                                                               NULL, --pi_vTipoAplicRepasseFilial
                                                               'N',  --pi_vCriticaObrigatorio
                                                               vnIntegradora,
                                                               'F',
                                                               vvTipoFv,
                                                               vvMensagemRepasse,
                                                               vvTipoRepasse,
                                                               vnValorRepasse);
              
                            -- Insere Faixa
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTINICIAL
                                      , QTFINAL
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPOLITICA
                                      , TIPOPRECODESCONTO
                                      , DESCRICAORESUMIDAPROMOCAO
                                      , DESCRICAODETALHADAPROMOCAO
                                      , VLST
                                      , VLREPASSE
                                      , CODFILIALST
                                      , PRECOFABRICA )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_PrecoPromoc_FV_FaixaQtde.QTINICIAL
                                      , vc_PrecoPromoc_FV_FaixaQtde.QTFINAL
                                      , vc_PrecoPromoc_FV_FaixaQtde.CODPROMOCAOMED
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PrecoPromoc_FV_FaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PrecoPromoc_FV_FaixaQtde.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                      , vc_PrecoPromoc_FV_FaixaQtde.TIPOPROMOCAO
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , vc_PrecoPromoc_FV_FaixaQtde.TIPOPOLITICA
                                      , vvTipoPrecoDescFaixaQtde
                                      , vc_PrecoPromoc_FV_FaixaQtde.DESCRICAORESUMIDAPROMOCAO
                                      , vc_PrecoPromoc_FV_FaixaQtde.DESCRICAODETALHADAPROMOCAO
                                      , vnValorSt
                                      , vnValorRepasse
                                      , vc_Produto.CODFILIAL
                                      , vnPrecoFabrica );
  
                          END LOOP; -- c_PrecoPromoc_FV_FaixaQtde
  
                          -- (Pega todas as Promoções por Faixa de Quantidade independente da condição) ------
                          FOR vc_Desconto_FV_FaixaQtde IN c_Desconto_FV_FaixaQtde(pi_vCodSistema,
                                                                                  vnCodCondicaoVenda,
                                                                                  vc_Produto.CODPROD,
                                                                                  vc_Produto.CODFORNEC,
                                                                                  vc_Produto.CODMARCA,
                                                                                  vc_Produto.CODLINHAPROD,
                                                                                  vc_Produto.NUMREGIAO,
                                                                                  vc_Produto.CODEPTO,
                                                                                  vc_Produto.CODCATEGORIA,
                                                                                  vc_Produto.CODSEC,
                                                                                  vc_Produto.CODFILIAL) LOOP
  
                            -->> ACHOU Desconto por Faixa de Quantidade
                            vvTipoPrecoDescFaixaQtde := 'D';
  
                            -- Calcula Preço Líquido
                            vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_Desconto_FV_FaixaQtde.PERCDESC,0)/100));
  
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  vnPrecoLiquido,
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  vnPreco, -- Preço Tabela
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                );
  
                            -- Calcula o Repasse
                            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                               vc_Produto.CODCLIST,
                                                               vc_Produto.NUMREGIAO,
                                                               1,    -- pi_nCondVenda,
                                                               vc_Produto.CODPROD,
                                                               NULL, --pi_nCodSt
                                                               vnPrecoFabrica,
                                                               vnPrecoLiquido,
                                                               NULL, --pi_vTipoAplicRepasseFilial
                                                               'N',  --pi_vCriticaObrigatorio
                                                               vnIntegradora,
                                                               'F',
                                                               vvTipoFv,
                                                               vvMensagemRepasse,
                                                               vvTipoRepasse,
                                                               vnValorRepasse);
  
                            -- Insere Faixa
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTINICIAL
                                      , QTFINAL
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPOLITICA
                                      , TIPOPRECODESCONTO
                                      , DESCRICAORESUMIDAPROMOCAO
                                      , DESCRICAODETALHADAPROMOCAO
                                      , VLST
                                      , VLREPASSE
                                      , CODFILIALST
                                      , PRECOFABRICA )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_Desconto_FV_FaixaQtde.QTINICIAL
                                      , vc_Desconto_FV_FaixaQtde.QTFINAL
                                      , vc_Desconto_FV_FaixaQtde.CODPROMOCAOMED
                                      , NVL(vc_Desconto_FV_FaixaQtde.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_Desconto_FV_FaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , vc_Desconto_FV_FaixaQtde.TIPOPROMOCAO
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , vc_Desconto_FV_FaixaQtde.TIPOPOLITICA
                                      , vvTipoPrecoDescFaixaQtde
                                      , vc_Desconto_FV_FaixaQtde.DESCRICAORESUMIDAPROMOCAO
                                      , vc_Desconto_FV_FaixaQtde.DESCRICAODETALHADAPROMOCAO
                                      , vnValorSt
                                      , vnValorRepasse
                                      , vc_Produto.CODFILIAL
                                      , vnPrecoFabrica );
  
                          END LOOP; -- Fim c_Desconto_FV_FaixaQtde
  
                          -- (Pega todas as Promoções Casadinha) ------
                          FOR vc_Desconto_FV_Casadinha IN c_Desconto_FV_Casadinha(pi_vCodSistema,
                                                                                  vnCodCondicaoVenda,
                                                                                  vc_Produto.CODPROD,
                                                                                  vc_Produto.CODFORNEC,
                                                                                  vc_Produto.CODMARCA,
                                                                                  vc_Produto.CODLINHAPROD,
                                                                                  vc_Produto.NUMREGIAO,
                                                                                  vc_Produto.CODEPTO,
                                                                                  vc_Produto.CODCATEGORIA,
                                                                                  vc_Produto.CODSEC,
                                                                                  vc_Produto.CODFILIAL) LOOP
  
                            -->> ACHOU Desconto por Faixa de Quantidade
                            vvTipoPrecoDescFaixaQtde := 'D';
  
                            -- Calcula Preço Líquido
                            vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_Desconto_FV_Casadinha.PERCDESC,0)/100));
  
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  vnPrecoLiquido,
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  vnPreco, -- Preço Tabela
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                );
  
                            -- Calcula o Repasse
                            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                               vc_Produto.CODCLIST,
                                                               vc_Produto.NUMREGIAO,
                                                               1,    -- pi_nCondVenda,
                                                               vc_Produto.CODPROD,
                                                               NULL, --pi_nCodSt
                                                               vnPrecoFabrica,
                                                               vnPrecoLiquido,
                                                               NULL, --pi_vTipoAplicRepasseFilial
                                                               'N',  --pi_vCriticaObrigatorio
                                                               vnIntegradora,
                                                               'F',
                                                               vvTipoFv,
                                                               vvMensagemRepasse,
                                                               vvTipoRepasse,
                                                               vnValorRepasse);
  
                            -- Insere Faixa
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_CTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTINICIAL
                                      , QTFINAL
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPOLITICA
                                      , TIPOPRECODESCONTO
                                      , DESCRICAORESUMIDAPROMOCAO
                                      , DESCRICAODETALHADAPROMOCAO
                                      , VLST
                                      , VLREPASSE
                                      , CODFILIALST )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_Desconto_FV_Casadinha.QTINICIAL
                                      , vc_Desconto_FV_Casadinha.QTFINAL
                                      , vc_Desconto_FV_Casadinha.CODPROMOCAOMED
                                      , NVL(vc_Desconto_FV_Casadinha.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_Desconto_FV_Casadinha.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , vc_Desconto_FV_Casadinha.TIPOPROMOCAO
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , vc_Desconto_FV_Casadinha.TIPOPOLITICA
                                      , vvTipoPrecoDescFaixaQtde
                                      , vc_Desconto_FV_Casadinha.DESCRICAORESUMIDAPROMOCAO
                                      , vc_Desconto_FV_Casadinha.DESCRICAODETALHADAPROMOCAO
                                      , vnValorSt
                                      , vnValorRepasse
                                      , vc_Produto.CODFILIAL );
  
                          END LOOP; -- Fim c_Desconto_FV_FaixaQtde
  
                        END IF; -- Fim Condição: Não for KIT
  
                      ------------------------------------------------------
                      -- Promoções por Faixa de Quantidade - OL e PE
                      ------------------------------------------------------
                      ELSE
  
                        -- Verificar se existe Promoção de Preço Fixo por Faixa de Quantidade(PRIORITARIA)
                        BEGIN
                          SELECT 'P' TIPOPROMOCAO
                               , PCMED_VIEWOLAUX04.CODPROMOCAOMED
                            INTO vvTipoPrecoDescFaixaQtde
                               , vnCodPromocaoMedFaixaQtde
                            FROM PCMED_VIEWOLAUX04
                           WHERE ((PCMED_VIEWOLAUX04.CODSISTEMA       = pi_vCodSistema))
                             AND ((PCMED_VIEWOLAUX04.CODCONDICAOVENDA = vnCodCondicaoVenda))
                             AND ((PCMED_VIEWOLAUX04.NUMREGIAO        = vc_Produto.NUMREGIAO) OR (PCMED_VIEWOLAUX04.NUMREGIAO IS NULL))
                             AND ( ((PCMED_VIEWOLAUX04.CODPROD        = vc_Produto.CODPROD))      OR
                                   ((PCMED_VIEWOLAUX04.CODFORNEC      = vc_Produto.CODFORNEC))    OR
                                   ((PCMED_VIEWOLAUX04.CODMARCA       = vc_Produto.CODMARCA))     OR
                                   ((PCMED_VIEWOLAUX04.CODLINHAPROD   = vc_Produto.CODLINHAPROD)) OR
                                   ((PCMED_VIEWOLAUX04.CODEPTO        = vc_Produto.CODEPTO))
                                 )
                             AND ((ROWNUM = 1));
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              vvTipoPrecoDescFaixaQtde  := NULL;
                              vnCodPromocaoMedFaixaQtde := NULL;
                        END;
  
                        -- Se não achou Promoção de Preço Fixo por Faixa de Quantidade
                        IF (vvTipoPrecoDescFaixaQtde IS NULL) THEN
  
                          -- Verificar se existe Promoção de Desconto por Faixa de Quantidade
                          FOR vc_MaiorDescFaixaQtde IN (SELECT 'D' TIPOPROMOCAO
                                                             , PCMED_VIEWOLAUX03.CODPROMOCAOMED
                                                             , PCMED_VIEWOLAUX03.PERCDESC
                                                          FROM PCMED_VIEWOLAUX03
                                                         WHERE ((PCMED_VIEWOLAUX03.CODSISTEMA       = pi_vCodSistema))
                                                           AND ((PCMED_VIEWOLAUX03.CODCONDICAOVENDA = vnCodCondicaoVenda))
                                                           AND ((PCMED_VIEWOLAUX03.NUMREGIAO        = vc_Produto.NUMREGIAO)   OR (PCMED_VIEWOLAUX03.NUMREGIAO IS NULL))
                                                           AND ((PCMED_VIEWOLAUX03.CODFILIAL        = vc_Produto.CODFILIAL) OR (PCMED_VIEWOLAUX03.CODFILIAL IS NULL))
                                                           AND ( ((PCMED_VIEWOLAUX03.CODPROD        = vc_Produto.CODPROD))     OR
                                                                 ((PCMED_VIEWOLAUX03.CODFORNEC      = vc_Produto.CODFORNEC))   OR
                                                                 ((PCMED_VIEWOLAUX03.CODMARCA       = vc_Produto.CODMARCA))    OR
                                                                 ((PCMED_VIEWOLAUX03.CODLINHAPROD   = vc_Produto.CODLINHAPROD)) OR
                                                                 ((PCMED_VIEWOLAUX03.CODEPTO        = vc_Produto.CODEPTO)) )
                                                         ORDER BY PCMED_VIEWOLAUX03.PERCDESC DESC) LOOP -->> Do maior para o menor desconto
                            -- Pega primeira linha do cursor que será o maior desconto e sai do laço
                            vvTipoPrecoDescFaixaQtde  := vc_MaiorDescFaixaQtde.TIPOPROMOCAO;
                            vnCodPromocaoMedFaixaQtde := vc_MaiorDescFaixaQtde.CODPROMOCAOMED;
                            EXIT; -->> SAI DO LAÇO
                          END LOOP;
  
                        END IF; -- Fim Condição se não achou Promoção de Preço Fixo
  
                        -- Atualiza Campos da Table
                        -- Desconto por Faixa de Quantidade -------------------------------------------------
                        IF (vvTipoPrecoDescFaixaQtde = 'D') THEN
  
                          FOR vc_DescontoFaixaQtde IN c_DescontoFaixaQtde(pi_vCodSistema,
                                                                          vnCodCondicaoVenda,
                                                                          vc_Produto.CODPROD,
                                                                          vc_Produto.CODFORNEC,
                                                                          vc_Produto.CODMARCA,
                                                                          vc_Produto.CODLINHAPROD,
                                                                          vc_Produto.CODEPTO,
                                                                          vc_Produto.CODCATEGORIA,
                                                                          vc_Produto.CODSEC,
                                                                          vnCodPromocaoMedFaixaQtde) LOOP
  
                            -- Calcula Preço Líquido
                            vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_DescontoFaixaQtde.PERCDESC,0)/100));
  
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  vnPrecoLiquido,
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  vnPreco, -- Preço Tabela
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                );
  
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTINICIAL
                                      , QTFINAL
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPRECODESCONTO
                                      , CODFILIALST
                                      , PRECOFABRICA
                                      , VLST )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_DescontoFaixaQtde.QTINICIAL
                                      , vc_DescontoFaixaQtde.QTFINAL
                                      , vc_DescontoFaixaQtde.CODPROMOCAOMED
                                      , NVL(vc_DescontoFaixaQtde.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_DescontoFaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , vvTipoPrecoDescFaixaQtde
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , vvTipoPrecoDescFaixaQtde
                                      , vc_Produto.CODFILIAL
                                      , vnPrecoFabrica
                                      , vnValorSt );
  
                          END LOOP; -- Fim c_DescontoFaixaQtde
  
                        -- Preço Promocional por Faixa de Quantidade ----------------------------------------
                        ELSIF (vvTipoPrecoDescFaixaQtde = 'P') THEN
  
                          FOR vc_PrecoPromocionalFaixaQtde IN c_PrecoPromocionalFaixaQtde(pi_vCodSistema,
                                                                                          vnCodCondicaoVenda,
                                                                                          vc_Produto.CODPROD,
                                                                                          vc_Produto.CODFORNEC,
                                                                                          vc_Produto.CODMARCA,
                                                                                          vc_Produto.CODLINHAPROD,
                                                                                          vc_Produto.CODEPTO,
                                                                                          vc_Produto.CODCATEGORIA,
                                                                                          vc_Produto.CODSEC,
                                                                                          vnCodPromocaoMedFaixaQtde) LOOP
  
                            -->> Calcula ST
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0),
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                  );
  
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_FTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTINICIAL
                                      , QTFINAL
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPRECODESCONTO
                                      , CODFILIALST
                                      , PRECOFABRICA
                                      , VLST )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_PrecoPromocionalFaixaQtde.QTINICIAL
                                      , vc_PrecoPromocionalFaixaQtde.QTFINAL
                                      , vc_PrecoPromocionalFaixaQtde.CODPROMOCAOMED
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PrecoPromocionalFaixaQtde.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PrecoPromocionalFaixaQtde.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                      , vvTipoPrecoDescFaixaQtde
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , vvTipoPrecoDescFaixaQtde
                                      , vc_Produto.CODFILIAL
                                      , vnPrecoFabrica
                                      , vnValorSt );
  
                          END LOOP; -- Fim c_PrecoPromocionalFaixaQtde
  
                        END IF; -- Fim Condição Tipo de Promoção por Faixa
  
                      END IF; -- Fim Condição Promoções por Faixa de Quantidade - Força de Vendas ou OL/PE
                    END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA (Promoções por Faixa de Quantidade)
  
                    ------------------------------------------------------
                    -- Promoções COMBO - OL e PE (Se não for FV)
                    ------------------------------------------------------
                    -->> Se Processo Específico Servcon NÃO ENTRA
                    IF (NVL(vvUsaMultiplasCondVenda,'N') <> 'P') THEN
                      IF (NOT vbGeraDicionarioForcaVendas) THEN
  
                        -- Combo de Preço Fixo --------------------------------------------------------------
                        FOR vc_PromocaoComboPreco IN c_PromocaoComboPreco(pi_vCodSistema,
                                                                          vnCodCondicaoVenda,
                                                                          vc_Produto.CODPROD,
                                                                          vc_Produto.NUMREGIAO,
                                                                          vc_Produto.CODFILIAL) LOOP
  
                          -->> Se encontrou COMBO
                          IF (NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0) > 0) THEN
  
                            -->> Calcula ST
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0),
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0), -- Preço Tabela é o Preço Promocional
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                  );
  
                            -- Calcula o Repasse
                            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                               vc_Produto.CODCLIST,
                                                               vc_Produto.NUMREGIAO,
                                                               1,    -- pi_nCondVenda,
                                                               vc_Produto.CODPROD,
                                                               NULL, --pi_nCodSt
                                                               vnPrecoFabrica,
                                                               vnPrecoLiquido,
                                                               NULL, --pi_vTipoAplicRepasseFilial
                                                               'N',  --pi_vCriticaObrigatorio
                                                               vnIntegradora,
                                                               'F',
                                                               vvTipoFv,
                                                               vvMensagemRepasse,
                                                               vvTipoRepasse,
                                                               vnValorRepasse);
  
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_KTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTCOMBO
                                      , OBRIGATORIO
                                      , PERMITIRAUMENTARQTDEKIT
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPRECODESCONTO
                                      , CODFILIALST
                                      , VLST )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_PromocaoComboPreco.QTCOMBO
                                      , vc_PromocaoComboPreco.OBRIGATORIO
                                      , vc_PromocaoComboPreco.PERMITIRAUMENTARQTDEKIT
                                      , vc_PromocaoComboPreco.CODPROMOCAOMED
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PromocaoComboPreco.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PromocaoComboPreco.PRECOPROMOCIONAL,0) -->> NÃO PODE FICAR NULO
                                      , 'P'
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , 'P'
                                      , vc_Produto.CODFILIAL
                                      , vnValorSt );
  
                          END IF; -- Fim Condição: Se encontrou COMBO
  
                        END LOOP; -- Fim c_PromocaoComboPreco
  
                        -- Combo de Desconto ----------------------------------------------------------------
                        FOR vc_PromocaoComboDesconto IN c_PromocaoComboDesconto(pi_vCodSistema,
                                                                                vnCodCondicaoVenda,
                                                                                vc_Produto.CODPROD,
                                                                                vc_Produto.NUMREGIAO,
                                                                                vc_Produto.CODFILIAL) LOOP
  
                          -->> Se encontrou COMBO
                          IF (NVL(vc_PromocaoComboDesconto.PERCDESC,0) <> 0) THEN
  
                            -- Calcula Preço Líquido
                            vnPrecoLiquido := NVL(vnPreco,0) * (1-(NVL(vc_PromocaoComboDesconto.PERCDESC,0)/100));
  
                            vnCodSt := NULL;
                            P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                                  vc_Produto.CODPROD,
                                                  vc_Produto.CODCLIST,
                                                  vc_Produto.NUMREGIAO,
                                                  1,       -- pi_nCondVenda,
                                                  100,     -- pi_nPercVenda
                                                  vnCodSt,
                                                  vnPrecoLiquido,
                                                  0,       -- pi_nValorIpi
                                                  0,       -- pi_nPrecoMaxConsum
                                                  0,       -- pi_nValorUltEnt
                                                  0,       -- pi_nCustoNfSemSt
                                                  vnPreco, -- Preço Tabela
                                                  'N',     -->> Padrão Não (Simples Nacional)
                                                  'S',     -->> Pesquisa Custos
                                                  'N',     -->> Não é Item Bonificado
                                                  0,       -->> Não passa Frete e Outras Despesas
                                                  vnBaseSt,
                                                  vnValorSt,
                                                  vvMensagemSt,
                                                  vvRegimeEspIsenStFonte,
                                                  vnAliqIcms1,
                                                  vnAliqIcms2,
                                                  vnIva,
                                                  vnPercBaseRedSt
                                                );
  
                            -- Calcula o Repasse
                            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                               vc_Produto.CODCLIST,
                                                               vc_Produto.NUMREGIAO,
                                                               1,    -- pi_nCondVenda,
                                                               vc_Produto.CODPROD,
                                                               NULL, --pi_nCodSt
                                                               vnPrecoFabrica,
                                                               vnPrecoLiquido,
                                                               NULL, --pi_vTipoAplicRepasseFilial
                                                               'N',  --pi_vCriticaObrigatorio
                                                               vnIntegradora,
                                                               'F',
                                                               vvTipoFv,
                                                               vvMensagemRepasse,
                                                               vvTipoRepasse,
                                                               vnValorRepasse);
  
                            INSERT INTO PCMED_VIEWOLCONDVENDAPROD_KTMP
                                      ( CODSISTEMA
                                      , NUMREGIAO
                                      , CODCONDICAOVENDA
                                      , CODPROD
                                      , QTCOMBO
                                      , OBRIGATORIO
                                      , PERMITIRAUMENTARQTDEKIT
                                      , CODPROMOCAOMED
                                      , PERCDESC
                                      , PERCDESCFIN
                                      , PRECOPROMOCIONAL
                                      , TIPOPROMOCAO
                                      , PRECO
                                      , PERCBONIFICVENDA
                                      , TIPOPRECODESCONTO
                                      , CODFILIALST
                                      , VLST )
                               VALUES ( pi_vCodSistema
                                      , vc_Produto.NUMREGIAO
                                      , vnCodCondicaoVenda
                                      , vc_Produto.CODPROD
                                      , vc_PromocaoComboDesconto.QTCOMBO
                                      , vc_PromocaoComboDesconto.OBRIGATORIO
                                      , vc_PromocaoComboDesconto.PERMITIRAUMENTARQTDEKIT
                                      , vc_PromocaoComboDesconto.CODPROMOCAOMED
                                      , NVL(vc_PromocaoComboDesconto.PERCDESC,0) -->> NÃO PODE FICAR NULO
                                      , NVL(vc_PromocaoComboDesconto.PERCDESCFIN,0) -->> NÃO PODE FICAR NULO
                                      , 0 -->> NÃO PODE FICAR NULO
                                      , 'D'
                                      , vnPreco
                                      , vnPercBonificVenda
                                      , 'D'
                                      , vc_Produto.CODFILIAL
                                      , vnValorSt );
  
                          END IF; -- Fim Condição: Se encontrou COMBO
  
                        END LOOP; -- Fim c_PromocaoComboDesconto
  
                      END IF; -- Fim Condição: Promoções COMBO - OL e PE (Se não for FV)
                    END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA (Promoções Combo
  
                    -- Efetiva Transações
                    viContaCommit := NVL(viContaCommit,0) + 1;
                    IF (viContaCommit > 1000) THEN
                      viContaCommit := 0;
                      --COMMIT;
                    END IF;
  
                  ELSE
  
                    -- CONTROLE DE RELATÓRIO ---------
                    IF (NVL(vvOrigemPreco,'F') = 'F') THEN
                      P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                       vc_Produto.CODFILIAL,
                                       vnCodCondicaoVenda,
                                       vc_Produto.CODPROD,
                                       'P', -- Critica Por Produto
                                       'Produto sem Preço (Origem Preço da Integradora = Preço Fábrica)');
                    ELSE
                      P_INSERE_CRITICA(vc_Produto.NUMREGIAO,
                                       vc_Produto.CODFILIAL,
                                       vnCodCondicaoVenda,
                                       vc_Produto.CODPROD,
                                       'P', -- Critica Por Produto
                                       'Produto sem Preço (Origem Preço da Integradora = Preço Tabela)');
                    END IF;
                    ----------------------------------
  
                  END IF; -- Fim Condição Se o Produto tem Preço

                END IF; -- Fim Condição: Se Aceita Principal

                -----------------------------------------------------------------------------
                -- Quando não Aceita Principal (Somente Escalonado - Processo Específico SERVCON)
                -----------------------------------------------------------------------------
                IF (NVL(vc_Produto.ACEITA_PRINCIPAL,'N') <> 'S') AND
                   (NVL(vvUsaMultiplasCondVenda,'N') = 'P')      AND
                   (NVL(vnPreco,0) > 0)                          THEN
                   
                  -- DDVENDAS-32698 - INSERE O PRODUTO SEM FAIXA DE QUANTIDADE SEM PROMOÇÃO -
                  ---------------------------------------------------------------------------
                  
                  -- Somente Insere o Registro na Tabela Principal na primeira Faixa
                  IF (NOT vtControleEscalonamento.EXISTS(vc_Produto.CODPROD)) THEN
                  
                    -- ST do Preço Bruto
                    vnCodSt := NULL;
                    P_OBTEM_STFONTE_4PMPF(vc_Produto.CODFILIAL,
                                          vc_Produto.CODPROD,
                                          vc_Produto.CODCLIST,
                                          vc_Produto.NUMREGIAO,
                                          1,       -- pi_nCondVenda,
                                          100,     -- pi_nPercVenda
                                          vnCodSt,
                                          vnPreco,
                                          0,       -- pi_nValorIpi
                                          0,       -- pi_nPrecoMaxConsum
                                          0,       -- pi_nValorUltEnt
                                          0,       -- pi_nCustoNfSemSt
                                          vnPreco, -- Preço Tabela é o Preço Bruto
                                          'N',     -->> Padrão Não (Simples Nacional)
                                          'S',     -->> Pesquisa Custos
                                          'N',     -->> Não é Item Bonificado
                                          0,       -->> Não passa Frete e Outras Despesas
                                          vnBaseStPrecoBruto,
                                          vnValorStPrecoBruto,
                                          vvMensagemSt,
                                          vvRegimeEspIsenStFonte,
                                          vnAliqIcms1,
                                          vnAliqIcms2,
                                          vnIva,
                                          vnPercBaseRedSt
                                          );
                                          
                    -- Preço Líquido = Preço Bruto
                    vnPrecoLiquido := vnPreco;

                    -- Dados Complementares - Produto
                    IF (NVL(vc_Produto.NATUREZAPRODUTO,' ') = 'ME') THEN
                      vvMedicamentoSimNao := 'S';
                      vvPerfumariaSimNao  := 'N';
                    ELSE
                      vvMedicamentoSimNao := 'N';
                      vvPerfumariaSimNao  := 'S';
                    END IF;
  
                    -->> Verifica se envia o Repasse
                    IF (NVL(vCALCREPASSEVIEWPROMOSERVCON,'N') = 'S') THEN
                      -- Calcula o Repasse
                      PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(vc_Produto.CODFILIAL,
                                                         vc_Produto.CODCLIST,
                                                         vc_Produto.NUMREGIAO,
                                                         1,    -- pi_nCondVenda,
                                                         vc_Produto.CODPROD,
                                                         NULL, --pi_nCodSt
                                                         vnPrecoFabrica,
                                                         vnPrecoLiquido,
                                                         NULL, --pi_vTipoAplicRepasseFilial
                                                         'N',  --pi_vCriticaObrigatorio
                                                         vnIntegradora,
                                                         'F',
                                                         vvTipoFv,
                                                         vvMensagemRepasse,
                                                         vvTipoRepasse,
                                                         vnValorRepasse);
                    END IF; -- Fim: Se Processo Específico Servcon NÃO ENTRA
    
                    -- Insere Campos da Table
                    INSERT INTO PCMED_VIEWOLCONDVENDAPROD_TMP
                              ( CODSISTEMA
                              , NUMREGIAO
                              , CODCONDICAOVENDA
                              , CODPROD
