                              , PERCMARKUPMED )
                       VALUES ( pi_vCodSistema
                              , vc_Produto.NUMREGIAO
                              , vnCodCondicaoVenda
                              , vc_Produto.CODPROD
                              , vnPreco
                              , 0    -->> SEM PERCDESC - NÃO PODE FICAR NULO
                              , 0    -->> SEM PERCDESCFIN - NÃO PODE FICAR NULO
                              , 1    -->> QTDEMINIMA
                              , vnCodPromocaoMed
                              , vnBaseSt
                              , vnValorSt
                              , vnCodSt
                              , vc_Produto.CODFILIAL
                              , vc_Produto.CODCLIST
                              , 0    -->> SEM PRECOPROMOCIONAL - NÃO PODE FICAR NULO
                              , NULL -->> TIPOPROMOCAO
                              , vtListaCondicoes(viIdxCondicao).vnCodPlPag
                              , vtListaCondicoes(viIdxCondicao).vnPrazoMedio
                              , vnSaldoEstoque
