                              , vvMedicamentoSimNao
                              , vvPerfumariaSimNao
                              , vnPerDesTab
                              , vnIvaFonte
                              , vnPrecoPauta
                              , vnPerPis
                              , vnPerCofins
                              , vnPercBonificVenda
