    vvMensagemLog := vvMensagemLog || '; ' || 'PCMED_VIEWOLCONDVENDACLI_TMP: ' || NVL(viQtRegLog,0);
    SELECT COUNT(*)
      INTO viQtRegLog
      FROM PCMED_VIEWOLCONDVENDAPROD_TMP;
    vvMensagemLog := vvMensagemLog || '; ' || 'PCMED_VIEWOLCONDVENDAPROD_TMP: ' || NVL(viQtRegLog,0);
    SELECT COUNT(*)
      INTO viQtRegLog
      FROM PCMED_VIEWOLCONDVENDAPROD_FTMP;
    vvMensagemLog := vvMensagemLog || '; ' || 'PCMED_VIEWOLCONDVENDAPROD_FTMP: ' || NVL(viQtRegLog,0);
    SELECT COUNT(*)
      INTO viQtRegLog
