                  , vdDataHoraIniTabTempDesc
                  , vdDataHoraFinTabTempDesc
                  , vdDataHoraFinCondicoesComerc
                  , vdDataHoraIniGerClientes
                  , vdDataHoraFinGerClientes
                  , vdDataHoraIniGerDescontos
                  , vdDataHoraFinGerDescontos
                  , vdDataHoraFinCondVendaProd );
  
    END IF; -- FIM CONDIÇÃO INSERE LOG
  
    -------------------------------------------------
    -- Efetiva Transações NO FINAL (Tabelas de Dados)
    -------------------------------------------------
    COMMIT;
  
  EXCEPTION
    WHEN OTHERS THEN
      RAISE_APPLICATION_ERROR(-20000, DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM);
  END P_CONDCOMERC_SISTOPERLOG_SERV;

 /*******************************************************************************
  Nome         : P_CONDCOMERC_SISTOPERLOG_HYPER
  Descrição    : Procedimento específico da PRC_MED_CONDCOMERC_SISTOPERLOG para
                 atender o Hypera - DDVENDAS-33943
  ********************************************************************************/
  PROCEDURE P_CONDCOMERC_SISTOPERLOG_HYPER(pi_vCodSistema IN VARCHAR2,
                                           pi_vCodFilial  IN VARCHAR2)
  IS
    vnRegs                       NUMBER;
    vvQuebraCondicao             VARCHAR2(255);
    vvDescricaoQuebraCondicao    VARCHAR2(2000);
    vvArquivoCondicao            VARCHAR2(255);
    vvConteudo                   PCCONFIGSISTCONDOPERLOG.CONTEUDO%TYPE;
    vvConteudoCondicao           PCCONFIGSISTCONDOPERLOG.CONTEUDO%TYPE;
    vvOperacao                   PCCONFIGSISTCONDOPERLOG.OPERACAO%TYPE;     
    vvAlterouDetalhes            VARCHAR2(1);
    vvQtdeFixaCondicao           VARCHAR2(1);
    vvProgressivoCondicao        VARCHAR2(1);
    TYPE TRecUf                  IS RECORD (
         NUMREGIAO               PCREGIAO.NUMREGIAO%TYPE,
         UF                      PCREGIAO.UF%TYPE,
         CODCLI                  PCCLIENT.CODCLI%TYPE);
    vrUf                         TRecUf;
    TYPE TTvUf                   IS TABLE OF TRecUf INDEX BY BINARY_INTEGER;
    vtUf                         TTvUf;      
    vvCodigoPromocao             VARCHAR2(2000);   
    vvDescricaoPromocao          VARCHAR2(2000);   
    -- Variáveis para Cálculo do ST
    vvUsaTributacaoPorUf         PCCONSUM.USATRIBUTACAOPORUF%TYPE;    
    vnNumCasasDecVenda           NUMBER;
    vvUsaRegraRecalDescPtabMed   VARCHAR2(200);
    vvOrigemPreco                PCINTEGRADORA.ORIGEMPRECO%TYPE;    
    vvAplicarDescPtabelaTribut   PCINTEGRADORA.APLICARDESCPTABELATRIBUT%TYPE;
    vnIntegradora                PCCONFIGSISTOPERLOG.INTEGRADORA%TYPE;
    vvGerarAcordoPreco           PCCONFIGSISTOPERLOG.GERARACORDOPRECO%TYPE;
    vvAplicarIndiceAcordoPreco   PCCONFIGSISTOPERLOG.APLICARINDICEACORDOPRECO%TYPE;    
    vnPreco                      PCPEDI.PVENDA%TYPE;
    vnCodSt                      PCPEDI.CODST%TYPE;
    vnPercDesc                   NUMBER;
    vnPrecoVendaMarkup           NUMBER;
    vnPrecoLiquido               PCPEDI.PVENDA%TYPE;
    vnBaseSt                     PCPEDI.BASEICST%TYPE;
    vnValorSt                    PCPEDI.ST%TYPE;
    vvMensagemSt                 VARCHAR2(2000);    
    vvRegimeEspIsenStFonte       VARCHAR2(1);
    vnAliqIcms1                  PCPEDI.ALIQICMS1%TYPE;
    vnAliqIcms2                  PCPEDI.ALIQICMS2%TYPE;
    vnIva                        PCPEDI.IVA%TYPE;
    vnPercBaseRedSt              PCPEDI.PERCBASEREDSTFONTE%TYPE;
    -- Informações de Custo
    vvCodFilialRetira            PCFILIALRETIRA.CODFILIALRETIRA%TYPE;
    TYPE TTEstoque_CodProd       IS TABLE OF PCEST.CODPROD%TYPE INDEX BY BINARY_INTEGER;
    TYPE TTEstoque_Custo         IS TABLE OF PCEST.CUSTOFIN%TYPE INDEX BY BINARY_INTEGER; -- DDMEDICA-5980
    vtEstoque_CodProd            TTEstoque_CodProd;
    vtEstoque_Custo              TTEstoque_Custo;
    vtEstoque_CodProd_Custo      TTEstoque_Custo;
    vnCustoFinanceiro            PCEST.CUSTOFIN%TYPE;
    -- Observação
    vvObsExportacao              PCCONFIGSISTCONDOPERLOG.OBSEXPORTACAO%TYPE;
    -- Informações de Extração
    TYPE TT_VARCHAR2             IS TABLE OF VARCHAR2(2000) INDEX BY BINARY_INTEGER;
    TYPE TT_NUMBER               IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    TYPE TT_DATE                 IS TABLE OF DATE INDEX BY BINARY_INTEGER;
    --
    vtCODPROMOCAOMED_AUX         TT_NUMBER;
    vtDESCRICAORESUMIDA_AUX      TT_VARCHAR2;
    vtDESCRICAODETALHADA_AUX     TT_VARCHAR2;
    vtDATAINICIAL_AUX            TT_DATE;
    vtDATAFINAL_AUX              TT_DATE;
    vtATIVA_AUX                  TT_VARCHAR2;
    vtTIPOCONDICAOHYPERA_AUX     TT_VARCHAR2;
    vtTIPOCAMPANHAHYPERA_AUX     TT_VARCHAR2;
    vtRESTRICAOPLANO_AUX         TT_VARCHAR2;
    vtRESTRICAOCLIENTE_AUX       TT_VARCHAR2;
    vtRESTRICAOREGIAO_AUX        TT_VARCHAR2;
    vtCODPROD_AUX                TT_NUMBER;
    vtCODAUXILIAR_AUX            TT_NUMBER;
    vtTIPOMERC_AUX               TT_VARCHAR2;
    vtUTILIZAPRECOFABRICA_AUX    TT_VARCHAR2;
    vtTIPOPROMOCAO_AUX           TT_VARCHAR2;
    vtTIPOPOLITICA_AUX           TT_VARCHAR2;
    vtPERCDESC_AUX               TT_NUMBER;
    vtPERCMARKUPMED_AUX          TT_NUMBER;
    vtPRECOFIXOPROMOCAOMED_AUX   TT_NUMBER; 
    vtINICIOINTERVALO_AUX        TT_NUMBER;
    vtFIMINTERVALO_AUX           TT_NUMBER;
    vtOBRIGATORIO_AUX            TT_VARCHAR2;
    vtFAIXAZERO_AUX              TT_VARCHAR2;
	vtVALORMINIMO_AUX            TT_NUMBER;
    --
    vtCODPROMOCAOMED             TT_NUMBER;
    vtDESCRICAORESUMIDA          TT_VARCHAR2;
    vtDESCRICAODETALHADA         TT_VARCHAR2;
    vtDATAINICIAL                TT_DATE;
    vtDATAFINAL                  TT_DATE;
    vtATIVA                      TT_VARCHAR2;
    vtTIPOCONDICAOHYPERA         TT_VARCHAR2;
    vtTIPOCAMPANHAHYPERA         TT_VARCHAR2;
    vtRESTRICAOPLANO             TT_VARCHAR2;
    vtRESTRICAOCLIENTE           TT_VARCHAR2;
    vtRESTRICAOREGIAO            TT_VARCHAR2;
    vtCODPROD                    TT_NUMBER;
    vtCODAUXILIAR                TT_NUMBER;
    vtTIPOMERC                   TT_VARCHAR2;
    vtUTILIZAPRECOFABRICA        TT_VARCHAR2;
    vtTIPOPROMOCAO               TT_VARCHAR2;
    vtTIPOPOLITICA               TT_VARCHAR2;
    vtPERCDESC                   TT_NUMBER;
    vtPERCMARKUPMED              TT_NUMBER;
    vtPRECOFIXOPROMOCAOMED       TT_NUMBER; 
    vtINICIOINTERVALOPROMOCAOMED TT_NUMBER;
    vtFIMINTERVALOPROMOCAOMED    TT_NUMBER;
    vtPROMOCAOMEDOBRIGATORIO     TT_VARCHAR2;
    vtFAIXAZERO                  TT_VARCHAR2;
	vtVALORMINIMO                TT_NUMBER;
    --
    vtCODPLPAG                   TT_NUMBER;
    vtCGCFILIAL_PLPAG            TT_VARCHAR2;
    --
    vtCGCENT                     TT_VARCHAR2;
    --
    vtNUMREGIAO                  TT_NUMBER;
    vtUF_REGIAO                  TT_VARCHAR2;
    -- Campanha
    vnQtdeMinima                 NUMBER;
    vnFaixaInicial               NUMBER;
    vnFaixaFinal                 NUMBER;
    --
    viSequencia                  NUMBER;    
    viSequenciaQuebra            NUMBER;    
    --
    vvTipoRegistroProduto        VARCHAR2(1);
    vvTipoRegistroPdv            VARCHAR2(1);
    --
    vvGerarUf                    VARCHAR2(1);
    --
    vvTipoCodigoComplementarProd VARCHAR2(1000);
    vvCodigoComplementarProd     VARCHAR2(1000);
    --
    e_View                       EXCEPTION;
    --
    vvSql                        VARCHAR2(32000);
    --
    vvUsaTabTemp                 VARCHAR2(1);
    --
    vvPromocaoExiste             VARCHAR2(1);
    --
    TYPE TRecConteudoFilial      IS RECORD (
         vvArquivoCondicao       VARCHAR2(255),
         vvConteudo              PCCONFIGSISTCONDOPERLOG.CONTEUDO%TYPE,
         vvObsExportacao         PCCONFIGSISTCONDOPERLOG.OBSEXPORTACAO%TYPE,
         vvCodigoPromocao        VARCHAR2(2000),
         vvCgcFilial             VARCHAR2(2000),
         vnCodPlPag              NUMBER);
    TYPE TTvConteudoFilial       IS TABLE OF TRecConteudoFilial INDEX BY BINARY_INTEGER;
    vtConteudoFilial             TTvConteudoFilial;
    viIdxConteudoFilial          INTEGER;
    --
    vvQuebraAnteriorProgressivo  VARCHAR2(255);
    vvNovaQuebraProgressivo      VARCHAR2(255);
    viIdxProxItem                INTEGER;
	vsVersaoLayout               PCCONFIGSISTOPERLOG.VERSAO%TYPE;
	vsMixProduto                 VARCHAR(1);
    vsTipoFaixaProgressivo       VARCHAR(1);
    viQtdCompraColetiva          PCPROMOCAOMED.VLRMINITENSPROMOCAO%TYPE;
    viLimitador                  NUMBER; 
    viLiberacaoDeCanais          NUMBER;
    
    -------------------------------------------------------------------------------------------------------
    -- Procedimento para Gerar as Filiais sempre que houver qualquer alteração da Promoção - DDVENDAS-37737
    -------------------------------------------------------------------------------------------------------
    PROCEDURE P_GERA_DADOS_FILIAIS IS
    BEGIN
    
      -- Verifica caso não tenha alterado os detalhes se vai ter alteração do Cabeçalho da Promoção
      IF (NVL(vvAlterouDetalhes,'N') = 'N') THEN
        vvOperacao := F_VALIDA_REGISTRO_HYPER(pi_vCodSistema,
                                              pi_vCodFilial,
                                              vvArquivoCondicao,
                                              '1',
                                              vvConteudoCondicao,
                                              vvAlterouDetalhes,
                                              vvObsExportacao,
                                              'PM',
                                              vvQuebraCondicao);
        IF (vvOperacao <> 'N') THEN
          vvAlterouDetalhes := 'S';
        END IF;
      END IF;                                                    
    
      -- Gera os Dados da Filial a cada quebra
      IF (vtConteudoFilial.COUNT > 0) THEN
        FOR viIdxConteudoFilial IN vtConteudoFilial.FIRST..vtConteudoFilial.LAST LOOP
          vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                               pi_vCodFilial,
                                               vtConteudoFilial(viIdxConteudoFilial).vvArquivoCondicao,
                                               '2',
                                               vtConteudoFilial(viIdxConteudoFilial).vvConteudo,
                                               vvAlterouDetalhes, -->> Se houver qualquer alteração na Promoção precisará enviar as Filiais
                                               vtConteudoFilial(viIdxConteudoFilial).vvObsExportacao,
                                               'PM',
                                               vtConteudoFilial(viIdxConteudoFilial).vvCodigoPromocao,
                                               'FI',
                                               vtConteudoFilial(viIdxConteudoFilial).vvCgcFilial,
                                               'PL',
                                               vtConteudoFilial(viIdxConteudoFilial).vnCodPlPag);
          IF (vvOperacao <> 'N') THEN
            vvAlterouDetalhes := 'S';
          END IF;
        END LOOP;
      END IF; 
      
      -- Inicializa Conteudo das Filiais
      vtConteudoFilial.DELETE; 
      
    END P_GERA_DADOS_FILIAIS;    
    --    
  BEGIN
  
    -- Inicializa Tabela Temporária 
    BEGIN
      SELECT 'S'
        INTO vvUsaTabTemp
        FROM USER_TABLES
       WHERE (TABLE_NAME = 'PCMED_PROMOCAO_NIVEL_DSC_OL')
         AND (ROWNUM     = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUsaTabTemp := 'N';
    END;    
    IF (vvUsaTabTemp = 'S') THEN
      EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMED_PROMOCAO_NIVEL_DSC_OL';
    END IF;  
  
    -- Inicializa Dados da Nova Exportação    
    P_INICIALIZA_REGISTRO_HYPER(pi_vCodSistema,
                                pi_vCodFilial);
  
    -- Parâmetro Usa Tributação por UF e Usa PisCofins por Filial
    BEGIN
      SELECT NVL(USATRIBUTACAOPORUF,'N') USATRIBUTACAOPORUF
           , PCCONSUM.NUMCASASDECVENDA
        INTO vvUsaTributacaoPorUf
           , vnNumCasasDecVenda
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvUsaTributacaoPorUf := 'N';
        vnNumCasasDecVenda   := 2;
    END;
    
    -- Regra para Calcular o Desconto do Medicamento a partir do Preço Tabela
    vvUsaRegraRecalDescPtabMed := FUSA_REGRA_MEDICAMENTOS('99',
                                                          'USAREGRARECALDESCPTABMED2313');
    
    -- Configuração do Sistema de Pedido Eletrônico
    BEGIN
      SELECT PCCONFIGSISTOPERLOG.INTEGRADORA
           , PCCONFIGSISTOPERLOG.GERARACORDOPRECO
           , PCCONFIGSISTOPERLOG.APLICARINDICEACORDOPRECO
		   , PCCONFIGSISTOPERLOG.VERSAO
        INTO vnIntegradora
           , vvGerarAcordoPreco
           , vvAplicarIndiceAcordoPreco
		   , vsVersaoLayout
        FROM PCCONFIGSISTOPERLOG
       WHERE (PCCONFIGSISTOPERLOG.CODSISTEMA = pi_vCodSistema);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnIntegradora              := NULL;
        vvGerarAcordoPreco         := NULL;
        vvAplicarIndiceAcordoPreco := NULL;
		vsVersaoLayout             := NULL;
    END;
    
    -- Pesquisa o Tipo de Preço da Integradora
    BEGIN
      SELECT NVL(PCINTEGRADORA.ORIGEMPRECO,'F')
           , NVL(APLICARDESCPTABELATRIBUT,'N')
        INTO vvOrigemPreco
           , vvAplicarDescPtabelaTribut
        FROM PCINTEGRADORA
       WHERE (PCINTEGRADORA.INTEGRADORA = vnIntegradora);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvOrigemPreco              := 'F';
        vvAplicarDescPtabelaTribut := 'N';
    END;
    
    ---------------------------------------
    -- Informação de Estoque, carrega Array
    ---------------------------------------
    -- Verifica se Usará a Filial Retira
    BEGIN
      SELECT CODFILIALRETIRA
        INTO vvCodFilialRetira
        FROM PCFILIALRETIRA
       WHERE (CODFILIALVENDA = pi_vCodFilial)
         AND ((SELECT VALOR 
                 FROM PCREGRASEXCECAOMED
                WHERE PCREGRASEXCECAOMED.NOME = 'USAFILIALRETIRADICDADOS' 
                  AND PCREGRASEXCECAOMED.CODFILIAL = '99') = 'S')
         AND (ROWNUM = 1);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvCodFilialRetira := pi_vCodFilial;
    END;
    vtEstoque_CodProd.DELETE;
    vtEstoque_Custo.DELETE; 
    vtEstoque_CodProd_Custo.DELETE;
    SELECT PCEST.CODPROD
         , PCEST.CUSTOFIN
    BULK COLLECT INTO vtEstoque_CodProd
                    , vtEstoque_Custo
     FROM PCEST
        , PCPRODUT
        , PCCONFIGSISTMARCAOPERLOG
    WHERE (PCEST.CODPROD                       = PCPRODUT.CODPROD)
      AND (PCCONFIGSISTMARCAOPERLOG.CODSISTEMA = pi_vCodSistema)
      AND (PCCONFIGSISTMARCAOPERLOG.CODMARCA   = PCPRODUT.CODMARCA)
      AND (PCEST.CODFILIAL                     = vvCodFilialRetira);
    -- Carrega Array Indexado pelo Produto
    IF (vtEstoque_CodProd.COUNT > 0) THEN
      FOR viIdxEstoque IN vtEstoque_CodProd.FIRST..vtEstoque_CodProd.LAST LOOP
        -- CUSTO
        vtEstoque_CodProd_Custo(vtEstoque_CodProd(viIdxEstoque)) := vtEstoque_Custo(viIdxEstoque);
      END LOOP;
    END IF;
          
    -- Inicializa Controle de Quebra de Condição
    vvQuebraCondicao          := '@';
    vvDescricaoQuebraCondicao := NULL;
    
    -- Inicializa Sequências
    viSequencia       := 0;
    viSequenciaQuebra := 0;    

    ------------------------------------------------------
    -- Verifica se está preparado para a Tabela Temporária
    ------------------------------------------------------

    IF (vvUsaTabTemp = 'S') THEN
    
      -- Prepara a Tabela Temporária
      EXECUTE IMMEDIATE 'INSERT INTO PCMED_PROMOCAO_NIVEL_DSC_OL
                              SELECT PCDESCONTO.CODPROMOCAOMED
                                   , PCPRODUT.CODPROD
                                   , NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0) AS INICIOINTERVALOPROMOCAOMED
                                   , NVL(PCDESCONTO.FIMINTERVALOPROMOCAOMED,0) AS FIMINTERVALOPROMOCAOMED
                                   , MIN(CASE WHEN (NVL(PCDESCONTO.CODPROD,0) > 0) THEN 1
                                           WHEN (NVL(PCDESCONTO.CODGRUPOREST,0) > 0) THEN 2
                                           WHEN (NVL(PCDESCONTO.CODFORNEC,0) > 0) THEN 3
                                           WHEN (NVL(PCDESCONTO.CODMARCA,0) > 0) THEN 4
                                           WHEN (NVL(PCDESCONTO.CODCATEGORIA,0) > 0) THEN 5
                                           WHEN (NVL(PCDESCONTO.CODSEC,0) > 0) THEN 6
                                           WHEN (NVL(PCDESCONTO.CODLINHAPROD,0) > 0) THEN 7
                                           WHEN (NVL(PCDESCONTO.CODEPTO,0) > 0) THEN 8
                                           ELSE 999
                                         END) NIVEL
                                FROM PCPRODUT
                                   , PCDESCONTO
                                   , VIEW_MED_PROMOCAO
                                   , PCGRUPOSCAMPANHAI
                               WHERE (PCDESCONTO.CODPROMOCAOMED = VIEW_MED_PROMOCAO.CODPROMOCAOMED)
                                 AND (PCDESCONTO.TIPOFV = ''OL'')
                                 AND (PCDESCONTO.DTFIM >= TRUNC(SYSDATE)-7)
                                 AND (PCPRODUT.DTEXCLUSAO IS NULL)
                                 AND (PCPRODUT.CODMARCA IN (SELECT PCCONFIGSISTMARCAOPERLOG.CODMARCA
                                                              FROM PCCONFIGSISTMARCAOPERLOG
                                                                 , PCCONFIGSISTOPERLOG
                                                                 , PCINTEGRADORA
                                                             WHERE (PCCONFIGSISTMARCAOPERLOG.CODSISTEMA = PCCONFIGSISTOPERLOG.CODSISTEMA)
                                                               AND (PCCONFIGSISTOPERLOG.INTEGRADORA     = PCINTEGRADORA.INTEGRADORA)
                                                               AND (PCINTEGRADORA.LAYOUT                = 57))) -- CLOSE-UP
                                 AND (PCPRODUT.CODPROD = PCGRUPOSCAMPANHAI.CODITEM(+))
                                 AND ((PCDESCONTO.CODEPTO = PCPRODUT.CODEPTO) OR
                                      (PCDESCONTO.CODSEC = PCPRODUT.CODSEC) OR
                                      (PCDESCONTO.CODCATEGORIA = PCPRODUT.CODCATEGORIA) OR
                                      (PCDESCONTO.CODFORNEC = PCPRODUT.CODFORNEC) OR
                                      (PCDESCONTO.CODMARCA = PCPRODUT.CODMARCA) OR
                                      (PCDESCONTO.CODLINHAPROD = PCPRODUT.CODLINHAPROD) OR
                                      (PCDESCONTO.CODGRUPOREST = PCGRUPOSCAMPANHAI.CODGRUPO) OR
                                      (PCDESCONTO.CODPROD = PCPRODUT.CODPROD))
                                GROUP BY PCDESCONTO.CODPROMOCAOMED
                                       , PCPRODUT.CODPROD
                                       , NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0)
                                       , NVL(PCDESCONTO.FIMINTERVALOPROMOCAOMED,0) ';

      -- SQL de Consulta
      vvSql := ' SELECT VIEW_MED_PROMOCAO.CODPROMOCAOMED
                      , VIEW_MED_PROMOCAO.DESCRICAORESUMIDA
                      , VIEW_MED_PROMOCAO.DESCRICAODETALHADA
                      , VIEW_MED_PROMOCAO.DATAINICIAL
                      , VIEW_MED_PROMOCAO.DATAFINAL
                      , VIEW_MED_PROMOCAO.ATIVA
                      , NVL((SELECT VALOR 
                               FROM PCPARAMINTEGRADORAMED
                              WHERE PCPARAMINTEGRADORAMED.INTEGRADORA = ' || NVL(vnIntegradora,0) || '
                                AND PCPARAMINTEGRADORAMED.NOME        = ''TIPOCONDICAOHYPERA2313''),1) TIPOCONDICAOHYPERA
                      , NVL((SELECT VALOR 
                               FROM PCPARAMINTEGRADORAMED
                              WHERE PCPARAMINTEGRADORAMED.INTEGRADORA = ' || NVL(vnIntegradora,0) || '
                                AND PCPARAMINTEGRADORAMED.NOME        = ''TIPOCAMPANHAHYPERA2313''),1) TIPOCAMPANHAHYPERA
                      , VIEW_MED_PROMOCAO.RESTRICAOPLANO
                      , VIEW_MED_PROMOCAO.RESTRICAOCLIENTE
                      , VIEW_MED_PROMOCAO.RESTRICAOREGIAO
                      , VIEW_MED_PROMOCAO_DESC_HYPER.CODPROD
                      , VIEW_MED_PROMOCAO_DESC_HYPER.CODAUXILIAR
                      , VIEW_MED_PROMOCAO_DESC_HYPER.TIPOMERC
                      , VIEW_MED_PROMOCAO_DESC_HYPER.UTILIZAPRECOFABRICA
                      , VIEW_MED_PROMOCAO_DESC_HYPER.TIPOPROMOCAO
                      , VIEW_MED_PROMOCAO_DESC_HYPER.TIPOPOLITICA
                      , VIEW_MED_PROMOCAO_DESC_HYPER.PERCDESC
                      , VIEW_MED_PROMOCAO_DESC_HYPER.PERCMARKUPMED
                      , VIEW_MED_PROMOCAO_DESC_HYPER.PRECOFIXOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESC_HYPER.INICIOINTERVALOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESC_HYPER.FIMINTERVALOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESC_HYPER.PROMOCAOMEDOBRIGATORIO
                      , ''N'' FAIXAZERO
					  , VIEW_MED_PROMOCAO.VALORMINIMO
                   FROM PCCONFIGSISTMARCAOPERLOG
                      , VIEW_MED_PROMOCAO
                      , VIEW_MED_PROMOCAO_FILIAL
                      , VIEW_MED_PROMOCAO_DESC_HYPER
                  WHERE (PCCONFIGSISTMARCAOPERLOG.CODSISTEMA = ' || '''' || pi_vCodSistema || '''' || ')
                    AND  VIEW_MED_PROMOCAO.DATAFINAL >= TRUNC(SYSDATE) - 7
                    AND NOT EXISTS(SELECT 1
                                     FROM PCCONFIGSISTCONDOPERLOG
                                    WHERE (PCCONFIGSISTCONDOPERLOG.CODSISTEMA = ' || '''' || pi_vCodSistema || '''' || ')
                                      AND (PCCONFIGSISTCONDOPERLOG.CODFILIAL  = ' || '''' || pi_vCodFilial || '''' || ')
                                      AND (PCCONFIGSISTCONDOPERLOG.TIPOREGISTRO = ''1'')
                                      AND (PCCONFIGSISTCONDOPERLOG.CODIGOPRINCIPAL = VIEW_MED_PROMOCAO.CODPROMOCAOMED)
                                      AND (PCCONFIGSISTCONDOPERLOG.DTEXPORTACAO > VIEW_MED_PROMOCAO.DATAFINAL))					
                    AND (PCCONFIGSISTMARCAOPERLOG.CODMARCA   = VIEW_MED_PROMOCAO_DESC_HYPER.CODMARCA)
                    AND (VIEW_MED_PROMOCAO.CODPROMOCAOMED    = VIEW_MED_PROMOCAO_DESC_HYPER.CODPROMOCAOMED)
                    AND (VIEW_MED_PROMOCAO.CODPROMOCAOMED    = VIEW_MED_PROMOCAO_FILIAL.CODPROMOCAOMED)
                    AND (VIEW_MED_PROMOCAO_FILIAL.CODFILIAL  = ' || '''' || pi_vCodFilial || '''' || ')
                    AND (VIEW_MED_PROMOCAO.ENVIAOL           = ''S'')
                    AND (VIEW_MED_PROMOCAO.TIPOPROMOCAO      NOT IN (''B'',''L''))
                    AND ((VIEW_MED_PROMOCAO.RESTRICAOCONDICAOVENDA = ''N'') OR
                         ((VIEW_MED_PROMOCAO.RESTRICAOCONDICAOVENDA = ''S'') AND 
                          (EXISTS (SELECT ''S'' 
                                     FROM VIEW_MED_PROMOCAO_CONDICAOVEN 
                                    WHERE VIEW_MED_PROMOCAO_CONDICAOVEN.CODPROMOCAOMED = VIEW_MED_PROMOCAO.CODPROMOCAOMED
                                      AND VIEW_MED_PROMOCAO_CONDICAOVEN.CODCONDICAOVENDA IN (SELECT PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA
                                                                                               FROM PCCONDVENDAINTEGRADORA
                                                                                                  , PCCONDVENDAFILIAL
                                                                                                  , PCCONFIGSISTFILOPERLOG
                                                                                                  , PCCONFIGSISTOPERLOG
                                                                                              WHERE PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDVENDAFILIAL.CODCONDICAOVENDA
                                                                                                AND PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL   
                                                                                                AND PCCONFIGSISTOPERLOG.INTEGRADORA         = PCCONDVENDAINTEGRADORA.INTEGRADORA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTMARCAOPERLOG.CODSISTEMA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODFILIAL        = ' || '''' || pi_vCodFilial || '''' || ')))))
                  ORDER BY VIEW_MED_PROMOCAO.CODPROMOCAOMED
                         , VIEW_MED_PROMOCAO_DESC_HYPER.CODPROD                         
                         , VIEW_MED_PROMOCAO_DESC_HYPER.INICIOINTERVALOPROMOCAOMED ';
    
    ELSE

      -- SQL de Consulta
      vvSql := ' SELECT VIEW_MED_PROMOCAO.CODPROMOCAOMED
                      , VIEW_MED_PROMOCAO.DESCRICAORESUMIDA
                      , VIEW_MED_PROMOCAO.DESCRICAODETALHADA
                      , VIEW_MED_PROMOCAO.DATAINICIAL
                      , VIEW_MED_PROMOCAO.DATAFINAL
                      , VIEW_MED_PROMOCAO.ATIVA
                      , NVL((SELECT VALOR 
                               FROM PCPARAMINTEGRADORAMED
                              WHERE PCPARAMINTEGRADORAMED.INTEGRADORA = ' || NVL(vnIntegradora,0) || '
                                AND PCPARAMINTEGRADORAMED.NOME        = ''TIPOCONDICAOHYPERA2313''),1) TIPOCONDICAOHYPERA
                      , NVL((SELECT VALOR 
                               FROM PCPARAMINTEGRADORAMED
                              WHERE PCPARAMINTEGRADORAMED.INTEGRADORA = ' || NVL(vnIntegradora,0) || '
                                AND PCPARAMINTEGRADORAMED.NOME        = ''TIPOCAMPANHAHYPERA2313''),1) TIPOCAMPANHAHYPERA
                      , VIEW_MED_PROMOCAO.RESTRICAOPLANO
                      , VIEW_MED_PROMOCAO.RESTRICAOCLIENTE
                      , VIEW_MED_PROMOCAO.RESTRICAOREGIAO
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.CODPROD
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.CODAUXILIAR
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.TIPOMERC
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.UTILIZAPRECOFABRICA
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.TIPOPROMOCAO
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.TIPOPOLITICA
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.PERCDESC
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.PERCMARKUPMED
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.PRECOFIXOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.INICIOINTERVALOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.FIMINTERVALOPROMOCAOMED
                      , VIEW_MED_PROMOCAO_DESCONTO_OL.PROMOCAOMEDOBRIGATORIO
                      , ''N'' FAIXAZERO
					  , VIEW_MED_PROMOCAO.VALORMINIMO
                   FROM PCCONFIGSISTMARCAOPERLOG
                      , VIEW_MED_PROMOCAO
                      , VIEW_MED_PROMOCAO_FILIAL
                      , VIEW_MED_PROMOCAO_DESCONTO_OL
                  WHERE (PCCONFIGSISTMARCAOPERLOG.CODSISTEMA = ' || '''' || pi_vCodSistema || '''' || ')
                    AND  VIEW_MED_PROMOCAO.DATAFINAL >= TRUNC(SYSDATE) - 7
                    AND NOT EXISTS(SELECT 1
                                     FROM PCCONFIGSISTCONDOPERLOG
                                    WHERE (PCCONFIGSISTCONDOPERLOG.CODSISTEMA = ' || '''' || pi_vCodSistema || '''' || ')
                                      AND (PCCONFIGSISTCONDOPERLOG.CODFILIAL  = ' || '''' || pi_vCodFilial || '''' || ')
                                      AND (PCCONFIGSISTCONDOPERLOG.TIPOREGISTRO = ''1'')
                                      AND (PCCONFIGSISTCONDOPERLOG.CODIGOPRINCIPAL = VIEW_MED_PROMOCAO.CODPROMOCAOMED)
                                      AND (PCCONFIGSISTCONDOPERLOG.DTEXPORTACAO > VIEW_MED_PROMOCAO.DATAFINAL))					
                    AND (PCCONFIGSISTMARCAOPERLOG.CODMARCA   = VIEW_MED_PROMOCAO_DESCONTO_OL.CODMARCA)
                    AND (VIEW_MED_PROMOCAO.CODPROMOCAOMED    = VIEW_MED_PROMOCAO_DESCONTO_OL.CODPROMOCAOMED)
                    AND (VIEW_MED_PROMOCAO.CODPROMOCAOMED    = VIEW_MED_PROMOCAO_FILIAL.CODPROMOCAOMED)
                    AND (VIEW_MED_PROMOCAO_FILIAL.CODFILIAL  = ' || '''' || pi_vCodFilial || '''' || ')
                    AND (VIEW_MED_PROMOCAO.ENVIAOL           = ''S'')
                    AND (VIEW_MED_PROMOCAO.TIPOPROMOCAO      NOT IN (''B'',''L''))
                    AND ((VIEW_MED_PROMOCAO.RESTRICAOCONDICAOVENDA = ''N'') OR
                         ((VIEW_MED_PROMOCAO.RESTRICAOCONDICAOVENDA = ''S'') AND 
                          (EXISTS (SELECT ''S'' 
                                     FROM VIEW_MED_PROMOCAO_CONDICAOVEN 
                                    WHERE VIEW_MED_PROMOCAO_CONDICAOVEN.CODPROMOCAOMED = VIEW_MED_PROMOCAO.CODPROMOCAOMED
                                      AND VIEW_MED_PROMOCAO_CONDICAOVEN.CODCONDICAOVENDA IN (SELECT PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA
                                                                                               FROM PCCONDVENDAINTEGRADORA
                                                                                                  , PCCONDVENDAFILIAL
                                                                                                  , PCCONFIGSISTFILOPERLOG
                                                                                                  , PCCONFIGSISTOPERLOG
                                                                                              WHERE PCCONDVENDAINTEGRADORA.CODCONDICAOVENDA = PCCONDVENDAFILIAL.CODCONDICAOVENDA
                                                                                                AND PCCONDVENDAFILIAL.CODFILIAL             = PCCONFIGSISTFILOPERLOG.CODFILIAL   
                                                                                                AND PCCONFIGSISTOPERLOG.INTEGRADORA         = PCCONDVENDAINTEGRADORA.INTEGRADORA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTOPERLOG.CODSISTEMA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODSISTEMA       = PCCONFIGSISTMARCAOPERLOG.CODSISTEMA
                                                                                                AND PCCONFIGSISTFILOPERLOG.CODFILIAL        = ' || '''' || pi_vCodFilial || '''' || ')))))
                  ORDER BY VIEW_MED_PROMOCAO.CODPROMOCAOMED
                         , VIEW_MED_PROMOCAO_DESCONTO_OL.CODPROD
                         , VIEW_MED_PROMOCAO_DESCONTO_OL.INICIOINTERVALOPROMOCAOMED ';
    
    END IF;
 
    -----------------------
    -- Carrega as Promoções
    -----------------------
    
    BEGIN
      EXECUTE IMMEDIATE vvSql 
        BULK COLLECT INTO vtCODPROMOCAOMED_AUX
                        , vtDESCRICAORESUMIDA_AUX
                        , vtDESCRICAODETALHADA_AUX
                        , vtDATAINICIAL_AUX
                        , vtDATAFINAL_AUX
                        , vtATIVA_AUX
                        , vtTIPOCONDICAOHYPERA_AUX
                        , vtTIPOCAMPANHAHYPERA_AUX
                        , vtRESTRICAOPLANO_AUX
                        , vtRESTRICAOCLIENTE_AUX
                        , vtRESTRICAOREGIAO_AUX
                        , vtCODPROD_AUX
                        , vtCODAUXILIAR_AUX
                        , vtTIPOMERC_AUX
                        , vtUTILIZAPRECOFABRICA_AUX
                        , vtTIPOPROMOCAO_AUX
                        , vtTIPOPOLITICA_AUX
                        , vtPERCDESC_AUX
                        , vtPERCMARKUPMED_AUX
                        , vtPRECOFIXOPROMOCAOMED_AUX
                        , vtINICIOINTERVALO_AUX
                        , vtFIMINTERVALO_AUX
                        , vtOBRIGATORIO_AUX
                        , vtFAIXAZERO_AUX
						, vtVALORMINIMO_AUX;
    EXCEPTION
      WHEN OTHERS THEN
        RAISE e_View;
    END;                        
  
    ------------------------------------------------------------------
    -- Inclusão das Faixas Iniciais com Zero
    ------------------------------------------------------------------
    IF (vtCODPROMOCAOMED_AUX.COUNT > 0) THEN

      vvQuebraAnteriorProgressivo := '@';

      FOR viIdxPromocao IN vtCODPROMOCAOMED_AUX.FIRST..vtCODPROMOCAOMED_AUX.LAST LOOP
            
        -- Se Possui Faixa de Quantidade
        IF (vtTIPOPOLITICA_AUX(viIdxPromocao) IN ('Q','F')) THEN
        
          vvNovaQuebraProgressivo := TO_CHAR(vtCODPROMOCAOMED_AUX(viIdxPromocao)) || '|' || TO_CHAR(vtCODPROD_AUX(viIdxPromocao));

          -- Se Quebra Promoção + Produto        
          IF (vvQuebraAnteriorProgressivo <> vvNovaQuebraProgressivo) THEN
          
            -- Se a primeira faixa iniciar com valor superior a 1 insere nova faixa 0 até a quantidade inicial - 1
            IF (vtINICIOINTERVALO_AUX(viIdxPromocao) > 1) THEN
          
              viIdxProxItem := NVL(vtCODPROMOCAOMED.COUNT,0) + 1;
              
              vtCODPROMOCAOMED(viIdxProxItem)             := vtCODPROMOCAOMED_AUX(viIdxPromocao);
              vtDESCRICAORESUMIDA(viIdxProxItem)          := vtDESCRICAORESUMIDA_AUX(viIdxPromocao);
              vtDESCRICAODETALHADA(viIdxProxItem)         := vtDESCRICAODETALHADA_AUX(viIdxPromocao);
              vtDATAINICIAL(viIdxProxItem)                := vtDATAINICIAL_AUX(viIdxPromocao);
              vtDATAFINAL(viIdxProxItem)                  := vtDATAFINAL_AUX(viIdxPromocao);
              vtATIVA(viIdxProxItem)                      := vtATIVA_AUX(viIdxPromocao);
              vtTIPOCONDICAOHYPERA(viIdxProxItem)         := vtTIPOCONDICAOHYPERA_AUX(viIdxPromocao);
              vtTIPOCAMPANHAHYPERA(viIdxProxItem)         := vtTIPOCAMPANHAHYPERA_AUX(viIdxPromocao);
              vtRESTRICAOPLANO(viIdxProxItem)             := vtRESTRICAOPLANO_AUX(viIdxPromocao);
              vtRESTRICAOCLIENTE(viIdxProxItem)           := vtRESTRICAOCLIENTE_AUX(viIdxPromocao);
              vtRESTRICAOREGIAO(viIdxProxItem)            := vtRESTRICAOREGIAO_AUX(viIdxPromocao);
              vtCODPROD(viIdxProxItem)                    := vtCODPROD_AUX(viIdxPromocao);
              vtCODAUXILIAR(viIdxProxItem)                := vtCODAUXILIAR_AUX(viIdxPromocao);
              vtTIPOMERC(viIdxProxItem)                   := vtTIPOMERC_AUX(viIdxPromocao);
              vtUTILIZAPRECOFABRICA(viIdxProxItem)        := vtUTILIZAPRECOFABRICA_AUX(viIdxPromocao);
              vtTIPOPROMOCAO(viIdxProxItem)               := vtTIPOPROMOCAO_AUX(viIdxPromocao);
              vtTIPOPOLITICA(viIdxProxItem)               := vtTIPOPOLITICA_AUX(viIdxPromocao);
              vtPERCDESC(viIdxProxItem)                   := vtPERCDESC_AUX(viIdxPromocao);
              vtPERCMARKUPMED(viIdxProxItem)              := vtPERCMARKUPMED_AUX(viIdxPromocao);
              vtPRECOFIXOPROMOCAOMED(viIdxProxItem)       := vtPRECOFIXOPROMOCAOMED_AUX(viIdxPromocao);
              vtINICIOINTERVALOPROMOCAOMED(viIdxProxItem) := 0; -- VALOR INICIAL COMEÇA COM ZERO
              vtFIMINTERVALOPROMOCAOMED(viIdxProxItem)    := (vtINICIOINTERVALO_AUX(viIdxPromocao) - 1); -- NOVO VALOR FINAL
              vtPROMOCAOMEDOBRIGATORIO(viIdxProxItem)     := vtOBRIGATORIO_AUX(viIdxPromocao);
              vtFAIXAZERO(viIdxProxItem)                  := 'S'; -->> INDICATIVO DE FAIXA ZERO PARA NÃO TER DESCONTO
              vtVALORMINIMO(viIdxProxItem)                := vtVALORMINIMO_AUX(viIdxPromocao);
            -- Se a primeira faixa iniciar no valor 1, somente puxa a quantidade inicial para zero
            ELSE

              vtINICIOINTERVALO_AUX(viIdxPromocao) := 0;
            
            END IF;
                        
            vvQuebraAnteriorProgressivo := vvNovaQuebraProgressivo;
           
          END IF; -- Fim: Se Quebra Promoção + Produto

        END IF; -- Fim: Se Possui Faixa de Quantidade         

        -- Adiciona Item à Lista Definitiva
        
        viIdxProxItem := NVL(vtCODPROMOCAOMED.COUNT,0) + 1;
        
        vtCODPROMOCAOMED(viIdxProxItem)             := vtCODPROMOCAOMED_AUX(viIdxPromocao);
        vtDESCRICAORESUMIDA(viIdxProxItem)          := vtDESCRICAORESUMIDA_AUX(viIdxPromocao);
        vtDESCRICAODETALHADA(viIdxProxItem)         := vtDESCRICAODETALHADA_AUX(viIdxPromocao);
        vtDATAINICIAL(viIdxProxItem)                := vtDATAINICIAL_AUX(viIdxPromocao);
        vtDATAFINAL(viIdxProxItem)                  := vtDATAFINAL_AUX(viIdxPromocao);
        vtATIVA(viIdxProxItem)                      := vtATIVA_AUX(viIdxPromocao);
        vtTIPOCONDICAOHYPERA(viIdxProxItem)         := vtTIPOCONDICAOHYPERA_AUX(viIdxPromocao);
        vtTIPOCAMPANHAHYPERA(viIdxProxItem)         := vtTIPOCAMPANHAHYPERA_AUX(viIdxPromocao);
        vtRESTRICAOPLANO(viIdxProxItem)             := vtRESTRICAOPLANO_AUX(viIdxPromocao);
        vtRESTRICAOCLIENTE(viIdxProxItem)           := vtRESTRICAOCLIENTE_AUX(viIdxPromocao);
        vtRESTRICAOREGIAO(viIdxProxItem)            := vtRESTRICAOREGIAO_AUX(viIdxPromocao);
        vtCODPROD(viIdxProxItem)                    := vtCODPROD_AUX(viIdxPromocao);
        vtCODAUXILIAR(viIdxProxItem)                := vtCODAUXILIAR_AUX(viIdxPromocao);
        vtTIPOMERC(viIdxProxItem)                   := vtTIPOMERC_AUX(viIdxPromocao);
        vtUTILIZAPRECOFABRICA(viIdxProxItem)        := vtUTILIZAPRECOFABRICA_AUX(viIdxPromocao);
        vtTIPOPROMOCAO(viIdxProxItem)               := vtTIPOPROMOCAO_AUX(viIdxPromocao);
        vtTIPOPOLITICA(viIdxProxItem)               := vtTIPOPOLITICA_AUX(viIdxPromocao);
        vtPERCDESC(viIdxProxItem)                   := vtPERCDESC_AUX(viIdxPromocao);
        vtPERCMARKUPMED(viIdxProxItem)              := vtPERCMARKUPMED_AUX(viIdxPromocao);
        vtPRECOFIXOPROMOCAOMED(viIdxProxItem)       := vtPRECOFIXOPROMOCAOMED_AUX(viIdxPromocao);
        vtINICIOINTERVALOPROMOCAOMED(viIdxProxItem) := vtINICIOINTERVALO_AUX(viIdxPromocao);
        vtFIMINTERVALOPROMOCAOMED(viIdxProxItem)    := vtFIMINTERVALO_AUX(viIdxPromocao);
        vtPROMOCAOMEDOBRIGATORIO(viIdxProxItem)     := vtOBRIGATORIO_AUX(viIdxPromocao);
        vtFAIXAZERO(viIdxProxItem)                  := vtFAIXAZERO_AUX(viIdxPromocao);
		vtVALORMINIMO(viIdxProxItem)                := vtVALORMINIMO_AUX(viIdxPromocao);
      
      END LOOP;

    END IF;

    ------------------------------------------------------------------
    -- Inicio do Processamento
    ------------------------------------------------------------------
    IF (vtCODPROMOCAOMED.COUNT > 0) THEN
  
      FOR viIdxPromocao IN vtCODPROMOCAOMED.FIRST..vtCODPROMOCAOMED.LAST LOOP
      
        -- Pega o Código e Descrição da Promoção
        vvCodigoPromocao    := TO_CHAR(vtCODPROMOCAOMED(viIdxPromocao));
        vvDescricaoPromocao := vtDESCRICAORESUMIDA(viIdxPromocao);

        ------------------------------------------------------------------
        -- Regra Hypera para Condição Vencida
        ------------------------------------------------------------------

        -- Data Inicial nunca pode ser inferior à data atual
        IF (TRUNC(vtDATAINICIAL(viIdxPromocao)) < TRUNC(SYSDATE)) THEN
          vtDATAINICIAL(viIdxPromocao) := TRUNC(SYSDATE);
        END IF;

        -- Data Final nunca pode ser inferior à data atual, e se venceu torna-se INATIVA
        IF (TRUNC(vtDATAFINAL(viIdxPromocao)) < TRUNC(SYSDATE)) THEN
          vtDATAFINAL(viIdxPromocao)   := TRUNC(SYSDATE);
          vtATIVA(viIdxPromocao)       := 'N';
        END IF;
                   
        ------------------------------------------------------------------
        -- Regra Hypera para Condição Futura
        ------------------------------------------------------------------

        -- Condição Futura será enviada como ATIVA
        IF (TRUNC(vtDATAFINAL(viIdxPromocao)) > TRUNC(SYSDATE)) THEN
          vtATIVA(viIdxPromocao)       := 'S';
        END IF;
                   
        ------------------------------------------------------------------
        -- Quebra e Geração de Valores que são gerados somente nas Quebras
        ------------------------------------------------------------------
                                  
        -- Quebra de Condição                                  
        IF (vvQuebraCondicao <> vvCodigoPromocao) THEN 
         
          -- Se não foi a primeira vez
          IF (vvQuebraCondicao <> '@') THEN
          
            ----------------------------------------
            -- Geração das Filiais -  DDVENDAS-37737
            ----------------------------------------
            P_GERA_DADOS_FILIAIS;
                    
            -- Observação da última quebra
            vvObsExportacao := TRIM(TO_CHAR(viSequenciaQuebra,'000000000')) ||
                               ' ; CODPROMOCAO: ' || vvQuebraCondicao       ||
                               ' ; DESCRICAO: '   || vvDescricaoQuebraCondicao;
          
            -- Grava o Registro da última quebra
            vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                 pi_vCodFilial,
                                                 vvArquivoCondicao,
                                                 '1',
                                                 vvConteudoCondicao,
                                                 vvAlterouDetalhes,
                                                 vvObsExportacao,
                                                 'PM',
                                                 vvQuebraCondicao);
            -- Inicializa Controle de Detalhes
            vvAlterouDetalhes := NULL;    
            
          END IF;
        
          -- Nova Quebra
          vvQuebraCondicao          := vvCodigoPromocao;
          vvDescricaoQuebraCondicao := vvDescricaoPromocao;
          
          -- Novo Arquivo
          IF (vtTIPOPROMOCAO(viIdxPromocao) IN ('K','M','V')) OR 
             (vtTIPOPOLITICA(viIdxPromocao) IN ('Q','F')) THEN
            -- Arquivo de Campanhas abrange Promoção Combos/Mix/Valor e por Faixa de Quantidade
            vvArquivoCondicao := 'CAMPANHA';
          ELSE
            -- Arquivo de Condição abrange as demais Promoções
            vvArquivoCondicao := 'CONDICAO';
          END IF;          
        
          -- Registro de Campanha - Promoção de Kit e Faixa de Quantidade
          IF (vvArquivoCondicao = 'CAMPANHA') THEN
            -- Somente Combo é Quantidade Fixa
            IF (vtTIPOPROMOCAO(viIdxPromocao) = 'K') THEN
              vvQtdeFixaCondicao := 'S';
            ELSE
              vvQtdeFixaCondicao := 'N';
            END IF;
            -- Somente Faixa de Quantidade é Progressivo
            IF (vtTIPOPOLITICA(viIdxPromocao) IN ('Q','F')) THEN              
              vvProgressivoCondicao := 'S';
			  vsTipoFaixaProgressivo := 'Q';
            ELSE
              vvProgressivoCondicao := 'N';
			  vsTipoFaixaProgressivo := '';
            END IF;            
            
			-- Novo Layout
			IF vsVersaoLayout = '4.18.2' THEN
               vsMixProduto        := 'N';
               viLimitador         := 99999;
               viLiberacaoDeCanais := 0;
              
               viQtdCompraColetiva := 0;
               IF vtTIPOPROMOCAO(viIdxPromocao) IN ('M', 'F') THEN
                 viQtdCompraColetiva := NVL(vtVALORMINIMO(viIdxPromocao),0); 
               END IF;
			   
               vvConteudoCondicao := '1'                                                  ||
                                  RPAD_BRANCOS(vvCodigoPromocao, 20)                      ||
                                  GET_CHR_OP                                              ||
                                  RPAD_BRANCOS(vvDescricaoPromocao, 255)                  ||
                                  TO_CHAR(vtDATAINICIAL(viIdxPromocao), 'YYYYMMDD')       ||
                                  TO_CHAR(vtDATAFINAL(viIdxPromocao), 'YYYYMMDD')         ||
                                  RPAD_BRANCOS(vtATIVA(viIdxPromocao), 1)                 ||
                                  RPAD_BRANCOS(vvQtdeFixaCondicao, 1)                     ||
                                  RPAD_BRANCOS(vvProgressivoCondicao, 1)                  ||
                                  RPAD_BRANCOS(vtDESCRICAODETALHADA(viIdxPromocao), 2000) ||
                                  RPAD_BRANCOS(vtTIPOCAMPANHAHYPERA(viIdxPromocao), 1)    ||
                                  RPAD_BRANCOS(vsMixProduto,1)                            ||
                                  RPAD_BRANCOS(vsTipoFaixaProgressivo,1)                  ||
                                  LPAD_ZEROS(viQtdCompraColetiva,5)                       ||
                                  LPAD_ZEROS(viLimitador,5)                               ||
                                  RPAD_BRANCOS(viLiberacaoDeCanais,1);
            ELSE
               vvConteudoCondicao := '1'                                                  ||
                                  RPAD_BRANCOS(vvCodigoPromocao, 20)                      ||
                                  GET_CHR_OP                                              ||
                                  RPAD_BRANCOS(vvDescricaoPromocao, 255)                  ||
                                  TO_CHAR(vtDATAINICIAL(viIdxPromocao), 'YYYYMMDD')       ||
                                  TO_CHAR(vtDATAFINAL(viIdxPromocao), 'YYYYMMDD')         ||
                                  RPAD_BRANCOS(vtATIVA(viIdxPromocao), 1)                 ||
                                  RPAD_BRANCOS(vvQtdeFixaCondicao, 1)                     ||
                                  RPAD_BRANCOS(vvProgressivoCondicao, 1)                  ||
                                  RPAD_BRANCOS(vtDESCRICAODETALHADA(viIdxPromocao), 2000) ||
                                  RPAD_BRANCOS(vtTIPOCAMPANHAHYPERA(viIdxPromocao), 1);
            END IF; -- vsVersaoLayout = '4.18.2'
			
          -- Registro de Condição - Demais Promoções
          ELSE
            vvConteudoCondicao := '1'                                                   ||
                                  RPAD_BRANCOS(vvCodigoPromocao, 20)                    ||
                                  GET_CHR_OP                                            ||
                                  RPAD_BRANCOS(vvDescricaoPromocao, 255)                ||
                                  TO_CHAR(vtDATAINICIAL(viIdxPromocao), 'YYYYMMDD')     ||
                                  TO_CHAR(vtDATAFINAL(viIdxPromocao), 'YYYYMMDD')       ||
                                  RPAD_BRANCOS(vtATIVA(viIdxPromocao), 1)               ||
                                  RPAD_BRANCOS(vtTIPOCONDICAOHYPERA(viIdxPromocao), 1);        
          END IF;  
          
          -- Incrementa Sequência
          viSequencia := viSequencia + 1;
          -- Guarda a Sequência da Quebra
          viSequenciaQuebra := viSequencia;
          -- Incrementa Sequência
          viSequencia := viSequencia + 1;
                                      
          -- Planos de Pagamento da Promoção (Produto Cartesiano Plano x Filial da Promoção)
          IF (vtRESTRICAOPLANO(viIdxPromocao) = 'S') THEN
            
            vtCODPLPAG.DELETE;
            vtCGCFILIAL_PLPAG.DELETE;
          
            EXECUTE IMMEDIATE ' SELECT VIEW_MED_PROMOCAO_PLPAG.CODPLPAG
                                     , VIEW_MED_PROMOCAO_FILIAL.CGC
                                  FROM VIEW_MED_PROMOCAO_PLPAG
                                     , VIEW_MED_PROMOCAO_FILIAL
                                 WHERE VIEW_MED_PROMOCAO_FILIAL.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '
                                   AND VIEW_MED_PROMOCAO_FILIAL.CODFILIAL = '      || '''' || pi_vCodFilial    || '''' || '
                                   AND VIEW_MED_PROMOCAO_PLPAG.CODPROMOCAOMED  = ' || '''' || vvCodigoPromocao || '''' || '
                                 ORDER BY VIEW_MED_PROMOCAO_FILIAL.CODFILIAL
                                        , VIEW_MED_PROMOCAO_PLPAG.CODPLPAG '
            BULK COLLECT INTO vtCODPLPAG
                            , vtCGCFILIAL_PLPAG;
          
            IF (vtCODPLPAG.COUNT > 0) THEN
          
              FOR viIdxPlPag IN vtCODPLPAG.FIRST..vtCODPLPAG.LAST LOOP
                          
                -- Conteúdo
                vvConteudo := '2'                                           ||
                              RPAD_BRANCOS(vvCodigoPromocao, 20)            ||
                              GET_CHR_OP                                    ||
                              LPAD_ZEROS(vtCGCFILIAL_PLPAG(viIdxPlPag), 14) ||
                              RPAD_BRANCOS(vtCODPLPAG(viIdxPlPag), 50);
                
                -- Observação
                vvObsExportacao := TRIM(TO_CHAR(viSequencia,'000000000'))       ||
                                   ' ; CODPROMOCAO: ' || vvCodigoPromocao       ||
                                   ' ; DESCRICAO: '   || vvDescricaoPromocao    ||
                                   ' ; CODPLPAG: '    || vtCODPLPAG(viIdxPlPag) ||
                                   ' ; CGCFILIAL: '   || vtCGCFILIAL_PLPAG(viIdxPlPag);

                -- Grava em Memória conteúdo das Filiais - DDVENDAS-37737
                viIdxConteudoFilial := NVL(vtConteudoFilial.COUNT,0) + 1;
                vtConteudoFilial(viIdxConteudoFilial).vvArquivoCondicao := vvArquivoCondicao; 
                vtConteudoFilial(viIdxConteudoFilial).vvConteudo        := vvConteudo; 
                vtConteudoFilial(viIdxConteudoFilial).vvObsExportacao   := vvObsExportacao;
                vtConteudoFilial(viIdxConteudoFilial).vvCodigoPromocao  := vvCodigoPromocao; 
                vtConteudoFilial(viIdxConteudoFilial).vvCgcFilial       := vtCGCFILIAL_PLPAG(viIdxPlPag); 
                vtConteudoFilial(viIdxConteudoFilial).vnCodPlPag        := vtCODPLPAG(viIdxPlPag); 

                -- Grava o Registro
                /*
                vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                     pi_vCodFilial,
                                                     vvArquivoCondicao,
                                                     '2',
                                                     vvConteudo,
                                                     NULL,
                                                     vvObsExportacao,
                                                     'PM',
                                                     vvCodigoPromocao,
                                                     'FI',
                                                     vtCGCFILIAL_PLPAG(viIdxPlPag),
                                                     'PL',
                                                     vtCODPLPAG(viIdxPlPag));
                IF (vvOperacao <> 'N') THEN
                  vvAlterouDetalhes := 'S';
                END IF;
                */                                                                                                     
                                
                -- Incrementa Sequência
                viSequencia := viSequencia + 1;
                                                      
              END LOOP; -- Fim: Loop de Planos de Pagamento                              
           
            END IF; -- Fim Condição: Carregou Planos de Pagamento
            
         
          ELSE
      
            vtCODPLPAG.DELETE;
            vtCGCFILIAL_PLPAG.DELETE;
          
            EXECUTE IMMEDIATE ' SELECT 0 CODPLPAG
                                     , VIEW_MED_PROMOCAO_FILIAL.CGC
                                  FROM VIEW_MED_PROMOCAO_FILIAL
                                 WHERE VIEW_MED_PROMOCAO_FILIAL.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '
                                   AND VIEW_MED_PROMOCAO_FILIAL.CODFILIAL = '      || '''' || pi_vCodFilial    || '''' || '
                                 ORDER BY VIEW_MED_PROMOCAO_FILIAL.CODFILIAL '
            BULK COLLECT INTO vtCODPLPAG
                            , vtCGCFILIAL_PLPAG;
          
            IF (vtCODPLPAG.COUNT > 0) THEN
          
              FOR viIdxPlPag IN vtCODPLPAG.FIRST..vtCODPLPAG.LAST LOOP
                          
                -- Conteúdo
                vvConteudo := '2'                                           ||
                              RPAD_BRANCOS(vvCodigoPromocao, 20)            ||
                              GET_CHR_OP                                    ||
                              LPAD_ZEROS(vtCGCFILIAL_PLPAG(viIdxPlPag), 14) ||
                              RPAD_BRANCOS('', 50); -- Sem Plano
                
                -- Observação
                vvObsExportacao := TRIM(TO_CHAR(viSequencia,'000000000'))       ||
                                   ' ; CODPROMOCAO: ' || vvCodigoPromocao       ||
                                   ' ; DESCRICAO: '   || vvDescricaoPromocao    ||
                                   ' ; CODPLPAG: '    || vtCODPLPAG(viIdxPlPag) ||
                                   ' ; CGCFILIAL: '   || vtCGCFILIAL_PLPAG(viIdxPlPag);

                -- Grava em Memória conteúdo das Filiais - DDVENDAS-37737
                viIdxConteudoFilial := NVL(vtConteudoFilial.COUNT,0) + 1;
                vtConteudoFilial(viIdxConteudoFilial).vvArquivoCondicao := vvArquivoCondicao; 
                vtConteudoFilial(viIdxConteudoFilial).vvConteudo        := vvConteudo; 
                vtConteudoFilial(viIdxConteudoFilial).vvObsExportacao   := vvObsExportacao;
                vtConteudoFilial(viIdxConteudoFilial).vvCodigoPromocao  := vvCodigoPromocao; 
                vtConteudoFilial(viIdxConteudoFilial).vvCgcFilial       := vtCGCFILIAL_PLPAG(viIdxPlPag); 
                vtConteudoFilial(viIdxConteudoFilial).vnCodPlPag        := vtCODPLPAG(viIdxPlPag); 

                -- Grava o Registro
                /*
                vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                     pi_vCodFilial,
                                                     vvArquivoCondicao,
                                                     '2',
                                                     vvConteudo,
                                                     NULL,
                                                     vvObsExportacao,
                                                     'PM',
                                                     vvCodigoPromocao,
                                                     'FI',
                                                     vtCGCFILIAL_PLPAG(viIdxPlPag),
                                                     'PL',
                                                     vtCODPLPAG(viIdxPlPag));
                IF (vvOperacao <> 'N') THEN
                  vvAlterouDetalhes := 'S';
                END IF;                                                                                                     
                */
                                
                -- Incrementa Sequência
                viSequencia := viSequencia + 1;
                                                      
              END LOOP; -- Fim: Loop de Planos de Pagamento                              
           
            END IF; -- Fim Condição: Carregou Planos de Pagamento     
          END IF; -- Fim Condição: Existe Restrição Planos de Pagamento da Promoção

          -- UFs x Clientes da Promoção em Arquivo de Campanha
          IF (vvArquivoCondicao = 'CAMPANHA') AND
             (vtRESTRICAOREGIAO(viIdxPromocao) = 'S') THEN
             
            EXECUTE IMMEDIATE 'SELECT CASE WHEN NVL((SELECT COUNT(DISTINCT UF) FROM VIEW_MED_PROMOCAO_REGIAO WHERE CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '),0) < NVL((SELECT COUNT(DISTINCT UF) FROM PCREGIAO),0) THEN
                                         ''S''
                                       ELSE
                                         ''N''
                                       END GERAR_UF 
                                  FROM DUAL'
                         INTO vvGerarUf;    
                         
            IF (vvGerarUf = 'S') THEN        
          
              vtUF_REGIAO.DELETE;

              EXECUTE IMMEDIATE ' SELECT DISTINCT VIEW_MED_PROMOCAO_REGIAO.UF
                                    FROM VIEW_MED_PROMOCAO_REGIAO
                                   WHERE VIEW_MED_PROMOCAO_REGIAO.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '
                                   ORDER BY VIEW_MED_PROMOCAO_REGIAO.UF '
              BULK COLLECT INTO vtUF_REGIAO;
              
              IF (vtUF_REGIAO.COUNT > 0) THEN
            
                FOR viIdxUf IN vtUF_REGIAO.FIRST..vtUF_REGIAO.LAST LOOP
                                              
                  -- Conteúdo
                  vvConteudo := '3'                                ||
                                RPAD_BRANCOS(vvCodigoPromocao, 20) ||
                                GET_CHR_OP                         ||
                                LPAD_ZEROS(vtUF_REGIAO(viIdxUf), 2);
                  
                  -- Observação
                  vvObsExportacao := TRIM(TO_CHAR(viSequencia,'000000000'))    ||
                                     ' ; CODPROMOCAO: ' || vvCodigoPromocao    ||
                                     ' ; DESCRICAO: '   || vvDescricaoPromocao ||
                                     ' ; UF: '          || vtUF_REGIAO(viIdxUf);
  
                  -- Grava o Registro
                  vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                       pi_vCodFilial,
                                                       vvArquivoCondicao,
                                                       '3',
                                                       vvConteudo,
                                                       NULL,
                                                       vvObsExportacao,
                                                       'PM',
                                                       vvCodigoPromocao,
                                                       'UF',
                                                       vtUF_REGIAO(viIdxUf));
                  IF (vvOperacao <> 'N') THEN
                    vvAlterouDetalhes := 'S';
                  END IF;                                     
                        
                  -- Incrementa Sequência
                  viSequencia := viSequencia + 1;
                                                        
                END LOOP; -- Fim: Loop de Clientes
             
              END IF; -- Fim Condição: Carregou Clientes
              
            END IF;
                                       
          END IF; -- Fim Condição: Gerar UFs x Clientes da Promoção em Arquivo de Campanha

          -- Clientes da Promoção
          IF (vtRESTRICAOCLIENTE(viIdxPromocao) = 'S') THEN
          
            vtCGCENT.DELETE;
          
            EXECUTE IMMEDIATE ' SELECT VIEW_MED_PROMOCAO_CLIENTE.CGCENT
                                  FROM VIEW_MED_PROMOCAO_CLIENTE
                                 WHERE VIEW_MED_PROMOCAO_CLIENTE.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '
                                 ORDER BY VIEW_MED_PROMOCAO_CLIENTE.CODCLI '
            BULK COLLECT INTO vtCGCENT;
            
            IF (vtCGCENT.COUNT > 0) THEN
          
              FOR viIdxCliente IN vtCGCENT.FIRST..vtCGCENT.LAST LOOP
              
                -- Tabela de Campanha
                IF (vvArquivoCondicao = 'CAMPANHA') THEN
                  vvTipoRegistroPdv := '4';
                -- Tabela de Condição
                ELSE
                  vvTipoRegistroPdv := '3';
                END IF;
                            
                -- Conteúdo
                vvConteudo := vvTipoRegistroPdv                  ||
                              RPAD_BRANCOS(vvCodigoPromocao, 20) ||
                              GET_CHR_OP                         ||
                              LPAD_ZEROS(vtCGCENT(viIdxCliente), 14);
                
                -- Observação
                vvObsExportacao := TRIM(TO_CHAR(viSequencia,'000000000'))    ||
                                   ' ; CODPROMOCAO: ' || vvCodigoPromocao    ||
                                   ' ; DESCRICAO: '   || vvDescricaoPromocao ||
                                   ' ; CGCCLI: '      || vtCGCENT(viIdxCliente);

                -- Grava o Registro
                vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                     pi_vCodFilial,
                                                     vvArquivoCondicao,
                                                     vvTipoRegistroPdv,
                                                     vvConteudo,
                                                     NULL,
                                                     vvObsExportacao,
                                                     'PM',
                                                     vvCodigoPromocao,
                                                     'CL',
                                                     vtCGCENT(viIdxCliente));
                IF (vvOperacao <> 'N') THEN
                  vvAlterouDetalhes := 'S';
                END IF;                                     
                      
                -- Incrementa Sequência
                viSequencia := viSequencia + 1;
                                                      
              END LOOP; -- Fim: Loop de Clientes
           
            END IF; -- Fim Condição: Carregou Clientes
                                       
          END IF; -- Fim Condição: Existe Restrição de Clientes da Promoção
          
          -- Carrega as UFs
          vtUf.DELETE;
          
          vtNUMREGIAO.DELETE;
          vtUF_REGIAO.DELETE;
          
          -- Arquivo de Campanha não tem UF no Produto
          IF (vvArquivoCondicao = 'CAMPANHA')  THEN

            EXECUTE IMMEDIATE ' SELECT TB.NUMREGIAO, (SELECT PCREGIAO.UF FROM PCREGIAO WHERE PCREGIAO.NUMREGIAO = TB.NUMREGIAO) UF
                                  FROM ( SELECT MIN(VIEW_MED_PROMOCAO_REGIAO.NUMREGIAO) NUMREGIAO
                                           FROM VIEW_MED_PROMOCAO_REGIAO
                                          WHERE VIEW_MED_PROMOCAO_REGIAO.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || ') TB'
            BULK COLLECT INTO vtNUMREGIAO
                            , vtUF_REGIAO;                                                        
          
          -- Arquivo de Condição tem UF no Produto
          ELSE
          
            EXECUTE IMMEDIATE ' SELECT MIN(VIEW_MED_PROMOCAO_REGIAO.NUMREGIAO) NUMREGIAO
                                     , VIEW_MED_PROMOCAO_REGIAO.UF
                                  FROM VIEW_MED_PROMOCAO_REGIAO
                                 WHERE VIEW_MED_PROMOCAO_REGIAO.CODPROMOCAOMED = ' || '''' || vvCodigoPromocao || '''' || '
                                 GROUP BY VIEW_MED_PROMOCAO_REGIAO.UF
                                 ORDER BY VIEW_MED_PROMOCAO_REGIAO.UF '
            BULK COLLECT INTO vtNUMREGIAO
                            , vtUF_REGIAO;
                            
          END IF;                            
          
          IF (vtNUMREGIAO.COUNT > 0) THEN
        
            FOR viIdxRegiao IN vtNUMREGIAO.FIRST..vtNUMREGIAO.LAST LOOP
          
              vrUf.NUMREGIAO := vtNUMREGIAO(viIdxRegiao);
              vrUf.UF        := vtUF_REGIAO(viIdxRegiao);
              vrUf.CODCLI    := F_CODCLI_ST(pi_vCodFilial,
                                            vtUF_REGIAO(viIdxRegiao));
              vtUf(NVL(vtUf.COUNT,0) + 1) :=  vrUf;                       
              
            END LOOP; -- Fim: Loop de Regiões
           
          END IF; -- Fim Condição: Carregou Regiões
        
        END IF; -- Fim Condição: Quebra de Condição                                  
        
        ------------------------
        -- Geração dos Produtos
        ------------------------
                                       
        -- Laço de UF's
        FOR viLaco IN vtUf.FIRST..vtUf.LAST LOOP
        
          -- Dados da UF
          vrUf := vtUf(viLaco); 
          
          -- Obter o Preço e a Tributação
          P_OBTER_PRECO_TRIBUTACAO(pi_vCodFilial,
                                   vvUsaTributacaoPorUf,
                                   vnNumCasasDecVenda,
                                   vvUsaRegraRecalDescPTabMed,
                                   vvOrigemPreco,
                                   vvAplicarDescPtabelaTribut,
                                   vvGerarAcordoPreco,
                                   vvAplicarIndiceAcordoPreco,
                                   vrUf.NUMREGIAO,
                                   vrUf.UF,
                                   vtCODPROD(viIdxPromocao),
                                   vtTIPOMERC(viIdxPromocao),
                                   vtUTILIZAPRECOFABRICA(viIdxPromocao),
                                   vnPreco,
                                   vnCodSt);
                             
          -- Custo do Produto
          IF (vtEstoque_CodProd_Custo.EXISTS(vtCODPROD(viIdxPromocao))) THEN
            vnCustoFinanceiro := NVL(vtEstoque_CodProd_Custo(vtCODPROD(viIdxPromocao)),0);
          ELSE
            vnCustoFinanceiro := 0;
          END IF;
                                   
          -- Se Faixa Zero não tem Desconto/Preço Fixo -> Vende a Preço Tabela e conforme Hypera colocar 0.01
          IF (NVL(vtFAIXAZERO(viIdxPromocao),'N') = 'S') THEN

            vnPercDesc     := 0.01;
            vnPrecoLiquido := vnPreco;
          
          -- Se tem Desconto/Preço Fixo
          ELSE
                                   
          -- Calcula o Preço Líquido
          vnPercDesc     := 0;
          vnPrecoLiquido := 0;
          IF   (vtTIPOPROMOCAO(viIdxPromocao) = 'R') THEN
            IF    NVL(vtPERCMARKUPMED(viIdxPromocao),0) = 0 THEN
              vnPercDesc           := 0;
            ELSIF NVL(vnPreco,0) = 0 THEN
              vnPercDesc           := 0;
            ELSIF NVL(vnCustoFinanceiro,0) = 0 THEN
              vnPercDesc           := 0;
              vnPreco              := 0;
            ELSE
              IF (NVL(vnCustoFinanceiro,0) = 0) THEN
                vnPercDesc         := 0;
                vnPreco            := 0;
              ELSE
                vnPrecoVendaMarkup := vnCustoFinanceiro * (1+(NVL(vtPERCMARKUPMED(viIdxPromocao),0) * 0.01));
                vnPercDesc         := ROUND((1-(vnPrecoVendaMarkup/vnPreco))*100,6);
              END IF;
            END IF;          
            vnPrecoLiquido := ROUND(vnPreco * (1- (NVL(vnPercDesc,0) / 100)), vnNumCasasDecVenda);
          ELSE
            IF (vtTIPOPOLITICA(viIdxPromocao) IN ('P','F')) THEN
              -- Como não tem como mandar o Preço Fixo, converto em desconto
              IF NVL(vnPreco,0) = 0 THEN
                vnPercDesc     := 0;
              ELSE
                vnPrecoLiquido := NVL(vtPRECOFIXOPROMOCAOMED(viIdxPromocao),0);
                vnPercDesc     := ROUND((1-(vtPRECOFIXOPROMOCAOMED(viIdxPromocao)/vnPreco))*100,6);
              END IF;
            ELSE
              vnPrecoLiquido := ROUND(vnPreco * (1- (NVL(vtPERCDESC(viIdxPromocao),0) / 100)), vnNumCasasDecVenda);
              vnPercDesc     := NVL(vtPERCDESC(viIdxPromocao),0);
            END IF;
          END IF;  
            
          END IF; -- Fim: Se tem Desconto/Preço Fixo
          
          -- Se tem Preço 
          IF (NVL(vnPrecoLiquido,0) > 0) THEN
          
            -- Calcula ST do Produto para a UF
            P_OBTEM_STFONTE_4PMPF(pi_vCodFilial,
                                  vtCODPROD(viIdxPromocao),
                                  vrUf.CODCLI,
                                  vrUf.NUMREGIAO,
                                  1,       -- pi_nCondVenda,
                                  100,     -- pi_nPercVenda
                                  vnCodSt,
                                  vnPrecoLiquido,
                                  0,       -- pi_nValorIpi
                                  0,       -- pi_nPrecoMaxConsum
                                  0,       -- pi_nValorUltEnt
                                  0,       -- pi_nCustoNfSemSt
                                  vnPreco,
                                  'N',     -->> Padrão Não (Simples Nacional)
                                  'S',     -->> Pesquisa Custos
                                  'N',     -->> Não é Item Bonificado
                                  0,       -->> Não passa Frete e Outras Despesas
                                  vnBaseSt,
                                  vnValorSt,
                                  vvMensagemSt,
                                  vvRegimeEspIsenStFonte,
                                  vnAliqIcms1,
                                  vnAliqIcms2,
                                  vnIva,
                                  vnPercBaseRedSt
                                  );
                                  
            -- Registro de Produtos da Campanha - Promoção de Kit/Mix/Valor e Faixa de Quantidade
            IF (vvArquivoCondicao = 'CAMPANHA') THEN
              IF (vtTIPOPROMOCAO(viIdxPromocao) IN ('K','M','V')) THEN
                vnQtdeMinima := vtINICIOINTERVALOPROMOCAOMED(viIdxPromocao);
              ELSE
                vnQtdeMinima := 0;
              END IF;
              IF (vtTIPOPOLITICA(viIdxPromocao) IN ('Q','F')) THEN
                vnFaixaInicial := vtINICIOINTERVALOPROMOCAOMED(viIdxPromocao);
                vnFaixaFinal   := vtFIMINTERVALOPROMOCAOMED(viIdxPromocao);
              ELSE
                vnFaixaInicial := 0;
                vnFaixaFinal   := 0;
              END IF;
              vvTipoRegistroProduto := '5';
              vvConteudo := vvTipoRegistroProduto                             ||
                            RPAD_BRANCOS(vvCodigoPromocao, 20)                ||
                            GET_CHR_OP                                        ||
                            RPAD_BRANCOS(vtCODAUXILIAR(viIdxPromocao), 13)    ||
                            LPAD_ZEROS_DEC(vnQtdeMinima, 10, 0)               ||
                            LPAD_ZEROS_DEC(vnFaixaInicial, 9, 2)              ||
                            LPAD_ZEROS_DEC(vnFaixaFinal, 9, 2)                ||
                            LPAD_ZEROS_DEC(vnPercDesc, 5, 2)                  ||
                            LPAD_ZEROS_DEC(vnValorSt, 5, 2);            
              vvTipoCodigoComplementarProd := 'FX';
              vvCodigoComplementarProd     := vnFaixaInicial;
            -- Registro de Produtos da Condição - Demais Promoções
            ELSE
              vvTipoRegistroProduto := '4';
              vvConteudo := vvTipoRegistroProduto                             ||
                            RPAD_BRANCOS(vvCodigoPromocao, 20)                ||
                            GET_CHR_OP                                        ||
                            RPAD_BRANCOS(vtCODAUXILIAR(viIdxPromocao), 13)    ||
                            RPAD_BRANCOS(vrUf.UF, 2)                          ||
                            LPAD_ZEROS_DEC(vnPercDesc, 5, 2)                  ||
                            LPAD_ZEROS_DEC(vnValorSt, 5, 2);            
              vvTipoCodigoComplementarProd := 'UF';
              vvCodigoComplementarProd     := vrUf.UF;
            END IF;
                          
            -- Observação
            vvObsExportacao := TRIM(TO_CHAR(viSequencia,'000000000'))               ||
                               ' ; NUMREGIAO: '    || vrUf.NUMREGIAO                || 
                               ' ; UF: '           || vrUf.UF                       ||
                               ' ; CODST: '        || vnCodSt                       ||
                               ' ; CODCLI: '       || vrUf.CODCLI                   ||
                               ' ; CODPROD: '      || vtCODPROD(viIdxPromocao)      ||
                               ' ; EAN: '          || vtCODAUXILIAR(viIdxPromocao)  ||
                               ' ; CODPROMOCAO: '  || vvCodigoPromocao              ||
                               ' ; DESCRICAO: '    || vvDescricaoPromocao           ||
                               ' ; TIPOPROMOCAO: ' || vtTIPOPROMOCAO(viIdxPromocao) ||
                               ' ; TIPOPOLITICA: ' || vtTIPOPOLITICA(viIdxPromocao) ||
                               ' ; PRECO: '        || vnPreco                       ||
                               ' ; PERCDESC: '     || vnPercDesc                    ||
                               ' ; PRECOLIQ: '     || vnPrecoLiquido                ||
                               ' ; ST: '           || vnValorSt                     ||
                               ' ; QTDEMINIMA: '   || vnQtdeMinima                  ||
                               ' ; FAIXAINICIAL: ' || vnFaixaInicial                ||
                               ' ; FAIXAFINAL: '   || vnFaixaFinal
                               ;
            
            -- Grava o Registro
            vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                                 pi_vCodFilial,
                                                 vvArquivoCondicao,
                                                 vvTipoRegistroProduto,
                                                 vvConteudo,
                                                 NULL,
                                                 vvObsExportacao,
                                                 'PM',
                                                 vvCodigoPromocao,
                                                 'PR',
                                                 vtCODAUXILIAR(viIdxPromocao),
                                                 vvTipoCodigoComplementarProd,
                                                 vvCodigoComplementarProd);
            IF (vvOperacao <> 'N') THEN
              vvAlterouDetalhes := 'S';
            END IF;                                     
                              
            -- Incrementa Sequência
            viSequencia := viSequencia + 1;
                                  
          END IF; -- Fim Condição: Se tem Preço          
        
        END LOOP; -- Fim Laço: UFs
           
      END LOOP; -- Fim Laço: Produtos na Promoção
      
    END IF; -- Fim Condição: Ocorreu Extração de Dados
    
    -- Grava o Registro da última quebra
    IF (vvConteudo IS NOT NULL) THEN
    
      ----------------------------------------
      -- Geração das Filiais -  DDVENDAS-37737
      ----------------------------------------
      P_GERA_DADOS_FILIAIS;
    
      -- Observação
      vvObsExportacao := TRIM(TO_CHAR(viSequenciaQuebra,'000000000')) ||
                         ' ; CODPROMOCAO: ' || vvQuebraCondicao       ||
                         ' ; DESCRICAO: '   || vvDescricaoQuebraCondicao;
    
      -- Grava o Registro
      vvOperacao := F_GRAVA_REGISTRO_HYPER(pi_vCodSistema,
                                           pi_vCodFilial,
                                           vvArquivoCondicao,
                                           '1',
                                           vvConteudoCondicao,
                                           vvAlterouDetalhes,
                                           vvObsExportacao,
                                           'PM',
                                           vvQuebraCondicao);
    END IF;  
    
    -- Atualiza com a Operação E - Exclusão os Registros com valor
    -- na última exportação mas não tem valor na exportação atual
    -- Primeiro marca a Promoção (Header) como alterada
    FOR vc_PromocaoAlterada IN (SELECT DISTINCT
                                       PCCONFIGSISTCONDOPERLOG.ARQUIVO
                                     , PCCONFIGSISTCONDOPERLOG.TIPOREGISTRO  
                                     , PCCONFIGSISTCONDOPERLOG.TIPOCODIGOPRINCIPAL  
                                     , PCCONFIGSISTCONDOPERLOG.CODIGOPRINCIPAL
                                     , SUBSTR(PCCONFIGSISTCONDOPERLOG.CONTEUDO,294,1) ATIVO
                                  FROM PCCONFIGSISTCONDOPERLOG
                                 WHERE (CODSISTEMA   = pi_vCodSistema)
                                   AND (CODFILIAL    = pi_vCodFilial)
                                   AND (TIPOREGISTRO = '1')
                                   AND (CONTEUDO     IS NOT NULL) 
                                   AND (NOVOCONTEUDO IS NULL)) LOOP
      -- Se já mandou a informação como Inativo
      IF (NVL(vc_PromocaoAlterada.ATIVO,'S') = 'N') THEN
        -- Verifica se a Promoção foi Excluída
        BEGIN 
          SELECT 'S' 
            INTO vvPromocaoExiste
            FROM PCPROMOCAOMED
           WHERE (PCPROMOCAOMED.CODPROMOCAOMED = TO_NUMBER(NVL(vc_PromocaoAlterada.CODIGOPRINCIPAL,'0')));             
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvPromocaoExiste := 'N';          
        END;
        -- Se a Promoção não existe mais
        IF (vvPromocaoExiste = 'N') THEN
          -- Exclui todos os Registros da Promoção para não mandar mais
          DELETE FROM PCCONFIGSISTCONDOPERLOG
           WHERE (CODSISTEMA          = pi_vCodSistema)
             AND (CODFILIAL           = pi_vCodFilial)
             AND (ARQUIVO             = vc_PromocaoAlterada.ARQUIVO)
             AND (TIPOCODIGOPRINCIPAL = vc_PromocaoAlterada.TIPOCODIGOPRINCIPAL)
             AND (CODIGOPRINCIPAL     = vc_PromocaoAlterada.CODIGOPRINCIPAL);
        ELSE
          -- Marca o Registro o registro como Excluído para não mandar mais,
          -- até que porventura seja ativada e passe a mandar novamente
          UPDATE PCCONFIGSISTCONDOPERLOG
             SET NOVAOPERACAO = 'E'
               , OBSEXPORTACAO = TO_CHAR(TO_NUMBER(SUBSTR(OBSEXPORTACAO,1,9) + viSequencia),'000000000') || SUBSTR(OBSEXPORTACAO,10,1000)
           WHERE (CODSISTEMA          = pi_vCodSistema)
             AND (CODFILIAL           = pi_vCodFilial)
             AND (ARQUIVO             = vc_PromocaoAlterada.ARQUIVO)
             AND (TIPOREGISTRO        = vc_PromocaoAlterada.TIPOREGISTRO)
             AND (TIPOCODIGOPRINCIPAL = vc_PromocaoAlterada.TIPOCODIGOPRINCIPAL)
             AND (CODIGOPRINCIPAL     = vc_PromocaoAlterada.CODIGOPRINCIPAL);
        END IF;             
      -- Se ainda não mandou como Inativo
      ELSE
        -- Quando a promoção não existe mais, deve mandar o Header com as Datas de Hoje e Inativa.
        -- Como não tenho mais a informação da Promoção, uso o último registro enviado e troco os valores das posições de período e ativo
        UPDATE PCCONFIGSISTCONDOPERLOG
           SET NOVAOPERACAO  = 'A'
             , NOVOCONTEUDO  = SUBSTR(CONTEUDO,1,277)      || 
                               TO_CHAR(SYSDATE,'YYYYMMDD') || -- Data Inicial HOJE 
                               TO_CHAR(SYSDATE,'YYYYMMDD') || -- Data Final HOJE 
                               'N'                         || -- Inativa
                               SUBSTR(CONTEUDO,295,4000) 
             , OBSEXPORTACAO = TO_CHAR(TO_NUMBER(SUBSTR(OBSEXPORTACAO,1,9) + viSequencia),'000000000') || SUBSTR(OBSEXPORTACAO,10,1000)
         WHERE (CODSISTEMA          = pi_vCodSistema)
           AND (CODFILIAL           = pi_vCodFilial)
           AND (ARQUIVO             = vc_PromocaoAlterada.ARQUIVO)
           AND (TIPOREGISTRO        = vc_PromocaoAlterada.TIPOREGISTRO)
           AND (TIPOCODIGOPRINCIPAL = vc_PromocaoAlterada.TIPOCODIGOPRINCIPAL)
           AND (CODIGOPRINCIPAL     = vc_PromocaoAlterada.CODIGOPRINCIPAL);
      END IF;     
    END LOOP;                                   
    -- Depois muda os registros para excluídos (detalhes)
    UPDATE PCCONFIGSISTCONDOPERLOG
       SET NOVAOPERACAO = 'E'
         , OBSEXPORTACAO = TO_CHAR(TO_NUMBER(SUBSTR(OBSEXPORTACAO,1,9) + viSequencia),'000000000') || SUBSTR(OBSEXPORTACAO,10,1000)
     WHERE (CODSISTEMA   = pi_vCodSistema)
       AND (CODFILIAL    = pi_vCodFilial)
       AND (CONTEUDO     IS NOT NULL) 
       AND (NOVOCONTEUDO IS NULL)
       AND (TIPOREGISTRO <> '1'); -- O Header não tem Flag de Exclusão
    
    -- Efetiva Transações
    COMMIT;
      
  EXCEPTION
    WHEN e_View THEN
      ROLLBACK;
      RAISE_APPLICATION_ERROR(-20000, 'Atualizar o Dicionário de Dados na Rotina 2302, opção "Views de Geração dos Dicionários de Dados"');
  END P_CONDCOMERC_SISTOPERLOG_HYPER;
                                     
END PKG_DICIONARIOS_MED;